// ═══════════════════════════════════════════════════════════
// 🔒 RSK PROTECTION SYSTEM v1.0 — ACTIVE
// Unauthorized access is illegal under IT Act 2000
// ═══════════════════════════════════════════════════════════
(function(){
  'use strict';

  function _isDevUser(){
    // Bypass 1: logged in with username "developer" (any case)
    try{
      if(typeof currentUser!=='undefined' && currentUser && currentUser.username &&
         String(currentUser.username).toLowerCase()==='developer') return true;
    }catch(e){}
    // Bypass 2: secret dev URL param ?rskdev=lakshya2026
    try{
      if(new URLSearchParams(window.location.search).get('rskdev')==='lakshya2026') return true;
    }catch(e){}
    return false; // Protection ACTIVE for everyone else
  }

  // ── LAYER 1: Right Click ──
  document.addEventListener('contextmenu', function(e){
    if(_isDevUser()) return true;
    e.preventDefault(); return false;
  });

  // ── LAYER 2: Keyboard Shortcuts ──
  document.addEventListener('keydown', function(e){
    if(_isDevUser()) return true;
    var _inInput = e.target && (e.target.tagName==='INPUT'||e.target.tagName==='TEXTAREA');
    if(e.key==='F12'||e.keyCode===123){ if(_isDevUser()) return true; e.preventDefault(); e.stopPropagation(); return false; }
    if(e.ctrlKey&&e.shiftKey&&(e.key==='I'||e.key==='i')){ e.preventDefault(); return false; }
    if(e.ctrlKey&&e.shiftKey&&(e.key==='J'||e.key==='j')){ e.preventDefault(); return false; }
    if(e.ctrlKey&&e.shiftKey&&(e.key==='C'||e.key==='c')){ e.preventDefault(); return false; }
    if(e.ctrlKey&&(e.key==='U'||e.key==='u')){ e.preventDefault(); return false; }
    if(e.ctrlKey&&(e.key==='S'||e.key==='s')){ e.preventDefault(); return false; }
    if(_inInput&&e.ctrlKey&&(e.key==='A'||e.key==='a'||e.key==='C'||e.key==='c'||e.key==='X'||e.key==='x'||e.key==='V'||e.key==='v'||e.key==='Z'||e.key==='z')) return true;
    if(e.ctrlKey&&(e.key==='A'||e.key==='a')){ e.preventDefault(); return false; }
    if(e.ctrlKey&&(e.key==='P'||e.key==='p')){ e.preventDefault(); return false; }
    if(e.ctrlKey&&(e.key==='F'||e.key==='f')){ e.preventDefault(); return false; }
  }, true);

  // ── LAYER 3: DevTools Debugger Trap ──
  var _devtrap = function(){
    if(_isDevUser()) return;
    var _st = performance.now();
    (function(){ return false; }).constructor('debugger')();
    if(performance.now() - _st > 80){
      try{
        document.documentElement.innerHTML = '<div style="display:flex;align-items:center;justify-content:center;height:100vh;background:#1a1a2e;color:#e94560;font-family:Arial;flex-direction:column;gap:20px"><div style="font-size:80px">🔒</div><div style="font-size:28px;font-weight:bold">Unauthorized Access Detected</div><div style="font-size:16px;color:#aaa">यह सॉफ्टवेयर सुरक्षित है। IT Act 2000 के तहत अनधिकृत पहुंच दंडनीय है।</div><div style="font-size:14px;color:#666">RSK Result Program — Licensed Software</div></div>';
      }catch(e){}
      setInterval(function(){ try{ document.title='⚠️ ACCESS DENIED'; }catch(e){} }, 100);
    }
  };
  setInterval(_devtrap, 800);

  // ── LAYER 4: Window Size DevTools Detection ──
  var _wincheck = function(){
    if(_isDevUser()) return;
    var wt = 160;
    if(window.outerWidth - window.innerWidth > wt || window.outerHeight - window.innerHeight > wt){
      try{
        document.body.style.display='none';
        document.title='⚠️ DevTools Detected';
        setTimeout(function(){ try{ document.body.style.display=''; }catch(e){} }, 3000);
      }catch(e){}
    }
  };
  setInterval(_wincheck, 500);

  // ── LAYER 5: Text Selection / Copy ──
  document.addEventListener('selectstart', function(e){ if(_isDevUser()) return true; var t=e.target; if(t&&(t.tagName==='INPUT'||t.tagName==='TEXTAREA')) return true; e.preventDefault(); return false; });
  document.addEventListener('dragstart',   function(e){ if(_isDevUser()) return true; e.preventDefault(); return false; });
  document.addEventListener('copy',        function(e){ if(_isDevUser()) return true; var t=e.target; if(t&&(t.tagName==='INPUT'||t.tagName==='TEXTAREA')) return true; e.preventDefault(); return false; });
  document.addEventListener('cut',         function(e){ if(_isDevUser()) return true; var t=e.target; if(t&&(t.tagName==='INPUT'||t.tagName==='TEXTAREA')) return true; e.preventDefault(); return false; });

  // ── LAYER 6: Iframe Busting ──
  if(window.top !== window.self){
    try{ window.top.location = window.self.location; }catch(e){ document.body.innerHTML = ''; }
  }

})();

