/* Load PDF libs via fetch to avoid Tracking Prevention blocking CDN cookies */
(function(){
  function loadScript(url, cb){
    fetch(url)
      .then(function(r){ return r.text(); })
      .then(function(code){
        var s=document.createElement('script');
        s.textContent=code;
        document.head.appendChild(s);
        if(cb) cb();
      })
      .catch(function(err){ console.warn('Could not load '+url, err); if(cb) cb(); });
  }
  loadScript('https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js', function(){
    loadScript('https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js', function(){
      loadScript('https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js', null);
    });
  });
  loadScript('https://cdnjs.cloudflare.com/ajax/libs/lz-string/1.4.4/lz-string.min.js', null);
  loadScript('https://cdnjs.cloudflare.com/ajax/libs/jszip/3.10.1/jszip.min.js', null);
})();

