// ── ERP Dropdown Stubs (defined early for HTML onclick compatibility) ──
var _erpDrop={};
function toggleErpDropdown(name,e){
  if(e) e.stopPropagation();
  var isOpen=_erpDrop[name];
  ['adm','staff','fee','exam','other'].forEach(function(n){
    _erpDrop[n]=false;
    var m=document.getElementById(n+'-dropdown'); if(m) m.style.display='none';
    var a=document.getElementById(n+'-arrow'); if(a) a.textContent='▼';
    var tb=document.getElementById('tab-'+n+'-btn');
    if(tb && !tb.classList.contains('rsk-tab-selected')) tb.classList.remove('active');
  });
  if(!isOpen){
    _erpDrop[name]=true;
    var btn=document.getElementById('tab-'+name+'-btn');
    var menu=document.getElementById(name+'-dropdown');
    if(btn&&menu){
      var r=btn.getBoundingClientRect();
      menu.style.cssText='display:block;position:fixed;top:'+(r.bottom+4)+'px;left:'+r.left+'px;min-width:220px;background:linear-gradient(160deg,#0a1628,#0f2952);border:1.5px solid rgba(255,255,255,.2);border-radius:12px;box-shadow:0 12px 40px rgba(0,0,0,.6);z-index:99999;padding:6px 0;';
      btn.classList.add('active');
    }
    var a=document.getElementById(name+'-arrow'); if(a) a.textContent='▲';
  }
}
function selectErpTab(tabId,dropName){
  _erpDrop[dropName]=false;
  var m=document.getElementById(dropName+'-dropdown'); if(m) m.style.display='none';
  var a=document.getElementById(dropName+'-arrow'); if(a) a.textContent='▼';
  if(typeof switchTab==='function') switchTab(tabId);
  else document.addEventListener('rsk-ready',function(){ switchTab(tabId); },{once:true});
}
document.addEventListener('click',function(e){
  ['adm','staff','fee','exam','other'].forEach(function(n){
    var wrap=document.getElementById(n+'-wrap');
    if(_erpDrop[n]&&wrap&&!wrap.contains(e.target)){
      _erpDrop[n]=false;
      var m=document.getElementById(n+'-dropdown'); if(m) m.style.display='none';
      var a=document.getElementById(n+'-arrow'); if(a) a.textContent='▼';
    }
  });
});


