var CF_WORKER_URL = 'https://rsk-12th-api.devrai1782.workers.dev';
var CF_SCHOOL_TOKEN = localStorage.getItem('rsk_school_token') || '';
var CF_ADMIN_SECRET = 'rsk_admin_2024';

function cfHeaders(isAdmin) {
  var h = { 'Content-Type': 'application/json' };
  if (isAdmin) h['X-Admin-Secret'] = CF_ADMIN_SECRET;
  else h['X-School-Token'] = CF_SCHOOL_TOKEN;
  return h;
}

function cfGetHeaders(isAdmin) {
  var h = {};
  if (isAdmin) h['X-Admin-Secret'] = CF_ADMIN_SECRET;
  else h['X-School-Token'] = CF_SCHOOL_TOKEN;
  return h;
}

var SB_DEVICE_ID = (function(){
  // 🔧 FIX: Machine fingerprint directly use karo — localStorage pe depend mat karo
  // Isse same physical machine par SARE browsers (Edge/Chrome/Firefox) ka same device_id banega
  function buildMachineFingerprint(){
    var parts = [];
    parts.push(screen.width + 'x' + screen.height + 'x' + screen.colorDepth);
    parts.push(Intl.DateTimeFormat().resolvedOptions().timeZone || '');
    parts.push(navigator.platform || '');
    parts.push(navigator.hardwareConcurrency || '');
    parts.push(navigator.deviceMemory || '');
    parts.push(navigator.language || '');
    parts.push(window.devicePixelRatio || '');
    // screen.availWidth/availHeight add karo for better uniqueness
    parts.push((screen.availWidth||'') + 'x' + (screen.availHeight||''));
    var str = parts.join('|');
    var hash = 0;
    for(var i=0; i<str.length; i++){
      hash = ((hash << 5) - hash) + str.charCodeAt(i);
      hash |= 0;
    }
    return 'mfp_' + Math.abs(hash).toString(36);
  }

  var fp = buildMachineFingerprint();

  // Old random dev_ ID tha — save kar lo taaki login pe DB se clean ho sake
  var stored = localStorage.getItem('rsk_device_id');
  if(stored && stored.indexOf('dev_') === 0){
    localStorage.setItem('rsk_old_device_id', stored);
  }

  // Hamesha machine fingerprint hi use karo (browser-agnostic)
  localStorage.setItem('rsk_device_id', fp);
  return fp;
})();

// ── LZ-String compression helpers ──
function rskCompress(jsonStr){
  try{
    if(typeof LZString!=='undefined') return 'LZ:'+LZString.compressToUTF16(jsonStr);
  }catch(e){}
  return jsonStr;
}
function rskDecompress(str){
  try{
    if(str && str.indexOf('LZ:')===0 && typeof LZString!=='undefined')
      return LZString.decompressFromUTF16(str.slice(3));
  }catch(e){}
  return str;
}

// ── Sync status indicator ──
function sbStatus(msg, color){
  var el = document.getElementById('sb-status-chip');
  if(!el) return;
  el.textContent = msg;
  el.style.background = color || '#1e40af';
  el.style.display = 'inline-flex';
}

// ── Push current profile to Cloudflare D1 ──
async function sbSync(profileKey, payload){
  try{
    sbStatus('☁️ Syncing…', '#92400e');
    var resp = await fetch(CF_WORKER_URL+'/profile', {
      method: 'POST',
      headers: cfHeaders(false),
      body: JSON.stringify({ profile_key: profileKey, device_id: SB_DEVICE_ID, data: payload })
    });
    var result = await resp.json();
    if(!result.ok) throw new Error(JSON.stringify(result));
    sbStatus('✅ Synced', '#166534');
    setTimeout(function(){ sbStatus('☁️ Cloud ON', '#1e40af'); }, 2500);
    // Broadcast activity after successful sync
    if(typeof rskBroadcastActivity === 'function' && _rskPendingActivity){
      rskBroadcastActivity(_rskPendingActivity.a, _rskPendingActivity.d);
      _rskPendingActivity = null;
    }
  }catch(e){
    console.warn('CF sync error:', e.message);
    sbStatus('⚠️ Sync failed', '#7f1d1d');
  }
}

// ── Tab-Switch Background Sync ──
var _rskTabLastSync = {}; // tab -> timestamp
var _rskTabSyncMinInterval = 30000; // 30 sec minimum between syncs per tab

async function rskTabSync(tab){
  if(!navigator.onLine) return;
  // FIX: Kuch change nahi hua toh unnecessary request mat karo
  if(!window._rskDirty) return;
  var now = Date.now();
  var last = _rskTabLastSync[tab] || 0;
  if(now - last < _rskTabSyncMinInterval) return; // too soon
  _rskTabLastSync[tab] = now;

  // Tab -> cloud key mapping
  var tabKeyMap = {
    'admlist3':    [erpKey('admList3')],
    'admform3':    [erpKey('admList3')],
    'admmissing':  [erpKey('admList3')],
    'staffmgmt':   [erpKey('erp_staff')],
    'salary':      [erpKey('erp_staff')],
    'leave':       [sessKey('erp_leave')],
    'feestructure':[erpKey('erp_customFees'),erpKey('erp_feeConfig'),erpKey('erp_feeMonths'),erpKey('erp_fees'),erpKey('erp_persist')],
    'vehiclemgmt': [erpKey('veh_list_v1'),sessKey('veh_students_v2')],
    'compemgmt':   [sessMgmtKey('comp'),_rskCTKey()],
    'funcmgmt':    [sessMgmtKey('func'),_rskCTKey()],
    'libmgmt':     [sessMgmtKey('lib'),_rskCTKey()],
    'calmgmt':     [sessMgmtKey('cal'),_rskCTKey()],
    'sportsmgmt':  [sessMgmtKey('sports'),sessKey('spt_s2_cols'),sessKey('spt_s2_data'),sessKey('spt_s3_data')],
  };

  var keys = tabKeyMap[tab];
  if(!keys || !keys.length) return;

  try{
    var resp = await fetch(CF_WORKER_URL+'/general?_t='+Date.now(), { headers: cfGetHeaders(false) });
    if(!resp.ok) return;
    var data = await resp.json();

    keys.forEach(function(k){
      if(!data[k]) return;
      var val = data[k];
      // Only update if cloud version is newer than local
      var localRaw = localStorage.getItem(k);
      var cloudStr = typeof val === 'string' ? val : JSON.stringify(val);
      if(localRaw === cloudStr) return; // same - no update needed
      // ── FIX: agar is key ke liye local mein pending unsaved changes hain
      // (jaise sub-user ne entry ki, cloud push nahi hua abhi), toh cloud
      // ka purana data local ko overwrite nahi karega. Warna sub-user ki
      // nayi entries rskTabSync ke chalte gayab ho jaati hain.
      if(window._gdPendingQueue && window._gdPendingQueue[k]) return;
      try{
        // Decompress if needed
        var decompressed = (typeof rskDecompress === 'function') ? rskDecompress(cloudStr) : cloudStr;
        var parsed = JSON.parse(decompressed);
        localStorage.setItem(k, cloudStr);
        // Update global vars
        if(k===erpKey('admList3') && Array.isArray(parsed)){
          window.admList3 = parsed;
          if(typeof renderAdmList3==='function' && (tab==='admlist3'||tab==='admmissing')) renderAdmList3();
        }
        if(k===erpKey('erp_staff') && Array.isArray(parsed)){
          window.staffRegistry = parsed;
          if(typeof renderStaffRegistry==='function' && tab==='staffmgmt') renderStaffRegistry();
        }
        if(k===sessKey('erp_leave') && Array.isArray(parsed)){
          window.leaveRegistry = parsed;
          if(typeof renderLeaveRecords==='function' && tab==='leave') renderLeaveRecords();
        }
        if(k===erpKey('erp_customFees')){
          window.fs1CustomFees = Array.isArray(parsed) ? parsed : [];
          localStorage.setItem(k, JSON.stringify(window.fs1CustomFees));
          if(typeof renderFs1==='function') try{ renderFs1(); }catch(e){}
        }
        if(k===erpKey('erp_feeConfig')){
          // ── FIX: cloud se feeConfig ko MERGE karo, blind overwrite nahi —
          // local jo bhi index already configure kar chuka hai, wahi priority
          // lega; cloud sirf NAYE/missing indices add karega. Isse local
          // "active:yes" fix cloud ke stale "active:no" se overwrite nahi hoga.
          if(parsed && typeof parsed==='object' && window.feeConfig && typeof window.feeConfig==='object' && Object.keys(window.feeConfig).length){
            var _mergedFC = Object.assign({}, parsed, window.feeConfig);
            window.feeConfig = _mergedFC;
            localStorage.setItem(k, JSON.stringify(_mergedFC));
          } else {
            window.feeConfig = parsed;
          }
        }
        // ── Competition/Function/Library/Calendar management — generic ──
        ['comp','func','lib','cal'].forEach(function(mod){
          if(k!==sessMgmtKey(mod)) return;
          _mgmtDataCache[mod] = (parsed && typeof parsed==='object') ? parsed : {};
          var renderFn = {comp:'renderCompMgmt',func:'renderFuncMgmt',lib:'renderLibMgmt',cal:'renderCalMgmt'}[mod];
          var tabId = {comp:'compemgmt',func:'funcmgmt',lib:'libmgmt',cal:'calmgmt'}[mod];
          if(tab===tabId && typeof window[renderFn]==='function') window[renderFn]();
        });
        // ── Custom Add-Row/Add-Column table data ──
        if(k===_rskCTKey()){
          window._rskCT = (parsed && typeof parsed==='object') ? parsed : {};
          var _ctRenderFn = {compemgmt:'renderCompMgmt',funcmgmt:'renderFuncMgmt',libmgmt:'renderLibMgmt',calmgmt:'renderCalMgmt'}[tab];
          if(_ctRenderFn && typeof window[_ctRenderFn]==='function') window[_ctRenderFn]();
        }
        // ── Sports Management (S1 House setup) ──
        if(k===sessMgmtKey('sports')){
          _mgmtDataCache['sports'] = (parsed && typeof parsed==='object') ? parsed : {};
          if(typeof window.s1AutoRestore==='function') window.s1AutoRestore();
        }
        // ── Sports Management S2 (Events Schedule) / S3 (Participation Register) ──
        if(k===sessKey('spt_s2_cols') || k===sessKey('spt_s2_data')){
          if(typeof window.s2AutoRestore==='function') window.s2AutoRestore();
        }
        if(k===sessKey('spt_s3_data')){
          if(typeof window.s3AutoRestore==='function') window.s3AutoRestore();
        }
        console.log('[RSK TabSync] Updated '+k+' from cloud');
      }catch(e){ /* silent */ }
    });
  }catch(e){ /* silent - background sync fail is ok */ }
}



