var _rskLastKnownCloudTs = parseInt(localStorage.getItem('rsk_last_cloud_ts')||'0');
var _rskTsCheckTimer = null;
var _rskTsCheckInterval = 60000; // 60 seconds

// Call this after every successful ☁️ Save
async function rskUpdateCloudTimestamp(){
  var ts = Date.now();
  try{
    await fetch(CF_WORKER_URL+'/general', {
      method:'POST',
      headers: cfHeaders(false),
      body: JSON.stringify({ key:'rsk_last_update_ts', value: ts })
    });
    _rskLastKnownCloudTs = ts;
    localStorage.setItem('rsk_last_cloud_ts', ts);
  }catch(e){ /* silent */ }
}

