// ══════════════════════════════════════════════════
// RSK CLASS PRESENCE WARNING SYSTEM
// Jab koi same class pe kaam kar raha ho → warning
// ══════════════════════════════════════════════════

var _rskMyCurrentClass = null;

// Broadcast ki main kaunsi class pe hoon
var _rskLastPresenceCls = null; // FIX: dedup tracker
async function rskBroadcastClassPresence(cls){
  if(!cls) return;
  // FIX: Same class pe dobara broadcast mat karo
  if(cls === _rskLastPresenceCls) return;
  _rskLastPresenceCls = cls;
  try{
    var uname = _rskMyUsername || (currentUser && currentUser.username) || 'Unknown';
    var entry = {
      u: uname,
      cls: cls,
      t: Date.now(),
      dev: SB_DEVICE_ID,
      school: (_activeUserPrefix||'').toUpperCase()
    };
    await fetch(CF_WORKER_URL+'/general', {
      method:'POST',
      headers: cfHeaders(false),
      body: JSON.stringify({ key:'rsk_class_presence', value: entry })
    });
  }catch(e){ /* silent */ }
}

// Check karo koi aur same class pe toh nahi
async function rskCheckClassPresence(cls){
  try{
    var resp = await fetch(CF_WORKER_URL+'/general?_t='+Date.now(), { headers: cfGetHeaders(false) });
    if(!resp.ok) return;
    var data = await resp.json();
    var presence = data && data['rsk_class_presence'];
    if(!presence) return;
    var myDev = SB_DEVICE_ID;
    var now = Date.now();
    // Sirf last 2 min ki presence valid hai
    if(!presence.t || (now - presence.t) > 120000) return;
    // Sirf apni school-family (main user + uske sub-users) ke beech warning —
    // kisi DUSRE school ka same class-number kaam karna irrelevant hai
    var myPrefix = (_activeUserPrefix||'').toUpperCase();
    if(presence.school && presence.school !== myPrefix) return;
    // Same class, different device
    if(presence.cls === cls && presence.dev !== myDev){
      var who = presence.u || 'कोई और';
      rskShowActivityToast(
        '⚠️ ' + who + ' भी Class ' + cls + ' में काम कर रहे हैं! Save करने से उनका data overwrite हो सकता है।',
        '#92400e'
      );
    }
  }catch(e){ /* silent */ }
}


// ── Save Error Alert ──
function rskShowSaveError(msg){
  var id = 'rsk-save-error-alert';
  var el = document.getElementById(id);
  if(!el){
    el = document.createElement('div');
    el.id = id;
    el.style.cssText = 'position:fixed;top:0;left:0;right:0;z-index:9999999;background:#7f1d1d;color:#fff;padding:14px 20px;font-size:14px;font-weight:800;display:flex;align-items:center;justify-content:space-between;gap:12px;box-shadow:0 4px 20px rgba(0,0,0,.5);font-family:inherit';
    document.body.appendChild(el);
  }
  el.innerHTML = '<span>❌ ' + (msg||'Data Save नहीं हुआ! Internet check करें।') + '</span>'
    + '<div style="display:flex;gap:8px">'
    + '<button onclick="rskCloudSave()" style="background:#fff;color:#7f1d1d;border:none;border-radius:6px;padding:6px 16px;font-weight:800;cursor:pointer;font-size:13px">🔄 Retry</button>'
    + '<button onclick="document.getElementById(&quot;rsk-save-error-alert&quot;).style.display=&quot;none&quot;" style="background:rgba(255,255,255,.2);color:#fff;border:none;border-radius:6px;padding:6px 12px;font-weight:700;cursor:pointer;font-size:13px">✕</button>'
    + '</div>';
  el.style.display = 'flex';
}

function rskHideSaveError(){
  var el = document.getElementById('rsk-save-error-alert');
  if(el) el.style.display = 'none';
}


