// ── Vehicle Management: always pull latest data from cloud on page open ──
// (rskTabSync only refreshes when _rskDirty is true, so a fresh device that
// hasn't made local edits never sees other devices' V1/V2 data. This fixes that.)
async function vehCloudRefresh(){
  var changed = false;
  // ── LOCAL MIGRATION: agar login se pehle (GUEST prefix) data save hua tha,
  // ab _activeUserPrefix sahi (e.g. ADMIN4) hone par usse migrate kar do ──
  try{
    [['veh_list_v1','_vehList'], ['veh_students_v2','_vehStudents']].forEach(function(pair){
      var base = pair[0], winVar = pair[1];
      var curKey = erpKey(base);
      var guestKey = 'rsk_u_GUEST_' + base;
      if(guestKey === curKey) return; // already guest, nothing to migrate
      var curRaw = localStorage.getItem(curKey);
      var gRaw = localStorage.getItem(guestKey);
      if((!curRaw || curRaw==='[]') && gRaw && gRaw!=='[]'){
        localStorage.setItem(curKey, gRaw);
        localStorage.removeItem(guestKey);
        try{ window[winVar] = JSON.parse(gRaw); }catch(e){}
        if(typeof smartSave==='function'){ try{ smartSave(curKey, window[winVar]); }catch(e){} }
        console.log('[RSK] Migrated '+guestKey+' -> '+curKey);
        changed = true;
      }
    });
  }catch(e){}

  if(navigator.onLine){
  try{
    var resp = await fetch(CF_WORKER_URL+'/general?_t='+Date.now(), { headers: cfGetHeaders(false) });
    if(resp.ok){
    var data = await resp.json();
    var keys = [erpKey('veh_list_v1'), sessKey('veh_students_v2')];
    keys.forEach(function(k){
      if(!(k in data)) return;
      var val = data[k];
      var cloudStr = typeof val === 'string' ? val : JSON.stringify(val);
      var localRaw = localStorage.getItem(k);
      if(localRaw === cloudStr) return; // same — no update needed
      try{
        var decompressed = (typeof rskDecompress === 'function') ? rskDecompress(cloudStr) : cloudStr;
        var parsed = JSON.parse(decompressed);
        localStorage.setItem(k, decompressed);
        if(k===erpKey('veh_list_v1') && Array.isArray(parsed)){ window._vehList = parsed; }
        if(k===sessKey('veh_students_v2') && Array.isArray(parsed)){ window._vehStudents = parsed; }
        changed = true;
      }catch(e){}
    });
    }
  }catch(e){ console.warn('[RSK] vehCloudRefresh failed:', e.message); }
  }

  if(changed){
    if(typeof window.vehRenderList==='function') window.vehRenderList();
    if(typeof window.vsPopulateVehicles==='function') window.vsPopulateVehicles();
    if(typeof window.vsRenderList==='function') window.vsRenderList();
    if(typeof window.vsPopulateStudents==='function') window.vsPopulateStudents();
  }
}

function vehSyncLang(){
  var en = (typeof isEnglish === 'function') ? isEnglish() : false;
  var pg = document.getElementById('page-vehiclemgmt');
  if(!pg) return;
  // data-hi/data-en elements (tab buttons)
  pg.querySelectorAll('[data-hi][data-en]').forEach(function(el){
    el.textContent = en ? el.getAttribute('data-en') : el.getAttribute('data-hi');
  });
  // Walk all text nodes and translate
  var allEls = pg.querySelectorAll('td, th, .section-title, label, span, div, button, option');
  allEls.forEach(function(el){
    if(el.children.length > 0) return; // skip parent elements
    var txt = el.textContent || '';
    if(!txt.trim()) return;
    if(en){
      Object.keys(_vehLangMapHiToEn).forEach(function(hi){
        if(txt === hi || txt.trim() === hi.trim()){
          el.textContent = _vehLangMapHiToEn[hi];
        }
      });
    } else {
      // Restore Hindi
      Object.keys(_vehLangMapHiToEn).forEach(function(hi){
        if(txt === _vehLangMapHiToEn[hi] || txt.trim() === _vehLangMapHiToEn[hi].trim()){
          el.textContent = hi;
        }
      });
    }
  });
  // Also handle placeholders with data-phi/data-pen
  pg.querySelectorAll('input[data-phi][data-pen]').forEach(function(el){
    el.placeholder = en ? el.getAttribute('data-pen') : el.getAttribute('data-phi');
  });
  // Handle select options with data-hi/data-en
  pg.querySelectorAll('select option[data-hi][data-en]').forEach(function(el){
    el.textContent = en ? el.getAttribute('data-en') : el.getAttribute('data-hi');
  });
  // Re-render dynamic list labels (summary cards, totals, empty msg, etc.)
  if(typeof vsRenderList === 'function') vsRenderList();
  // Re-render vs_veh_info info line (has hardcoded रूट/Route text)
  if(typeof vsOnVehicleChange === 'function') vsOnVehicleChange();
  // Also update vsToggleNewEntry button text if in manual mode
  var _newEntryBtn = document.getElementById('vs_newEntryBtn');
  if(_newEntryBtn){
    var _curText = _newEntryBtn.textContent||'';
    var _inManual = (_curText.indexOf('Admission List')>-1 || _curText.indexOf('Admission List से')>-1);
    if(_inManual){
      _newEntryBtn.textContent = en ? '📋 Select from Admission List' : '📋 Admission List से चुनें';
    } else {
      _newEntryBtn.textContent = en ? '✏️ New Entry (Manual)' : '✏️ New Entry (Manual)';
    }
  }
}

// ── Cloud Save globals ──
var _rskCloudPendingKey = null;
var _rskCloudPendingPayload = null;

// ── Manual cloud save function ──
async function rskCloudSave(){
  var btn = g('ds-cloud-save-btn');
  if(btn){ btn.textContent='⏳ Saving...'; btn.disabled=true; }
  // Check internet before attempting
  if(!navigator.onLine){
    if(btn){ btn.textContent='☁️ Save'; btn.disabled=false; }
    if(typeof rskShowSaveError==='function') rskShowSaveError('Internet नहीं है! Data Local में safe है। Internet आने पर दोबारा Save करें।');
    return;
  }
  try{
    // Step 1: Save current active class to localStorage first
    saveData();

    // Step 2: Queue any missing keys not covered by gdQueueSave
    var _extraKeys = [
      sessKey('rsk_ctt'), erpKey('veh_list_v1'), sessKey('veh_students_v2'),
      sessMgmtKey('comp'), sessMgmtKey('func'), sessMgmtKey('lib'), sessMgmtKey('cal'), sessMgmtKey('sports'),
      _rskCTKey(),
      sessKey('spt_s2_cols'), sessKey('spt_s2_data'), sessKey('spt_s3_data'),
      // ── Missing keys added ──
      sessKey('erp_leave'),
      sessKey('att_sched_'),
    ];
    // Also queue all prefix-based sessKey data from localStorage
    var _sessPrefixes = [
      sessKey('rsk_cal_'), sessKey('rsk_comp_'), sessKey('rsk_func_'),
      sessKey('rsk_lib_'), sessKey('rsk_sports_'), sessKey('att_'),
      sessKey('erp_custom_tables_data'),
    ];
    _sessPrefixes.forEach(function(pfx){
      Object.keys(localStorage).forEach(function(k){
        if(k.indexOf(pfx)===0 || k===pfx){
          var v=localStorage.getItem(k);
          if(v && !_gdPendingQueue[k]){ try{_gdPendingQueue[k]=JSON.parse(v);}catch(e){_gdPendingQueue[k]=v;} }
        }
      });
    });
    _extraKeys.forEach(function(k){
      var v = localStorage.getItem(k);
      if(v && !_gdPendingQueue[k]){
        try{ _gdPendingQueue[k] = JSON.parse(v); }catch(e){ _gdPendingQueue[k] = v; }
      }
    });
    // Also queue erp_students/attendance/fees/exams (may have been saved without gdQueueSave)
    // ── FEE F1-F7 AUTO-SYNC PATCH: Queue all dynamic fee keys ──
    var _feeStaticKeys = [erpKey('erp_feeConfig'),erpKey('erp_feeMonths'),erpKey('erp_customFees'),erpKey('erp_fees'),erpKey('erp_persist'),erpKey('erp_lastReceiptNo'),erpKey('erp_fs2_password')];
    _feeStaticKeys.forEach(function(k){
      var v = localStorage.getItem(k);
      if(v && !_gdPendingQueue[k]){ try{ _gdPendingQueue[k]=JSON.parse(v); }catch(e){ _gdPendingQueue[k]=v; } }
    });
    // Queue all per-student F2 receipt keys (erp_fs2_<admNo>)
    Object.keys(localStorage).forEach(function(k){
      if((k.indexOf(erpKey('erp_fs2_'))===0 ) && !_gdPendingQueue[k]){
        var v = localStorage.getItem(k);
        if(v){ try{ _gdPendingQueue[k]=JSON.parse(v); }catch(e){ _gdPendingQueue[k]=v; } }
      }
    });
    var _erpKeys = [erpKey('erp_students'),erpKey('erp_attendance'),erpKey('erp_fees'),erpKey('erp_exams')];
    _erpKeys.forEach(function(k){
      var v = localStorage.getItem(k);
      if(v && !_gdPendingQueue[k]){
        try{ _gdPendingQueue[k] = JSON.parse(v); }catch(e){ _gdPendingQueue[k] = v; }
      }
    });
    // ── FIX: admList3 / School Details / Admission Registry — FORCE re-queue ──
    // Pehle ye sirf smartSave() ke pehle-se-queue hone par depend karte the.
    // Agar pehli flush fail/skip ho gayi thi, ya in-memory queue page-reload
    // mein lost ho gayi, toh ye keys cloud tak kabhi nahi pohchti thi.
    // Ab ☁️ Save par hamesha localStorage ki latest value force-queue hoti hai.
    // ── FIX: ut_marks_ keys force-queue (Unit Test DataSheet all classes) ──
    Object.keys(localStorage).forEach(function(k){
      if(k.indexOf(sessKey('ut_marks_'))===0){
        var v = localStorage.getItem(k);
        if(v){ try{ _gdPendingQueue[k]=JSON.parse(v); }catch(e){ _gdPendingQueue[k]=v; } }
      }
    });
    var _criticalGeneralKeys = [erpKey('admList3'), erpKey('rsk_school_info_global'), erpKey('rsk_adm_registry')];
    _criticalGeneralKeys.forEach(function(k){
      var v = localStorage.getItem(k);
      if(v){ try{ _gdPendingQueue[k] = JSON.parse(v); }catch(e){ _gdPendingQueue[k] = v; } }
    });
    // Flush all tabs queue (Admission, Staff, Fee, Leave etc)
    var _generalSyncOk = true;
    if(typeof gdFlushQueue === 'function' && Object.keys(_gdPendingQueue).length){
      _generalSyncOk = await gdFlushQueue();
      // ── Retry once if some keys failed (transient network blip) ──
      if(!_generalSyncOk && Object.keys(_gdPendingQueue).length){
        await new Promise(function(r){ setTimeout(r, 1500); });
        _generalSyncOk = await gdFlushQueue();
      }
    }

    // Step 3: Sync ALL class profiles from localStorage to cloud
    var allKeys = typeof getAllProfiles === 'function' ? getAllProfiles() : [];
    var curKey = currentProfileKey();
    // Always include current key
    if(allKeys.indexOf(curKey) === -1) allKeys.push(curKey);
    var synced = 0;
    var _ckSync = {}; try{ _ckSync=JSON.parse((window._lsReal||localStorage).getItem('rsk_cleared_keys')||'{}'); }catch(e){}
    for(var ki=0; ki<allKeys.length; ki++){
      var pKey = allKeys[ki];
      var raw = window._lsReal.getItem(pKey);
      if(!raw) continue;
      // Skip if this profile was explicitly cleared — don't re-upload
      if(_ckSync[pKey]){ console.log('[RSK CloudSave SKIP cleared] '+pKey); continue; }
      try{
        // LZ compressed string directly push karo — parse/re-stringify se data loss avoid karo
        await fetch(CF_WORKER_URL+'/profile', {
          method: 'POST',
          headers: cfHeaders(false),
          body: JSON.stringify({ profile_key: pKey, device_id: SB_DEVICE_ID, data: raw })
        });
        synced++;
      }catch(e){ console.warn('[RSK] Profile sync failed: '+pKey, e); }
    }

    _rskCloudPendingKey = null;
    _rskCloudPendingPayload = null;
    if(_generalSyncOk) window._rskDirty = false; // reset dirty flag only if FULLY synced
    if(typeof rskUpdateLastSavedTs === 'function') rskUpdateLastSavedTs();
    if(btn){
      if(_generalSyncOk){
        btn.style.background='rgba(16,185,129,.3)';
        btn.style.color='#6ee7b7';
        btn.style.border='1px solid rgba(16,185,129,.5)';
        btn.textContent='☁️ Saved! ('+synced+' classes)';
        btn.disabled=false;
        setTimeout(function(){ btn.textContent='☁️ Save'; btn.style.background='rgba(16,185,129,.3)'; btn.style.color='#6ee7b7'; btn.style.border='1px solid rgba(16,185,129,.5)'; }, 3000);
      } else {
        // ── Kuch general keys (Admission/School Details/Fees) push nahi ho payi ──
        btn.style.background='rgba(251,191,36,.4)';
        btn.style.color='#fef08a';
        btn.style.border='1px solid rgba(251,191,36,.6)';
        btn.textContent='⚠️ Partial Save — फिर कोशिश करें';
        btn.disabled=false;
        if(typeof rskShowSaveError === 'function') rskShowSaveError('कुछ data (Admission/Fees/School Details) Cloud तक नहीं पहुँचा। Internet check करें और दोबारा ☁️ Save दबाएं।');
      }
    }
    // Hide any previous error alert
    if(typeof rskHideSaveError === 'function') rskHideSaveError();
    // Update cloud timestamp
    if(typeof rskUpdateCloudTimestamp === 'function') await rskUpdateCloudTimestamp();
    // Broadcast activity
    if(typeof rskBroadcastActivity==='function'){
      rskBroadcastActivity('Cloud Save किया', synced+' classes sync हुईं');
    }
  }catch(e){
    if(btn){ 
      btn.textContent='❌ Save Failed'; 
      btn.style.background='rgba(220,38,38,.4)';
      btn.style.color='#fca5a5';
      btn.style.border='1px solid rgba(220,38,38,.6)';
      btn.disabled=false;
      setTimeout(function(){ btn.textContent='☁️ Save'; btn.style.background='rgba(16,185,129,.3)'; btn.style.color='#6ee7b7'; btn.style.border='1px solid rgba(16,185,129,.5)'; }, 5000);
    }
    // Show big red alert
    var msg = !navigator.onLine 
      ? 'Internet नहीं है! Data सिर्फ Local में है। Internet आने पर ☁️ Save दबाएं।'
      : 'Cloud Save नहीं हुआ! Internet check करें और दोबारा ☁️ Save दबाएं।';
    if(typeof rskShowSaveError === 'function') rskShowSaveError(msg);
    console.error('[RSK CloudSave]', e);
  }
}


// ══════════════════════════════════════════════════
// RSK ACTIVITY BROADCAST + POLLING NOTIFICATION SYSTEM
// ══════════════════════════════════════════════════

var _rskLastActivityTs = Date.now();
var _rskPendingActivity = null;
var _rskActivityPollTimer = null;
var _rskMyUsername = null; // set on login
var _rskLastBroadcastTs = 0;        // FIX: broadcast throttle
var _rskBroadcastMinGap = 10000;    // FIX: 10 sec minimum gap between broadcasts

// Broadcast activity to cloud (all users same school_id share /general)
async function rskBroadcastActivity(action, detail){
  // FIX: Throttle — same action 10 sec ke andar dobara mat bhejo
  var now = Date.now();
  if(now - _rskLastBroadcastTs < _rskBroadcastMinGap) return;
  _rskLastBroadcastTs = now;
  try{
    var uname = _rskMyUsername || (currentUser && currentUser.username) || 'Unknown';
    var entry = {
      u: uname,
      a: action,
      d: detail||'',
      t: Date.now(),
      dev: SB_DEVICE_ID,
      // ── Main user + uske sub-users ka common family-id (parent ka username) —
      // isse activity notifications sirf isi school-family ke andar dikhengi,
      // kisi DUSRE main user/uske sub-users ko nahi ──
      school: (_activeUserPrefix||'').toUpperCase()
    };
    await fetch(CF_WORKER_URL+'/general', {
      method:'POST',
      headers:cfHeaders(false),
      body:JSON.stringify({ key:'rsk_activity_log', value: entry })
    });
  }catch(e){ /* silent */ }
}

// Show toast notification
function rskShowActivityToast(msg, color){
  // ── Sirf ACTIVE main/sub-users ko dikhana hai — VIEW_ONLY (expired/viewer) accounts ko nahi ──
  if(window.VIEW_ONLY===true) return;
  // ── Debounce: same message 2 second mein dobara nahi dikhega ──
  var _toastKey = 'rsk_toast_' + msg;
  if(window[_toastKey]) return;
  window[_toastKey] = true;
  setTimeout(function(){ window[_toastKey] = false; }, 2000);
  var el = document.getElementById('rsk-activity-toast');
  if(!el){
    el = document.createElement('div');
    el.id = 'rsk-activity-toast';
    el.style.cssText = 'position:fixed;bottom:70px;left:50%;transform:translateX(-50%);z-index:9999998;display:flex;flex-direction:column;gap:6px;pointer-events:none;max-width:360px;width:90%';
    document.body.appendChild(el);
  }
  var t = document.createElement('div');
  t.style.cssText = 'background:'+(color||'#1e3a6b')+';color:#fff;padding:10px 18px;border-radius:10px;font-size:12px;font-weight:700;font-family:inherit;box-shadow:0 4px 18px rgba(0,0,0,.35);border-left:4px solid rgba(255,255,255,.3);opacity:1;transition:opacity 0.5s';
  t.textContent = msg;
  el.appendChild(t);
  setTimeout(function(){ t.style.opacity='0'; setTimeout(function(){ t.remove(); }, 500); }, 5000);
}

// Unified poll — single /general call handles BOTH activity log AND timestamp check
// Previously two separate setInterval loops (15s + 60s) caused duplicate concurrent requests
async function rskPollActivity(){
  if(!navigator.onLine) return;
  try{
    var resp = await fetch(CF_WORKER_URL+'/general?_t='+Date.now(), { headers: cfGetHeaders(false) });
    if(!resp.ok) return;
    var data = await resp.json();

    // ── 1. Activity log check ──
    var entry = data && data['rsk_activity_log'];
    // School-family check — sirf apne main-user/sub-users ke beech notification dikhao,
    // kisi DUSRE school (main user/uske sub-users) ka activity nahi.
    // Purane entries (without 'school' field) ke liye backward-compatible (dikha do).
    var myPrefix = (_activeUserPrefix||'').toUpperCase();
    var _isMyFamily = !entry || !entry.school || entry.school === myPrefix;
    if(entry && _isMyFamily){
      var myDev = SB_DEVICE_ID;
      var myUser = _rskMyUsername || (currentUser && currentUser.username) || '';
      if(entry.dev && entry.dev !== myDev && entry.t && entry.t > _rskLastActivityTs && (Date.now() - entry.t) < 60000){
        _rskLastActivityTs = entry.t;
        var who = entry.u || 'किसी ने';
        var action = entry.a || 'कुछ किया';
        var detail = entry.d ? ' — ' + entry.d : '';
        var color = (entry.u && myUser && entry.u.toLowerCase() === myUser.toLowerCase()) ? '#166534' : '#1e3a6b';
        rskShowActivityToast('🔔 ' + who + ' ने ' + action + detail, color);
      }
    }

    // ── 2. Timestamp check (merged from rskCheckTimestamp to avoid duplicate /general fetch) ──
    var cloudTs = parseInt(data['rsk_last_update_ts']||'0');
    if(cloudTs){
      var myTs = parseInt(localStorage.getItem('rsk_last_cloud_ts')||'0');
      if(cloudTs > myTs){
        console.log('[RSK] Cloud updated at '+new Date(cloudTs).toLocaleTimeString()+' — refreshing...');
        _rskLastKnownCloudTs = cloudTs;
        localStorage.setItem('rsk_last_cloud_ts', cloudTs);
        // "नया डेटा मिला" toast bhi sirf apni school-family ke update par dikhao
        if(_isMyFamily) rskShowActivityToast('🔄 नया डेटा मिला — अपडेट हो रहा है...', '#1e3a6b');
        await gdInitLoadAll();
        if(typeof curTab !== 'undefined' && typeof rskTabSync === 'function'){
          _rskTabLastSync[curTab] = 0;
          rskTabSync(curTab);
        }
      }
    }
  }catch(e){ /* silent */ }
}

// Start polling after login
var _rskVisibilityListenerAdded = false;
function rskStartActivityPolling(){
  _rskLastActivityTs = Date.now();
  if(_rskActivityPollTimer) clearInterval(_rskActivityPollTimer);
  _rskActivityPollTimer = setInterval(rskPollActivity, 45000); // FIX: 15s→45s (3x kam requests)

  // FIX: Tab hidden ho toh polling pause karo
  if(!_rskVisibilityListenerAdded){
    _rskVisibilityListenerAdded = true;
    document.addEventListener('visibilitychange', function(){
      if(document.hidden){
        // Tab hide hone pe — sirf dirty hone pe flush karo
        if(window._rskDirty && typeof gdFlushQueue === 'function' && Object.keys(_gdPendingQueue||{}).length){
          gdFlushQueue();
        }
        if(_rskActivityPollTimer){ clearInterval(_rskActivityPollTimer); _rskActivityPollTimer = null; }
      } else {
        if(!_rskActivityPollTimer){
          _rskActivityPollTimer = setInterval(rskPollActivity, 45000);
          rskPollActivity(); // tab wapas aane pe ek baar turant check karo
        }
      }
    });
  }
}

// Stop polling
function rskStopActivityPolling(){
  if(_rskActivityPollTimer){ clearInterval(_rskActivityPollTimer); _rskActivityPollTimer = null; }
}


// ── Pull a profile from Cloudflare D1 ──
async function cfFetchProfile(profileKey){
  try{
    var resp = await fetch(CF_WORKER_URL+'/profile?key='+encodeURIComponent(profileKey), {
      headers: cfGetHeaders(false)
    });
    var result = await resp.json();
    if(!result.data) return null;
    // School name strip karo agar user ka apna school_info_global nahi hai
    // (naam purani shared file se contaminated ho sakta hai)
    try{
      var _d = typeof result.data === 'string' ? JSON.parse(result.data) : result.data;
      var _hasOwnSI = !!_lsReal.getItem(erpKey('rsk_school_info_global'));
      if(!_hasOwnSI && _d && _d.schoolInfo && _d.schoolInfo.name){
        _d.schoolInfo.name = '';
        if(_d.sc) _d.sc.name = '';
        result.data = _d;
      }
    }catch(e){}
    return { data: result.data, updated_at: result.updated_at };
  }catch(e){ console.warn('CF fetch error:', e.message); return null; }
}

// ── Pull ALL profile keys ──
async function cfFetchAllKeys(){
  try{
    var resp = await fetch(CF_WORKER_URL+'/profiles', { headers: cfGetHeaders(false) });
    var result = await resp.json();
    return Array.isArray(result) ? result : [];
  }catch(e){ return []; }
}

// ── Smart load: compare localStorage vs Cloud timestamps ──
async function sbSmartLoad(profileKey, _forceOverwrite){
  var _ck = {}, _dk = {};
  try{ _ck = JSON.parse((_lsReal||localStorage).getItem('rsk_cleared_keys')||'{}'); }catch(e){}
  try{ _dk = JSON.parse((_lsReal||localStorage).getItem('rsk_deleted_keys')||'{}'); }catch(e){}

  sbStatus('☁️ Loading…', '#92400e');
  try{
    var remote = await cfFetchProfile(profileKey);
    if(!remote){ sbStatus('☁️ Cloud ON', '#1e40af'); return false; }

    var remoteTime = new Date(remote.updated_at).getTime();

    // ── FIX: rsk_cleared_keys / rsk_deleted_keys sirf tab block kare jab cloud
    // data clear/delete-action se PURANA ho. Agar doosre device ne clear ke baad
    // naya data cloud par push kiya hai (cloud updated_at > clear timestamp), to
    // wo data fresh hai — usse load hone do aur stale flag yahan clean kar do.
    if(_ck[profileKey] && remoteTime <= _ck[profileKey]){ sbStatus('☁️ Cloud ON', '#1e40af'); return false; }
    if(_dk[profileKey] && remoteTime <= _dk[profileKey]){ sbStatus('☁️ Cloud ON', '#1e40af'); return false; }
    if(_ck[profileKey]){ delete _ck[profileKey]; try{ (_lsReal||localStorage).setItem('rsk_cleared_keys', JSON.stringify(_ck)); }catch(e){} }
    if(_dk[profileKey]){ delete _dk[profileKey]; try{ (_lsReal||localStorage).setItem('rsk_deleted_keys', JSON.stringify(_dk)); }catch(e){} }

    var localRaw = _lsReal.getItem(profileKey);
    var localPayload = null;
    if(localRaw){
      try{
        // Handle LZ-compressed data
        var _dec = (typeof rskDecompress==='function') ? rskDecompress(localRaw) : localRaw;
        localPayload = JSON.parse(_dec);
      }catch(e){ localPayload = null; }
    }

    var localTime = 0;
    if(localPayload){
      var _savedAt = (localPayload.S && localPayload.S.savedAt) || localPayload.savedAt;
      localTime = _savedAt ? new Date(_savedAt).getTime() : 0;
    }
    // If local data exists but has no savedAt (old format), treat as newer than cloud
    // to prevent cloud from overwriting data that was entered after a clear
    if(localRaw && localTime === 0 && !_forceOverwrite) localTime = Date.now();

    if(_forceOverwrite || remoteTime > localTime){
      // Cloud se profile load ho raha hai — school name sanitize karo
      try{
        var _cloudData = remote.data;
        // ── CRITICAL FIX: Cloud se data LZ-compressed string aata hai ──
        // JSON.stringify(string) double-wraps karta hai → ""LZ:..."" ban jaata hai
        // → rskDecompress fail → students empty dikhte hain
        // Fix: string hai toh directly store karo, object hai toh JSON.stringify karo
        var _toStore;
        if(typeof _cloudData === 'string'){
          _toStore = _cloudData; // LZ string — seedha store
        } else if(_cloudData && typeof _cloudData === 'object'){
          // Object hai — school name sanitize karo phir compress karke store karo
          var _hasOwnSI = !!_lsReal.getItem(erpKey('rsk_school_info_global'));
          if(!_hasOwnSI && _cloudData.schoolInfo && _cloudData.schoolInfo.name){
            _cloudData.schoolInfo.name = '';
            if(_cloudData.sc) _cloudData.sc.name = '';
          }
          var _jsonStr = JSON.stringify(_cloudData);
          _toStore = (typeof rskCompress==='function') ? rskCompress(_jsonStr) : _jsonStr;
        } else {
          _toStore = JSON.stringify(_cloudData);
        }
        _lsReal.setItem(profileKey, _toStore);
      }catch(e){ 
        var _fb = remote.data;
        _lsReal.setItem(profileKey, typeof _fb==='string' ? _fb : JSON.stringify(_fb)); 
      }
      sbStatus('☁️ Cloud loaded', '#166634');
      // ── FIX: Sirf current active profile ke liye loadProfile call karo ──
      // Non-current profiles ke liye loadProfile mat karo —
      // loadProfile → UI re-render → saveData() → current class ka data empty se overwrite!
      if(typeof currentProfileKey==='function' && profileKey===currentProfileKey()){
        if(typeof loadProfile==='function') loadProfile(profileKey);
        if(typeof renderSchoolDetails==='function') setTimeout(renderSchoolDetails, 100);
      }
      // Note: Non-current profiles sirf localStorage mein store hote hain (upar setItem se)
      // Jab user us class pe click karega tab loadProfile automatically chalega
      return true;
    }
    sbStatus('☁️ Cloud ON', '#1e40af');
    return false;
  }catch(e){ sbStatus('⚠️ Cloud error', '#7f1d1d'); return false; }
}

// ── Upload ALL local profiles to Cloud ──
async function sbUploadAll(){
  sbStatus('☁️ Uploading all…', '#92400e');
  var keys=[];
  for(var i=0;i<localStorage.length;i++){
    var k=localStorage.key(i);
    if(k && k.indexOf('rsk_cls_')===0) keys.push(k);
  }
  if(!keys.length){ alert('कोई profile नहीं मिली upload करने के लिए।'); return; }
  var ok=0, fail=0;
  for(var j=0;j<keys.length;j++){
    try{
      var raw = _lsReal.getItem(keys[j]);
      if(!raw) continue;
      var resp = await fetch(CF_WORKER_URL+'/profile', {
        method:'POST',
        headers: cfHeaders(false),
        body: JSON.stringify({ profile_key: keys[j], device_id: SB_DEVICE_ID, data: JSON.parse(raw) })
      });
      var r = await resp.json();
      if(r.ok) ok++; else fail++;
    }catch(e){ fail++; }
  }
  sbStatus('✅ Synced', '#166534');
  alert('✅ Upload complete!\n'+ok+' profiles synced to Cloud.\n'+(fail?'⚠️ '+fail+' failed.':''));
  setTimeout(function(){ sbStatus('☁️ Cloud ON','#1e40af'); },3000);
}

// ── Download all Cloud profiles to localStorage ──
async function sbDownloadAll(){
  sbStatus('☁️ Downloading…','#92400e');
  try{
    var resp = await fetch(CF_WORKER_URL+'/profiles/all', { headers: cfGetHeaders(false) });
    var data = await resp.json();
    if(!data||!data.length){ alert('Cloud में कोई data नहीं मिला।'); return; }
    var count=0;
    data.forEach(function(row){
      if(row.profile_key && row.data){
        _lsReal.setItem(row.profile_key, JSON.stringify(row.data));
        count++;
      }
    });
    var idx=data.map(function(r){return r.profile_key;});
    _lsReal.setItem(erpKey('rsk_profile_index'), JSON.stringify(idx));
    sbStatus('✅ Downloaded','#166534');
    alert('✅ '+count+' profiles Cloud से download हो गए!\nPage reload हो रहा है…');
    location.reload();
  }catch(e){ sbStatus('⚠️ Error','#7f1d1d'); alert('Error: '+e.message); }
}

// ===================================================================
// BLOCK 5  (originally inline <script> at source line 1063)
// ===================================================================

// ╔══════════════════════════════════════════════════════════════╗
// ║   🌩️  RSK UNIVERSAL CLOUD STORAGE LAYER v2.0 (Cloudflare)  ║
// ╚══════════════════════════════════════════════════════════════╝

var GD_SKIP_KEYS = [
  'rsk_device_id', 'rsk_sb_url', 'rsk_sb_key',
  'rsk_last_profile', 'rsk_users_cache', 'rsk_subs_ver',
  'rsk_school_token', 'rsk_col_widths', 'rsk_col_drag',
  'rsk_pending_keys'
];

var _gdPendingQueue = {};
var _gdFlushTimer = null;

// ══════════════════════════════════════════════════════════════
// 🔁 PENDING-KEYS PERSISTENCE — agar gdFlushQueue beech mein fail/
// page band ho jaaye, to in-memory _gdPendingQueue lost ho jaata tha
// aur "☁️ Saved!" dikhne ke baad bhi kuch keys (admList3, school_info
// etc.) cloud tak nahi pohchti thi. Ab key-NAMES localStorage mein
// persist hote hain — next login/save par fresh value se retry hota hai.
// ══════════════════════════════════════════════════════════════
function _gdPersistPendingKeys(){
  try{
    var keys = Object.keys(_gdPendingQueue);
    if(keys.length) (window._lsReal||localStorage).setItem('rsk_pending_keys', JSON.stringify(keys));
    else (window._lsReal||localStorage).removeItem('rsk_pending_keys');
  }catch(e){}
}
function _gdRestorePendingKeys(){
  try{
    var keys = JSON.parse((window._lsReal||localStorage).getItem('rsk_pending_keys')||'[]');
    var restored = 0;
    keys.forEach(function(k){
      if(gdShouldSkip(k)) return;
      var v = (window._lsReal||localStorage).getItem(k);
      if(v!=null){
        try{ _gdPendingQueue[k] = JSON.parse(v); }catch(e){ _gdPendingQueue[k] = v; }
        restored++;
      }
    });
    if(restored){
      window._rskDirty = true;
      console.log('[RSK] '+restored+' pending general-sync key(s) restored from last session — retry on save/online.');
    }
  }catch(e){}
}

function gdShouldSkip(key){
  if(!key) return true;
  // ── REMOVED: `key.indexOf('rsk_u_')===0` rule ──
  // erpKey() prefixes EVERYTHING (admList3, school_info_global, erp_fees,
  // erp_students, staff, leave, vehicles etc.) with 'rsk_u_<USER>_'. This
  // rule was silently blocking ALL of that data from (a) being queued via
  // gdQueueSave/smartSave, AND (b) being restored in gdInitLoadAll even
  // when present in /general. Cross-user isolation is already correctly
  // handled below by the 'rsk_u_'+_activeUserPrefix+'_' prefix check.
  if(key.indexOf('rsk_ph')===0) return true;
  if(key.indexOf('rsk_cls_')===0) return true; // profiles go via sbSync (compressed), not gdQueue
  for(var i=0;i<GD_SKIP_KEYS.length;i++){
    if(GD_SKIP_KEYS[i]===key) return true;
  }
  return false;
}

// ── Payload size guard (before any network send) ──
function rskPayloadCheck(jsonStr){
  try{
    var bytes = new TextEncoder().encode(jsonStr).byteLength;
    if(bytes > 4*1024*1024){
      console.warn('[RSK] Payload too large ('+Math.round(bytes/1024)+' KB) — skipping key, chunk karo.');
      return false;
    }
  }catch(e){}
  return true;
}

// ── Fee-data downgrade guard helpers ──
// Counts how many fee-rows have a non-zero paid amount —
// Part-B (monthly tPaid/trPaid) + Part-A (Sports/Library/Computer/etc. "paid")
// Including Part-A makes the guard catch downgrades where only the
// "other fees" section lost data (Part-B months unchanged).
function _fs2PaidCount(obj){
  try{
    var n = 0;
    var partB = (obj && obj.partB) || [];
    for(var i=0;i<partB.length;i++){
      var r = partB[i] || {};
      if(parseFloat(r.tPaid||0) > 0 || parseFloat(r.trPaid||0) > 0) n++;
    }
    var partA = (obj && obj.partA) || [];
    for(var j=0;j<partA.length;j++){
      if(parseFloat((partA[j]||{}).paid||0) > 0) n++;
    }
    return n;
  }catch(e){ return 0; }
}
// Fetches current cloud value for a single key and returns its paid-month count
// Returns null if the key doesn't exist on cloud yet or the check fails
// (null = "no guard info available", caller should proceed with normal push)
async function _fs2CloudPaidCount(key){
  try{
    var resp = await fetch(CF_WORKER_URL+'/general?key='+encodeURIComponent(key)+'&_t='+Date.now(), {
      headers: cfGetHeaders(false)
    });
    if(!resp.ok) return null;
    var kd = await resp.json();
    if(!kd || kd.value===undefined || kd.value===null) return null;
    var raw = rskDecompress(typeof kd.value==='string' ? kd.value : JSON.stringify(kd.value));
    var d = JSON.parse(raw);
    return _fs2PaidCount(d);
  }catch(e){ return null; }
}

// ── Batch flush with: timeout controller, retry, offline guard ──
var _gdRetryCount = {};
var _gdOfflineRetryCount = 0; // FIX: exponential backoff counter
async function gdFlushQueue(){
  _gdFlushTimer = null;
  if(!navigator.onLine){
    // FIX: Exponential backoff — 3s, 6s, 12s, 24s, max 30s
    var delay = Math.min(3000 * Math.pow(2, _gdOfflineRetryCount), 30000);
    _gdOfflineRetryCount++;
    _gdFlushTimer = setTimeout(gdFlushQueue, delay);
    return Object.keys(_gdPendingQueue).length === 0;
  }
  _gdOfflineRetryCount = 0; // FIX: reset on success
  var keys = Object.keys(_gdPendingQueue);
  if(!keys.length) return true;
  var snapshot = Object.assign({}, _gdPendingQueue);
  _gdPendingQueue = {}; // clear queue immediately; new writes queue fresh
  for(var i=0;i<keys.length;i++){
    var k = keys[i];
    var val = snapshot[k];
    var attempt = 0;
    var sent = false;
    while(attempt < 2 && !sent){
      attempt++;
      var ctrl = new AbortController();
      var warnT  = setTimeout(function(){ sbStatus('⏳ Cloud busy…','#92400e'); }, 20000);
      var abortT = setTimeout(function(){ ctrl.abort(); }, 25000);
      try{
        var jsonStr = typeof val === 'string' ? val : JSON.stringify(val);
        if(!rskPayloadCheck(jsonStr)){ sent=true; break; }
        // ── FEE DOWNGRADE GUARD ──
        // erp_fs2_* (per-student fee) keys: never let an emptier/older local copy
        // overwrite a cloud copy that already has MORE paid months recorded.
        // Stops the "tab-switch / auto-flush pushes stale local data and wipes
        // out fee entries saved from another device" bug.
        if(typeof erpKey==='function' && k.indexOf(erpKey('erp_fs2_'))===0){
          try{
            var _localObj = typeof val === 'string' ? JSON.parse(val) : val;
            var _localPaid = _fs2PaidCount(_localObj);
            var _cloudPaid = await _fs2CloudPaidCount(k);
            if(_cloudPaid !== null && _localPaid < _cloudPaid){
              console.warn('[RSK FeeGuard] Skipped cloud push for '+k+' — local paid('+_localPaid+') < cloud paid('+_cloudPaid+'). Local copy is stale; not overwriting cloud.');
              sent = true;
              delete _gdRetryCount[k];
              break;
            }
          }catch(ge){ /* guard failed — fall through to normal push */ }
        }
        var compressed = rskCompress(jsonStr);
        await fetch(CF_WORKER_URL+'/general', {
          method:'POST',
          headers: cfHeaders(false),
          body: JSON.stringify({ key: k, value: compressed }),
          signal: ctrl.signal
        });
        sent = true;
        delete _gdRetryCount[k];
      }catch(e){
        if(attempt < 2){ await new Promise(function(r){setTimeout(r,1800);}); }
        else{
          _gdPendingQueue[k] = val;
          _gdRetryCount[k] = (_gdRetryCount[k]||0)+1;
          if(_gdRetryCount[k] >= 3) sbStatus('⚠️ Cloud Error','#7f1d1d');
        }
      }finally{
        clearTimeout(warnT); clearTimeout(abortT);
      }
    }
  }
  // ── Persist whatever is still pending (failed keys) for next session ──
  _gdPersistPendingKeys();
  // ── Dirty flag reset — sab sync ho gaya ✅ ──
  if(Object.keys(_gdPendingQueue).length === 0){
    window._rskDirty = false;
    // Server timestamp update karo — doosre devices ko pata chalega
    updateServerTimestamp();
    return true;
  }
  return false;
}

// ── SmartSave: Duplicate request blocker ──
var _smartSaveCache = {};
function smartSave(key, value){
  var current = JSON.stringify(value);
  if(_smartSaveCache[key] && _smartSaveCache[key] === current){
    return; // Same data — skip, no request needed
  }
  _smartSaveCache[key] = current; // Cache update
  gdQueueSave(key, value); // Actually save
}

function gdQueueSave(key, value){
  if(gdShouldSkip(key)) return;
  // Only queue locally — cloud flush via ☁️ Save button (rskCloudSave)
  _gdPendingQueue[key] = value;
  // Mark dirty — something changed, cloud push needed
  window._rskDirty = true;
  // Persist pending key-names so a failed/aborted flush isn't lost on reload
  _gdPersistPendingKeys();
  // Mark cloud save button as pending
  var csb = document.getElementById('ds-cloud-save-btn');
  if(csb && csb.textContent !== '⏳ Saving...'){ 
    csb.style.background='rgba(251,191,36,.4)'; 
    csb.style.color='#fef08a'; 
    csb.style.border='1px solid rgba(251,191,36,.6)'; 
    csb.textContent='☁️ Save (pending)'; 
  }
}

/* ══════════════════════════════════════════════════════════════
   GENERIC "OTHER MANAGEMENT" FIELD PERSISTENCE
   Competition/Function/Library/Calendar/Sports modules ke saare
   <input>/<select>/<textarea> fields ek hi JSON object mein save
   hote hain: erp_<mod>_data → { sectionId: { f0:'..', f1:'..' } }
   localStorage (instant) + cloud /general (debounced gdQueueSave)
   dono mein sync hota hai — ☁️ Save / auto-sync se doosre device
   tak pohchta hai.
══════════════════════════════════════════════════════════════ */
var _mgmtDataCache = {};
function mgmtKey(mod){ return erpKey('erp_'+mod+'_data'); }
function sessMgmtKey(mod){ return sessKey('erp_'+mod+'_data'); }
function _mgmtCacheKey(mod){
  var sess=(document.getElementById('sc_yr')?document.getElementById('sc_yr').value:'')||getCurrentSession();
  return mod+'__'+sess;
}
function mgmtLoad(mod){
  var ck=_mgmtCacheKey(mod);
  if(!_mgmtDataCache[ck]) _mgmtDataCache[ck] = _erpSafeLoad(sessMgmtKey(mod), {});
  return _mgmtDataCache[ck];
}
function mgmtGetVal(mod, sec, key){
  var d = mgmtLoad(mod);
  return (d[sec] && d[sec][key]!=null) ? d[sec][key] : '';
}
var _mgmtSaveTimer = {};
function mgmtSetVal(mod, sec, key, val){
  var ck=_mgmtCacheKey(mod);
  var d = mgmtLoad(mod);
  if(!d[sec]) d[sec]={};
  d[sec][key]=val;
  _mgmtDataCache[ck]=d;
  try{ localStorage.setItem(sessMgmtKey(mod), JSON.stringify(d)); }catch(e){}
  clearTimeout(_mgmtSaveTimer[ck]);
  _mgmtSaveTimer[ck] = setTimeout(function(){
    if(typeof smartSave==='function') smartSave(sessMgmtKey(mod), d);
  }, 700);
}
function mgmtInvalidate(mod){ delete _mgmtDataCache[_mgmtCacheKey(mod)]; }
function mgmtInvalidateAll(){ _mgmtDataCache={}; }
function _mgmtLoadData(mod){
  mgmtInvalidate(mod);
  var renderFnMap={comp:'renderCompMgmt',func:'renderFuncMgmt',lib:'renderLibMgmt',cal:'renderCalMgmt',sports:'s1AutoRestore'};
  var fn=renderFnMap[mod];
  if(fn && typeof window[fn]==='function') try{ window[fn](); }catch(e){}
}
window.mgmtGetVal = mgmtGetVal;
window.mgmtSetVal = mgmtSetVal;

// ── Manual 🔄 Refresh/Sync button handler ──

async function gdForceSync(){
  var ok = confirm('Cloud से fresh data download करें?\n\nLocal unsaved changes पहले save हो जाएंगे।');
  if(!ok) return;
  // Flush any pending writes first
  if(Object.keys(_gdPendingQueue).length){
    clearTimeout(_gdFlushTimer);
    await gdFlushQueue();
  }
  await gdInitLoadAll();
  sbStatus('✅ Synced','#166534');
  setTimeout(function(){sbStatus('☁️ Cloud ON','#1e40af');},3000);
}

function gdDeleteKey(key){
  if(gdShouldSkip(key)) return;
  fetch(CF_WORKER_URL+'/general', {
    method:'POST',
    headers: cfHeaders(false),
    body: JSON.stringify({ key: key, value: null })
  }).catch(function(){});
}

// ══════════════════════════════════════════════════════════════
//  SMART LOAD — Server timestamp compare karo
//  Match     → local data use karo (no full fetch) ✅
//  Mismatch  → fresh fetch from Worker ✅
//  Device A saves → Server ts update → Device B reload → mismatch detect ✅
// ══════════════════════════════════════════════════════════════

async function gdSmartLoad() {
  if(!navigator.onLine) return false;
  if(!currentUser || !currentUser.username) return false;

  // ── Duplicate-call guard: ek session me sirf ek baar chalao ──
  // (Page-load setTimeout aur login ke baad dono se call hota hai,
  //  isliye dusri call ko yahin rok do — duplicate toast/fetch band)
  if(window._rskSmartLoadDone) return true;
  window._rskSmartLoadDone = true;

  var localTsKey = '_rsk_local_ts_' + currentUser.username;

  try {
    // Step 1: Server timestamp fetch karo (tiny 1 request)
    var ctrl = new AbortController();
    var abortT = setTimeout(function(){ ctrl.abort(); }, 8000);
    var resp = await fetch(CF_WORKER_URL + '/school/timestamp', {
      headers: cfHeaders(false),
      signal: ctrl.signal
    });
    clearTimeout(abortT);
    var data = await resp.json();
    var serverTs = data.ok ? String(data.ts) : null;

    if(!serverTs || serverTs === '0') {
      // Server pe koi ts nahi — first time, full fetch karo
      console.log('[RSK SmartLoad] No server ts — full fetch');
      await gdInitLoadAll();
      await updateServerTimestamp(); // pehli baar ts set karo
      return true;
    }

    // Step 2: Local timestamp compare karo
    var localTs = localStorage.getItem(localTsKey) || '0';

    if(serverTs === localTs) {
      // Match — local data fresh hai, no fetch needed
      console.log('[RSK SmartLoad] Cache HIT — local data fresh ✅');
      return true;
    }

    // Step 3: Mismatch — fresh fetch karo (genuine cross-device update)
    console.log('[RSK SmartLoad] Cache MISS — fetching fresh data');
    rskShowActivityToast('🔄 नया डेटा मिल रहा है...', '#1e3a6b');
    await gdInitLoadAll();

    // Step 4: Local ts update karo
    localStorage.setItem(localTsKey, serverTs);
    return true;

  } catch(e) {
    console.warn('[RSK SmartLoad] Error — falling back to full fetch:', e);
    await gdInitLoadAll();
    return true;
  }
}

// ── Server timestamp update karo (data save hone ke baad call karo) ──
async function updateServerTimestamp() {
  if(!navigator.onLine || !currentUser) return;
  try {
    // ── Server apna ts generate karke save karta hai AUR response mein
    //    wahi exact value wapas bhejta hai ({ok:true, ts}).
    //    Yahi authoritative value seedha localTs mein save karo —
    //    isse client/server timestamp hamesha bit-by-bit match karega
    //    aur false-positive "naya data" mismatch nahi aayega. ──
    var resp = await fetch(CF_WORKER_URL + '/school/timestamp', {
      method: 'POST',
      headers: cfHeaders(false)
    });
    var data = await resp.json();
    var localTsKey = '_rsk_local_ts_' + currentUser.username;
    if(data && data.ok && data.ts){
      localStorage.setItem(localTsKey, String(data.ts));
    }
  } catch(e) { /* silent */ }
}

async function gdInitLoadAll(){
  if(!navigator.onLine){ console.warn('[RSK] Offline — gdInitLoadAll skipped'); return; }
  var ctrl = new AbortController();
  var abortT = setTimeout(function(){ ctrl.abort(); }, 25000);
  // ── FIX: saveData()/cloud-push ko PUREE gdInitLoadAll duration ke liye block karo ──
  // Pehle ye block sirf profile-sync loop ke andar tha. Lekin loop se PEHLE
  // loadProfile(currentProfileKey()) LOCAL (pre-cloud-sync, stale) data ke saath
  // call hota hai — uske UI re-render se saveData() fire ho sakta hai, aur
  // initCloudSaveHook ke through ye STALE PHOTOS turant cloud par push ho jaata
  // hai (cloud ka sahi/empty photoUrls overwrite). Isliye function shuru se end
  // tak saveData block rehna chahiye, fresh cloud data load hone tak.
  var _gdInitOrigSaveData = window.saveData;
  window.saveData = function(){ /* blocked during gdInitLoadAll */ };
  try{
    var resp = await fetch(CF_WORKER_URL+'/general', {
      headers: cfGetHeaders(false),
      signal: ctrl.signal
    });
    clearTimeout(abortT);
    if(!resp.ok) throw new Error('HTTP '+resp.status);
    var data = await resp.json();
    console.log('[RSK gdInitLoadAll] token='+(CF_SCHOOL_TOKEN?CF_SCHOOL_TOKEN.slice(0,3)+'***':'(empty)')+' prefix='+_activeUserPrefix+' | /general returned '+Object.keys(data).length+' keys: '+Object.keys(data).join(' | '));
    console.log('[RSK gdInitLoadAll] admList3='+(erpKey('admList3') in data)+' erp_students='+(erpKey('erp_students') in data)+' erp_fees='+(erpKey('erp_fees') in data)+' school_info='+(erpKey('rsk_school_info_global') in data));
    var _gdClearedKeys={};
    try{
      // Merge local + cloud cleared_keys (cloud may have newer deletes from this session)
      var _localCk = JSON.parse((_lsReal||localStorage).getItem('rsk_cleared_keys')||'{}');
      var _cloudCk = data['rsk_cleared_keys'];
      if(_cloudCk && typeof _cloudCk === 'object') {
        Object.assign(_localCk, _cloudCk);
        (_lsReal||localStorage).setItem('rsk_cleared_keys', JSON.stringify(_localCk));
      }
      _gdClearedKeys = _localCk;
    }catch(e){ try{ _gdClearedKeys=JSON.parse((_lsReal||localStorage).getItem('rsk_cleared_keys')||'{}'); }catch(e2){} }
    // PERMANENT FIX: Also merge cloud rsk_deleted_keys — DS clears are stored here permanently
    try{
      var _localDk = JSON.parse((_lsReal||localStorage).getItem('rsk_deleted_keys')||'{}');
      var _cloudDk = data['rsk_deleted_keys'];
      if(_cloudDk && typeof _cloudDk === 'object'){
        Object.assign(_localDk, _cloudDk);
        (_lsReal||localStorage).setItem('rsk_deleted_keys', JSON.stringify(_localDk));
        // Also merge into cleared_keys so all load checks catch it
        Object.assign(_gdClearedKeys, _localDk);
        (_lsReal||localStorage).setItem('rsk_cleared_keys', JSON.stringify(_gdClearedKeys));
      }
    }catch(e){}
    var _admHardCleared = (_lsReal||localStorage).getItem('rsk_adm_hard_cleared')==='1';
    var _feeHardCleared = (_lsReal||localStorage).getItem('rsk_fee_hard_cleared')==='1';
    Object.keys(data).forEach(function(k){
      // Skip heavy keys — profiles via sbSmartLoad, photos stay local
      if(gdShouldSkip(k)) return;
      if(k.indexOf(erpKey('erp_fs2_'))===0) return; // per-student fee — load on demand
      if(k.indexOf(sessKey('erp_fs5_'))===0) return; // per-class fee summary — load on demand
      // Skip admission keys if user did a hard clear
      if(_admHardCleared && (k===erpKey('admList3')||k===erpKey('rsk_adm_registry')||k===erpKey('erp_students')||k===erpKey('erp_attendance')||k===erpKey('erp_exams'))){ console.log('[RSK HARD-CLEARED] '+k); return; }
      // Skip fee keys if user did a hard clear
      if(_feeHardCleared && (k===erpKey('erp_feeConfig')||k===erpKey('erp_feeMonths')||k===erpKey('erp_customFees')||k===erpKey('erp_fees')||k===erpKey('erp_persist')||k===erpKey('erp_lastReceiptNo'))){ console.log('[RSK FEE-HARD-CLEARED] '+k); return; }
      // Skip keys that user explicitly cleared
      if(_gdClearedKeys[k]){ console.log('[RSK SKIP-CLEARED] '+k); return; }
      // Skip old unprefixed school_info_global — it belongs to no specific user
      if(k==='rsk_school_info_global'){ 
        // Delete from localStorage if exists (cleanup old data)
        try{ (_lsReal||localStorage).removeItem('rsk_school_info_global'); }catch(e){}
        return; 
      }
      // Skip ALL unprefixed ERP/Admission/Fee keys — old pre-isolation data, belongs to no specific user
      var _unprefixedErpKeys = ['admList3','rsk_adm_registry','erp_students','erp_attendance',
        'erp_fees','erp_exams','erp_feeConfig','erp_feeMonths','erp_customFees',
        'erp_lastReceiptNo','erp_persist','erp_staff','erp_leave','erp_fs2_password','erp_tcregister'];
      if(_unprefixedErpKeys.indexOf(k)!==-1){ return; }
      // Skip unprefixed erp_fs2_/erp_fs5_ dynamic keys
      if((k.indexOf('erp_fs2_')===0||k.indexOf('erp_fs5_')===0) && k.indexOf('rsk_u_')!==0){ return; }
      // Skip other users' prefixed keys (rsk_u_OTHERUSERNAME_...)
      if(k.indexOf('rsk_u_')===0 && k.indexOf('rsk_u_'+(_activeUserPrefix||'').toUpperCase()+'_')!==0){ return; }
      // ── FIX: agar is key ke liye local mein pending unsaved changes hain
      // toh cloud ka data overwrite nahi karega (same fix as rskTabSync)
      if(window._gdPendingQueue && window._gdPendingQueue[k]) return;
      var v = data[k];
      var toStore = typeof v === 'string' ? v : JSON.stringify(v);
      // ── Decompress if compressed ──
      toStore = rskDecompress(toStore);
      try{ (_lsReal||localStorage).setItem(k, toStore); }catch(qe){}
      // Restore seal window variables
      if(k==='rsk_principal_seal') window._rskSealData = toStore;
      if(k==='rsk_exam_seal') window._rskExamSealData = toStore;
      if(k==='rsk_school_logo') { SCHOOL_LOGO = toStore; }
      // Reload school info from cloud if it's our key
      if(k===erpKey('rsk_school_info_global')){
        try{
          var _csi=JSON.parse(toStore);
          // Only apply non-junk name
          if(_csi&&_csi.name&&!/^(\d+|.\1{4,})$/.test(_csi.name.trim())){
            if(typeof _rskSetName==='function') _rskSetName(_csi.name);
          }
          // Other fields
          ['address','dise','mpbse','jsk','gramPanchayat','basahat','village','block','district','vidhansabha','medium','mediumExplicitlySet'].forEach(function(fk){
            if(_csi[fk]!==undefined&&_csi[fk]!==null&&_csi[fk]!=='') SCHOOL_INFO[fk]=_csi[fk];
          });
        }catch(e){}
      }
      if(k.indexOf('rsk_teacher_seal_')===0){
        var cls = k.replace('rsk_teacher_seal_','');
        if(typeof _teacherSealWinKey==='function') window[_teacherSealWinKey(cls)] = toStore;
      }
    });
    // After cloud load — reload current profile so SCHOOL_INFO stays correct
    try{
      if(typeof currentProfileKey==='function' && typeof loadProfile==='function'){
        loadProfile(currentProfileKey());
        if(typeof renderSchoolDetails==='function') setTimeout(renderSchoolDetails, 100);
      }
    }catch(e){}
    // ── CRITICAL FIX: Cloud data localStorage mein aa gaya, ab in-memory variables reload karo ──
    // Bina is step ke registry/fees/admList3 purane in-memory values pe kaam karte rahe
    // aur DataSheet mein ghost students / Admission mein naya student nahi dikhta tha
    try{
      if(typeof _erpSafeLoad==='function' && typeof erpKey==='function'){
        registry   = _erpSafeLoad(erpKey('erp_students'),   []);
        attendance = _erpSafeLoad(erpKey('erp_attendance'), {});
        fees       = _erpSafeLoad(erpKey('erp_fees'),        []);
        exams      = _erpSafeLoad(erpKey('erp_exams'),       []);
        admList3   = _erpSafeLoad(erpKey('admList3'),        []);
        // ── Migrate session for legacy records loaded from cloud ──
        (function(){
          var _dSess=(document.getElementById('sc_yr')&&document.getElementById('sc_yr').value)||'2026-27';
          var _ch=false;
          admList3.forEach(function(r){ if(!r.session){ r.session=_dSess; _ch=true; } });
          if(_ch) try{ localStorage.setItem(erpKey('admList3'),JSON.stringify(admList3)); }catch(e){}
        })();
        feeConfig  = _erpSafeLoad(erpKey('erp_feeConfig'),  {});
        console.log('[RSK gdInitLoadAll] In-memory ERP vars reloaded — registry:'+registry.length+' adm:'+admList3.length+' feeConfig:'+Object.keys(feeConfig).length);
        // ── FIX: staffRegistry/leaveRegistry bhi reload karo — pehle ye yahan
        // refresh nahi hote the, isliye doosre device par naye Staff/Leave
        // entries cloud me aane ke baad bhi UI mein purana data hi dikhta tha ──
        if(typeof staffRegistry !== 'undefined'){
          window.staffRegistry = _erpSafeLoad(erpKey('erp_staff'), []);
          if(document.getElementById('staffRegistryBody')){
            try{ if(typeof renderStaffRegistry==='function') renderStaffRegistry(); if(typeof updateStaffStats==='function') updateStaffStats(); }catch(re){}
          }
        }
        if(typeof leaveRegistry !== 'undefined'){
          window.leaveRegistry = _erpSafeLoad(sessKey('erp_leave'), []);
          try{ if(typeof renderLeaveRecords==='function' && document.getElementById('leaveRecordsBody')) renderLeaveRecords(); }catch(re){}
        }
        // ── FIX: Competition/Function/Library/Calendar Management — in-memory
        // cache invalidate karo taaki cloud se aaya naya data dikhe, aur agar
        // wahi tab khula hai to turant re-render bhi ho jaye ──
        if(typeof mgmtInvalidateAll==='function') mgmtInvalidateAll();
        _rskCTLoaded = false; // force fresh read of erp_custom_tables_data on next restore
        try{ if(typeof window.s1AutoRestore==='function') window.s1AutoRestore(); }catch(re){}
        try{ if(typeof window.s2AutoRestore==='function') window.s2AutoRestore(); }catch(re){}
        try{ if(typeof window.s3AutoRestore==='function') window.s3AutoRestore(); }catch(re){}
        try{
          var _mgmtRenderMap={compemgmt:'renderCompMgmt',funcmgmt:'renderFuncMgmt',libmgmt:'renderLibMgmt',calmgmt:'renderCalMgmt'};
          if(typeof curTab!=='undefined' && curTab && _mgmtRenderMap[curTab] && typeof window[_mgmtRenderMap[curTab]]==='function'){
            window[_mgmtRenderMap[curTab]]();
          }
        }catch(re){}
      }
    }catch(e){ console.warn('[RSK] ERP reload error:',e); }

    // CRITICAL FIX: Sabhi class profiles cloud se load karo
    // /profiles endpoint se keys lo, har class force=true se load karo
    try{
      if(typeof sbSmartLoad === 'function'){
        var _allProfs = [];
        try{
          var _pr = await fetch(CF_WORKER_URL+'/profiles', { headers: cfGetHeaders(false) });
          if(_pr.ok){
            var _pd = await _pr.json();
            if(Array.isArray(_pd)) _allProfs = _pd;
          }
        }catch(e){ console.warn('[RSK] /profiles list error:',e); }

        // Local index merge
        try{
          var _li = JSON.parse((_lsReal||localStorage).getItem(erpKey('rsk_profile_index'))||'[]');
          _li.forEach(function(k){ if(_allProfs.indexOf(k)===-1) _allProfs.push(k); });
          if(_allProfs.length>0) (_lsReal||localStorage).setItem(erpKey('rsk_profile_index'), JSON.stringify(_allProfs));
        }catch(e){}

        // Current class pehle
        var _curPK = (typeof currentProfileKey==='function') ? currentProfileKey() : null;
        if(_curPK && _allProfs.indexOf(_curPK)===-1) _allProfs.unshift(_curPK);
        else if(_curPK) _allProfs = [_curPK].concat(_allProfs.filter(function(k){ return k!==_curPK; }));

        console.log('[RSK gdInitLoadAll] Loading '+_allProfs.length+' profiles from cloud...');
        // ── CRITICAL FIX: saveData() block karo loop ke dauran ──
        // loadProfile → form fields change → saveData() fire → cloud data empty se overwrite!
        var _origSaveData = window.saveData;
        window.saveData = function(){ /* blocked during cloud profile sync */ };
        try{
          for(var _pi=0; _pi<_allProfs.length; _pi++){
            var _pk = _allProfs[_pi];
            if(!_pk) continue;
            try{
              var _ok = await sbSmartLoad(_pk, true);
              if(_ok && _pk===_curPK){
                try{ if(typeof drawTable==='function') setTimeout(drawTable, 200); }catch(e){}
              }
            }catch(e){ console.warn('[RSK] Profile load error '+_pk+':', e); }
          }
        }finally{
          window.saveData = _origSaveData; // restore
        }
        console.log('[RSK gdInitLoadAll] All '+_allProfs.length+' profiles loaded');
      }
    }catch(e){ console.warn('[RSK] Profile cloud load error:', e); }

  }catch(e){
    clearTimeout(abortT);
    if(e.name==='AbortError') sbStatus('⚠️ Cloud timeout','#92400e');
    else console.warn('[RSK] gdInitLoadAll error:', e.message);
  } finally {
    window.saveData = _gdInitOrigSaveData;
  }
}

async function gdUploadAllGeneral(){
  sbStatus('☁️ Uploading…','#92400e');
  try{
    var rows=[];
    for(var i=0;i<localStorage.length;i++){
      var k=localStorage.key(i);
      if(!k||gdShouldSkip(k)) continue;
      if(k==='rsk_school_info_global') continue; // unprefixed — skip, use erpKey version only
      // Skip unprefixed ERP keys — old pre-isolation data
      var _upKeys=['admList3','rsk_adm_registry','erp_students','erp_attendance','erp_fees','erp_exams','erp_feeConfig','erp_feeMonths','erp_customFees','erp_lastReceiptNo','erp_persist','erp_staff','erp_leave','erp_fs2_password','erp_tcregister'];
      if(_upKeys.indexOf(k)!==-1) continue;
      if((k.indexOf('erp_fs2_')===0||k.indexOf('erp_fs5_')===0)&&k.indexOf('rsk_u_')!==0) continue;
      var v=_lsReal.getItem(k);
      if(v) rows.push({key:k,value:v});
    }
    for(var b=0;b<rows.length;b++){
      await fetch(CF_WORKER_URL+'/general',{
        method:'POST',
        headers: cfHeaders(false),
        body:JSON.stringify({key:rows[b].key,value:rows[b].value})
      });
    }
    sbStatus('✅ Synced','#166534');
    alert('✅ '+rows.length+' keys Cloud pe upload!');
    setTimeout(function(){sbStatus('☁️ Cloud ON','#1e40af');},3000);
  }catch(e){
    sbStatus('⚠️ Error','#7f1d1d');
    alert('❌ Upload failed: '+e.message);
  }
}

async function gdDownloadAllGeneral(){
  sbStatus('☁️ Downloading…','#92400e');
  try{
    var resp = await fetch(CF_WORKER_URL+'/general?_t='+Date.now(), { headers: cfGetHeaders(false) });
    var data = await resp.json();
    var count = Object.keys(data).length;
    if(!count){ alert('Cloud में कोई data नहीं मिला।'); return; }
    Object.keys(data).forEach(function(k){
      if(!k) return;
      var v = data[k];
      var toStore = typeof v === 'string' ? v : JSON.stringify(v);
      // ── Decompress if compressed ──
      toStore = rskDecompress(toStore);
      (_lsReal||localStorage).setItem(k, toStore);
    });
    sbStatus('✅ Restored','#166534');
    alert('✅ '+count+' keys cloud से restore!\nPage reload हो रहा है…');
    location.reload();
  }catch(e){
    sbStatus('⚠️ Error','#7f1d1d');
    alert('❌ Download failed: '+e.message);
  }
}

