  var CHARS = ' !"#$%&\'()*+,-./0123456789:;<=>?@ABCDEFGHIJKLMNOPQRSTUVWXYZ[\\]^_' + String.fromCharCode(96) + 'abcdefghijklmnopqrstuvwxyz{|}~';
