// ── DS Sub-tab switcher ──
function switchDsSubTab(tab){
  var tabs=['main','ut'];
  tabs.forEach(function(t){
    var el=document.getElementById('ds-subtab-'+t);
    var btn=document.getElementById('ds-subtab-btn-'+t);
    if(!el||!btn) return;
    var isActive=(t===tab);
    el.style.display=isActive?'flex':'none';
    btn.style.background=isActive?'#fbbf24':'#e2e8f0';
    btn.style.color=isActive?'#1a1a1a':'#475569';
    btn.style.borderBottom=isActive?'2px solid #fbbf24':'2px solid #e2e8f0';
  });
  if(tab==='ut'){
    if(!_utDSSelectedCls && typeof S!=='undefined' && S && S.cls) _utDSSelectedCls = S.cls;
    // If S.stu is empty but localStorage has saved profile, load it silently
    if(typeof S!=='undefined' && S && S.cls && (!S.stu || S.stu.length===0)){
      try{
        var _utTabPKey = (typeof currentProfileKey==='function') ? currentProfileKey() : null;
        if(_utTabPKey){
          var _utTabRaw = (window._lsReal||localStorage).getItem(_utTabPKey);
          if(_utTabRaw){
            var _utTabDec = (typeof rskDecompress==='function') ? rskDecompress(_utTabRaw) : _utTabRaw;
            var _utTabParsed = JSON.parse(_utTabDec);
            var _utTabS = _utTabParsed.S || _utTabParsed;
            if(_utTabS && _utTabS.stu && _utTabS.stu.length > 0){
              S.stu = _utTabS.stu;
              S.n = _utTabS.n || _utTabS.stu.length;
              console.log('[UT] Loaded '+S.stu.length+' students from saved profile for class '+S.cls);
            }
          }
        }
      }catch(e){}
    }
    renderClassPickerForTab('ut');
    // Force sidebar open — renderUTDataSheet may collapse it on early return
    var _utSb = g('cls-picker-sidebar-ut');
    if(_utSb) _utSb.classList.remove('collapsed');
    var _utRb = g('cls-reopen-btn-ut');
    if(_utRb) _utRb.style.display='none';
    renderUTDataSheet();
  }
}

// ── RS Sub-tab switcher (Result Sheet + Monthly Test Result Sheet) ──
