  h+='</div>';

  var cardNum=0;
  // 2 cards per row, group them
  var validStudents=[];
  for(var ri=0;ri<n;ri++){
    var st=stuList[ri]||{};
    if(!(st.name||st.anukra)) continue;
    validStudents.push({ri:ri,st:st});
  }

  // ── Navigation Panel (after validStudents is ready) ──
  var totalPages=Math.ceil(validStudents.length/10);
  h+='<div class="no-print" style="display:flex;align-items:center;gap:10px;padding:8px 16px;background:#1e3050;flex-wrap:wrap;">';
