  h+='<input id="srut-page-input" type="number" min="1" max="'+totalPages+'" value="1" onchange="srutGoPage(0)" style="width:50px;text-align:center;border:2px solid #6366f1;border-radius:4px;padding:3px;font-size:13px;font-weight:800;color:#1e1b4b;">';
