  h+='<button onclick="srutPrintRange()" style="background:#d97706;color:#fff;border:none;border-radius:6px;padding:6px 18px;font-size:12px;font-weight:800;cursor:pointer;">&#128438; Print by Range</button>';
  h+='</div>';

  // ── Print area ──
  h+='<div id="srut-print-area" style="padding:10px;font-family:Arial,sans-serif;background:#f0f0f0;">';

  // Cards per page: 10 per page (5 rows x 2 cols)
