      h+='<div style="min-width:130px;max-width:140px;padding:2px 4px;border-right:1px solid #ccc;font-size:7px;line-height:1.35;">';
      h+='<div><b>S.N.- '+cardNum+' &nbsp; CLASS - '+cls+sec+'</b></div>';
      h+='<div><b>ROLL NO. -</b> <span style="color:#c00;font-weight:800;">'+anukra+'</span></div>';
      h+='<div><b>SCHOLAR NO. -</b> '+(scholar||'—')+'</div>';
      h+='<div><b>MEDIUM -</b> '+med+'</div>';
      h+='<div><b>CATEGORY -</b> '+cat+'</div>';
      h+='<div><b>STUDENT\'S NAME -</b> <span style="font-weight:800;">'+name+'</span></div>';
      h+='<div><b>FATHER\'S NAME SHRI -</b> <span style="font-weight:800;">'+father+'</span></div>';
      h+='<div><b>MOTHER\'S NAME SMT. -</b> <span style="font-weight:800;">'+mother+'</span></div>';
      if(dob) h+='<div><b>DATE OF BIRTH -</b> '+dob+'</div>';
