      // Top notice
      h+='<div style="text-align:center;font-size:6.5px;font-weight:700;padding:1px 3px;border-bottom:1px solid #ccc;background:#fffbe6;">माह: <b>'+selMonthLabel+'</b> | Max: <b>'+MAX_UT+'</b> | Min: <b>'+MIN_UT+'</b></div>';
      // Table
      h+='<table style="width:100%;border-collapse:collapse;font-size:8.5px;">';
