  var ALL_SECS_UT=['ALL'].concat(allSecs);
  var ALL_MEDS_UT=['ALL'].concat(allMeds);

  // Filtered student lists per table
  function _utFilter(secF,medF){
    return allStudents.filter(function(s){
      return (secF==='ALL'||s.sec===secF)&&(medF==='ALL'||s.med===medF);
    });
  }
