    +'.smut-sec-badge .smut-bl{font-weight:800;font-size:13px;color:#1e3a6e;letter-spacing:.3px;font-family:Calibri,Arial,sans-serif;border-left:3px solid #2b579a;padding-left:8px}'
    +'.smut-card{background:#fff;border:1px solid #b8cce4;border-top:3px solid #2b579a;box-shadow:0 3px 12px rgba(43,87,154,.15);overflow:hidden;margin-bottom:28px}'
    +'</style>';
  h+='<div style="display:flex;flex-direction:column;gap:0;padding:16px 20px;font-family:Arial,sans-serif;">';

  // ── Month selector bar ──
  h+='<div class="no-print" style="display:flex;align-items:center;gap:10px;margin-bottom:14px;background:#fff;padding:8px 14px;border-radius:8px;border:1.5px solid #b8cce4;flex-wrap:wrap;">';
  h+='<span style="font-weight:700;color:#1e3a6e;font-size:12px;">📅 माह चुनें:</span>';
  h+='<select id="smut-month-sel" onchange="renderUTSummary()" style="border:2px solid #2b579a;border-radius:6px;padding:4px 10px;font-family:inherit;font-weight:700;font-size:12px;color:#1e3a6e;cursor:pointer;">';
  availMonths.forEach(function(m){ h+='<option value="'+m.id+'"'+(selMonth===m.id?' selected':'')+'>'+m.hi+'</option>'; });
  h+='</select>';
  var _totAll=allStudents.length, _appAll=allStudents.filter(function(s){return s.appeared;}).length, _passAll=allStudents.filter(function(s){return s.pass;}).length;
  h+='<span style="margin-left:auto;font-size:11px;color:#374151;">कुल: <b>'+_totAll+'</b> &nbsp;|&nbsp; उपस्थित: <b>'+_appAll+'</b> &nbsp;|&nbsp; उत्तीर्ण: <b style="color:green">'+_passAll+'</b> &nbsp;|&nbsp; अनुत्तीर्ण: <b style="color:#b91c1c">'+(_appAll-_passAll)+'</b></span>';
  h+='</div>';

