  h+='<tr><td colspan="'+t1TotCols+'" style="'+BD+'font-size:11px;font-weight:700;text-align:center;padding:4px 3px;background:#fff;color:#1e3a6e">DISTRICT- '+(dist||'—')+'&nbsp;&nbsp;&nbsp;Unit Test '+selMonthLabel+' '+yr+'&nbsp;&nbsp;&nbsp;DISE CODE- '+(dise||'—')+'</td></tr>';
  h+='<tr><td colspan="'+t1TotCols+'" style="'+BD+'font-size:11px;font-weight:700;text-align:center;padding:4px 3px;background:#fff;color:#375623">BLOCK - '+(block||dist||'—')+'&nbsp;&nbsp;&nbsp;Sectionwise Result Class - '+cls+'&nbsp;&nbsp;&nbsp;MPBSE CODE- '+(mpbse||'—')+'</td></tr>';
  // Medium filter
