  h+='<span style="background:#333;color:#fff;padding:5px 7px;font-size:13px;font-weight:900;vertical-align:middle">&#9658;</span>';
  h+=_bSel('smut-t1-med',ALL_MEDS_UT,_utT1Med,'background:#fff;color:#1e3a6e;padding:5px 14px;min-width:100px;border-radius:0 4px 4px 0;border-left:none;font-weight:900;');
  h+='</td></tr>';
  // Column headers
  h+='<tr>';
