  // ════ TABLE 2 — Category-wise SC/ST/OBC/UR ════
  h+='<div class="smut-sec-badge"><span class="smut-bn">📋 TABLE 2</span><span class="smut-bl">Category-wise Result (SC / ST / OBC / UR)</span></div>';
  h+='<div class="smut-card" style="overflow-x:auto;margin-bottom:28px;">';
