  h+='<tr><td colspan="16" style="'+BD+'font-size:11px;font-weight:700;text-align:center;padding:4px 3px;background:#fff;color:#1e3a6e">DISTRICT- '+(dist||'—')+'&nbsp;&nbsp;&nbsp;Unit Test '+selMonthLabel+' '+yr+'&nbsp;&nbsp;&nbsp;DISE CODE- '+(dise||'—')+'</td></tr>';
  h+='<tr><td colspan="16" style="'+BD+'font-size:11px;font-weight:700;text-align:center;padding:4px 3px;background:#fff;color:#375623">BLOCK - '+(block||dist||'—')+'&nbsp;&nbsp;&nbsp;Sectionwise Result Class - '+cls+'</td></tr>';
  // Section + Medium filter
  h+='<tr>';
  h+='<td colspan="5" style="'+BD+'padding:5px 8px;background:#fff;vertical-align:middle">';
  h+='<span style="background:#7030a0;color:#fff;padding:5px 8px;font-weight:700;font-size:10px;border-radius:4px 0 0 4px;vertical-align:middle;line-height:1.3;display:inline-block">Select<br>Section</span>';
  h+='<span style="background:#333;color:#fff;padding:5px 6px;font-size:13px;font-weight:900;vertical-align:middle">&#9658;</span>';
  h+=_bSel('smut-t2-sec',ALL_SECS_UT,_utT2Sec,'background:#7030a0;color:#fff;padding:5px 14px;min-width:90px;border-radius:0 4px 4px 0;font-size:13px;');
  h+='</td>';
