  h+='&nbsp;<span style="background:#c00000;color:#fff;padding:5px 14px;font-weight:900;font-size:12px;border-radius:4px;cursor:pointer;vertical-align:middle" onclick="var a=document.getElementById(\'smut-t2-sec\'),b=document.getElementById(\'smut-t2-med\');if(a)a.value=\'ALL\';if(b)b.value=\'ALL\';renderUTSummary();">ALL</span>';
  h+='</td></tr>';
  // Cat super-header
  h+='<tr>';
  h+='<td rowspan="2" style="'+BD+'font-weight:900;font-size:11px;text-align:center;padding:4px 8px;background:#1e3a6e;color:#fff">GRADE</td>';
