    var bg=cat==='TOTAL'?'background:#c55a11;color:#fff':'background:#2b579a;color:#fff';
    h+='<td colspan="3" style="'+BD+'font-weight:900;font-size:11px;text-align:center;padding:3px 6px;'+bg+'">'+cat+'</td>';
