  h+='<button onclick="exportUTExcel()" style="background:#1d4ed8;color:#fff;border:none;border-radius:5px;padding:5px 14px;font-size:11px;font-weight:700;cursor:pointer;margin-left:auto;">\u{1F4E5} Export CSV</button>';
  h+='</div>';

  h+='<div style="overflow-x:auto;">';
  h+='<table id="ut-main-tbl" style="border-collapse:collapse;font-size:9px;white-space:nowrap;border:1.5px solid #475569;">';
  h+='<thead>';

