  var GRP_COLORS=['#000000','#000000','#000000','#cc00cc','#cc00cc','#cc00cc'];
  GRP_LABELS.forEach(function(gl,gi){
    h+='<th colspan="2" style="'+BD+TH+'color:'+GRP_COLORS[gi]+';font-weight:'+(gi>=3?'800':'700')+';">'+gl+'</th>';
  });
  // Grand Total, Percentage, Result Grade (rowspan=6)
  h+='<th rowspan="6" style="'+BD+TH+'min-width:40px;">'+(_EN?'Grand Total':'कुल अंक')+'</th>';
  h+='<th rowspan="6" style="'+BD+TH+'min-width:40px;">'+(_EN?'Percentage':'प्रतिशत')+'</th>';
