// Per-class custom subject map — persists across sessions
// Structure: { 'cls': { main: [...], extra: [...] } }
var CUSTOM_SUBS_MAP = {};
// Version key — agar SUBS_MAP badla to purane localStorage subjects hata ke naye load hoon
var SUBS_MAP_VERSION = 'v27_eng';
function loadCustomSubsMap(){
  try{ var r=localStorage.getItem('rsk_custom_subs'); if(r) CUSTOM_SUBS_MAP=JSON.parse(r); }catch(e){}
  // Migration: agar version match nahi — SUBS_MAP se saari classes reset kar do
  var savedVer='';
  try{ savedVer=localStorage.getItem('rsk_subs_ver')||''; }catch(e){}
  if(savedVer !== SUBS_MAP_VERSION){
    // Force overwrite all classes with new English SUBS_MAP, preserving only extra subjects
    Object.keys(SUBS_MAP).forEach(function(cls){
      var prevExtra=(CUSTOM_SUBS_MAP[cls]&&CUSTOM_SUBS_MAP[cls].extra)||[];
      CUSTOM_SUBS_MAP[cls]={ main: SUBS_MAP[cls].slice(), extra: prevExtra };
    });
    saveCustomSubsMap();
    try{ localStorage.setItem('rsk_subs_ver', SUBS_MAP_VERSION); }catch(e){}
  }
}
