/* ══ EXCEL DRAG-TO-RESIZE — direct <th> width approach ══
   Works correctly with table-layout:fixed tables.
   Each <th> gets a right-edge drag handle.
   Dragging updates the <col> width (for non-fixed) AND updates
   all <th> in the same leaf-column index for fixed-layout tables.
══════════════════════════════════════════════════════════════════════ */
(function(){
  var _drag=false, _startX=0, _startW=0, _colIdx=0, _tbl=null, _activeHandle=null;

  /* Build a flat map: colIndex -> {col:<col>, ths:[<th>...]} */
  function buildColMap(tbl){
    var allRows=tbl.querySelectorAll('thead tr');
    // Count total leaf columns from the row with most cells (expanded)
    var maxCols=0;
    allRows.forEach(function(row){
      var c=0;
      row.querySelectorAll('th').forEach(function(th){ c+=parseInt(th.getAttribute('colspan')||1); });
      if(c>maxCols) maxCols=c;
    });
    if(!maxCols) return null;

    // Build map
    var map=[];
    for(var i=0;i<maxCols;i++) map.push({ths:[]});

    // Track rowspan occupancy
    var occupy={};
    allRows.forEach(function(row,ri){
      var cursor=0;
      row.querySelectorAll('th').forEach(function(th){
        while(occupy[ri+'-'+cursor]) cursor++;
        var span=parseInt(th.getAttribute('colspan')||1);
        var rspan=parseInt(th.getAttribute('rowspan')||1);
        for(var r=1;r<rspan;r++) for(var c=0;c<span;c++) occupy[(ri+r)+'-'+(cursor+c)]=true;
        // Register this th for each leaf column it covers
        for(var c=0;c<span;c++) if(map[cursor+c]) map[cursor+c].ths.push(th);
        cursor+=span;
      });
    });

    // Create/update colgroup
    var cg=tbl.querySelector('colgroup.rz-cg');
    if(!cg){
      cg=document.createElement('colgroup');
      cg.className='rz-cg';
      for(var i=0;i<maxCols;i++){
        var col=document.createElement('col');
        cg.appendChild(col);
      }
      tbl.insertBefore(cg,tbl.firstChild);
    }
    var cols=cg.querySelectorAll('col');

    // Initialize col widths from rendered th widths
    // Use last header row for single-col ths (most accurate)
    var lastRow=allRows[allRows.length-1];
    var cur2=0;
    lastRow&&lastRow.querySelectorAll('th').forEach(function(th){
      var span=parseInt(th.getAttribute('colspan')||1);
      var perW=Math.round(th.offsetWidth/span)||40;
      for(var s=0;s<span;s++){
        if(map[cur2+s]&&!map[cur2+s].initW){ map[cur2+s].initW=perW; if(cols[cur2+s]) cols[cur2+s].style.width=perW+'px'; }
      }
      cur2+=span;
    });

    // Store map on table
    tbl._rzMap=map;
    tbl._rzCols=cols;
    return map;
  }

  function setColWidth(tbl,colIdx,nw){
    var map=tbl._rzMap;
    var cols=tbl._rzCols;
    if(!map||!cols) return;
    // Update the <col>
    if(cols[colIdx]) cols[colIdx].style.width=nw+'px';
    // Update all <th>s that cover this colIdx
    var coveredThs=map[colIdx]?map[colIdx].ths:[];
    coveredThs.forEach(function(th){
      var span=parseInt(th.getAttribute('colspan')||1);
      // Find start colIdx for this th by scanning map
      var startCol=-1;
      for(var i=0;i<map.length;i++){
        if(map[i].ths.indexOf(th)>=0){ startCol=i; break; }
      }
      if(startCol<0) return;
      // Sum widths of all cols in this th's span
      var totalW=0;
      for(var c=startCol;c<startCol+span;c++){
        totalW+=parseInt(cols[c]?cols[c].style.width:40)||40;
      }
      th.style.width=totalW+'px';
      th.style.minWidth=totalW+'px';
    });
  }

  function onMouseMove(e){
    if(!_drag) return;
    var dx=e.clientX-_startX;
    var nw=Math.max(20,_startW+dx);
    setColWidth(_tbl,_colIdx,nw);
  }

  function onMouseUp(){
    if(!_drag) return;
    _drag=false;
    document.body.classList.remove('col-resizing');
    if(_activeHandle) _activeHandle.classList.remove('dragging');
    // Save to localStorage
    try{
      var raw=JSON.parse(localStorage.getItem('rsk_col_drag')||'{}');
      var tblId=_tbl.id||_tbl.dataset.rzId||'';
      if(tblId){
        if(!raw[tblId]) raw[tblId]={};
        var cols=_tbl._rzCols;
        if(cols&&cols[_colIdx]) raw[tblId][_colIdx]=parseInt(cols[_colIdx].style.width)||40;
        localStorage.setItem('rsk_col_drag',JSON.stringify(raw));
      }
    }catch(ex){}
    updateStickyColCSSFromDrag(_tbl);
    document.removeEventListener('mousemove',onMouseMove);
    document.removeEventListener('mouseup',onMouseUp);
  }

  window.attachResizers=function(tbl){
    if(!tbl) return;
    if(!tbl.id && !tbl.dataset.rzId) tbl.dataset.rzId='rztbl_'+(Date.now()%99999);
    // Reset occupancy tracker
    tbl._rzRowOccupy={};
    var map=buildColMap(tbl);
    if(!map) return;

    // Restore saved widths
    try{
      var raw=JSON.parse(localStorage.getItem('rsk_col_drag')||'{}');
      var tblId=tbl.id||tbl.dataset.rzId;
      if(raw[tblId]){
        Object.keys(raw[tblId]).forEach(function(ci){
          setColWidth(tbl,parseInt(ci),raw[tblId][ci]);
        });
      }
    }catch(ex){}

    // Add drag handle to EACH <th> in ALL header rows
    tbl.querySelectorAll('thead th').forEach(function(th){
      var old=th.querySelector('.col-resizer');
      if(old) old.remove();

      // Find the rightmost leaf-column index for this th
      var span=parseInt(th.getAttribute('colspan')||1);
      var startCol=-1;
      for(var i=0;i<map.length;i++){
        if(map[i].ths.indexOf(th)>=0){ startCol=i; break; }
      }
      if(startCol<0) return;
      var rightCol=startCol+span-1;

      var handle=document.createElement('div');
      handle.className='col-resizer';
      handle.title='↔ Drag to resize';
      handle.addEventListener('mousedown',function(e){
        e.preventDefault(); e.stopPropagation();
        _drag=true;
        _startX=e.clientX;
        var cols=tbl._rzCols;
        _startW=parseInt(cols&&cols[rightCol]?cols[rightCol].style.width:th.offsetWidth)||40;
        _colIdx=rightCol;
        _tbl=tbl;
        _activeHandle=handle;
        document.body.classList.add('col-resizing');
        handle.classList.add('dragging');
        document.addEventListener('mousemove',onMouseMove);
        document.addEventListener('mouseup',onMouseUp);
      });
      handle.addEventListener('dblclick',function(e){e.stopPropagation();});
      th.appendChild(handle);
    });
  };
})();

function updateStickyColCSSFromDrag(tbl){
  if(!tbl) return;
  var cg=tbl.querySelector('colgroup.rz-cg');
  if(!cg) return;
  var cols=cg.querySelectorAll('col');
  if(cols.length<3) return;
  var c1w=parseInt(cols[0].style.width)||36;
  var c2w=parseInt(cols[1].style.width)||70;
  var c3w=parseInt(cols[2].style.width)||165;
  var isRS=(tbl.id==='rs-main-tbl');
  if(isRS){
    var styleEl=g('colw-dyn-style-rs');
    if(!styleEl){ styleEl=document.createElement('style'); styleEl.id='colw-dyn-style-rs'; document.head.appendChild(styleEl); }
    styleEl.textContent=
      '#rs-main-tbl .c1{left:0!important;width:'+c1w+'px!important;min-width:'+c1w+'px!important}'+
      '#rs-main-tbl .c2{left:'+c1w+'px!important;width:'+c2w+'px!important;min-width:'+c2w+'px!important}'+
      '#rs-main-tbl .c3{left:'+(c1w+c2w)+'px!important;width:'+c3w+'px!important;min-width:'+c3w+'px!important}';
  } else {
    var styleEl=g('colw-dyn-style');
    if(!styleEl){ styleEl=document.createElement('style'); styleEl.id='colw-dyn-style'; document.head.appendChild(styleEl); }
    styleEl.textContent=
      '.c1{left:0;width:'+c1w+'px;min-width:'+c1w+'px}'+
      '.c2{left:'+c1w+'px;width:'+c2w+'px;min-width:'+c2w+'px}'+
      '.c3{left:'+(c1w+c2w)+'px;width:'+c3w+'px;min-width:'+c3w+'px}';
  }
}
function updateStickyColCSS(){
  var CW=COL_W.ds;
  var c1w=CW.sno, c2w=CW.roll;
  var c2left=c1w, c3left=c1w+c2w;
  var styleEl=g('colw-dyn-style');
  if(!styleEl){ styleEl=document.createElement('style'); styleEl.id='colw-dyn-style'; document.head.appendChild(styleEl); }
  styleEl.textContent=
    '.c1{left:0;width:'+c1w+'px;min-width:'+c1w+'px}'+
    '.c2{left:'+c2left+'px;width:'+c2w+'px;min-width:'+c2w+'px}'+
    '.c3{left:'+c3left+'px;width:'+COL_W.ds.name+'px;min-width:'+COL_W.ds.name+'px}';
}

