  var printArea = document.getElementById('admForm3PrintArea');
  /* Global sweep — all data-hi/data-en elements outside printArea */
  document.querySelectorAll('[data-hi][data-en]').forEach(function(el){
    if(printArea && printArea.contains(el)) return; // handled separately below
    var tag = el.tagName.toLowerCase();
    var val = en ? el.getAttribute('data-en') : el.getAttribute('data-hi');
    if(tag === 'input' || tag === 'textarea'){ el.placeholder = val; }
    else if(tag === 'option'){ el.text = val; }
    else { el.textContent = val; }
  });
  if(printArea){
    /* All elements with data-hi / data-en */
    printArea.querySelectorAll('[data-hi][data-en]').forEach(function(el){
      var tag = el.tagName.toLowerCase();
      var val = en ? el.getAttribute('data-en') : el.getAttribute('data-hi');
      if(tag === 'input' || tag === 'textarea'){
        el.placeholder = val;
      } else {
        el.textContent = val;
      }
    });

    /* Title div (contains span with data attrs) */
    /* already handled above via querySelectorAll */

    /* Photo label */
    var photoLbl = document.getElementById('af3_photoLabel');
    if(photoLbl) photoLbl.textContent = en ? 'Photo' : 'फ़ोटो';

    /* Form No span text node */
    var formNoSpan = printArea.querySelector('span:not([id])');
    if(formNoSpan && formNoSpan.childNodes.length > 0){
      formNoSpan.childNodes.forEach(function(n){
        if(n.nodeType === 3){
          if(en  && n.textContent.indexOf('फ़ॉर्म क्र.') > -1)
            n.textContent = 'Form No. : ';
          if(!en && n.textContent.indexOf('Form No.') > -1 && n.textContent.indexOf('फ़ॉर्म') === -1)
            n.textContent = 'फ़ॉर्म क्र. (Form No.) : ';
        }
      });
    }

    /* Divyang Yes/No inline text */
    var divRow = printArea.querySelector('[id="af3_divtype"]');
    if(divRow && divRow.parentNode){
      divRow.parentNode.childNodes.forEach(function(n){
        if(n.nodeType === 3){
          if(en  && n.textContent.indexOf('यदि हाँ') > -1)   n.textContent = ' If Yes, type : ';
          if(!en && n.textContent.indexOf('If Yes') > -1)     n.textContent = ' यदि हाँ, तो प्रकार : ';
        }
      });
      /* Also swap radio labels */
      divRow.parentNode.querySelectorAll('label').forEach(function(lbl){
        var inp = lbl.querySelector('input');
        if(!inp) return;
        if(inp.value === 'हाँ')  lbl.childNodes[lbl.childNodes.length-1].textContent = en ? ' Yes' : ' हाँ (Yes)';
        if(inp.value === 'नहीं') lbl.childNodes[lbl.childNodes.length-1].textContent = en ? ' No'  : ' नहीं (No)';
      });
    }

    /* Medium select placeholder sync */
    var medSel = document.getElementById('af3_med');
    if(medSel && medSel.options.length > 0) medSel.options[0].text = en ? '-- Medium --' : '-- Medium --';

    /* Class dropdown placeholder option */
    var clsSel = document.getElementById('af3_class');
    if(clsSel && clsSel.options.length > 0)
      clsSel.options[0].text = en ? '-- Select Class --' : '-- Select Class --';

    /* Guardian signature sub-labels */
    printArea.querySelectorAll('td > div[style*="color:#555"]').forEach(function(el){
      if(el.textContent.indexOf('Guardian') > -1 || el.textContent.indexOf('अभिभावक') > -1)
        el.textContent = en ? '(Guardian)' : '(Guardian Signature)';
      if(el.textContent.indexOf('Principal') > -1 || el.textContent.indexOf('प्रधानाध्यापक') > -1)
        el.textContent = en ? '(Principal)' : '(Principal Signature & Seal)';
    });

    /* Document checkboxes text nodes */
    var DOC_MAP = {
      'जन्म प्रमाण पत्र (Birth Certificate)': 'Birth Certificate',
      'जाति प्रमाण पत्र (Caste Certificate)': 'Caste Certificate',
      'स्थानांतरण प्रमाण पत्र (TC)': 'Transfer Certificate (TC)',
      'विगत कक्षा अंक सूची (Marksheet)': 'Previous Marksheet',
      'पासपोर्ट साइज़ फोटो × 2': 'Passport Size Photo × 2',
      'आधार कार्ड (Aadhaar Card)': 'Aadhaar Card',
      'निवास प्रमाण पत्र (Domicile Certificate)': 'Domicile Certificate',
      'आय प्रमाण पत्र (Income Certificate)': 'Income Certificate',
      'समग्र / अपार ID प्रिंट': 'Samagra / APAAR ID Print',
    };
    var DOC_MAP_EN_TO_HI = {};
    Object.keys(DOC_MAP).forEach(function(k){ DOC_MAP_EN_TO_HI[DOC_MAP[k]] = k; });

    printArea.querySelectorAll('td').forEach(function(td){
      if(td.querySelector('input[type="checkbox"]')) return;
      var txt = td.textContent.trim();
      if(!txt || td.querySelector('input')) return;
      /* Only plain text TDs (doc list cells) */
      if(td.children.length === 0){
        var enVal = DOC_MAP[txt];
        var hiVal = DOC_MAP_EN_TO_HI[txt];
        if(en && enVal)   td.textContent = enVal;
        if(!en && hiVal)  td.textContent = hiVal;
      }
    });
  }

  /* ── Staff Form language swap ── */
