    /* ── Date/signature labels (sf-declaration area) ── */
    var sfDeclDate = sfWrap.querySelector('.sf-declaration .decl-date-label');
    var sfDeclPlace = sfWrap.querySelector('.sf-declaration .decl-place-label');
    if(sfDeclDate) sfDeclDate.textContent = en ? 'Date:' : 'दिनांक / Date:';
    if(sfDeclPlace) sfDeclPlace.textContent = en ? 'Place:' : 'स्थान / Place:';

    var sfSigLabels = sfWrap.querySelectorAll('.sf-sig-label');
    var sfSigEN = ['Signature of Staff','Head Master / Principal'];
    var sfSigHI = ['कर्मचारी के हस्ताक्षर','प्रधानाध्यापक / प्राचार्य'];
    sfSigLabels.forEach(function(el, i){
      if(i < sfSigEN.length) el.textContent = en ? sfSigEN[i] : sfSigHI[i];
    });
