(function(){
  var _lockedName = '';
  var _nameUnlocked = false;

  // Expose unlock/lock for sdNameUnlock function
  window._rskNameUnlock  = function(){ _nameUnlocked = true; };
  window._rskNameLock    = function(){ _nameUnlocked = false; };
  window._rskSetName     = function(v){ _lockedName = v; };
  window._rskGetName     = function(){ return _lockedName; };

  Object.defineProperty(SCHOOL_INFO, 'name', {
    get: function(){ return _lockedName; },
    set: function(v){
      if(_nameUnlocked){
        _lockedName = v;
      } else {
        // Silent ignore — console se direct change nahi hoga
        console.warn('[RSK] School name is PIN-protected. Use School Details tab.');
      }
    },
    enumerable: true,
    configurable: false
  });
})();

