var CUSTOM_CLASS_SETTINGS = {}; // key: class name ('Nursery','1','6' etc)
function loadCustomPatternSettings(){
  try{var r=localStorage.getItem('rsk_class_mw_settings');if(r)CUSTOM_CLASS_SETTINGS=JSON.parse(r);}catch(e){}
}
function saveCustomPatternSettings(){
  try{localStorage.setItem('rsk_class_mw_settings',JSON.stringify(CUSTOM_CLASS_SETTINGS)); smartSave('rsk_class_mw_settings', CUSTOM_CLASS_SETTINGS);}catch(e){}
}
function getEffectiveMaxMap(cls){
  if(CUSTOM_CLASS_SETTINGS[cls]&&CUSTOM_CLASS_SETTINGS[cls].max) return CUSTOM_CLASS_SETTINGS[cls].max;
  return MAX_MAP[getPattern(cls)];
}
function getEffectiveWMap(cls){
  if(CUSTOM_CLASS_SETTINGS[cls]&&CUSTOM_CLASS_SETTINGS[cls].w) return CUSTOM_CLASS_SETTINGS[cls].w;
  return W_MAP[getPattern(cls)];
}

function g(id){return document.getElementById(id);}
function getPattern(c){ return (c==='Nursery'||c==='LKG'||c==='UKG'||c==='KG')?'NKG':(parseInt(c)>=9?'9_12':(parseInt(c)>=6?'6_7':'1_5')); }

