function get9thMax(info, phId, isTh){
  if(!info) return isTh?75:25;
  if(phId==='a'||phId==='sa'){
    return isTh ? info.aThMax : info.aPrMax;
  }
  return isTh ? info.thMax : info.prMax;
}

function get9thMin(info, isTh){
  if(!info) return isTh?25:8;
  return isTh ? info.thMin : info.prMin;
}

function get9Mark(ph, ri, si, isTh){
  if(!S.marks9) return '';
  var m=S.marks9[ph];
  if(!m) return '';
  var d=isTh?m.th:m.pr;
  var v=d[ri+'_'+si];
  return (v===undefined||v===null)?'':v;
}

function set9Mark(ph, ri, si, isTh, val){
  if(!S.marks9) S.marks9={q:{th:{},pr:{}},h:{th:{},pr:{}},a:{th:{},pr:{}},sa:{th:{},pr:{}}};
  if(!S.marks9[ph]) S.marks9[ph]={th:{},pr:{}};
  var d=isTh?S.marks9[ph].th:S.marks9[ph].pr;
  var k=ri+'_'+si;
  if(val===''||val===undefined||val===null) delete d[k];
  else d[k]=val;
}

function calc9SubTotal(ri, si, ph){
  // Returns {th, pr, total, passed} for one subject in one phase
  var info=getStu9SubInfo(ri,si);
  var th=get9Mark(ph,ri,si,true);
  var pr=get9Mark(ph,ri,si,false);
  var thMax=get9thMax(info,ph,true);
  var prMax=get9thMax(info,ph,false);
  var thMin=get9thMin(info,true);
  var prMin=get9thMin(info,false);
  var thN=parseFloat(th); var prN=parseFloat(pr);
  var thOk=(th==='ABS')?false:(isNaN(thN)?null:thN);
  var prOk=(pr==='ABS')?false:(isNaN(prN)?null:prN);
  var hasData=(th!==''&&th!==undefined)||(pr!==''&&pr!==undefined);
  if(!hasData) return {th:'',pr:'',total:'',passed:null,hasData:false};
  var total=(th==='ABS'||pr==='ABS')?'ABS':
    (th===''||pr==='')?'':
    (isNaN(thN)||isNaN(prN))?'':Math.round(thN)+Math.round(prN);
  var passed=null;
  if(th!==''&&pr!==''&&th!=='ABS'&&pr!=='ABS'&&!isNaN(thN)&&!isNaN(prN)){
    passed=(thN>=thMin)&&(prN>=prMin);
  }
  return {th:th,pr:pr,total:total,passed:passed,hasData:true,thMax:thMax,prMax:prMax};
}

function calc9FullResult(ri, am){
  am = am || 'final'; // default: final (max of Annual+SA)
  var codes=getStu9SubCodes(ri);
  var subs=[], grandTotal=0, maxPossible=0;
  for(var si=0;si<6;si++){
    var code=codes[si];
    var info=getSubInfo9(code)||null;
    var maxTH=info?info.aThMax:75, maxPR=info?info.aPrMax:25;
    var thMin=info?info.thMin:25, prMin=info?info.prMin:8;
    // Raw values
    function gm(ph,isTh){ return get9Mark(ph,ri,si,isTh); }
    var qThV=gm('q',true),qPrV=gm('q',false);
    var hThV=gm('h',true),hPrV=gm('h',false);
    var aThV=gm('a',true),aPrV=gm('a',false);
    var saThV=gm('sa',true),saPrV=gm('sa',false);
    function toN(v){ return v===''||v===undefined||v===null?NaN:(v==='ABS'?NaN:parseFloat(v)); }
    var qTH=toN(qThV)||0, qPR=toN(qPrV)||0;
    var hTH=toN(hThV)||0, hPR=toN(hPrV)||0;
    var aTH=toN(aThV)||0, aPR=toN(aPrV)||0;
    var hasQ=(qThV!==''&&qThV!==undefined)||(qPrV!==''&&qPrV!==undefined);
    var hasH=(hThV!==''&&hThV!==undefined)||(hPrV!==''&&hPrV!==undefined);
    var hasA=(aThV!==''&&aThV!==undefined)||(aPrV!==''&&aPrV!==undefined);
    var thAbsA=(aThV==='ABS');
    var prAbsA=(aPrV==='ABS');
    var isAbsA=thAbsA;
    var qTotal=hasQ?qTH+qPR:0;
    var hTotal=hasH?hTH+hPR:0;
    var codeNum=parseInt(code)||0;
    var isVoc9=codeNum>=800&&codeNum<=899; // 800-series vocational: no weightage
    var q5=(!isVoc9&&hasQ)?Math.round(qTotal*5)/100:0;
    var h5=(!isVoc9&&hasH)?Math.round(hTotal*5)/100:0;
    var aPR_eff=prAbsA?0:aPR;
    var annPassed=hasA&&!isAbsA&&aTH>=thMin&&aPR_eff>=prMin;
    var hasSA=(saThV!==''&&saThV!==undefined)||(saPrV!==''&&saPrV!==undefined);

    // ── Exam Mode logic ──
    var finalTH, finalPR_raw, saUsed=false;
    if(am==='quarterly'){
      // Only Quarterly marks
      finalTH=qTH; finalPR_raw=qPR; saUsed=false;
    } else if(am==='half-yearly'){
      // Only Half-Yearly marks
      finalTH=hTH; finalPR_raw=hPR; saUsed=false;
    } else if(am==='annual'){
      // Only Annual (no SA)
      finalTH=aTH;
      finalPR_raw=q5+h5+aPR_eff;
      saUsed=false;
    } else if(am==='second'){
      // SA मिले तो SA use करो, नहीं मिला तो Annual
      finalTH=aTH; finalPR_raw=q5+h5+aPR_eff;
      if(hasSA){
        if(saThV!==''&&saThV!=='ABS') { finalTH=toN(saThV)||0; saUsed=true; }
        if(saPrV!==''&&saPrV!=='ABS') { finalPR_raw=q5+h5+(toN(saPrV)||0); saUsed=true; }
      }
    } else {
      // final (default): SA overrides only if Annual failed/absent
      finalTH=aTH; finalPR_raw=q5+h5+aPR_eff;
      if(hasSA&&!annPassed){
        if(saThV!==''&&saThV!=='ABS') finalTH=toN(saThV)||0;
        if(saPrV!==''&&saPrV!=='ABS') finalPR_raw=q5+h5+(toN(saPrV)||0);
        saUsed=true;
      }
    }

    var finalPR=Math.round(finalPR_raw);
    // ── Mode-aware "hasData" — which phase's data presence to check ──
    var _isQmode=(am==='quarterly'), _isHmode=(am==='half-yearly'), _isSecond=(am==='second');
    var hasData=_isQmode?hasQ:(_isHmode?hasH:(_isSecond?(hasA||hasSA):hasA));
    var thAbsEff=_isQmode?(qThV==='ABS'):(_isHmode?(hThV==='ABS'):(_isSecond?(hasSA?(saThV==='ABS'):thAbsA):thAbsA));
    var isAbsEff=thAbsEff;
    var finalTotal=hasData&&!isAbsEff?finalTH+finalPR:0;
    var passed=hasData&&!isAbsEff&&finalTH>=thMin&&finalPR>=prMin;
    var subMaxTot=maxTH+maxPR;
    var subPct=subMaxTot&&hasData&&!isAbsEff?Math.round(finalTotal/subMaxTot*1000)/10:0;
    var thFail9=hasData&&!isAbsEff&&finalTH<thMin;
    var prFail9=hasData&&!isAbsEff&&finalPR<prMin;
    var subGrade='';
    if(!hasData){ subGrade=''; }
    else if(isAbsEff){ subGrade='ABS'; }
    else{ subGrade=getSubjectGrade(subPct, thFail9, prFail9, false, finalTotal); }
    if(hasData&&!isAbsEff){ grandTotal+=finalTotal; maxPossible+=subMaxTot; }
    subs.push({si:si,code:code||'',info:info,isVoc9:isVoc9,
      qThV:qThV,qPrV:qPrV,qTotal:hasQ?qTotal:null,q5:hasQ?q5:null,
      hThV:hThV,hPrV:hPrV,hTotal:hasH?hTotal:null,h5:hasH?h5:null,
      aThV:aThV,aPrV:aPrV,aTotal:hasA&&!isAbsA?aTH+aPR_eff:null,
      saThV:saThV,saPrV:saPrV,saUsed:saUsed,
      finalTH:hasData&&!isAbsEff?finalTH:'',finalPR:hasData&&!isAbsEff?finalPR:'',finalTotal:hasData&&!isAbsEff?finalTotal:'',
      passed:passed,hasA:hasData,isAbsA:isAbsEff,thAbsA:thAbsEff,prAbsA:(_isQmode?(qPrV==='ABS'):(_isHmode?(hPrV==='ABS'):prAbsA)),hasQ:hasQ,hasH:hasH,
      subPct:subPct,subGrade:subGrade,thMin:thMin,prMin:prMin});
  }
  var pct=maxPossible?Math.round(grandTotal/maxPossible*10000)/100:0;
  var hasSomeData=subs.some(function(s){return s.hasA;});
  var allAbs=hasSomeData&&subs.filter(function(s){return s.hasA;}).every(function(s){return s.thAbsA;});

  // ── Grace Marks Rule (max 6 marks total) — only for annual/final/second modes ──
  var _graceMode=(am==='annual'||am==='second'||am==='final');
  var graceUsed=0;
  subs.forEach(function(s){
    if(!_graceMode||!s.hasA||s.isAbsA||s.passed) return;
    var thShort=s.finalTH<s.thMin?(s.thMin-s.finalTH):0;
    var prShort=s.finalPR<s.prMin?(s.prMin-s.finalPR):0;
    graceUsed+=thShort+prShort;
  });
  if(_graceMode&&graceUsed>0&&graceUsed<=6){
    subs.forEach(function(s){
      if(!s.hasA||s.isAbsA||s.passed) return;
      var thShort=s.finalTH<s.thMin?(s.thMin-s.finalTH):0;
      var prShort=s.finalPR<s.prMin?(s.prMin-s.finalPR):0;
      if(thShort>0){ s.graceAppliedTH=thShort; }
      if(prShort>0){ s.graceAppliedPR=prShort; }
      s.passed=true;
      s.graceApplied=(thShort+prShort);
      var subMaxTot=(s.info?s.info.aThMax:75)+(s.info?s.info.aPrMax:25);
      var effTotal=s.finalTotal+(s.graceApplied||0);
      var subPct=subMaxTot?Math.round(effTotal/subMaxTot*1000)/10:0;
      s.subGrade=getSubjectGrade(subPct,false,false);
    });
  }

  var failedSubs=subs.filter(function(s){return s.hasA&&(!s.passed||s.isAbsA);});
  var result='';
  if(!hasSomeData) result='';
  else if(allAbs) result='ABS';
  else if(failedSubs.length>0) result='FAIL';
  else result='PASS';
  var hasE1orE2=subs.some(function(s){return s.subGrade==='E1'||s.subGrade==='E2';});
  var grade='';
  if(!hasSomeData||allAbs){ grade=''; }
  else if(hasE1orE2){ grade=pct<20?'E2':'E1'; }
  else{ grade=pct>=85?'A+':pct>=75?'A':pct>=60?'B':pct>=45?'C':pct>=33?'D':pct>=20?'E1':'E2'; }
  var division=result==='PASS'?(pct>=60?'I':pct>=45?'II':pct>=33?'III':''):'';
  return{subs:subs,grandTotal:grandTotal,maxPossible:maxPossible,pct:pct,
    result:result,grade:grade,division:division,failedSubs:failedSubs,
    hasSomeData:hasSomeData,allAbs:allAbs,envGrade:(S.stu[ri]||{}).envGrade||''};
}
function calc9StudentResult(ri){
  var r=calc9FullResult(ri);
  r.subs.forEach(function(s){ s.total=s.finalTotal||0; });
  return r;
}

