/* ── 9th Annual Result — Exam Mode ── */
window.rs9AttemptMode = window.rs9AttemptMode || 'final'; // 'quarterly' | 'half-yearly' | 'annual' | 'second' | 'final'
window.rs11ExamMode = window.rs11ExamMode || 'final'; // same 5 modes for 11th Annual Result

/* ── Row click highlight for RS9 and DS9 tables ── */
function initRowHighlight(tblId){
  var tbl=document.getElementById(tblId); if(!tbl) return;
  var rows=tbl.querySelectorAll('tbody tr');
  rows.forEach(function(tr){
    if(tr._rowHighlightInit) return;
    tr._rowHighlightInit=true;
    tr.addEventListener('click',function(e){
      // ignore clicks on input/select/button
      if(e.target.tagName==='INPUT'||e.target.tagName==='SELECT'||e.target.tagName==='BUTTON') return;
      var wasSelected=tr.classList.contains('row-selected');
      // deselect all rows in this table
      rows.forEach(function(r){ r.classList.remove('row-selected'); });
      if(!wasSelected) tr.classList.add('row-selected');
    });
  });
}
var _ALL_ROW_HIGHLIGHT_TBLS=[
  'rs9-tbl','ds9-tbl',
  'rs10-tbl','ds10-tbl',
  'rs11-tbl','ds11-tbl',
  'rs12-tbl','ds12-tbl',
  'rs-main-tbl','ds-main-tbl',
  'cc-main-tbl'
];
function initAllRowHighlights(){
  _ALL_ROW_HIGHLIGHT_TBLS.forEach(function(id){ initRowHighlight(id); });
}
// Re-init after any render (use MutationObserver)
(function(){
  var _rh_obs=new MutationObserver(function(){
    _ALL_ROW_HIGHLIGHT_TBLS.forEach(function(id){ initRowHighlight(id); });
  });
  document.addEventListener('DOMContentLoaded',function(){
    var rs=document.getElementById('sheet-wrap-rs');
    var ds=document.getElementById('sheet-wrap-ds');
    var cc=document.getElementById('sheet-wrap-cc');
    if(rs) _rh_obs.observe(rs,{childList:true,subtree:true});
    if(ds) _rh_obs.observe(ds,{childList:true,subtree:true});
    if(cc) _rh_obs.observe(cc,{childList:true,subtree:true});
    initAllRowHighlights();
  });
})();


