  h+=TH((_en?'SECTION':'अनुभाग'),INFO_RS,1,_IB,'width:44px;',_IT);
  /* Subject codes placeholder */
  h+=TH((_en?'Subject Codes':'विषय कोड'),1,6,'#374151','font-size:11px;');
  /* Marks section header — dynamic based on selected phase */
  var _marksHdr = _ph==='qr'?'Quarterly Exam\nत्रैमासिक परीक्षा के प्राप्तांक':_ph==='hy'?'Half-Yearly\nHALF-YEARLY परीक्षा के प्राप्तांक':_ph==='pb'?'Pre-Board\nPRE-BOARD परीक्षा के प्राप्तांक':_ph==='h'?'Term-2\nवार्षिक परीक्षा TERM-2 के प्राप्तांक':'Term-1\nवार्षिक परीक्षा TERM-1 के प्राप्तांक';
  h+=TH(_marksHdr,1,15,_LB,'font-size:10px;',_LBtc);
