  var subLbls=['1st Language\n/Vocational\nSub.','2nd Language\n/Vocational\nSub.','3rd Language\n/Vocational\nSub.','SUB. -1\nMaths\n/Music\n/Painting\n/Computer','SUB. -2\nScience\n/Music\n/Painting\n/Computer','Social\nScience'];
  var sgLbls=['1st\nLanguage\nSub.','2nd\nLanguage\n/Voc\nSub.','3rd\nLanguage\n/Voc.\nSub.','Maths','Science','So.\nScience','Environmental\nEducation\nand Disaster'];
  h+='<tr>';
