  h+=TH('3rd Language\nCode\n/Voc. Code',6,1,'#e0e7ef','width:50px;font-size:9px;','#374151');
  h+=TH('Code of\nSUB-1',6,1,'#e0e7ef','width:46px;font-size:9px;','#374151');
  h+=TH('Code of\nSUB-2',6,1,'#e0e7ef','width:46px;font-size:9px;','#374151');
  h+=TH('Code of\nSUB-3',6,1,'#e0e7ef','width:46px;font-size:9px;','#374151');
  /* TERM-1 subject labels — image-matched colors */
