  var _subColorsTc=[_LBtc,_LBtc,_LBtc,_LBtc,_LBtc,_LBtc];
  h+='<tr>';
  for(var si2=0;si2<6;si2++){
    h+=TH('max.',1,1,_subColors[si2],'font-size:9px;',_subColorsTc[si2]);
    h+=TH('max.',1,1,_subColorsPR[si2],'font-size:9px;',_subColorsTc[si2]);
  }
