    h9+='<button class="btn no-print" onclick="attachResizers&&attachResizers(g(\'rs9q-tbl\'));this.textContent=\'✅\';setTimeout(function(){this.textContent=\'↔ Resize\';}.bind(this),1200);" style="background:#f59e0b;color:#111;font-weight:800">↔ Resize</button>';
