    var sgLbls9=['1st\nLanguage\nSub.','2nd\nLanguage\n/Voc\nSub.','3rd\nLanguage\n/Voc.\nSub.','Maths','Science','So.\nScience','Environmental\nEducation\nand Disaster'];
