    for(var si2=0;si2<6;si2++){
      h9+=TH9('max.',1,1,_LB9,'font-size:9px;',_LBtc9);
      h9+=TH9('max.',1,1,_LB9,'font-size:9px;',_LBtc9);
    }
    h9+='</tr>';

    /* ROW 5 — max values */
    h9+='<tr>';
    for(var si2=0;si2<6;si2++){
      var info9hdr=getStu9SubInfo&&getStu9SubInfo(0,si2);
      var _thMx9=info9hdr?(info9hdr.thMax||75):75;
      var _prMx9=info9hdr?(info9hdr.prMax||25):25;
      h9+=TH9(_thMx9,1,1,_LB9,'font-size:9px;',_LBtc9);
      h9+=TH9(_prMx9,1,1,_LB9,'font-size:9px;',_LBtc9);
    }
    h9+='</tr>';

    /* ROW 6 — min. labels */
