        var _prFail9=(prV9!==''&&prV9!=='ABS'&&prV9!==undefined&&prN9<prMin9);
        /* TH ABS → subject grade = ABS; PR only ABS → grade on TH marks */
        var subGr9=isThAbs9?'ABS':(isPrAbs9?((thV9!==''&&thV9!==undefined)?qrGrade9s(thN9,thMax9,_thFail9,true):''):((thV9!==''&&thV9!==undefined)?qrGrade9s(tot9,maxTot9,_thFail9,_prFail9):'')); 
        subD9.push({thV:thV9,prV:prV9,thN:thN9,prN:prN9,tot:tot9,maxTot:maxTot9,thMin:thMin9,prMin:prMin9,abs:isAbs9,subGr:subGr9});
