      var _allThAbs9q=subD9.every(function(s){ return s.thV==='ABS'; });
      var _allPrAbs9q=subD9.every(function(s){ return s.prVeff==='ABS'; });
      var _allBothAbs9q=subD9.every(function(s){ return s.abs; });
      var oGrade9;
      if(_allBothAbs9q||_allThAbs9q){
        oGrade9='ABS';
      } else if(_allPrAbs9q){
        oGrade9=pct9<20?'E2':'E1';
      } else {
        oGrade9=_hasE1E2_9q?(pct9<20?'E2':'E1'):qrGrade9s(grandTot9,grandMax9||1,false,false);
      }

      /* Result / Division */
      var result9q='PASS';
