        for(var ci=0;ci<6;ci++) dataRow.push(codes9c[ci]||'',subD9c[ci].thV===undefined?'':subD9c[ci].thV,subD9c[ci].prV===undefined?'':subD9c[ci].prV);
        dataRow.push(pct9c.toFixed(2)+'%',oGrade9c);
