          var thN9c=(thV9c==='ABS'||thV9c===''||thV9c===undefined)?0:(parseFloat(thV9c)||0);
          var prN9c=(prV9c==='ABS'||prV9c===''||prV9c===undefined)?0:(parseFloat(prV9c)||0);
