  h+=TH(_L('Half-Yearly Exam','अर्द्धवार्षिक परीक्षा'),1,13,CL.h,'border-left:3px solid '+CL.h+';');
  h+=TH(_L('Annual Exam','वार्षिक परीक्षा'),1,13,CL.a,'border-left:3px solid '+CL.a+';');
  /* 5% headers */
