  h+=TH(_L('Half-Yearly Exam\n5% Weightage','अर्द्धवार्षिक परीक्षा\nका 5% अधिभार'),1,6,CL.h5,'border-left:3px solid '+CL.h5+';');
/* Final header — colspan extended to include 5 summary columns */
  h+=TH(_L('Annual Evaluation\nWeightage Total\nTHEORY=Annual TH\nPR=Q5%+H5%+Annual PR','वार्षिक मूल्यांकन अधिभार का योग\nTHEORY=वार्षिक TH\nPR=Q5%+H5%+Annual PR'),1,18,CL.fin,'border-left:3px solid '+CL.fin+';');
