  var sgLbls=['Lang-1\n/Voc. Sub.','Lang-2\n/Voc. Sub.','Lang-3\n/Voc. Sub.','Maths/Music\n/Painting\n/Computer','Science/Music\n/Painting\n/Computer','Social\nScience','Environmental\nEducation and\nDisaster Mgmt'];
