       +'<input class="mi" value="'+codeVal+'" data-ri="'+ri+'" data-fi="subcode_'+ci+'" onchange="on11SubCode(this)" onblur="on11SubCode(this);saveData();" style="width:100%;text-align:center;font-size:11px;font-weight:800;background:#fef9c3;border:none;padding:0" maxlength="4">'
