           +'<input class="mi" type="text" inputmode="numeric" maxlength="3" value="'+prVal+'" '
           +'id="dm-'+ph.id+'-'+ri+'-'+si+'-pr" data-ri="'+ri+'" data-si="'+si+'" data-ph="'+ph.id+'" data-sub="pr" data-max="'+_getDS11Sch(ri,si).pr+'" '
