       +'<button onclick="removeStudent('+ri+')" style="background:#dc2626;color:#fff;border:none;border-radius:5px;cursor:pointer;font-size:9px;font-weight:700;padding:2px 5px;font-family:inherit;line-height:1.3;width:100%">🗑️ '+(isEnglish()?'Remove':'हटाएं')+'</button>'
