    function grColor11QY(g2){return{'A+':'#14532d','A':'#166534','B':'#1d4ed8','C':'#78350f','D':'#92400e','E1':'#b91c1c','E2':'#7f1d1d','ABS':'#7f1d1d'}[g2]||'#374151';}

