        var subGr=isThAbs11QY?'ABS':(isPrAbs11QY?((thV!==''&&thV!==undefined)?(thFail?(thN>19?'E1':'E2'):qyGrade11(_sch.th>0?thN/_sch.th*100:0)):''):((thV!==''&&thV!==undefined)?(thFail||prFail?(tot>19?'E1':'E2'):qyGrade11(subPct)):'')); 
        subD11QY.push({thV:thV,prV:prV,thN:thN,prN:prN,tot:tot,maxTot:maxTot,thFail:thFail,prFail:prFail,abs:isAbs,subGr:subGr,sch:_sch});
