      var _main5E1E2_11QY=subD11QY.slice(0,nMain-1).some(function(s){return s.subGr==='E1'||s.subGr==='E2';});
      var _allThAbs11QY=subD11QY.every(function(s){ return s.thV==='ABS'; });
