  h+='<th rowspan="3" style="'+BD+'background:#dbeafe;color:#1e3a5f;width:80px;font-size:10px;padding:2px;position:sticky;top:'+colHdrTop+'px;z-index:200">'+(_en?'APAAR<br>ID':'APAAR<br>ID')+'</th>';
