  h+='<th rowspan="3" style="'+BD+'background:#7c3aed;color:#fff;font-size:10px;font-weight:900;padding:3px;text-align:center;position:sticky;top:'+colHdrTop+'px;z-index:200">'+(_en?'Grade':'समेकित<br>ग्रेड')+'</th>';
  h+='<th rowspan="3" style="'+BD+'background:#7c3aed;color:#fff;font-size:10px;font-weight:900;padding:3px;text-align:center;position:sticky;top:'+colHdrTop+'px;z-index:200">'+(_en?'Rank':'रैंक')+'</th>';
  h+='</tr>';

