    var rH='<tr style="'+rowHide+'background:'+rowBg+';text-align:center;font-size:11px'+((!rowHide)?';cursor:pointer':'')+'" id="rsr-'+ri+'"'+((!rowHide)?' title="Double-click → Annual Report Card" ondblclick="openRCFromRS('+(ri+1)+')"':'')+'>'; 
    rH+='<td class="cs c1" style="'+BD+'font-weight:700;color:#1a3a6b;background:#eef2ff">'+(st.anukra?_rsSnoCount:'')+'</td>';
