    rH+='<td class="cs c3" style="'+BD+'text-align:left;padding-left:4px;font-weight:600;color:#1e3a5f;background:#eef2ff">'+(st.name||'')+'</td>';
    rH+='<td style="'+BD+'text-align:left;padding-left:4px">'+(st.father||'')+'</td>';
    rH+='<td style="'+BD+'text-align:left;padding-left:4px">'+(st.mother||'')+'</td>';
