        val=(val===undefined||val===null)?'':val;
        var isEx=(si>=nMain);
        var adh=0;
        if(val&&!isEx){
          if(ph.id==='proj') adh=Math.round(parseFloat(val)/(ph.max||20)*ph.wPct*10)/10;
          else adh=adhVal(ph.id,val,ph.max,ph.wPct);
          adhSum+=adh;
        }
        var cellBg=isEx?'#f0f4ff':(val==='ABS'?'#bbf7d0':rowBg);
        var cellC=isEx?'#6d28d9':(val==='ABS'?'#166534':'');
        var over=(!isEx&&val&&val!=='ABS'&&parseFloat(val)>ph.max)?'color:#dc2626;font-weight:900;':'';
        rH+='<td style="'+BD+'background:'+cellBg+';'+over+(cellC?'color:'+cellC+';':'')+'">'+(val||'')+'</td>';
