/* ═══════════════════════════════════════
   DS INPUT HANDLERS
═══════════════════════════════════════ */
function onMarkInput(inp){
  var raw=inp.value.toUpperCase();
  if(raw===''){inp.classList.remove('over','abs','abs-part');inp.style.outline='';return;}
  if(raw[0]==='A'){
    inp.classList.remove('over');
    if(raw==='ABS'){inp.value='ABS';inp.classList.add('abs');inp.classList.remove('abs-part');inp.style.outline='';}
    else{var allowed='ABS'.slice(0,raw.length);if(raw!==allowed){inp.value=allowed;raw=allowed;}inp.classList.add('abs-part');inp.classList.remove('abs');}
  } else {
    inp.classList.remove('abs','abs-part');
    var cleaned=raw.replace(/[^0-9]/g,'');
    if(cleaned!==raw) inp.value=cleaned;
    // Enforce max marks during typing
    var max=parseFloat(inp.dataset.max);
    if(!isNaN(max)&&cleaned!==''&&parseFloat(cleaned)>max){
      inp.value=String(max);
      inp.style.outline='2px solid #f59e0b';
      setTimeout(function(){inp.style.outline='';},600);
    } else {
      inp.style.outline='';
    }
  }
}

function onMark(inp){
  var ri=parseInt(inp.dataset.ri), si=parseInt(inp.dataset.si);
  var ph=inp.dataset.ph, max=parseFloat(inp.dataset.max);
  var v=inp.value.trim().toUpperCase();
  inp.classList.remove('over','abs','abs-part');
  var k=ri+'_'+si;
  var prev=S.marks[ph][k]; var hadVal=(prev!==undefined&&prev!=='');
  delete S.marks[ph][k];
  if(v===''){if(hadVal) _markDel(ph,k,true);}
  else if(v==='ABS'){inp.value='ABS';inp.classList.add('abs');S.marks[ph][k]='ABS';if(!hadVal)_markSet(ph,k,false);}
  else if(v==='A'||v==='AB'){inp.value='';inp.classList.remove('abs-part');if(hadVal)_markDel(ph,k,true);}
  else{var num=parseFloat(v);if(isNaN(num)||num<0){inp.value='';return;}if(num>max){inp.value=max;num=max;}inp.classList.toggle('over',false);S.marks[ph][k]=num;if(!hadVal)_markSet(ph,k,false);}
  var el=g('pt-'+ph+'-'+ri); if(el) el.textContent=phTotal(ph,ri);
  markDirty('rs'); markDirty('ml'); markDirty('sr');
  updateCounts();
  autoSave();
}

function onMarkBlur(inp){
  var v=inp.value.trim().toUpperCase();
  if(v==='A'||v==='AB'){
    inp.value='';inp.classList.remove('abs','abs-part','over');
    var ri=parseInt(inp.dataset.ri),si=parseInt(inp.dataset.si),ph=inp.dataset.ph;
    var k=ri+'_'+si; var hadVal=S.marks[ph][k]!==undefined&&S.marks[ph][k]!=='';
    delete S.marks[ph][k];
    if(hadVal) _markDel(ph,k,true);
    var el=g('pt-'+ph+'-'+ri); if(el) el.textContent=phTotal(ph,ri);
    markDirty('rs'); markDirty('ml'); markDirty('sr');
    updateCounts();
  }
}

function onMark11(inp){
  var ri=parseInt(inp.dataset.ri), si=parseInt(inp.dataset.si);
  var ph=inp.dataset.ph, sub=inp.dataset.sub||'th';
  var max=parseFloat(inp.dataset.max);
  var v=inp.value.trim().toUpperCase();
  if(!S.marks9) S.marks9={q:{th:{},pr:{}},h:{th:{},pr:{}},a:{th:{},pr:{}},sa:{th:{},pr:{}}};
  if(!S.marks9[ph]) S.marks9[ph]={th:{},pr:{}};
  if(!S.marks9[ph].th) S.marks9[ph].th={};
  if(!S.marks9[ph].pr) S.marks9[ph].pr={};
  var k=ri+'_'+si;
  inp.classList.remove('over','abs');
  delete S.marks9[ph][sub][k];
  if(v===''){}
  else if(v==='ABS'){inp.value='ABS';inp.classList.add('abs');S.marks9[ph][sub][k]='ABS';}
  else if(v==='A'||v==='AB'){inp.value='';}
  else{
    var num=parseFloat(v);
    if(isNaN(num)||num<0){inp.value='';return;}
    if(num>max){inp.value=max;num=max;}
    S.marks9[ph][sub][k]=num;
  }
  autoSave(); markDirty('rs'); markDirty('ml'); markDirty('sr'); updateCounts();
}
function onMarkBlur11(inp){
  var v=inp.value.trim().toUpperCase();
  if(v==='A'||v==='AB'){
    inp.value=''; inp.classList.remove('abs','over');
    var ri=parseInt(inp.dataset.ri),si=parseInt(inp.dataset.si);
    var ph=inp.dataset.ph, sub=inp.dataset.sub||'th';
    if(!S.marks9) return;
    if(S.marks9[ph]&&S.marks9[ph][sub]) delete S.marks9[ph][sub][ri+'_'+si];
    autoSave(); markDirty('rs'); markDirty('ml'); markDirty('sr'); updateCounts();
  }
}

function onStu(inp){
  var ri=parseInt(inp.dataset.ri), fi=inp.dataset.fi;
  if(!S.stu[ri]) S.stu[ri]={};
  var v=inp.value;
  // VALIDATION
  if(fi==='gender'){
    var vu=v.toUpperCase().trim();
    if(vu!==''&&vu!=='M'&&vu!=='F'){
      inp.style.background='#fee2e2'; inp.style.color='#dc2626';
      inp.title='Only M or F allowed'; return;
    }
    inp.style.background=''; inp.style.color=''; inp.title='';
    v=vu; inp.value=vu;
  }
  if(fi==='cat'){
    var vc=v.toUpperCase().trim();
    if(vc!==''&&['SC','ST','OBC','UR'].indexOf(vc)<0){
      inp.style.background='#fee2e2'; inp.style.color='#dc2626';
      inp.title='Only SC, ST, OBC, UR allowed'; return;
    }
    inp.style.background=''; inp.style.color=''; inp.title='';
    v=vc; inp.value=vc;
  }
  if(fi==='samagra'||fi==='aadhar'||fi==='apaar'){
    var vn=v.replace(/[^0-9]/g,'');
    if(v!==vn){ inp.style.background='#fee2e2'; inp.style.color='#dc2626';
      inp.title='Only numeric values allowed'; inp.value=vn; v=vn; }
    else { inp.style.background=''; inp.style.color=''; inp.title=''; }
  }
  if(fi==='medium'){
    var vm=v.toUpperCase().trim();
    var MEDS=['HINDI','ENGLISH','SANSKRIT','URDU'];
    if(vm!==''&&MEDS.indexOf(vm)<0){
      inp.style.background='#fee2e2'; inp.style.color='#dc2626';
      inp.title='Only HINDI, ENGLISH, SANSKRIT, URDU allowed'; return;
    }
    inp.style.background=''; inp.style.color=''; inp.title='';
    v=vm; inp.value=vm;
  }
  S.stu[ri][fi]=v;
  // att_p / att_t ko S.att mein bhi save karo (renderDS9 wahan se padhta hai)
  if(fi==='att_p'||fi==='att_t'){
    if(!S.att) S.att={};
    S.att[ri+'_'+(fi==='att_p'?'p':'t')]=v?parseFloat(v)||v:v;
  }
  if(fi==='anukra') refreshSno();
  if(fi==='anukra'||fi==='name') refreshDsRowVisibility(ri);
  markDirty('rs'); markDirty('ml'); markDirty('cc'); markDirty('sr');
  autoSave();
}
function refreshSno(){
  var n2=S&&S.stu?S.stu.length:0;
  var cnt=0;
  for(var i=0;i<n2;i++){
    var st2=S.stu[i]||{};
    if(st2.anukra) cnt++;
    // 9th/6-8th class
    var el=document.getElementById('sno-'+i);
    if(el){ el.textContent=st2.anukra?cnt:''; }
    // 10th class
    var el10=document.getElementById('sno10-'+i);
    if(el10){ el10.textContent=st2.anukra?cnt:''; }
    // 12th class
    var el12=document.getElementById('sno12-'+i);
    if(el12){ el12.textContent=st2.anukra?cnt:''; }
  }
}
function refreshDsRowVisibility(ri){
  var st=S.stu[ri]||{};
  var hasStudent=!!(st.anukra||st.name);
  // Marks inputs
  var markEls=document.querySelectorAll('[id^="dm-"][data-ri="'+ri+'"], [id^="dpj-"][data-ri="'+ri+'"]');
  markEls.forEach(function(el){ el.style.opacity=hasStudent?'':'0'; el.style.pointerEvents=hasStudent?'':'none'; });
  // CCA inputs + grade divs
  var ccaEls=document.querySelectorAll('[id^="dc-'+ri+'-"], [id^="cg-'+ri+'-"]');
  ccaEls.forEach(function(el){ el.style.opacity=hasStudent?'':'0'; el.style.pointerEvents=hasStudent?'':'none'; });
  // PSG inputs + grade divs
  var psgEls=document.querySelectorAll('[id^="dp-'+ri+'-"], [id^="pg-'+ri+'-"]');
  psgEls.forEach(function(el){ el.style.opacity=hasStudent?'':'0'; el.style.pointerEvents=hasStudent?'':'none'; });
  // Attendance
  var attT=document.getElementById('dat-'+ri+'-t');
  var attP=document.getElementById('dat-'+ri+'-p');
  var attPct=document.getElementById('dap-'+ri);
  if(attT){ attT.style.opacity=hasStudent?'':'0'; attT.style.pointerEvents=hasStudent?'':'none'; }
  if(attP){ attP.style.opacity=hasStudent?'':'0'; attP.style.pointerEvents=hasStudent?'':'none'; }
  if(attPct){ attPct.textContent=hasStudent?(attPct.textContent||''):''; }
  // Buttons cell
  var tr=document.getElementById('dtr-'+ri);
  if(tr){
    var lastTd=tr.querySelector('td:last-child');
    if(lastTd) lastTd.style.visibility=hasStudent?'':'hidden';
  }
}

