function _hyrcUpdateNav(){
  var inp=g('hyrc-sn-inp'); if(inp) inp.value=_hyrcCurSN;
  var btnP=g('hyrc-btn-prev'), btnN=g('hyrc-btn-next');
  if(btnP) btnP.disabled=(_hyrcCurSN<=1);
  if(btnN) btnN.disabled=(_hyrcCurSN>=S.n);
  var chip=g('hyrc-stu-chip');
  if(chip){
    var st=S.stu[_hyrcCurSN-1]||{};
    chip.textContent=(st.name||st.anukra||'—')+' (S.N. '+_hyrcCurSN+')';
  }
  // Sync dropdown selection
  var sel=g('hyrc-stu-select');
  if(sel) sel.value=_hyrcCurSN;
}

function hyrcGoToBySelect(sel){
  var sn=parseInt(sel.value);
  if(sn&&sn>=1&&sn<=S.n) hyrcGoTo(sn);
  sel.value=''; // Reset so user can re-select same student
}

function hyrcNav(d){
  hyrcGoTo(_hyrcCurSN+d);
}

function hyrcGoTo(sn){
  if(isNaN(sn)||sn<1) sn=1;
  if(sn>S.n) sn=S.n;
  _hyrcCurSN=sn;
  var area=g('hyrc-card-area');
  if(area) area.innerHTML=buildHYRCCard(_hyrcCurSN-1);
  _hyrcUpdateNav();
  var _hySt=S.stu[_hyrcCurSN-1]||{};
  var _hyMob=(_hySt.mobile||'').trim().replace(/\D/g,'');
  var _hyBtn=document.getElementById('sendto-wa-btn-hy');
  if(_hyBtn) _hyBtn.title=_hyMob?('📲 '+_hySt.name+' को '+_hyMob+' पर भेजें'):'⚠️ मोबाइल नम्बर नहीं — click पर पूछा जाएगा';
  setTimeout(function(){
    try{
      var wrap=g('hyrc-page');
      if(wrap) wrap.querySelectorAll('svg.rc-barcode').forEach(function(svg){
        var val=svg.getAttribute('data-val')||'0';
        JsBarcode(svg,val,{width:1.2,height:36,margin:2});
      });
    }catch(e){}
  },150);
}

function hyrcSNKey(e){
  if(e.key==='Enter') hyrcGoTo(parseInt(g('hyrc-sn-inp').value)||1);
}

function hyrcPrintAll(){
  window.print();
}

function hyrcPreview(){
  var ri=_hyrcCurSN-1;
  var st=S.stu[ri]||{};
  if(!st.name&&!st.anukra){alert('इस क्रमांक पर कोई छात्र नहीं है।');return;}
  var cardHTML=buildHYRCCard(ri);
  var styleContent='';
  var sheets=document.styleSheets;
  for(var i=0;i<sheets.length;i++){
    try{var rules=sheets[i].cssRules||sheets[i].rules||[];for(var j=0;j<rules.length;j++) styleContent+=rules[j].cssText+'\n';}catch(e){}
  }
  var pw=window.open('','_blank','width=1000,height=750,scrollbars=yes,resizable=yes');
  if(!pw){alert('Popup blocked!');return;}
  pw.document.write('<!DOCTYPE html><html><head><meta charset="UTF-8"><title>HY RC Preview</title>');
  pw.document.write('<style>'+styleContent+'</style>');
  pw.document.write('<style>body{background:#d0d0d0;margin:0;padding:0;font-family:Arial,sans-serif;}');
  pw.document.write('.preview-toolbar{position:fixed;top:0;left:0;right:0;height:52px;background:linear-gradient(135deg,#7b0000,#b91c1c);display:flex;align-items:center;gap:10px;padding:0 20px;z-index:9999;box-shadow:0 2px 8px rgba(0,0,0,.3);}');
  pw.document.write('.preview-toolbar h3{color:#fff;font-size:14px;font-weight:800;margin:0;flex:1;}');
  pw.document.write('.pv-btn{padding:7px 18px;border:none;border-radius:7px;cursor:pointer;font-size:13px;font-weight:800;font-family:inherit;}');
  pw.document.write('.pv-print{background:#16a34a;color:#fff;}.pv-close{background:#dc2626;color:#fff;}');
  pw.document.write('.preview-body{padding:70px 20px 30px;display:flex;justify-content:center;}');
  pw.document.write('.rc-card{box-shadow:0 4px 24px rgba(0,0,0,.25);}');
  pw.document.write('@media print{.preview-toolbar{display:none!important;}.preview-body{padding:0;background:#fff;}.rc-card{box-shadow:none;}}');
  pw.document.write('</style></head><body>');
  pw.document.write('<div class="preview-toolbar"><h3>👁️ HY Report Card Preview — '+(st.name||st.anukra||'')+'</h3>');
  pw.document.write('<button class="pv-btn pv-print" onclick="window.print()">🖨️ Print / Save PDF</button>');
  pw.document.write('<button class="pv-btn pv-close" onclick="window.close()">✕ बंद करें</button></div>');
  pw.document.write('<div class="preview-body">'+cardHTML+'</div></body></html>');
  pw.document.close();
  setTimeout(function(){
    try{pw.document.querySelectorAll('svg.rc-barcode').forEach(function(svg){var val=svg.getAttribute('data-val')||'0';JsBarcode(svg,val,{width:1.2,height:36,margin:2});});}catch(e){}
  },400);
}

function hyrcPrintByRange(){
  var from=parseInt(g('hyrc-range-from').value)||1;
  var to=parseInt(g('hyrc-range-to').value)||S.n;
  if(from<1) from=1; if(to>S.n) to=S.n;
  if(from>to){alert('FROM क्रमांक TO से बड़ा नहीं हो सकता।');return;}
  var students=_hyrcValidList.filter(function(ri){return (ri+1)>=from&&(ri+1)<=to;});
  if(!students.length){alert(isEnglish()?'No students found in this range.':'इस range में कोई छात्र नहीं मिला।');return;}
  if(!confirm('क्रमांक '+from+' से '+to+' तक के '+students.length+' Half Yearly Report Card Print होंगे।\nशुरू करें?')) return;
  var prog=g('hyrc-pdf-progress');
  var idx=0;
  var origSN=_hyrcCurSN;
  function printNext(){
    if(idx>=students.length){
      if(prog) prog.style.display='none';
      hyrcGoTo(origSN);
      alert('✅ '+students.length+' HY Report Card Print हो गए।');
      return;
    }
    var ri=students[idx];
    var st=S.stu[ri]||{};
    if(prog){prog.style.display='block';prog.textContent='🖨️ Print: '+(idx+1)+'/'+students.length+' — '+(st.name||st.anukra||'');}
    hyrcGoTo(ri+1);
    setTimeout(function(){window.print();idx++;setTimeout(printNext,800);},500);
  }
  printNext();
}

function hyrcAutoPDFByRange(){
  var from=parseInt(g('hyrc-range-from').value)||1;
  var to=parseInt(g('hyrc-range-to').value)||S.n;
  if(from<1) from=1; if(to>S.n) to=S.n;
  if(from>to){alert('FROM क्रमांक TO से बड़ा नहीं हो सकता।');return;}
  var students=_hyrcValidList.filter(function(ri){return (ri+1)>=from&&(ri+1)<=to;});
  if(!students.length){alert(isEnglish()?'No students found in this range.':'इस range में कोई छात्र नहीं मिला।');return;}

  if(typeof window.jspdf==='undefined'){
    alert('PDF library load नहीं हुई। Internet connection check करें और page reload करें।');
    return;
  }

  if(!confirm('क्रमांक '+from+' से '+to+' तक के '+students.length+' छात्रों के HY Report Card\nएक PDF file में Save होंगे।\nशुरू करें?')) return;

  var prog=g('hyrc-pdf-progress');
  var origSN=_hyrcCurSN;
  var jsPDF=window.jspdf.jsPDF;
  var pdf=null;
  var idx=0;

  function captureNext(){
    if(idx>=students.length){
      if(prog) prog.style.display='none';
      var fname='HY_ReportCard_'+from+'_to_'+to+'_'+(g('sc_yr')?g('sc_yr').value:'2026-27')+'.pdf';
      pdf.save(fname);
      hyrcGoTo(origSN);
      alert('✅ PDF saved: '+fname+'\n('+students.length+' HY Report Cards)');
      return;
    }
    var ri=students[idx];
    var st=S.stu[ri]||{};
    if(prog){
      prog.style.display='block';
      prog.textContent='💾 PDF बना रहा है: '+(idx+1)+'/'+students.length+' — '+(st.name||st.anukra||'');
    }
    hyrcGoTo(ri+1);
    setTimeout(function(){
      var cardEl=document.querySelector('#hyrc-card-area .rc-card');
      if(!cardEl){ idx++; captureNext(); return; }
      html2canvas(cardEl,{
        scale:2,
        useCORS:true,
        logging:false,
        backgroundColor:'#ffffff'
      }).then(function(canvas){
        var imgData=canvas.toDataURL('image/jpeg',0.92);
        var cw=canvas.width, ch=canvas.height;
        var pageW=210, pageH=Math.round(ch/cw*pageW);
        if(!pdf){
          pdf=new jsPDF({orientation:pageH>pageW?'portrait':'landscape',unit:'mm',format:[pageW,pageH]});
        } else {
          pdf.addPage([pageW,pageH], pageH>pageW?'portrait':'landscape');
        }
        pdf.addImage(imgData,'JPEG',0,0,pageW,pageH);
        idx++;
        setTimeout(captureNext,300);
      }).catch(function(err){
        console.error('html2canvas error',err);
        idx++;
        setTimeout(captureNext,300);
      });
    },600);
  }
  captureNext();
}


