function rcBulkAIMessage(){
  var from = parseInt((document.getElementById('rc-range-from')||{}).value) || 1;
  var to   = parseInt((document.getElementById('rc-range-to')||{}).value)   || (S&&S.stu?S.stu.length:10);
  if(from > to){ alert('Range fix करें — From > To'); return; }

  // Build rows
  var rows = [];
  for(var ri = from-1; ri < to; ri++){
    var st = S.stu[ri]||{};
    if(!st.name && !st.anukra) continue;
    var d = aiWAGetStudentData(ri);
    var style = (d.result==='FAIL'||d.failedSubjects.length>=2) ? 'urgent' : d.pct>=80 ? 'praise' : 'caring';
    var msg = _rskSmartRemark(d, style, 'bi', '');
    rows.push({ ri: ri, name: d.name, pct: d.pct, result: d.result, msg: msg });
  }
  if(!rows.length){ alert('इस range में कोई student नहीं मिला।'); return; }

  // Store messages globally for button access
  window._baiMessages = rows.map(function(r){ return r.msg; });

  // Remove existing modal
  var existing = document.getElementById('rsk-bulk-ai-modal');
  if(existing) existing.remove();

  var modal = document.createElement('div');
  modal.id = 'rsk-bulk-ai-modal';
  modal.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.75);z-index:300000;display:flex;align-items:flex-start;justify-content:center;padding:20px;overflow-y:auto';

  var box = document.createElement('div');
  box.style.cssText = 'background:#0f172a;border-radius:16px;padding:20px;width:100%;max-width:600px;font-family:inherit';

  // Header
  var header = document.createElement('div');
  header.style.cssText = 'display:flex;align-items:center;justify-content:space-between;margin-bottom:16px';
  header.innerHTML = '<div><div style="font-size:16px;font-weight:900;color:#fff">🤖 AI Messages — Roll '+from+' to '+to+'</div>'
    + '<div style="font-size:11px;color:#94a3b8;margin-top:3px">'+rows.length+' students | Smart auto remarks</div></div>';
  var closeBtn = document.createElement('button');
  closeBtn.textContent = '✕';
  closeBtn.style.cssText = 'background:rgba(255,255,255,.12);border:none;border-radius:8px;color:#fff;width:32px;height:32px;cursor:pointer;font-size:18px;font-family:inherit';
  closeBtn.onclick = function(){ modal.remove(); };
  header.appendChild(closeBtn);
  box.appendChild(header);

  // Cards container
  var cardsWrap = document.createElement('div');
  cardsWrap.style.cssText = 'max-height:65vh;overflow-y:auto;padding-right:4px';

  rows.forEach(function(r, i){
    var isPassed = r.result === 'PASS';
    var card = document.createElement('div');
    card.style.cssText = 'background:#1e293b;border:1px solid rgba(255,255,255,.12);border-radius:12px;padding:12px 14px;margin-bottom:10px';

    var cardHeader = document.createElement('div');
    cardHeader.style.cssText = 'display:flex;align-items:center;justify-content:space-between;margin-bottom:8px';
    cardHeader.innerHTML = '<span style="font-size:13px;font-weight:900;color:#fff">'+(i+1)+'. '+r.name+'</span>'
      + '<span style="font-size:10px;font-weight:800;padding:3px 10px;border-radius:20px;background:'+(isPassed?'#dcfce7':'#fee2e2')+';color:'+(isPassed?'#166534':'#b91c1c')+'">'+r.result+' '+r.pct+'%</span>';

    var msgDiv = document.createElement('div');
    msgDiv.style.cssText = 'font-size:11px;color:#cbd5e1;white-space:pre-wrap;line-height:1.6;background:rgba(0,0,0,.2);border-radius:8px;padding:10px;max-height:160px;overflow-y:auto';
    msgDiv.textContent = r.msg;

    var btnRow = document.createElement('div');
    btnRow.style.cssText = 'display:flex;gap:6px;margin-top:8px';

    var copyBtn = document.createElement('button');
    copyBtn.textContent = '📋 Copy';
    copyBtn.style.cssText = 'flex:1;padding:6px;background:#1e40af;color:#fff;border:none;border-radius:7px;font-size:10px;font-weight:800;cursor:pointer;font-family:inherit';
    (function(btn, div){ btn.onclick = function(){
      navigator.clipboard.writeText(div.textContent).then(function(){
        btn.textContent = '✅ Copied!';
        setTimeout(function(){ btn.textContent = '📋 Copy'; }, 2000);
      }).catch(function(){ alert('Copy failed'); });
    }; })(copyBtn, msgDiv);

    var waBtn = document.createElement('button');
    waBtn.textContent = '📲 WhatsApp';
    waBtn.style.cssText = 'flex:1;padding:6px;background:#25D366;color:#fff;border:none;border-radius:7px;font-size:10px;font-weight:800;cursor:pointer;font-family:inherit';
    (function(btn, div, row){ btn.onclick = function(){
      var mobile = (S.stu[row.ri] && S.stu[row.ri].mobile) ? S.stu[row.ri].mobile.trim().replace(/\D/g,'') : '';
      var waURL = mobile
        ? 'https://web.whatsapp.com/send?phone=91'+mobile+'&text='+encodeURIComponent(div.textContent)
        : 'https://web.whatsapp.com/send?text='+encodeURIComponent(div.textContent);
      window.open(waURL, '_blank');
    }; })(waBtn, msgDiv, r);

    btnRow.appendChild(copyBtn);
    btnRow.appendChild(waBtn);
    card.appendChild(cardHeader);
    card.appendChild(msgDiv);
    card.appendChild(btnRow);
    cardsWrap.appendChild(card);
  });
  box.appendChild(cardsWrap);

  // Footer buttons
  var footer = document.createElement('div');
  footer.style.cssText = 'display:flex;gap:8px;margin-top:14px';

  var copyAllBtn = document.createElement('button');
  copyAllBtn.textContent = '📋 Copy All Messages';
  copyAllBtn.style.cssText = 'flex:1;padding:10px;background:#7c3aed;color:#fff;border:none;border-radius:9px;font-size:12px;font-weight:800;cursor:pointer;font-family:inherit';
  copyAllBtn.onclick = function(){
    var all = window._baiMessages || [];
    navigator.clipboard.writeText(all.join('\n\n---\n\n')).then(function(){
      alert('✅ सभी ' + all.length + ' messages copied!');
    }).catch(function(){ alert('Copy failed'); });
  };

  var closeBtn2 = document.createElement('button');
  closeBtn2.textContent = '✖ Close';
  closeBtn2.style.cssText = 'padding:10px 18px;background:#374151;color:#fff;border:none;border-radius:9px;font-size:12px;font-weight:800;cursor:pointer;font-family:inherit';
  closeBtn2.onclick = function(){ modal.remove(); };

  footer.appendChild(copyAllBtn);
  footer.appendChild(closeBtn2);
  box.appendChild(footer);

  modal.appendChild(box);
  document.body.appendChild(modal);
  modal.addEventListener('click', function(e){ if(e.target===modal) modal.remove(); });
}


function _rcBulkDL(blob,fname,cls,sec,yr,openWA){
  var url=URL.createObjectURL(blob),a=document.createElement('a');
  a.href=url;a.download=fname;document.body.appendChild(a);a.click();document.body.removeChild(a);
  setTimeout(function(){URL.revokeObjectURL(url);},5000);
  if(openWA){
    var t=encodeURIComponent('📋 *Bulk Result Cards — Class '+cls+'-'+sec+' | '+yr+'*\n🏫 '+(SCHOOL_INFO.name||'')+'\n\nSabhi images download folder mein hain. WhatsApp pe attach karein 📎');
    setTimeout(function(){window.open('https://wa.me/?text='+t,'_blank');},500);
  }
}


function rcSavePDF(){
  var students=_rcValidList.slice();
  if(!students.length){alert(isEnglish()?'No students found.':'कोई छात्र नहीं मिला।');return;}
  var prog=g('rc-pdf-progress');
  var idx=0;
  function printNext(){
    if(idx>=students.length){
      if(prog) prog.style.display='none';
      rcGoTo(_rcCurSN);
      alert('सभी '+students.length+' PDF Print/Save हो गए।');
      return;
    }
    var ri=students[idx];
    var st=S.stu[ri]||{};
    if(prog){prog.style.display='block';prog.textContent='PDF: '+(idx+1)+'/'+students.length+' — '+(st.name||st.anukra||'');}
    rcGoTo(ri+1);
    setTimeout(function(){
      window.print();
      idx++;
      setTimeout(printNext,800);
    },500);
  }
  if(!confirm('सभी '+students.length+' छात्रों के Report Card एक-एक करके Print/PDF dialog खुलेगा।\nprint dialog में "Save as PDF" चुनें।\nशुरू करें?')) return;
  printNext();
}

