  var t1Ap=cntStat(t1Students,function(s){return s.appeared;}), t1Ps=cntStat(t1Students,function(s){return s.isPass;});
  h+='<td style="'+BD+'background:#c55a11;color:#fff;text-align:center;font-weight:900;padding:3px">'+(t1Ap?(Math.round(t1Ps/t1Ap*10000)/100).toFixed(2):'0.00')+'</td>';
  h+='</tr>';
