  h+='<tr><td colspan="16" style="'+BD+'font-size:11px;font-weight:700;text-align:center;padding:4px 3px;background:#dae3f3;color:#1e3a6e">DISTRICT- '+(dist||'—')+'&nbsp;&nbsp;&nbsp;['+_amSM9Label+'] '+yr+'&nbsp;&nbsp;&nbsp;DISE CODE- '+(dise||'—')+'</td></tr>';
  h+='<tr><td colspan="16" style="'+BD+'font-size:11px;font-weight:700;text-align:center;padding:4px 3px;background:#f0fdf4;color:#375623">BLOCK- '+(block||'—')+'&nbsp;&nbsp;&nbsp;Sectionwise Result Class-'+cls+'th&nbsp;&nbsp;&nbsp;MPBSE CODE- '+(SI.mpbse||'—')+'</td></tr>';

