      var isTot=cat==='TOTAL'; var cf=isTot?'ALL':cat;
      var mStu=t2Students.filter(function(s){return (cf==='ALL'||s.cat===cf)&&s.gender==='M'&&row[1](s);});
      var fStu=t2Students.filter(function(s){return (cf==='ALL'||s.cat===cf)&&s.gender==='F'&&row[1](s);});
      var tStu=t2Students.filter(function(s){return (cf==='ALL'||s.cat===cf)&&row[1](s);});
      h+='<td style="'+BD+'text-align:center;font-weight:700;padding:2px 4px">'+_smN(mStu.length,mStu,row[0]+' M')+'</td>';
