      /* CONTENT: Left student info + Right marks table */
      h+='<div style="display:flex;border-top:1px solid #000">';

      /* LEFT: Student Info */
      h+='<div style="min-width:190px;width:190px;border-right:1.5px solid #000;flex-shrink:0;font-size:9px">';
      /* S.N. + Class header */
      h+='<div style="background:#fff;border-bottom:1px solid #000;padding:2px 5px;font-weight:900;font-size:10px">';
