    h+='<td style="font-weight:700;color:#1a3a6b">'+(ri+1)+'</td>';
    h+='<td>'+(st.anukra||'')+'</td>';
    h+='<td style="text-align:left;padding-left:8px;font-weight:600;color:#1e3a5f;max-width:140px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">'+(st.name||'')+'</td>';
    h+='<td style="text-align:left;padding-left:8px;max-width:120px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">'+(st.father||'')+'</td>';
    h+='<td><div class="ph-cell" onclick="triggerPhotoClick('+ri+')" title="क्लिक करें — फोटो बदलें">'+(imgSrc?'<img src="'+imgSrc+'" alt="photo">':(PHOTOS[ri]===undefined?'<div class="ph-placeholder">📷<br>Photo<br>Click to add</div>':''))+'</div>';
