function triggerPhotoClick(ri){ var inp=g('ph-input-'+ri); if(inp) inp.click(); }

function handleSinglePhoto(input,ri){
  var file=input.files[0]; if(!file) return;
  if(r2Enabled()){
    // R2 upload mode
    var si=g('save-ind');
    if(si){ si.textContent='📤 Photo upload ho rahi hai...'; si.style.color='#fbbf24'; }
    // Delete old if URL photo
    var oldV=PHOTOS[ri];
    if(oldV&&oldV.startsWith('http')) r2Delete(r2Key(ri));
    r2Upload(file, r2Key(ri)).then(function(url){
      if(url){
        PHOTOS[ri]=url;
        r2SavePhotos(); saveData(); // photo URL save karo
        if(si){ si.textContent='✅ Photo uploaded!'; si.style.color='#6ee7b7'; setTimeout(_updateSaveInd,3000); }
      } else {
        // Fallback to base64 if R2 fails
        var reader=new FileReader();
        reader.onload=function(e){
          PHOTOS[ri]=e.target.result;
          r2SavePhotos(); saveData(); // base64 bhi save karo
          renderPH();
          var phEl=g('ph-total'); if(phEl) phEl.textContent=Object.keys(PHOTOS).length;
        };
        reader.readAsDataURL(file);
        if(si){ si.textContent='⚠️ Cloud fail — locally saved'; si.style.color='#fbbf24'; setTimeout(_updateSaveInd,3000); }
        return;
      }
      renderPH();
      var phEl=g('ph-total'); if(phEl) phEl.textContent=Object.keys(PHOTOS).length;
      if(typeof renderHYRC==='function') renderHYRC();
    });
  } else {
    // Local base64 mode
    var reader=new FileReader();
    reader.onload=function(e){
      PHOTOS[ri]=e.target.result;
      r2SavePhotos(); saveData(); // local mode mein bhi save karo
      renderPH();
      var phEl=g('ph-total'); if(phEl) phEl.textContent=Object.keys(PHOTOS).length;
      if(typeof renderHYRC==='function') renderHYRC();
    };
    reader.readAsDataURL(file);
  }
}

function handlePhotosUpload(input){
  var files=Array.from(input.files); if(!files.length) return;
  var n=S.n;
  var stuList=[];
  for(var ri=0;ri<n;ri++){ var st=S.stu[ri]||{}; if(st.name||st.anukra) stuList.push({ri:ri,anukra:(st.anukra||'').trim()}); }
  files.sort(function(a,b){ return a.name.localeCompare(b.name,undefined,{numeric:true}); });
  var total=files.length, loaded=0;
  var si=g('save-ind');

  files.forEach(function(file,idx){
    var matchRi=-1;
    var fname=file.name.replace(/\.[^.]+$/,'').trim();
    for(var i=0;i<stuList.length;i++){ if(stuList[i].anukra&&stuList[i].anukra===fname){ matchRi=stuList[i].ri; break; } }
    if(matchRi===-1&&idx<stuList.length) matchRi=stuList[idx].ri;
    if(matchRi===-1){ loaded++; if(loaded===total){ renderPH(); r2SavePhotos(); } return; }

    if(r2Enabled()){
      if(si) si.textContent='📤 Uploading '+loaded+'/'+total+'...'; si&&(si.style.color='#fbbf24');
      r2Upload(file, r2Key(matchRi)).then((function(rowIdx){
        return function(url){
          if(url) PHOTOS[rowIdx]=url;
          else {
            // fallback base64 — save karo jab read complete ho
            var rd=new FileReader();
            rd.onload=(function(rIdx){ return function(e){
              PHOTOS[rIdx]=e.target.result;
              // Check if all done
              loaded++;
              if(si) si.textContent='📤 '+loaded+'/'+total+'...';
              if(loaded===total){
                renderPH();
                r2SavePhotos(); saveData();
                if(si){ si.textContent='✅ '+total+' photos saved locally'; si.style.color='#fbbf24'; setTimeout(_updateSaveInd,4000); }
              }
            }; })(rowIdx);
            rd.readAsDataURL(file);
            return; // loaded++ happens in onload above
          }
          loaded++;
          if(si) si.textContent='📤 Uploading '+loaded+'/'+total+'...';
          if(loaded===total){
            renderPH();
            r2SavePhotos(); saveData(); // photo URLs save karo
            if(si){ si.textContent='✅ '+loaded+' photos uploaded!'; si.style.color='#6ee7b7'; setTimeout(_updateSaveInd,4000); }
          }
        };
      })(matchRi));
    } else {
      var reader=new FileReader();
      reader.onload=(function(rowIdx){ return function(e){
        PHOTOS[rowIdx]=e.target.result;
        loaded++;
        if(loaded===total){ renderPH(); r2SavePhotos(); saveData(); }
      }; })(matchRi);
      reader.readAsDataURL(file);
    }
  });
  input.value='';
}

function handleLogoUpload(input){
  var file=input.files[0]; if(!file) return;
  var reader=new FileReader();
  reader.onload=function(e){
    SCHOOL_LOGO=e.target.result;
    // Save locally first
    try{ localStorage.setItem('rsk_school_logo', SCHOOL_LOGO); }catch(ex){ console.warn('Logo save failed',ex); }
    renderPH();
    // Upload to Cloudinary if enabled
    if(r2Enabled()){
      var schoolId = (currentUser&&(currentUser.username||currentUser.user))||'school';
      r2UploadBase64(SCHOOL_LOGO, 'rsk_logos', schoolId+'_logo').then(function(url){
        if(url){
          SCHOOL_LOGO = url;
          try{ localStorage.setItem('rsk_school_logo', url); smartSave('rsk_school_logo', url); }catch(e){}
          console.log('[LOGO] Cloudinary uploaded: '+url);
          renderPH();
        } else {
          // Cloudinary failed — save base64 to D1
          smartSave('rsk_school_logo', SCHOOL_LOGO);
        }
      });
    } else {
      smartSave('rsk_school_logo', SCHOOL_LOGO);
    }
    // Logo upload ke baad Annual aur HY Report Card bhi update karo
    if(typeof renderRC === 'function') renderRC();
    if(typeof renderHYRC === 'function') renderHYRC();
    // Admission Form watermark update
    (function(){
      var wm = document.getElementById('af3_logo_watermark');
      if(wm && SCHOOL_LOGO) wm.innerHTML = '<img src="'+SCHOOL_LOGO+'" style="width:100%;height:100%;object-fit:contain;">';
    })();
  };
  reader.readAsDataURL(file);
  input.value='';
}

