/* ── School Name Lock System (backend-matched) ── */
function sdIsNameLocked(){
  return !!(SCHOOL_INFO.name && SCHOOL_INFO.name.trim() !== '');
}

function sdTogglePinPopup(){
  var popup = document.getElementById('sd-pin-popup');
  if(!popup) return;
  var isHidden = popup.style.display === 'none' || popup.style.display === '';
  popup.style.display = isHidden ? 'block' : 'none';
  if(isHidden){
    var p = document.getElementById('sd-name-pin');
    if(p){ p.value=''; p.focus(); p.style.borderColor=''; p.style.animation=''; }
  }
}

document.addEventListener('click', function(e){
  var popup = document.getElementById('sd-pin-popup');
  var icon  = document.getElementById('sd-lock-icon');
  if(popup && icon && !popup.contains(e.target) && !icon.contains(e.target)){
    popup.style.display = 'none';
  }
});

function sdNameUnlock(){
  var pin = document.getElementById('sd-name-pin');
  if(!pin) return;
  if(pin.value === '16412'){
    var popup = document.getElementById('sd-pin-popup');
    if(popup) popup.style.display = 'none';
    var inp = document.getElementById('sd_name_locked');
    if(inp){ inp.removeAttribute('readonly'); inp.style.background=''; inp.style.color=''; inp.style.fontWeight=''; inp.style.cursor='text'; inp.focus(); }
    if(typeof _rskNameUnlock === 'function') _rskNameUnlock(); // allow name change
    var lockIcon = document.getElementById('sd-lock-icon');
    if(lockIcon) lockIcon.style.display = 'none';
    var ftMsg = document.getElementById('sd-lock-msg');
    if(ftMsg){ ftMsg.textContent = isEnglish() ? '🔓 Name unlocked — will lock again after saving' : '🔓 Name unlock है — Save करने के बाद फिर lock हो जाएगा'; ftMsg.style.color='#166534'; }
  } else {
    pin.value = '';
    pin.style.borderColor = '#dc2626';
    pin.style.animation = 'shake .3s ease';
    setTimeout(function(){
      var p = document.getElementById('sd-name-pin');
      if(p){ p.style.animation=''; p.style.borderColor=''; }
    }, 400);
    alert(isEnglish() ? '❌ Wrong PIN!' : '❌ गलत PIN!');
  }
}

