function toggleInstrDropdown(e){
  e.stopPropagation();
  var dd = document.getElementById('instr-dropdown');
  var arrow = document.getElementById('instr-arrow');
  if(!dd) return;
  var isOpen = dd.style.display === 'block';
  // close code list if open
  var cdd=document.getElementById('code-dropdown'); if(cdd) cdd.style.display='none';
  var ca=document.getElementById('code-arrow'); if(ca) ca.style.transform='rotate(0deg)';
  dd.style.display = isOpen ? 'none' : 'block';
  if(arrow) arrow.style.transform = isOpen ? 'rotate(0deg)' : 'rotate(180deg)';
}

