function showInstructions(cls){
  // Close dropdown
  var dd = document.getElementById('instr-dropdown');
  var arrow = document.getElementById('instr-arrow');
  if(dd) dd.style.display='none';
  if(arrow) arrow.style.transform='rotate(0deg)';

  // Close Result dropdown menu + its submenu (agar Result menu se select kiya)
  var rsm = document.getElementById('result-instr-submenu');
  var rar = document.getElementById('result-instr-arrow');
  if(rsm) rsm.style.display='none';
  if(rar) rar.style.transform='rotate(0deg)';
  var rdd = document.getElementById('result-dropdown');
  if(rdd) rdd.style.display='none';
  var rda = document.getElementById('result-arrow');
  if(rda) rda.textContent='▼';
  if(typeof _dropOpen !== 'undefined') _dropOpen = false;

  // Remove existing modal if any
  var existing = document.getElementById('instr-modal-overlay');
  if(existing) existing.remove();

  var _en = (typeof isEnglish==='function') ? isEnglish() : false;
  var lines = (_en ? INSTRUCTIONS_EN : INSTRUCTIONS)[cls] || [];
  var listHTML = lines.map(function(line, i){
    if(i===0) return '<p style="font-weight:700;color:#fbbf24;margin:0 0 14px 0;font-size:14px;border-bottom:1px solid rgba(251,191,36,0.3);padding-bottom:10px">⚠️ '+line+'</p>';
    return '<p style="margin:0 0 9px 0;font-size:13.5px;line-height:1.7;color:#e2e8f0">'+line+'</p>';
  }).join('');

  var titleMap = _en
    ? {9:'Class 9', 11:'Class 11', 'primary':'Nursery to Class 7'}
    : {9:'कक्षा 9वीं', 11:'कक्षा 11वीं', 'primary':'नर्सरी से कक्षा 7वीं'};
  var iconMap  = {9:'🏫', 11:'🏫', 'primary':'🌱'};
  var modal = document.createElement('div');
  modal.id = 'instr-modal-overlay';
  modal.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.7);z-index:99999;display:flex;align-items:center;justify-content:center;backdrop-filter:blur(4px)';
  modal.innerHTML = '<div style="background:linear-gradient(135deg,#0f2744,#1e3a5f);border:2px solid #f59e0b;border-radius:16px;width:90%;max-width:700px;max-height:85vh;display:flex;flex-direction:column;box-shadow:0 20px 60px rgba(0,0,0,0.6);overflow:hidden">'
    + '<div style="background:linear-gradient(135deg,#1e3a5f,#0f2744);padding:18px 22px;display:flex;align-items:center;justify-content:space-between;border-bottom:2px solid #f59e0b;flex-shrink:0">'
    + '<div style="display:flex;align-items:center;gap:12px">'
    + '<div style="background:#f59e0b;border-radius:10px;width:40px;height:40px;display:flex;align-items:center;justify-content:center;font-size:20px">'+(iconMap[cls]||'📖')+'</div>'
    + '<div><div style="color:#fff;font-size:17px;font-weight:800">'+(_en?'Important Instructions':'महत्वपूर्ण निर्देश')+'</div>'
    + '<div style="color:#fbbf24;font-size:12px;font-weight:600">'+(titleMap[cls]||cls)+' — Instructions</div></div></div>'
    + '<button onclick="document.getElementById(\'instr-modal-overlay\').remove()" style="background:rgba(239,68,68,0.2);border:1px solid rgba(239,68,68,0.5);color:#fca5a5;border-radius:8px;padding:6px 12px;cursor:pointer;font-size:16px;font-weight:700" title="'+(_en?'Close':'बंद करें')+'">✕</button>'
    + '</div>'
    + '<div style="padding:20px 24px;overflow-y:auto;flex:1">' + listHTML + '</div>'
    + '<div style="padding:12px 22px;border-top:1px solid rgba(245,158,11,0.3);background:rgba(0,0,0,0.2);flex-shrink:0;display:flex;justify-content:flex-end">'
    + '<button onclick="document.getElementById(\'instr-modal-overlay\').remove()" style="background:linear-gradient(135deg,#f59e0b,#d97706);color:#fff;border:none;border-radius:8px;padding:9px 22px;font-size:13px;font-weight:700;cursor:pointer">'+(_en?'✓ Got it / Close':'✓ समझ गया / Close')+'</button>'
    + '</div>'
    + '</div>';

  modal.addEventListener('click', function(e){ if(e.target===modal) modal.remove(); });
  document.body.appendChild(modal);
}

