function showCodeList(cls){
  var cdd=document.getElementById('code-dropdown'); if(cdd) cdd.style.display='none';
  var ca=document.getElementById('code-arrow'); if(ca) ca.style.transform='rotate(0deg)';
  var existing=document.getElementById('codelist-modal-overlay'); if(existing) existing.remove();

  var data = CODE_LIST[cls];
  if(!data) return;

  var sectionsHTML = data.sections.map(function(sec){
    var rowsHTML = sec.rows.map(function(r){
      var isSectionHeader = !r.code || r.sn==='';
      if(isSectionHeader && !r.sn && r.subject && !r.code){
        return '<tr><td colspan="3" style="padding:6px 10px;font-size:11px;font-style:italic;color:#94a3b8;background:rgba(16,185,129,0.05)">'+ r.subject +'</td></tr>';
      }
      return '<tr style="border-bottom:1px solid rgba(255,255,255,0.05)">'
        +'<td style="padding:6px 10px;font-size:12px;color:#94a3b8;text-align:center;width:36px">'+(r.sn||'')+'</td>'
        +'<td style="padding:6px 10px;font-size:12.5px;color:#e2e8f0">'+ r.subject +'</td>'
        +'<td style="padding:6px 10px;font-size:13px;font-weight:700;color:#34d399;text-align:center;white-space:nowrap;width:80px">'+(r.code||'')+'</td>'
        +'</tr>';
    }).join('');
    var headLines = sec.heading.split('\n');
    var headHTML = '<div style="background:linear-gradient(135deg,rgba(16,185,129,0.2),rgba(5,150,105,0.1));padding:8px 12px;border-left:3px solid #10b981;margin-bottom:2px">'
      +'<div style="color:#34d399;font-size:12px;font-weight:800">'+ headLines[0] +'</div>'
      +(headLines[1]?'<div style="color:#6ee7b7;font-size:11px;margin-top:2px">'+ headLines[1] +'</div>':'')
      +'</div>';
    return '<div style="margin-bottom:14px;background:rgba(255,255,255,0.03);border-radius:8px;overflow:hidden;border:1px solid rgba(16,185,129,0.15)">'
      + headHTML
      +'<table style="width:100%;border-collapse:collapse">'+ rowsHTML +'</table></div>';
  }).join('');

  var notesHTML = data.notes.length ? '<div style="margin-top:12px;padding:12px 14px;background:rgba(251,191,36,0.08);border:1px solid rgba(251,191,36,0.25);border-radius:8px">'
    +'<div style="color:#fbbf24;font-size:12px;font-weight:700;margin-bottom:8px">📌 नोट / Notes</div>'
    + data.notes.map(function(n,i){ return '<p style="margin:0 0 7px 0;font-size:12px;color:#d1d5db;line-height:1.6">'+(data.notes.length>1?(i+1)+'. ':'')+n+'</p>'; }).join('')
    +'</div>' : '';

  var modal = document.createElement('div');
  modal.id = 'codelist-modal-overlay';
  modal.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.75);z-index:99999;display:flex;align-items:center;justify-content:center;backdrop-filter:blur(4px)';
  modal.innerHTML = '<div style="background:linear-gradient(135deg,#0f2744,#1e3a5f);border:2px solid #10b981;border-radius:16px;width:92%;max-width:780px;max-height:88vh;display:flex;flex-direction:column;box-shadow:0 20px 60px rgba(0,0,0,0.6);overflow:hidden">'
    +'<div style="background:linear-gradient(135deg,#064e3b,#065f46);padding:16px 22px;display:flex;align-items:center;justify-content:space-between;border-bottom:2px solid #10b981;flex-shrink:0">'
    +'<div style="display:flex;align-items:center;gap:12px">'
    +'<div style="background:#10b981;border-radius:10px;width:40px;height:40px;display:flex;align-items:center;justify-content:center;font-size:20px">📋</div>'
    +'<div><div style="color:#fff;font-size:16px;font-weight:800">'+ data.title +'</div>'
    +'<div style="color:#6ee7b7;font-size:11px;margin-top:2px">BOARD OF SECONDARY EDUCATION M.P. BHOPAL</div></div></div>'
    +'<button onclick="document.getElementById(\'codelist-modal-overlay\').remove()" style="background:rgba(239,68,68,0.2);border:1px solid rgba(239,68,68,0.5);color:#fca5a5;border-radius:8px;padding:6px 12px;cursor:pointer;font-size:16px;font-weight:700">✕</button>'
    +'</div>'
    +'<div style="padding:18px 20px;overflow-y:auto;flex:1">'+ sectionsHTML + notesHTML +'</div>'
    +'<div style="padding:12px 22px;border-top:1px solid rgba(16,185,129,0.3);background:rgba(0,0,0,0.2);flex-shrink:0;display:flex;justify-content:flex-end">'
    +'<button onclick="document.getElementById(\'codelist-modal-overlay\').remove()" style="background:linear-gradient(135deg,#10b981,#059669);color:#fff;border:none;border-radius:8px;padding:9px 22px;font-size:13px;font-weight:700;cursor:pointer">✓ Close</button>'
    +'</div></div>';

  modal.addEventListener('click', function(e){ if(e.target===modal) modal.remove(); });
  document.body.appendChild(modal);
}

// ── Beforeunload dirty guard — data loss prevent ──
window.addEventListener('beforeunload', function(e){
  var pending = Object.keys(_gdPendingQueue).length > 0;
  var saving  = !!_gdFlushTimer;
  var dirty   = !!window._rskDirty;
  if(pending || saving || dirty){
    e.preventDefault();
    e.returnValue = '⚠️ You have unsaved changes! Closing now may cause data loss. Please Save to Cloud first.';
  }
});

// ── Offline / Online banner ──
window.addEventListener('offline', function(){
  sbStatus('📵 Offline','#7f1d1d');
  var b=document.getElementById('rsk-offline-banner');
  if(b) b.style.display='flex';
});
window.addEventListener('online', function(){
  sbStatus('☁️ Cloud ON','#1e40af');
  var b=document.getElementById('rsk-offline-banner');
  if(b) b.style.display='none';
  // Flush any writes that queued while offline
  if(Object.keys(_gdPendingQueue).length) gdFlushQueue();
});

function autoSave(){
  clearTimeout(_st);
  _st=setTimeout(function(){
    // Double-defer: pehle frame paint ho, phir save karo (main thread block nahi hoga)
    setTimeout(function(){
    saveData();
    window._lsReal.setItem(erpKey('rsk_last_profile'), currentProfileKey());
    // Always sync global school info so all classes get latest data
    try{
      if(SCHOOL_INFO && (SCHOOL_INFO.name||SCHOOL_INFO.dise||SCHOOL_INFO.district)){
        window._lsReal.setItem(erpKey('rsk_school_info_global'), JSON.stringify(SCHOOL_INFO)); smartSave(erpKey('rsk_school_info_global'), SCHOOL_INFO);
        // Propagate to all other profiles
        var _aidx=JSON.parse(window._lsReal.getItem(erpKey('rsk_profile_index'))||'[]');
        var _siK=['name','address','dise','mpbse','jsk','gramPanchayat','basahat','village','block','district','vidhansabha','medium','mediumExplicitlySet'];
        _aidx.forEach(function(pKey){
          if(pKey===currentProfileKey()) return;
          var _pr=window._lsReal.getItem(pKey); if(!_pr) return;
          try{
            var _pd=JSON.parse(_pr);
            if(!_pd.schoolInfo) _pd.schoolInfo={};
            var _chg=false;
            _siK.forEach(function(k){
              if(SCHOOL_INFO[k]!==undefined&&SCHOOL_INFO[k]!==null&&SCHOOL_INFO[k]!==''&&_pd.schoolInfo[k]!==SCHOOL_INFO[k]){
                _pd.schoolInfo[k]=SCHOOL_INFO[k]; _chg=true;
              }
            });
            if(_chg){ _lsSafeSet(pKey, JSON.stringify(_pd)); _idbBackup(pKey, JSON.stringify(_pd)); }
          }catch(e){}
        });
      }
    }catch(e){}
    var el=g('save-ind');
    if(el){el.textContent='✓ Saved';setTimeout(function(){el.textContent='';},2000);}
    },0); // end inner defer
  },500);
}

function clearAll(){
  // ── Password Verify before Clear ──
  var storedPass = (currentUser && currentUser.password) ? currentUser.password : null;
  if(storedPass){
    // Build inline password modal
    var existingPwdModal = document.getElementById('rsk-clearall-pwd-modal');
    if(existingPwdModal) existingPwdModal.remove();
    var pwdHtml = '<div id="rsk-clearall-pwd-modal" style="position:fixed;inset:0;z-index:999999;display:flex;align-items:center;justify-content:center;background:rgba(0,0,0,0.7);">'
      +'<div style="background:linear-gradient(160deg,#0a1628,#0f2952);border:1.5px solid rgba(255,255,255,.2);border-radius:16px;padding:30px 28px;min-width:300px;max-width:360px;box-shadow:0 20px 60px rgba(0,0,0,.7);text-align:center;">'
      +'<div style="font-size:2rem;margin-bottom:8px;">🔐</div>'
      +'<div style="color:#f87171;font-size:1rem;font-weight:700;margin-bottom:6px;">Clear Data — Security Check</div>'
      +'<div style="color:#cbd5e1;font-size:.82rem;margin-bottom:18px;">Please enter your <strong style=\'color:#fbbf24\'>Login Password</strong> before deleting data.</div>'
      +'<input id="rsk-clearall-pwd-inp" type="password" placeholder="Enter Password here" style="width:100%;padding:10px 14px;border-radius:9px;border:1.5px solid rgba(255,255,255,.2);background:rgba(255,255,255,.07);color:#fff;font-size:.95rem;outline:none;box-sizing:border-box;margin-bottom:10px;">'
      +'<div id="rsk-clearall-pwd-err" style="color:#f87171;font-size:.78rem;min-height:18px;margin-bottom:10px;"></div>'
      +'<div style="display:flex;gap:10px;justify-content:center;">'
      +'<button onclick="document.getElementById(\'rsk-clearall-pwd-modal\').remove();" style="flex:1;padding:9px;border-radius:8px;border:1px solid rgba(255,255,255,.2);background:rgba(255,255,255,.08);color:#cbd5e1;font-size:.88rem;cursor:pointer;">❌ Cancel</button>'
      +'<button id="rsk-clearall-pwd-btn" onclick="_rskVerifyClearAllPwd()" style="flex:1;padding:9px;border-radius:8px;border:none;background:linear-gradient(135deg,#dc2626,#b91c1c);color:#fff;font-size:.88rem;font-weight:700;cursor:pointer;">🗑️ Proceed</button>'
      +'</div>'
      +'</div></div>';
    document.body.insertAdjacentHTML('beforeend', pwdHtml);
    var inp = document.getElementById('rsk-clearall-pwd-inp');
    if(inp){ inp.focus(); inp.addEventListener('keydown', function(e){ if(e.key==='Enter') _rskVerifyClearAllPwd(); }); }
    return;
  }
  // No user / no password stored — proceed directly
  _rskDoClearAll();
}

function _rskVerifyClearAllPwd(){
  var inp = document.getElementById('rsk-clearall-pwd-inp');
  var err = document.getElementById('rsk-clearall-pwd-err');
  var btn = document.getElementById('rsk-clearall-pwd-btn');
  if(!inp) return;
  var entered = inp.value;
  var storedPass = (currentUser && currentUser.password) ? currentUser.password : null;
  if(!entered){ err.textContent='⚠️ Password खाली है।'; inp.focus(); return; }
  if(entered !== storedPass){
    err.textContent='❌ गलत Password! दोबारा कोशिश करें।';
    inp.value=''; inp.focus();
    // shake effect
    var box = inp.closest('div[style*="border-radius:16px"]');
    if(box){ box.style.animation='none'; void box.offsetHeight; box.style.animation='loginShake .3s ease'; }
    return;
  }
  // Password correct
  var modal = document.getElementById('rsk-clearall-pwd-modal');
  if(modal) modal.remove();
  _rskDoClearAll();
}

function _rskDoClearAll(){
  // Show custom backup confirm modal
  var modal=document.getElementById('backup-modal');
  if(!modal) return;
  // Set class name in modal headings
  var cn=document.getElementById('bkp-cls-name');
  var cn2=document.getElementById('bkp-cls-name2');
  if(cn) cn.textContent=S.cls||'';
  if(cn2) cn2.textContent=S.cls||'';
  document.getElementById('bkp-step1').style.display='block';
  document.getElementById('bkp-step2').style.display='none';
  ['ds','ut','adm','subphoto','tt','clstt'].forEach(function(t){
    var p=document.getElementById('bkp-cls-panel-'+t); if(p) p.style.display='none';
    var a=document.getElementById('bkp-cls-all-'+t); if(a) a.checked=false;
    var w=document.getElementById('bkp-cls-warn-'+t); if(w) w.style.display='none';
  });
  document.querySelectorAll('.bkp-cls-chk-inp-ds,.bkp-cls-chk-inp-ut,.bkp-cls-chk-inp-adm,.bkp-cls-chk-inp-subphoto,.bkp-cls-chk-inp-tt,.bkp-cls-chk-inp-clstt').forEach(function(cb){ cb.checked=false; var l=cb.closest('label'); if(l) l.classList.remove('cls-checked'); });

  // ── Dynamically populate classes from localStorage ──
  _bkpPopulateClasses();

  modal.classList.remove('hidden');
}

function _bkpPopulateClasses(){
  var yr=(g('sc_yr')||{}).value||'2026-27';
  var uname=(_activeUserPrefix&&_activeUserPrefix!=='guest')?_activeUserPrefix.toUpperCase():'GUEST';
  var prefix='rsk_cls_'+uname+'_';
  // Key format: rsk_cls_USER_CLS_SEC_YR  e.g. rsk_cls_ADMIN_10_A_2026-27
  // Year contains a hyphen so split from right: last token = year, second-last = sec, rest = cls
  var foundCls={};
  for(var i=0;i<_lsReal.length;i++){
    var k=_lsReal.key(i);
    if(k&&k.indexOf(prefix)===0){
      var rest=k.slice(prefix.length); // e.g. "10_A_2026-27"
      // Find year suffix — always ends with something like "_YYYY-YY"
      var yrIdx=rest.lastIndexOf('_'+yr);
      if(yrIdx<0) continue; // different year
      var clsSec=rest.slice(0,yrIdx); // e.g. "10_A"
      var lastUs=clsSec.lastIndexOf('_');
      if(lastUs<0) continue;
      var cls=clsSec.slice(0,lastUs); // e.g. "10"
      if(!cls) continue;
      // Check if this key has actual student data
      try{
        var raw=_lsReal.getItem(k);
        if(!raw) continue;
        var dec=(typeof rskDecompress==='function')?rskDecompress(raw):raw;
        var d=JSON.parse(dec);
        var hasData=d&&d.S&&d.S.stu&&d.S.stu.some(function(st){return st&&(st.name||st.anukra);});
        if(hasData) foundCls[cls]=true;
      }catch(e){}
    }
  }
  var clsGridDs=document.getElementById('bkp-cls-grid-ds');
  var clsGridUt=document.getElementById('bkp-cls-grid-ut');
  if(!clsGridDs&&!clsGridUt) return;
  var clsList=Object.keys(foundCls);
  // Sort: Nursery/LKG/UKG/KG first, then numeric, then rest
  var ORDER=['Nursery','LKG','UKG','KG'];
  clsList.sort(function(a,b){
    var ia=ORDER.indexOf(a), ib=ORDER.indexOf(b);
    if(ia>=0&&ib>=0) return ia-ib;
    if(ia>=0) return -1;
    if(ib>=0) return 1;
    var na=parseInt(a),nb=parseInt(b);
    if(!isNaN(na)&&!isNaN(nb)) return na-nb;
    return a.localeCompare(b);
  });
  if(!clsList.length){
    clsGridDs.innerHTML='<div style="font-size:.78rem;color:#6b7280;grid-column:1/-1;">कोई Class नहीं मिली — पहले DataSheet बनाएं।</div>';
    return;
  }
  // Display label: 1→1st, 2→2nd, 3→3rd, 4-12→Nth, Nursery/LKG/UKG/KG as-is
  function clsLabel(c){
    if(ORDER.indexOf(c)>=0) return c;
    var n=parseInt(c);
    if(isNaN(n)) return c;
    var sfx=n===1?'st':n===2?'nd':n===3?'rd':'th';
    return n+sfx;
  }
  var noDataHtml='<div style="font-size:.78rem;color:#6b7280;grid-column:1/-1;">कोई Class नहीं मिली।</div>';
  // Helper: generate html for any tab type
  function _makeClsHtml(tabKey){
    var upper=tabKey.toUpperCase();
    return clsList.length?clsList.map(function(c){
      return '<label class="bkp-cls-chk">'
        +'<input type="checkbox" class="bkp-cls-chk-inp-'+tabKey+'" value="'+c+'" onchange="bkpClsChkChange(\''+tabKey+'\')"> Class '+clsLabel(c)
        +'</label>';
    }).join(''):noDataHtml;
  }
  var html=_makeClsHtml('ds');
  if(clsGridDs) clsGridDs.innerHTML=html;
  var htmlUt=_makeClsHtml('ut');
  if(clsGridUt) clsGridUt.innerHTML=htmlUt;
  // Populate subphoto, tt, clstt grids with same class list
  ['subphoto','tt','clstt'].forEach(function(t){
    var g2=document.getElementById('bkp-cls-grid-'+t);
    if(g2) g2.innerHTML=_makeClsHtml(t);
  });

  // ── Populate Admission List class grid (from admList3 array) ──
  var admGrid=document.getElementById('bkp-cls-grid-adm');
  if(admGrid){
    try{
      var _admRaw=_lsReal.getItem(erpKey('admList3'));
      var _admArr=_admRaw?JSON.parse(_admRaw):[];
      // Also check erp_students (registry)
      var _regRaw=_lsReal.getItem(erpKey('erp_students'))||_lsReal.getItem(erpKey('rsk_adm_registry'));
      var _regArr=_regRaw?JSON.parse(_regRaw):[];
      // Collect unique class values — format: "Class 9", "Class 10" etc
      var _admClsSet={};
      (_admArr||[]).forEach(function(r){ if(r&&r.class) _admClsSet[r.class]=true; });
      (_regArr||[]).forEach(function(r){ if(r&&r.class) _admClsSet[r.class]=true; });
      var _admClsList=Object.keys(_admClsSet).sort(function(a,b){
        // Sort by numeric part: "Class 9" → 9
        var na=parseInt((a||'').replace(/\D/g,'')||'0');
        var nb=parseInt((b||'').replace(/\D/g,'')||'0');
        return na-nb;
      });
      if(_admClsList.length){
        admGrid.innerHTML=_admClsList.map(function(c){
          return '<label class="bkp-cls-chk">'
            +'<input type="checkbox" class="bkp-cls-chk-inp-adm" value="'+c+'" onchange="bkpClsChkChange(\'adm\')"> '+c
            +'</label>';
        }).join('');
      } else {
        admGrid.innerHTML='<div style="font-size:.78rem;color:#6b7280;grid-column:1/-1;">कोई Admission data नहीं मिला।</div>';
      }
    }catch(e){
      admGrid.innerHTML='<div style="font-size:.78rem;color:#6b7280;grid-column:1/-1;">Data load नहीं हो सका।</div>';
    }
  }
}

function exportCSV(){
  if(!built){alert('पहले डेटाशीट बनाएं।');return;}
  var subs=S.subs,n=S.n,maxM=S.maxM;
  var hdrs=['स.क्र.','अनुक्रमांक','सेक्शन','नाम','पिता','माता','DOB','लिंग','वर्ग','समग्र','आधार','APAAR','जाति','माध्यम'];
  PH.forEach(function(ph){subs.forEach(function(s){hdrs.push(ph.label+'-'+s);});hdrs.push(ph.label+'-योग');});
  CCA_ITEMS.forEach(function(c){hdrs.push('CCA-'+c);}); hdrs.push('CCA-योग');
  PSG_ITEMS.forEach(function(p){hdrs.push('PSG-'+p);}); hdrs.push('PSG-योग');
  hdrs.push('कुल दिवस','उपस्थित','उपस्थिति%');
  var rows=[hdrs];
  for(var ri=0;ri<n;ri++){
    var st=S.stu[ri]||{};
    var row=[ri+1,st.anukra||'',st.anusec||'',st.name||'',st.father||'',st.mother||'',st.dob||'',st.gender||'',st.cat||'',st.samagra||'',st.aadhar||'',st.apaar||'',st.caste||'',st.medium||''];
    PH.forEach(function(ph){subs.forEach(function(_,si){row.push(S.marks[ph.id][ri+'_'+si]||'');});row.push(phTotal(ph.id,ri));});
    var cT=0; CCA_ITEMS.forEach(function(_,ci){var v=S.cca[ri+'_'+ci]||0;row.push(v);cT+=v;}); row.push(cT);
    var pT=0; PSG_ITEMS.forEach(function(_,pi){var v=S.psg[ri+'_'+pi]||0;row.push(v);pT+=v;}); row.push(pT);
    var aT=S.att[ri+'_t']||0,aP=S.att[ri+'_p']||0;
    row.push(aT,aP,aT>0?Math.round(aP/aT*100)+'%':'—');
    rows.push(row);
  }
  var csv='\ufeff'+rows.map(function(r){return r.map(function(v){return '"'+(v+'').replace(/"/g,'""')+'"';}).join(',');}).join('\n');
  var a=document.createElement('a'); a.href='data:application/vnd.ms-excel;charset=utf-8,'+encodeURIComponent(csv);
  a.download='DataSheet_'+S.cls+'_'+g('sc_yr').value+'.xlsx'; a.click();
}

