/* ── PASTE EXCEL ── */
function openPasteModal(){
  var m = document.getElementById('paste-modal');
  m.style.display = 'flex';
  document.getElementById('paste-area').value = '';
  document.getElementById('paste-msg').innerHTML = '';
}
function closePasteModal(){
  document.getElementById('paste-modal').style.display = 'none';
}

function processPasteData(){
  var raw = document.getElementById('paste-area').value.trim();
  if(!raw){ document.getElementById('paste-msg').innerHTML='<span style="color:#dc2626">❌ Kuch paste nahi kiya!</span>'; return; }
  if(!built){ document.getElementById('paste-msg').innerHTML='<span style="color:#dc2626">❌ Pehle DataSheet banaayen.</span>'; return; }
  var lines = raw.split(/[\r\n]+/).filter(function(l){ return l.replace(/[\t,\s]/g,'').length > 0; });

  var result = _importLines(lines, null);  // auto-detect sep
  var _rawLineCount = raw.split(/[\r\n]+/).filter(function(l){ return l.replace(/[\t,\s]/g,'').length > 0; }).length;
  var _skipInfo = result.headerSkipped ? ' (1 header row skipped)' : '';
  var _rawInfo = ' | Raw lines: '+_rawLineCount+' → Students: '+result.stu;
  document.getElementById('paste-msg').innerHTML='<span style="color:#166534">✅ '+result.stu+' students import | '+result.marks+' marks cells fill'+_rawInfo+_skipInfo+'</span>';
  setTimeout(closePasteModal, 2000);
}

/* ── IMPORT EXCEL (.xlsx/.csv) ── */
function handleExcelImport(inp){
  var file = inp.files[0]; if(!file) return;
  var ext = file.name.split('.').pop().toLowerCase();
  var reader = new FileReader();
  if(ext === 'csv'){
    reader.onload = function(e){
      var lines = e.target.result.split('\n').filter(function(l){return l.trim();});
      importLinesCSV(lines);
    };
    reader.readAsText(file, 'utf-8');
  } else {
    reader.onload = function(e){
      try{
        var data = new Uint8Array(e.target.result);
        var wb = XLSX.read(data, {type:'array'});
        var ws = wb.Sheets[wb.SheetNames[0]];
        var arr = XLSX.utils.sheet_to_csv(ws);
        var lines = arr.split('\n').filter(function(l){return l.trim();});
        importLinesCSV(lines, true);
      }catch(err){
        alert('❌ Excel read error. SheetJS library load nahi hui.\nCSV format mein try karen.');
      }
    };
    reader.readAsArrayBuffer(file);
  }
  inp.value = '';
}

/* ── Shared import engine (paste + excel) ── */
function _importLines(lines, sep){
  // Clean \r and filter empty lines (including rows with only tabs/commas/spaces — Excel trailing rows)
  lines = lines.map(function(l){ return l.replace(/\r/g,''); })
               .filter(function(l){ return l.replace(/[\t,\s]/g,'').length > 0; });
  if(!lines.length) return {stu:0, marks:0};

  // Auto-detect separator
  if(!sep) sep = (lines[0].indexOf('\t') >= 0) ? '\t' : ',';

  // Parse one row
  function parseRow(line){
    line = line.replace(/\r/g,'');
    if(sep === ','){
      var res=[], cur='', inQ=false;
      for(var ci=0;ci<line.length;ci++){
        var ch=line[ci];
        if(ch==='"'){ inQ=!inQ; }
        else if(ch===sep && !inQ){ res.push(cur.trim()); cur=''; }
        else cur+=ch;
      }
      res.push(cur.trim());
      return res;
    }
    return line.split('\t').map(function(c){ return c.replace(/^"|"$/g,'').trim(); });
  }

  // Detect header
  var row0 = parseRow(lines[0]);
  var fc = (row0[0]||'').replace(/[^\w]/g,'').toLowerCase();
  var start = (isNaN(fc) && fc !== '' && fc !== '0') ? 1 : 0;

  // ── Format Detection ──
  // Format A  (Program Export 9th): Sr | Roll | Sec | Name | Father | Mother | DOB | Gender | Cat | Samagra | Aadhar | APAAR | Caste | Medium | marks...
  // Format A2 (Program Export 10th/12th): Sr | Roll | R/P | Name | Father | Mother | Cat | Gender | DOB | Scholar | SSSMID | Enrolment | Medium | Section | SubCodes×6 | Marks...
  // Format B  (User's Excel): Roll | Name | Father | Mother | Cat | Gender | DOB | Scholar | SSSMID | ... | SubCodes(6) | marks(TH PR pairs)...

  var COL, marksStart, fmt;
  var sample = parseRow(lines[start] || lines[0]);

  var col0 = (sample[0]||'').trim();
  var col1 = (sample[1]||'').trim();
  var col2 = (sample[2]||'').trim();
  var col3 = (sample[3]||'').trim();
  var col4 = (sample[4]||'').trim();
  var col5 = (sample[5]||'').trim();
  var col6 = (sample[6]||'').trim();

  // ── AUTO-STRIP SERIAL NO. COLUMN ──
  // Agar user ne Format B data paste kiya aur saath mein Sr.No. column bhi copy kar liya:
  // col0=Sr(num), col1=Roll(num), col2=Name(text), col5=Cat or col6=Gender
  // → Automatically pehla column (Sr.No.) strip karo taaki data sahi parse ho
  var _isFormatBWithSr = !isNaN(col0) && col0 !== '' &&
    !isNaN(col1) && col1 !== '' &&
    isNaN(col2.charAt(0)) && col2 !== '' &&
    (/^(UR|SC|ST|OBC|GEN)/i.test(col5) || /^(M|F)$/i.test(col6));
  if(_isFormatBWithSr){
    // Strip Sr.No. (first column) from all data rows automatically
    lines = lines.map(function(l, li){
      if(li < start) return l;
      var p = parseRow(l);
      p.shift(); // remove first column
      return p.join('\t');
    });
    sep = '\t';
    // Recompute sample and col variables after strip
    var _s2 = parseRow(lines[start] || lines[0]);
    col0=(_s2[0]||'').trim(); col1=(_s2[1]||'').trim(); col2=(_s2[2]||'').trim();
    col3=(_s2[3]||'').trim(); col4=(_s2[4]||'').trim(); col5=(_s2[5]||'').trim(); col6=(_s2[6]||'').trim();
  }

  // Format B: col0=Roll(num), col1=Name(text), col4=Cat or col5=Gender
  var isFormatB = !isNaN(col0) && col0 !== '' &&
    isNaN(col1.charAt(0)) && col1 !== '' &&
    (/^(UR|SC|ST|OBC|GEN)/i.test(col4) || /^(M|F)$/i.test(col5));

  // Format A2 (10th/12th): col0=Sr(num), col1=Roll(long num), col2=R/P/blank (single char),
  // col3=Name(text), col6=Cat(UR/SC/ST/OBC) — RegPrivate indicator at col2 distinguishes from Format A
  // Format A2: col2 can be empty (Regular students may have blank R/P field)
  var isFormatA2 = !isFormatB &&
    !isNaN(col0) && col0 !== '' && !isNaN(col1) && col1 !== '' &&
    /^[RrPp]?$/.test(col2) &&
    isNaN(col3.charAt(0)) && col3 !== '' &&
    /^(UR|SC|ST|OBC|GEN|SC\/TC|BC|TC|PWD)/i.test(col6);

  if(isFormatB){
    // Format B (User Excel)
    fmt = 'B';
    var is11fmt = (S.cls==='11'||S.cls==='12');
    if(is11fmt){
      COL = { roll:0, name:1, father:2, mother:3, cat:4, gender:5,
              dob:6, scholar:7, samagra:8, apaar:9, enroll:10, medium:11, job:12, sec:13 };
      marksStart = 20;
      COL.subCodesStart = 14;
    } else {
      COL = { roll:0, name:1, father:2, mother:3, cat:4, gender:5,
              dob:6, scholar:7, samagra:8, aadhar:9, enroll:10, medium:11, sec:12 };
      marksStart = 19;
      COL.subCodesStart = 13;
    }
  } else if(isFormatA2){
    // Format A2 (10th/12th Program Export)
    // Sr(0) | Roll(1) | RegPrivate(2) | Name(3) | Father(4) | Mother(5) | Cat(6) | Gender(7) | DOB(8)
    // Scholar(9) | SSSMID(10) | Enrolment(11) | Medium(12) | GroupCode(13) | Section(14) | SubCodes(15-20) | Marks(21+)
    fmt = 'A2';
    // Detect if this export has the new Section column after Group Code (col 14 is A/B/C/D)
    var _sampleA2 = parseRow(lines[start] || lines[0]);
    var _col13 = (_sampleA2[13]||'').trim();
    var _col14 = (_sampleA2[14]||'').trim();
    var _hasNewSecCol = /^[A-D]$/.test(_col14) || (!isNaN(_col13) && /^[A-D]$/.test(_col14));
    if(_hasNewSecCol){
      // New format: GroupCode(13) | Section(14) | SubCodes(15-20) | Marks(21+)
      COL = { sr:0, roll:1, regprivate:2, name:3, father:4, mother:5,
              cat:6, gender:7, dob:8, scholar:9, samagra:10,
              enroll:11, medium:12, job:13, sec:14 };
      COL.subCodesStart = 15;
      marksStart = 21;
    } else {
      // Old format: Section(13) | SubCodes(14-19) | Marks(20+)
      COL = { sr:0, roll:1, regprivate:2, name:3, father:4, mother:5,
              cat:6, gender:7, dob:8, scholar:9, samagra:10,
              enroll:11, medium:12, sec:13 };
      COL.subCodesStart = 14;
      marksStart = 20;
    }
    // Some exports have a blank col before marks; skip it
    COL._a2BlankAfterCodes = true;
  } else {
    // Format A: Sr | Roll | Sec | Name | Father | Mother | DOB | Gender | Cat | Samagra | Aadhar | APAAR | Caste | Medium | marks...
    fmt = 'A';
    COL = { sr:0, roll:1, sec:2, name:3, father:4, mother:5,
            dob:6, gender:7, cat:8, samagra:9, aadhar:10,
            apaar:11, caste:12, medium:13 };
    marksStart = 14;

    // Header-based override
    if(start === 1){
      var hdr = row0.map(function(h){ return h.toLowerCase().replace(/[^a-z0-9]/g,''); });
      var HINTS = {
        roll:['roll','anukramank','anukra'], sec:['section','anusec','sec'],
        name:['name','naam','student'], father:['father','pita'],
        mother:['mother','mata'], dob:['dob','janm','birth'],
        gender:['gender','ling','sex'], cat:['cat','varg','category'],
        samagra:['samagra','smgr'], aadhar:['aadhar','aadhaar'],
        apaar:['apaar','apar'], caste:['caste','jaati'],
        medium:['medium','madhyam'],
        scholar:['scholar','scholarno','scholarnum'],
        enroll:['enroll','enrollment','enrolment','enrolno','enrollno']
      };
      Object.keys(HINTS).forEach(function(k){
        var kws=HINTS[k];
        for(var hi=0;hi<hdr.length;hi++){
          for(var ki=0;ki<kws.length;ki++){
            if(hdr[hi].indexOf(kws[ki])>=0){ COL[k]=hi; break; }
          }
        }
      });
      var maxCol = Object.keys(COL).reduce(function(m,k){ return Math.max(m,COL[k]); },0);
      marksStart = maxCol + 1;
    }
  }

  // Determine class type
  var is9 = (typeof is9th === 'function') ? is9th() : (parseInt(S.cls)>=9 && parseInt(S.cls)<=10);
  var is11 = (S.cls==='11'||S.cls==='12');
  var ns = S.subs ? S.subs.length : 6;
  var nMain = S.nMain || ns;
  var maxM = S.maxM || {};

  // 9th class phases: q, h, a
  // 6-8 class phases: m, h, a (or m, q, h, a)
  var phases9 = ['q','h','a'];
  var phases68 = [];
  if(maxM.m) phases68.push('m');
  if(maxM.q) phases68.push('q');
  if(maxM.h) phases68.push('h');
  if(maxM.a) phases68.push('a');

  var stuCount=0, marksCount=0;

  // ── MERGE SPLIT ROWS ──
  // Some Excel exports produce 2 rows per student (wrapped cells).
  // Detection: if a data row does NOT start with a number (Sr/Roll), it belongs to the previous student row.
  // We merge such rows by appending their non-empty columns to the previous row's trailing empty slots.
  var mergedLines = [];
  for(var mi=start; mi<lines.length; mi++){
    var mrow = parseRow(lines[mi]);
    var mfirst = (mrow[0]||'').trim();
    var msecond = (mrow[1]||'').trim();
    // A new student row starts with a number (Sr or Roll) OR has a long numeric roll at col0/col1
    // For Format A2 (11th/12th export): col0=Sr(num), col1=Roll(num), col2=R/P — check col0 OR col1
    // Also handle rows where col0 is empty but col1 has a roll number (some exports shift columns)
    // Also handle mixed roll like "11224 A" or "11224 B" — starts with digits
    var mfirstNumPart = mfirst.replace(/^(\d+).*$/, '$1');
    var mfirstIsNum = (mfirst !== '' && !isNaN(mfirst));
    var mfirstStartsNum = (mfirst !== '' && /^\d/.test(mfirst) && mfirstNumPart !== '' && !isNaN(mfirstNumPart));
    var msecondNum = (msecond !== '' && !isNaN(msecond) && msecond.length >= 3);
    var isNewStudent = mfirstIsNum || mfirstStartsNum || msecondNum;
    if(!isNewStudent && mergedLines.length > 0){
      // This is a continuation row — merge into last merged row
      var prevParsed = parseRow(mergedLines[mergedLines.length-1]);
      // Fill empty slots in prevParsed with values from this row
      var mergedArr = prevParsed.slice();
      var mci = 0;
      for(var mpi=0; mpi<mrow.length; mpi++){
        if((mrow[mpi]||'').trim() === '') continue;
        // Find next empty slot in merged row from current position
        while(mci < mergedArr.length && (mergedArr[mci]||'').trim() !== '') mci++;
        if(mci < mergedArr.length){
          mergedArr[mci] = mrow[mpi];
          mci++;
        } else {
          mergedArr.push(mrow[mpi]);
        }
      }
      // Rebuild as tab-separated (safe for re-parsing)
      mergedLines[mergedLines.length-1] = mergedArr.join('\t');
      // Override sep for merged rows
      if(sep !== '\t') sep = '\t';
    } else {
      mergedLines.push(lines[mi]);
    }
  }
  // Replace lines with merged version (re-include header if present)
  var headerLines = lines.slice(0, start);
  lines = headerLines.concat(mergedLines);
  if(sep !== '\t' && mergedLines.length > 0 && mergedLines[0].indexOf('\t') >= 0) sep = '\t';

  // Auto-expand S.n if importing more students than current limit
  var totalDataRows = lines.length - start;
  if(totalDataRows > S.n){
    S.n = totalDataRows;
    var nInp = document.getElementById('sc_n');
    if(nInp) nInp.value = S.n;
  }

  for(var i=start; i<lines.length; i++){
    var ri = i - start;
    var cols = parseRow(lines[i]);
    if(!cols.length || (cols.length<=1 && !cols[0])) continue;

    var cgc = cols; // closure for gc
    var gc = function(idx){ return ((cgc[idx]||'')+'').replace(/^"|"$/g,'').trim(); };

    if(!S.stu[ri]) S.stu[ri] = {};
    var st = S.stu[ri];

    var v;
    v=gc(COL.roll);    if(v) st.anukra  = v;
    // sec column: for 11th/12th with separate job(GroupCode) col, sec = Section (A/B/C/D)
    if(COL.sec !== undefined){
      v=gc(COL.sec);
      if(v){
        if(is11 && COL.job !== undefined){
          // New format: sec=Section, job=GroupCode — store section separately
          st.sssmid = v; st.section = v;
        } else if(is11){
          // Old format: sec=GroupCode for 11th/12th
          st.groupCode = v; st.anusec = v;
        } else {
          st.anusec = v;
        }
      }
    }
    v=gc(COL.name);    if(v) st.name    = v;
    v=gc(COL.father);  if(v) st.father  = v;
    v=gc(COL.mother);  if(v) st.mother  = v;
    v=gc(COL.dob);     if(v) st.dob     = v;
    v=gc(COL.gender);  if(v) st.gender  = v;
    v=gc(COL.cat);     if(v) st.cat     = v;
    v=gc(COL.samagra); if(v) st.samagra = v;
    if(COL.aadhar !== undefined){ v=gc(COL.aadhar); if(v) st.aadhar = v; }
    v=gc(COL.apaar);   if(v && COL.apaar!==undefined) st.apaar = v;
    if(COL.caste !== undefined){ v=gc(COL.caste); if(v) st.caste = v; }
    v=gc(COL.medium);  if(v) st.medium  = v;
    if(COL.scholar !== undefined){ v=gc(COL.scholar); if(v) st.scholar = v; }
    if(COL.enroll  !== undefined){ v=gc(COL.enroll);  if(v){ st.enroll=v; if(is11) st.ist=v; } }
    if(COL.job     !== undefined){ v=gc(COL.job);     if(v){
      // Group code is stored as-is (1-8 numeric value)
      st.job=v; if(is11){ st.groupCode=v; st.anusec=v; }
    } }
    // Format A2: RegPrivate indicator — store R or P as-is
    if(fmt==='A2' && COL.regprivate!==undefined){ v=gc(COL.regprivate); if(v) st.anukraP = v; }

    // Subject codes (Format B and A2)
    if((fmt === 'B' || fmt === 'A2') && COL.subCodesStart !== undefined){
      if(!st.subCodes) st.subCodes = ['','','','','',''];
      for(var sci=0; sci<6; sci++){
        var scv = gc(COL.subCodesStart + sci);
        if(scv){
          st.subCodes[sci] = scv;
          if(is11) st['subcode_'+sci] = scv;
        }
      }
    }
    // Only count as valid student if name or roll number exists
    if((st.name||'').trim() || (st.anukra||'').trim()) stuCount++;

    // ── MARKS IMPORT ──
    // Dynamic marksStart: skip blank col(s) right after subcodes (A2 format sometimes has blank at col 20)
    var mc = marksStart;
    if(fmt === 'A2' || (COL && COL._a2BlankAfterCodes)){
      while(mc < cols.length && (cols[mc]||'').trim() === '') mc++;
    }
    var _effectiveMarksStart = mc;

    if(is9 || is11){
      if(!S.marks9) S.marks9 = {q:{th:{},pr:{}}, h:{th:{},pr:{}}, a:{th:{},pr:{}}, sa:{th:{},pr:{}}, qr:{th:{},pr:{}}, hy:{th:{},pr:{}}, pb:{th:{},pr:{}}};

      // Choose phases based on class, format, and actual column count
      var is10or12Cls = (S.cls==='10'||S.cls==='12');
      var phList;

      // Detect how many extra (non-mark) columns follow each phase's nMain*2 marks.
      // Pattern can be: 0 extra, 1 grade, or 2 blanks + 1 grade = 3 extra.
      // We detect by counting consecutive blank/non-numeric cols after first phase marks.
      var _extraPerPhase = 0;
      // Use the first data row's sample at _effectiveMarksStart
      var _detectRow = null;
      for(var _sri = start; _sri < Math.min(start+5, lines.length); _sri++){
        var _sr2 = parseRow(lines[_sri]);
        // skip ABS rows for detection
        var _firstTH = (_sr2[_effectiveMarksStart]||'').trim();
        if(_firstTH.toUpperCase() === 'ABS' || _firstTH === '') continue;
        _detectRow = _sr2; break;
      }
      if(_detectRow){
        // Count how many cols after nMain*2 marks are non-mark (blank or letter) before next numeric
        var _afterMarks = _effectiveMarksStart + nMain * 2;
        var _cnt = 0;
        while(_afterMarks + _cnt < _detectRow.length){
          var _c = (_detectRow[_afterMarks + _cnt]||'').trim();
          if(_c !== '' && !isNaN(_c) && parseFloat(_c) >= 0) break; // next numeric = next phase
          _cnt++;
        }
        _extraPerPhase = _cnt;
      }

      var _colsPerGroup = nMain * 2 + _extraPerPhase;
      var _remaining = cols.length - _effectiveMarksStart;
      var _numPhases = _colsPerGroup > 0 ? Math.floor(_remaining / _colsPerGroup) : 3;
      // If last phase has exactly nMain*2 marks but no trailing grade/blank cols, count it too
      var _leftover = _remaining - _numPhases * _colsPerGroup;
      if(_leftover >= nMain) _numPhases++;  // last phase may lack trailing grade col

      if(is10or12Cls || fmt==='A2'){
        // 10th/12th phases: Quarterly(qr), HalfYearly(hy), PreBoard(pb), Annual Term-1(q), Annual Term-2(h)
        if(_numPhases >= 5)      phList = ['qr','hy','pb','q','h'];
        else if(_numPhases >= 4) phList = ['qr','hy','pb','q'];
        else if(_numPhases >= 3) phList = ['qr','hy','pb'];
        else if(_numPhases >= 2) phList = ['qr','hy'];
        else                     phList = ['qr'];
      } else {
        if(_numPhases >= 5)      phList = ['qr','hy','pb','q','h'];
        else if(_numPhases >= 4) phList = ['qr','hy','q','h'];
        else if(_numPhases >= 3) phList = ['q','h','a'];
        else                     phList = ['q','h'];
      }

      phList.forEach(function(ph){
        if(!S.marks9[ph]) S.marks9[ph] = {th:{},pr:{}};
        // Use 100 as safe upper limit — actual subject-wise max is enforced by on9Mark on input
        // Previously thMax9=75/prMax9=25 was causing Vocational/Music subjects (higher PR) to be silently rejected
        var thMax9 = 100;
        var prMax9 = 100;
        for(var si=0; si<nMain; si++){
          var k = ri+'_'+si;
          var thv = gc(mc); mc++;
          var prv = gc(mc); mc++;
          if((thv||'').toUpperCase()==='ABS'){ S.marks9[ph].th[k]='ABS'; marksCount++; }
          else if(thv !== '' && !isNaN(thv) && parseFloat(thv)>=0 && parseFloat(thv)<=thMax9){ S.marks9[ph].th[k]=thv; marksCount++; }
          if((prv||'').toUpperCase()==='ABS'){ S.marks9[ph].pr[k]='ABS'; marksCount++; }
          else if(prv !== '' && !isNaN(prv) && parseFloat(prv)>=0 && parseFloat(prv)<=prMax9){ S.marks9[ph].pr[k]=prv; marksCount++; }
        }
        // After each phase: skip _extraPerPhase trailing columns (may be blanks + grade letter)
        if(_extraPerPhase > 0){
          for(var _ep=0; _ep<_extraPerPhase; _ep++){
            var _afterPh = (gc(mc)||'').trim();
            if(_afterPh !== '' && isNaN(_afterPh)){
              // capture grade/envGrade from any non-numeric non-blank col in this block
              if(!st.envGrade) st.envGrade = _afterPh.toUpperCase();
            }
            mc++;
          }
        }
      });

      // envGrade fallback (legacy: comes after all phases)
      if(!st.envGrade){
        var egv = gc(mc);
        if(egv && isNaN(egv)){
          var egvBase = egv.toUpperCase().replace(/[^A-E+\d]/g,'').charAt(0);
          if(egvBase && ['A','B','C','D','E'].indexOf(egvBase) >= 0) st.envGrade = egv.toUpperCase().trim();
          mc++;
        }
      }

      // Second Attempt (SA) marks — may follow
      var saStart = mc;
      if(!S.marks9['sa']) S.marks9['sa'] = {th:{}, pr:{}};
      for(var si=0; si<nMain; si++){
        var k9 = ri+'_'+si;
        var saTH = gc(saStart + si*2);
        var saPR = gc(saStart + si*2 + 1);
        if(saTH !== '' && !isNaN(saTH) && parseFloat(saTH) >= 0){ S.marks9['sa'].th[k9] = saTH; marksCount++; }
        if(saPR !== '' && !isNaN(saPR) && parseFloat(saPR) >= 0){ S.marks9['sa'].pr[k9] = saPR; marksCount++; }
      }
    } else {
      // Class 6-8: single mark per subject per phase
      if(!S.marks) S.marks = {m:{},q:{},h:{},a:{},sa:{}};
      phases68.forEach(function(ph){
        if(!S.marks[ph]) S.marks[ph] = {};
        for(var si=0; si<ns; si++){
          var mv = gc(mc); mc++;
          if(mv !== '' && !isNaN(mv) && parseFloat(mv)>=0 && parseFloat(mv)<=(maxM[ph]||100)){
            S.marks[ph][ri+'_'+si] = mv; marksCount++;
          }
        }
        mc++; // skip phase-total column (only in Format A)
      });

      // Proj
      if(maxM.proj){
        if(!S.proj) S.proj = {};
        for(var si2=0; si2<ns; si2++){
          var pv = gc(mc); mc++;
          if(pv!==''&&!isNaN(pv)) S.proj[ri+'_'+si2] = pv;
        }
        mc++;
      }

      // CCA
      if(!S.cca) S.cca = {};
      for(var ci=0; ci<CCA_ITEMS.length; ci++){
        var cv = gc(mc); mc++;
        if(cv!==''&&!isNaN(cv)) S.cca[ri+'_'+ci] = parseInt(cv)||0;
      }
      mc++;

      // PSG
      if(!S.psg) S.psg = {};
      for(var pi=0; pi<PSG_ITEMS.length; pi++){
        var pv2 = gc(mc); mc++;
        if(pv2!==''&&!isNaN(pv2)) S.psg[ri+'_'+pi] = parseInt(pv2)||0;
      }
      mc++;

      // Attendance
      if(!S.att) S.att = {};
      var atT = gc(mc); mc++;
      var atP = gc(mc); mc++;
      if(atT&&!isNaN(atT)) S.att[ri+'_t'] = parseInt(atT);
      if(atP&&!isNaN(atP)) S.att[ri+'_p'] = parseInt(atP);
    }
  }

  // Trim S.n to actual imported students — removes trailing blank rows
  if(stuCount > 0 && stuCount < S.n){
    S.n = stuCount;
    var nInpFix = document.getElementById("sc_n");
    if(nInpFix) nInpFix.value = S.n;
  }

  saveData(); rebuildAll();
  return {stu: stuCount, marks: marksCount, headerSkipped: start > 0};
}


function importLinesCSV(lines, isXlsx){
  if(!built){ alert('❌ Pehle DataSheet banaayen.'); return; }
  var sep = isXlsx ? ',' : '\t';
  var result = _importLines(lines, sep);
  alert('✅ '+result.stu+' students import | '+result.marks+' marks cells fill ho gaye!');
}

/* ── EXPORT EXCEL (.xlsx via SheetJS or CSV fallback) ── */
function doExportExcel(){
  if(!built){ alert('Pehle DataSheet banaayen.'); return; }
  var subs=S.subs, n=S.n;
  var hdrs=['Sr.','Anukramank','Section','Naam','Pita','Mata','DOB','Gender','Varg','Samagra','Aadhar','APAAR','Jaati','Madhyam'];
  PH.forEach(function(ph){ subs.forEach(function(s){ hdrs.push(ph.label+'-'+s); }); hdrs.push(ph.label+'-Total'); });
  CCA_ITEMS.forEach(function(c){ hdrs.push('CCA-'+c); }); hdrs.push('CCA-Total');
  PSG_ITEMS.forEach(function(p){ hdrs.push('PSG-'+p); }); hdrs.push('PSG-Total');
  hdrs.push('Kul Divas','Upasthit','Upasthiti%');

  var rows = [hdrs];
  for(var ri=0;ri<n;ri++){
    var st=S.stu[ri]||{};
    var row=[ri+1,st.anukra||'',st.anusec||'',st.name||'',st.father||'',st.mother||'',st.dob||'',st.gender||'',st.cat||'',st.samagra||'',st.aadhar||'',st.apaar||'',st.caste||'',st.medium||''];
    PH.forEach(function(ph){ subs.forEach(function(_,si){ row.push(S.marks[ph.id][ri+'_'+si]||''); }); row.push(phTotal(ph.id,ri)); });
    var cT=0; CCA_ITEMS.forEach(function(_,ci){ var v=S.cca[ri+'_'+ci]||0; row.push(v); cT+=v; }); row.push(cT);
    var pT=0; PSG_ITEMS.forEach(function(_,pi){ var v=S.psg[ri+'_'+pi]||0; row.push(v); pT+=v; }); row.push(pT);
    var aT=S.att[ri+'_t']||0, aP=S.att[ri+'_p']||0;
    row.push(aT,aP,aT>0?Math.round(aP/aT*100)+'%':'');
    rows.push(row);
  }

  try{
    var wb = XLSX.utils.book_new();
    var ws = XLSX.utils.aoa_to_sheet(rows);
    ws['!cols'] = hdrs.map(function(_,i){ return {wch: i<4?20:12}; });
    XLSX.utils.book_append_sheet(wb, ws, 'DataSheet');
    XLSX.writeFile(wb, 'DataSheet_'+S.cls+'_'+(g('sc_yr')?g('sc_yr').value:'2026-27')+'.xlsx');
    return;
  }catch(e){}

  // Fallback: Excel download
  var csv='\ufeff'+rows.map(function(r){return r.map(function(v){return '"'+(v+'').replace(/"/g,'""')+'"';}).join(',');}).join('\n');
  var a=document.createElement('a'); a.href='data:application/vnd.ms-excel;charset=utf-8,'+encodeURIComponent(csv);
  a.download='DataSheet_'+S.cls+'.xlsx'; a.click();
}

