/* ═══════════════════════════════════════
   USER-AWARE localStorage WRAPPER
   Har key ke aage username prefix lagata hai
   Taaki alag users ka data kabhi mix na ho
═══════════════════════════════════════ */
var _activeUserPrefix = 'guest';

// _lsReal = direct real localStorage, koi proxy nahi
// window pe assign karo taki har jagah accessible ho
window._lsReal = window.localStorage;

/* ═══════════════════════════════════════
   USER MANAGEMENT — CLOUDFLARE D1
   rsk_users table: username, password, disabled, sessions, expiry
   rsk_data  table: username, profile_key, data, updated_at
   Offline fallback: localStorage cache
═══════════════════════════════════════ */
var currentUser = null;
var VIEW_ONLY   = false;
var CLOUD_SYNC  = true; // set false if offline

/* ── Mode helper ── */
function getUserMode(u){
  if(!u) return 'DISABLED';
  if(u.disabled) return 'DISABLED';
  if(u.expiry){
    var exp=new Date(u.expiry); exp.setHours(23,59,59,999);
    if(new Date()>exp) return 'VIEW_ONLY';
  }
  return 'ACTIVE';
}
function fmtDate(d){ if(!d) return '—'; var p=d.split('-'); return p[2]+'/'+p[1]+'/'+p[0]; }

/* ── Class Access Filter — login ke baad SAARE class dropdowns restrict karo ── */
// sc_class values: numeric '9','10' etc. + 'Nursery','LKG','UKG','KG'
// af3_class / admList3Class / ifCls values: 'Class 9','Class 10' etc.
// Dono formats ka mapping:
var _CLS_NUMERIC_TO_LABEL = {
  'Nursery':'Nursery','LKG':'LKG','UKG':'UKG','KG':'KG',
  '1':'Class 1','2':'Class 2','3':'Class 3','4':'Class 4','5':'Class 5',
  '6':'Class 6','7':'Class 7','8':'Class 8','9':'Class 9','10':'Class 10',
  '11':'Class 11','12':'Class 12'
};
var _CLS_LABEL_TO_NUMERIC = {};
(function(){ for(var k in _CLS_NUMERIC_TO_LABEL) _CLS_LABEL_TO_NUMERIC[_CLS_NUMERIC_TO_LABEL[k]]=k; })();

function _isClassAllowed(optVal, allowedArr){
  if(!optVal) return true; // blank/placeholder always allowed
  if(allowedArr.indexOf(optVal)>=0) return true; // direct match (numeric)
  var num=_CLS_LABEL_TO_NUMERIC[optVal];
  if(num && allowedArr.indexOf(num)>=0) return true; // label->numeric match
  return false;
}

function _filterSelectEl(sel, allowedArr){
  if(!sel) return;
  // Store original options on first run
  if(!sel._origOptions){
    sel._origOptions = [];
    for(var i=0;i<sel.options.length;i++){
      sel._origOptions.push({value:sel.options[i].value, text:sel.options[i].text});
    }
  }
  // Rebuild options — only allowed ones (display:none not reliable in native dropdowns)
  var curVal = sel.value;
  sel.innerHTML = '';
  var firstAllowed = null;
  sel._origOptions.forEach(function(o){
    var ok = _isClassAllowed(o.value||o.text, allowedArr);
    if(ok){
      var opt = document.createElement('option');
      opt.value = o.value; opt.text = o.text;
      sel.appendChild(opt);
      if(!firstAllowed) firstAllowed = o.value||o.text;
    }
  });
  // Restore selection if still valid, else select first allowed
  if(_isClassAllowed(curVal, allowedArr)) sel.value = curVal;
  else if(firstAllowed) sel.value = firstAllowed;
}

function applyClassFilter(allowedClasses){
  var ALL_CLASS_DROP_IDS = [
    'sc_class',       // DataSheet main selector (numeric values)
    'af3_class',      // Admission Form 3 (Class 1..12 format)
    'admList3Class',  // Admission List 3
    'ifCls',          // Incomplete Fields modal
  ];

  if(!allowedClasses || allowedClasses==='ALL') {
    ALL_CLASS_DROP_IDS.forEach(function(id){
      var sel=document.getElementById(id); if(!sel) return;
      for(var i=0;i<sel.options.length;i++){
        sel.options[i].style.display='';
        sel.options[i].disabled=false;
      }
    });
    return;
  }

  var allowed=allowedClasses.split(',').map(function(s){return s.trim();});

  ALL_CLASS_DROP_IDS.forEach(function(id){
    _filterSelectEl(document.getElementById(id), allowed);
  });

  // sc_class change trigger
  var sc=document.getElementById('sc_class');
  if(sc && typeof onClassChange==='function') onClassChange();
}

/* ── View-Only visual ── */
function applyViewOnly(expiry){
  VIEW_ONLY=true;
  document.body.classList.add('view-only');
  var b=document.getElementById('vo-banner');
  if(b) b.classList.add('show');
  var t=document.querySelector('.topbar'); if(t) t.style.top='36px';
  var m=document.querySelector('.main-tabs'); if(m) m.style.marginTop='36px';
  var et=document.getElementById('vo-exp-txt');
  if(et) et.textContent='Plan समाप्त: '+fmtDate(expiry);
}

/* ── Session check ── */
function isSessionAllowed(yr){
  if(!currentUser) return true;
  var sess=currentUser.sessions||'ALL';
  if(sess==='ALL') return true;
  return sess.split(',').map(function(s){return s.trim();}).indexOf(yr)>=0;
}
function getAllowedSessionsLabel(){
  if(!currentUser) return 'सभी';
  var sess=currentUser.sessions||'ALL';
  return sess==='ALL'?'सभी Sessions':sess;
}

