// ⏰ LAST SAVED TIMESTAMP — Topbar display
// ══════════════════════════════════════════════════
function rskUpdateLastSavedTs(){
  var now = new Date();
  var h = now.getHours(), m = now.getMinutes();
  var ampm = h >= 12 ? 'PM' : 'AM';
  h = h % 12 || 12;
  var timeStr = h + ':' + (m < 10 ? '0'+m : m) + ' ' + ampm;
  var el = document.getElementById('rsk-last-saved-ts');
  if(el) el.textContent = '☁️ ' + timeStr + ' saved';
  // Also persist to localStorage
  try{ localStorage.setItem('rsk_last_cloud_save_ts', now.toISOString()); }catch(e){}
}

// On page load — restore last saved timestamp from localStorage
(function(){
  document.addEventListener('DOMContentLoaded', function(){
    try{
      var ts = localStorage.getItem('rsk_last_cloud_save_ts');
      if(ts){
        var d = new Date(ts);
        var h = d.getHours(), m = d.getMinutes();
        var ampm = h >= 12 ? 'PM' : 'AM';
        h = h % 12 || 12;
        var timeStr = h + ':' + (m < 10 ? '0'+m : m) + ' ' + ampm;
        var el = document.getElementById('rsk-last-saved-ts');
        if(el) el.textContent = '☁️ ' + timeStr + ' saved';
      }
    }catch(e){}
  });
})();

// ══════════════════════════════════════════════════
// 🔄 SESSION RESTORE — F5/Refresh pe auto login
// ══════════════════════════════════════════════════
(function(){
  document.addEventListener('DOMContentLoaded', function(){
    // Sirf tab try karo jab login screen visible ho
    var loginScreen = document.getElementById('login-screen');
    if(!loginScreen || loginScreen.classList.contains('hidden')) return;

    // ── 30-min browser-close timeout check ──
    var IDLE_LIMIT_MS = 30 * 60 * 1000;
    var lastActiveTs = parseInt(localStorage.getItem('rsk_last_active_ts') || '0', 10);
    var nowTs = Date.now();
    if(lastActiveTs && (nowTs - lastActiveTs) > IDLE_LIMIT_MS){
      localStorage.removeItem('rsk_last_logged_user');
      localStorage.removeItem('rsk_last_active_ts');
      var errEl = document.getElementById('login-err');
      if(errEl){ errEl.style.color='#dc2626'; errEl.textContent='⏱️ Session expired: 30 minutes of inactivity, please login again.'; }
      return;
    }

    var cached = null;
    try{
      var arr = JSON.parse(localStorage.getItem('rsk_users_cache') || '[]');
      var lastUser = localStorage.getItem('rsk_last_logged_user');
      if(lastUser && arr.length){
        cached = arr.find(function(u){ return u.username === lastUser; });
      }
    }catch(e){}
    if(!cached) return;

    // Auto login silently
    var mode = typeof getUserMode === 'function' ? getUserMode(cached) : 'NORMAL';
    if(mode === 'DISABLED') return;

    // Try CF Worker login to verify session still valid
    fetch(CF_WORKER_URL + '/login', {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({username: cached.username, password: cached.password})
    })
    .then(function(r){ return r.json(); })
    .then(function(data){
      if(!data || !data.ok) return; // invalid — show login screen normally
      var u = data.school;
      u.password = cached.password;
      u.user = u.username;
      u.disabled = (u.status === 'DISABLED');
      var m = typeof getUserMode === 'function' ? getUserMode(u) : 'NORMAL';
      if(m === 'DISABLED') return;
      if(typeof _proceedLogin === 'function') _proceedLogin(u, m);
    })
    .catch(function(){
      // Offline — use cached credentials directly
      if(typeof currentUser !== 'undefined'){
        window.currentUser = cached;
        window._activeUserPrefix = cached.username;
        if(typeof CF_SCHOOL_TOKEN !== 'undefined') CF_SCHOOL_TOKEN = cached.password || CF_SCHOOL_TOKEN;
        if(typeof _rskResetUserState === 'function') _rskResetUserState();
        if(typeof loadSaved === 'function') loadSaved();
        if(typeof rebuildAll === 'function') rebuildAll();
        if(typeof updateTopbarClass === 'function') updateTopbarClass();
        if(typeof switchTab === 'function') switchTab('sd');
        if(loginScreen) loginScreen.classList.add('hidden');
        var ring = document.getElementById('hold-ring');
        if(ring) ring.style.display = 'none';
        // ── Dispatch rsk-ready (offline auto-login path) ──
        document.dispatchEvent(new CustomEvent('rsk-ready'));
      }
    });
  });
})();

