function rskCpShowStep(n){
  [1,2,3].forEach(function(i){
    var el=document.getElementById('rskCpStep'+i);
    if(el) el.style.display=(i===n?'block':'none');
  });
}

function rskCpGenOTP(){
  var userId = (document.getElementById('rskCpUser').value||'').trim().toUpperCase();
  var msg = document.getElementById('rskCpMsg1');
  if(!userId){ msg.innerHTML='<span style="color:red;">❌ Username डालें।</span>'; return; }
  // ── SECURITY: Sirf apna password reset kar sakte hain ──
  var loggedInUser = currentUser ? (currentUser.username||currentUser.user||'').toUpperCase() : '';
  if(loggedInUser && userId !== loggedInUser){
    msg.innerHTML='<span style="color:red;">⛔ आप केवल अपना Password reset कर सकते हैं।</span>';
    return;
  }
  // Verify user exists via CF Worker
  fetch(CF_WORKER_URL+'/users/get?username='+encodeURIComponent(userId), {headers: cfGetHeaders(true)})
    .then(function(r){return r.json();})
    .then(function(data){
      if(!data||!data.ok||!data.user){ msg.innerHTML='<span style="color:red;">❌ यह Username नहीं मिला।</span>'; return; }
      var otp = String(Math.floor(100000+Math.random()*900000));
      var expiry = Date.now()+10*60*1000;
      window._rskOtpStore[userId]={otp:otp,expiry:expiry};
      rskCpShowStep(2);
      // Show OTP to the user (self-reset)
      var box=document.getElementById('rskCpOtpBox');
      var val=document.getElementById('rskCpOtpVal');
      var exp=document.getElementById('rskCpOtpExp');
      if(box&&val&&exp){
        box.style.display='block';
        val.textContent=otp;
        exp.textContent='⏱️ Expires: '+new Date(expiry).toLocaleTimeString('hi-IN');
      }
      document.getElementById('rskCpUser')._resolved=userId;
    })
    .catch(function(){ msg.innerHTML='<span style="color:red;">❌ Network error। फिर कोशिश करें।</span>'; });
}

function rskCpVerifyOTP(){
  var entered=(document.getElementById('rskCpOtpInput').value||'').trim();
  var userId=document.getElementById('rskCpUser')._resolved||'';
  var msg=document.getElementById('rskCpMsg2');
  var stored=window._rskOtpStore[userId];
  if(!stored){ msg.innerHTML='<span style="color:red;">❌ पहले OTP Generate करें।</span>'; return; }
  if(Date.now()>stored.expiry){ msg.innerHTML='<span style="color:red;">⏱️ OTP Expire हो गया। फिर Generate करें।</span>'; delete window._rskOtpStore[userId]; return; }
  if(entered!==stored.otp){ msg.innerHTML='<span style="color:red;">❌ गलत OTP।</span>'; return; }
  delete window._rskOtpStore[userId];
  document.getElementById('rskCpNew').dataset.userId=userId;
  rskCpShowStep(3);
}

function rskCpStrength(){
  var val=document.getElementById('rskCpNew').value;
  var bar=document.getElementById('rskCpBar');
  var lbl=document.getElementById('rskCpBarLbl');
  var score=0;
  if(val.length>=6) score++;
  if(val.length>=8) score++;
  if(/[A-Z]/.test(val)) score++;
  if(/[0-9]/.test(val)) score++;
  if(/[^A-Za-z0-9]/.test(val)) score++;
  var levels=[
    {w:'0%',bg:'#eee',t:''},
    {w:'20%',bg:'#dc2626',t:'बहुत कमज़ोर'},
    {w:'40%',bg:'#ea580c',t:'कमज़ोर'},
    {w:'60%',bg:'#ca8a04',t:'ठीक है'},
    {w:'80%',bg:'#65a30d',t:'अच्छा'},
    {w:'100%',bg:'#16a34a',t:'बहुत मज़बूत ✅'}
  ];
  var lvl=levels[score]||levels[0];
  if(bar){bar.style.width=lvl.w;bar.style.background=lvl.bg;}
  if(lbl){lbl.textContent=lvl.t;lbl.style.color=lvl.bg;}
}

function rskCpSave(){
  var newPass=document.getElementById('rskCpNew').value;
  var confirm=document.getElementById('rskCpConfirm').value;
  var userId=document.getElementById('rskCpNew').dataset.userId||'';
  var msg=document.getElementById('rskCpMsg3');
  if(!newPass||newPass.length<4){ msg.innerHTML='<span style="color:red;">❌ Password कम से कम 4 characters का होना चाहिए।</span>'; return; }
  if(newPass!==confirm){ msg.innerHTML='<span style="color:red;">❌ दोनों Password match नहीं हो रहे।</span>'; return; }
  // Update password via CF Worker
  fetch(CF_WORKER_URL+'/users/update', {
    method:'POST', headers: cfGetHeaders(true),
    body: JSON.stringify({username: userId, password: newPass})
  })
    .then(function(r){return r.json();})
    .then(function(d){
      if(d.ok){
        msg.innerHTML='<span style="color:#16a34a;font-weight:bold;">✅ Password बदल गया!</span>';
        setTimeout(function(){ var m=document.getElementById('rskCpModal'); if(m) m.remove(); },1800);
      } else {
        msg.innerHTML='<span style="color:red;">❌ Save failed. फिर कोशिश करें।</span>';
      }
    })
    .catch(function(){ msg.innerHTML='<span style="color:red;">❌ Network error।</span>'; });
}

