var holdStart=null, holdInterval=null;
var ADMIN_HOLD_KEY='a', HOLD_DURATION=5000;

document.addEventListener('keydown',function(e){
  var ls=document.getElementById('login-screen');
  if(!ls||ls.classList.contains('hidden')) return;
  // Input/textarea focused ho toh ignore karo
  var tag=(document.activeElement||{}).tagName||'';
  if(tag==='INPUT'||tag==='TEXTAREA') return;
  if(e.key.toLowerCase()===ADMIN_HOLD_KEY&&!holdStart){
    holdStart=Date.now();
    document.getElementById('hold-ring').style.display='block';
    holdInterval=setInterval(function(){
      var el=Date.now()-holdStart, c=138;
      document.getElementById('hold-prog').style.strokeDashoffset=c*(1-Math.min(el/HOLD_DURATION,1));
      if(el>=HOLD_DURATION){
        clearInterval(holdInterval);holdInterval=null;holdStart=null;
        document.getElementById('hold-ring').style.display='none';
        document.getElementById('hold-prog').style.strokeDashoffset=c;
        showAdminPasswordPrompt();
      }
    },50);
  }
});
document.addEventListener('keyup',function(e){
  if(e.key.toLowerCase()===ADMIN_HOLD_KEY&&holdStart){
    clearInterval(holdInterval);holdInterval=null;holdStart=null;
    document.getElementById('hold-ring').style.display='none';
    document.getElementById('hold-prog').style.strokeDashoffset=138;
  }
});

function showAdminPasswordPrompt(){
  var pwd=prompt('🔐 Admin Panel Password:');
  if(pwd==='1782') openAdminModal();
  else if(pwd!==null) alert('❌ गलत Password!');
}

function openAdminModal(){adminSwitchTab('users');renderAdminUserList();document.getElementById('admin-modal').classList.remove('hidden');feeAutoDownloadCheck();}
function closeAdminModal(){
  document.getElementById('admin-modal').classList.add('hidden');
  document.getElementById('new-uname').value='';
  document.getElementById('new-upass').value='';
  if(document.getElementById('new-expiry')) document.getElementById('new-expiry').value='';
  if(document.getElementById('new-max-devices')) document.getElementById('new-max-devices').value='';
  document.getElementById('admin-msg').textContent='';
}

/* ── Session Checkboxes ── */
function buildSessCheckboxes(containerId,selectedSessions){
  var wrap=document.getElementById(containerId);if(!wrap)return;
  var isAll=(!selectedSessions||selectedSessions==='ALL');
  var selArr=isAll?[]:selectedSessions.split(',').map(function(s){return s.trim();});
  var startY=2026; // Fixed: 2026-27 से 2030-31 तक
  var html='<label style="display:flex;align-items:center;gap:5px;background:#f0fdf4;border:1.5px solid #86efac;border-radius:6px;padding:5px 11px;cursor:pointer;font-size:12px;font-weight:700;color:#166534">'
    +'<input type="checkbox" class="sess-cb" value="ALL" '+(isAll?'checked':'')
    +' onchange="sessAllToggle(this,\''+containerId+'\')" style="cursor:pointer"> सभी (ALL)</label>';
  for(var i=0;i<5;i++){
    var y=startY+i,y2=(y+1).toString().slice(-2),val=y+'-'+y2;
    var chk=!isAll&&selArr.indexOf(val)>=0;
    html+='<label style="display:flex;align-items:center;gap:5px;background:#eff6ff;border:1.5px solid #bfdbfe;border-radius:6px;padding:5px 11px;cursor:pointer;font-size:12px;font-weight:700;color:#1e40af">'
      +'<input type="checkbox" class="sess-cb sess-yr" value="'+val+'" '+(chk?'checked':'')+(isAll?' disabled':'')
      +' style="cursor:pointer"> '+val+'</label>';
  }
  wrap.innerHTML=html;
}
function sessAllToggle(cb,cid){
  var w=document.getElementById(cid);if(!w)return;
  w.querySelectorAll('.sess-yr').forEach(function(c){c.disabled=cb.checked;if(cb.checked)c.checked=false;});
}
function getSelectedSessions(cid){
  var w=document.getElementById(cid);if(!w)return 'ALL';
  var a=w.querySelector('.sess-cb[value="ALL"]');
  if(a&&a.checked)return 'ALL';
  var s=[];w.querySelectorAll('.sess-yr:checked').forEach(function(c){s.push(c.value);});
  return s.length?s.join(','):'ALL';
}

/* ── Class Access Checkboxes ── */
var RSK_ALL_CLASSES = [
  {val:'Nursery',label:'Nursery'},{val:'LKG',label:'LKG'},{val:'UKG',label:'UKG'},{val:'KG',label:'KG'},
  {val:'1',label:'Class 1'},{val:'2',label:'Class 2'},{val:'3',label:'Class 3'},
  {val:'4',label:'Class 4'},{val:'5',label:'Class 5'},{val:'6',label:'Class 6'},
  {val:'7',label:'Class 7'},{val:'8',label:'Class 8'},{val:'9',label:'Class 9'},{val:'10',label:'Class 10'},
  {val:'11',label:'Class 11'},{val:'12',label:'Class 12'}
];

function buildClassCheckboxes(containerId, selectedClasses){
  var wrap=document.getElementById(containerId); if(!wrap) return;
  var isAll=(!selectedClasses || selectedClasses==='ALL');
  var selArr=isAll?[]:selectedClasses.split(',').map(function(s){return s.trim();});
  var html='<label style="display:flex;align-items:center;gap:5px;background:#f0fdf4;border:1.5px solid #86efac;border-radius:6px;padding:5px 11px;cursor:pointer;font-size:12px;font-weight:700;color:#166534">'
    +'<input type="checkbox" class="cls-cb cls-all" value="ALL" '+(isAll?'checked':'')
    +' onchange="clsAllToggle(this,\''+containerId+'\')" style="cursor:pointer"> सभी (ALL)</label>';
  RSK_ALL_CLASSES.forEach(function(c){
    var chk=!isAll && selArr.indexOf(c.val)>=0;
    html+='<label style="display:flex;align-items:center;gap:5px;background:#eff6ff;border:1.5px solid #bfdbfe;border-radius:6px;padding:5px 10px;cursor:pointer;font-size:11px;font-weight:700;color:#1e40af">'
      +'<input type="checkbox" class="cls-cb cls-item" value="'+c.val+'" '+(chk?'checked':'')+(isAll?' disabled':'')
      +' style="cursor:pointer"> '+c.label+'</label>';
  });
  wrap.innerHTML=html;
}
function clsAllToggle(cb,cid){
  var w=document.getElementById(cid); if(!w) return;
  w.querySelectorAll('.cls-item').forEach(function(c){c.disabled=cb.checked; if(cb.checked) c.checked=false;});
}
function getSelectedClasses(cid){
  var w=document.getElementById(cid); if(!w) return 'ALL';
  var a=w.querySelector('.cls-all');
  if(a&&a.checked) return 'ALL';
  var s=[]; w.querySelectorAll('.cls-item:checked').forEach(function(c){s.push(c.value);});
  return s.length ? s.join(',') : 'ALL';
}

/* ── Render Admin User List (from CF Worker) ── */
function renderAdminUserList(){
  buildSessCheckboxes('new-sess-wrap','ALL');
  buildClassCheckboxes('new-class-wrap','ALL');
  var list=document.getElementById('admin-user-list');
  list.innerHTML='<p style="color:#888;font-size:12px">⏳ Users लोड हो रहे हैं...</p>';

  fetch(CF_WORKER_URL+'/users/list', {headers: cfGetHeaders(true)})
    .then(function(r){return r.json();})
    .then(function(d){
      var users = d.users || [];
      try{localStorage.setItem('rsk_users_cache',JSON.stringify(users));}catch(e){}
      renderUserListHTML(users);
    })
    .catch(function(){
      var cached=[];
      try{cached=JSON.parse(localStorage.getItem('rsk_users_cache')||'[]');}catch(e){}
      renderUserListHTML(cached);
      list.insertAdjacentHTML('afterbegin','<div style="background:#fef3c7;border-radius:6px;padding:6px 12px;font-size:11px;font-weight:700;color:#92400e;margin-bottom:8px">📴 Offline — cached data दिख रहा है</div>');
    });
}

function renderUserListHTML(users){
  var list=document.getElementById('admin-user-list');
  if(!users||!users.length){list.innerHTML='<p style="color:#888;font-size:12px;margin-bottom:12px">कोई user नहीं है</p>';return;}
  var html='<div style="margin-bottom:16px"><div style="font-size:11px;font-weight:800;color:#374151;margin-bottom:8px">👥 Users ('+users.length+')</div>';
  users.forEach(function(u,idx){
    var mode=getUserMode(u);
    var mColor=mode==='ACTIVE'?'#166534':mode==='VIEW_ONLY'?'#b45309':'#dc2626';
    var mBg=mode==='ACTIVE'?'#dcfce7':mode==='VIEW_ONLY'?'#fef3c7':'#fee2e2';
    var mLabel=mode==='ACTIVE'?'✏️ Editor':mode==='VIEW_ONLY'?'👁️ View-Only':'🚫 Disabled';
    var bColor=mode==='DISABLED'?'#fecaca':mode==='VIEW_ONLY'?'#fcd34d':'#e5e7eb';
    var sess=u.sessions||'ALL'; var exp=u.expiry||'';
    var uid=u.username||u.id||('idx_'+idx);
    html+='<div style="border:2px solid '+bColor+';border-radius:10px;padding:12px 14px;margin-bottom:8px">';
    html+='<div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-bottom:8px">';
    html+='<span style="font-size:13px;font-weight:900;color:#1a3a6b">👤 '+escH(u.username)+'</span>';
    html+='<span style="background:'+mBg+';color:'+mColor+';font-size:10px;font-weight:800;border-radius:4px;padding:2px 8px">'+mLabel+'</span>';
    html+='<span style="font-size:10px;color:#6b7280">Pass: '+escH(u.password)+'</span>';
    html+='<span style="font-size:10px;color:#6b7280">📅 '+(sess==='ALL'?'सभी':escH(sess))+'</span>';
    html+='<span style="font-size:10px;color:#6b7280">⏳ '+(exp?'Expiry: '+fmtDate(exp):'No expiry')+'</span>';
    html+='<span style="font-size:10px;color:#6b7280">📱 Devices: '+(u.max_devices>0?u.max_devices:'∞')+'</span>';
    html+='<span style="font-size:10px;color:#6b7280">👥 Sub-Users: '+(u.max_users>0?u.max_users:'0')+'</span>';
    html+='<span style="font-size:10px;color:#6b7280">📱 Sub Devices: '+(u.max_sub_devices>0?u.max_sub_devices:'∞')+'</span>';
    if(u.mobile) html+='<span style="font-size:10px;color:#059669;background:#d1fae5;border-radius:4px;padding:2px 7px;font-weight:700">📞 '+escH(u.mobile)+'</span>';
    var acStr = u.allowed_classes||'ALL';
    html+='<span style="font-size:10px;color:#0369a1;background:#e0f2fe;border-radius:4px;padding:2px 7px;font-weight:700">🏫 Classes: '+(acStr==='ALL'?'सभी':escH(acStr))+'</span>';
    html+='</div>';
    html+='<div style="display:flex;gap:6px;flex-wrap:wrap">';
    if(u.disabled){
      html+='<button onclick="adminToggleUser(\''+uid+'\',false)" style="padding:5px 12px;background:#16a34a;color:#fff;border:none;border-radius:5px;font-size:11px;font-weight:800;cursor:pointer;font-family:inherit">✅ Enable</button>';
    } else {
      html+='<button onclick="adminToggleUser(\''+uid+'\',true)" style="padding:5px 12px;background:#dc2626;color:#fff;border:none;border-radius:5px;font-size:11px;font-weight:800;cursor:pointer;font-family:inherit">🚫 Disable</button>';
    }
    html+='<button onclick="adminEditUser(\''+uid+'\','+idx+')" style="padding:5px 12px;background:#2563eb;color:#fff;border:none;border-radius:5px;font-size:11px;font-weight:800;cursor:pointer;font-family:inherit">✏️ Edit</button>';
    html+='<button onclick="adminDelUser(\''+uid+'\',\''+escH(u.username)+'\')" style="padding:5px 12px;background:#f3f4f6;color:#dc2626;border:1px solid #fecaca;border-radius:5px;font-size:11px;font-weight:700;cursor:pointer;font-family:inherit">🗑 हटाएं</button>';
    html+='</div>';
    // Edit panel
    html+='<div id="edit-panel-'+uid+'" style="display:none;margin-top:10px;padding-top:10px;border-top:1px solid #f0f0f0">';
    html+='<div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:8px">';
    html+='<div><label style="font-size:10px;font-weight:700;color:#374151;display:block;margin-bottom:3px">Expiry Date</label>'
      +'<input type="date" id="exp-inp-'+uid+'" value="'+escH(exp||'')+'" style="padding:6px 10px;border:1.5px solid #d1d5db;border-radius:6px;font-size:12px;font-family:inherit"></div>';
    html+='<div><label style="font-size:10px;font-weight:700;color:#374151;display:block;margin-bottom:3px">New Password</label>'
      +'<input type="text" id="pass-inp-'+uid+'" placeholder="खाली = पुराना रहेगा" style="padding:6px 10px;border:1.5px solid #d1d5db;border-radius:6px;font-size:12px;font-family:inherit;width:160px"></div>';
    html+='<div><label style="font-size:10px;font-weight:700;color:#374151;display:block;margin-bottom:3px">📞 Mobile No.</label>'
      +'<input type="text" id="mob-inp-'+uid+'" value="'+escH(u.mobile||'')+'" placeholder="10 digit" maxlength="10" inputmode="numeric" oninput="this.value=this.value.replace(/\\D/g,\'\')" style="padding:6px 10px;border:1.5px solid #d1d5db;border-radius:6px;font-size:12px;font-family:inherit;width:140px"></div>';
    html+='<div><label style="font-size:10px;font-weight:700;color:#374151;display:block;margin-bottom:3px">📱 Max Devices (0=∞)</label>'
      +'<input type="number" id="mdev-inp-'+uid+'" min="0" max="20" value="'+(u.max_devices||0)+'" style="padding:6px 10px;border:1.5px solid #d1d5db;border-radius:6px;font-size:12px;font-family:inherit;width:80px"></div>';
    html+='<div><label style="font-size:10px;font-weight:700;color:#374151;display:block;margin-bottom:3px">👥 Max Sub-Users (0=none)</label>'
      +'<input type="number" id="musr-inp-'+uid+'" min="0" max="20" value="'+(u.max_users||0)+'" style="padding:6px 10px;border:1.5px solid #d1d5db;border-radius:6px;font-size:12px;font-family:inherit;width:80px"></div>';
    html+='<div><label style="font-size:10px;font-weight:700;color:#374151;display:block;margin-bottom:3px">📱 Max Sub-User Devices (0=∞)</label>'
      +'<input type="number" id="msudev-inp-'+uid+'" min="0" max="20" value="'+(u.max_sub_devices||0)+'" style="padding:6px 10px;border:1.5px solid #d1d5db;border-radius:6px;font-size:12px;font-family:inherit;width:80px"></div>';
    html+='</div>';
    html+='<div style="font-size:10px;font-weight:700;color:#374151;margin-bottom:5px">📅 Sessions:</div>';
    html+='<div id="sess-edit-wrap-'+uid+'" style="display:flex;flex-wrap:wrap;gap:6px;margin-bottom:8px"></div>';
    html+='<div style="font-size:10px;font-weight:700;color:#0369a1;margin-bottom:5px;margin-top:8px">🏫 Class Access (कौनसी classes allow हों):</div>';
    html+='<div id="cls-edit-wrap-'+uid+'" style="display:flex;flex-wrap:wrap;gap:6px;margin-bottom:10px"></div>';
    html+='<button onclick="adminSaveUser(\''+uid+'\',\''+escH(u.username)+'\')" style="padding:6px 16px;background:#1a3a6b;color:#fff;border:none;border-radius:6px;font-size:12px;font-weight:800;cursor:pointer;font-family:inherit">✓ Save</button>';
    html+='<button onclick="document.getElementById(\'edit-panel-'+uid+'\').style.display=\'none\'" style="padding:6px 12px;background:#f3f4f6;color:#374151;border:none;border-radius:6px;font-size:12px;font-weight:700;cursor:pointer;font-family:inherit;margin-left:6px">✕</button>';
    html+='</div></div>';
  });
  html+='</div>';
  list.innerHTML=html;
}

function filterAdminUsers(val){
  val=(val||'').trim().replace(/\D/g,'');
  try{
    var cached=JSON.parse(localStorage.getItem('rsk_users_cache')||'[]');
    if(!val){ renderUserListHTML(cached); return; }
    var filtered=cached.filter(function(u){ return (u.mobile||'').replace(/\D/g,'').indexOf(val)!==-1; });
    renderUserListHTML(filtered);
  }catch(e){}
}

function adminEditUser(uid,idx){
  var panel=document.getElementById('edit-panel-'+uid);if(!panel)return;
  var isOpen=panel.style.display!=='none';
  document.querySelectorAll('[id^="edit-panel-"]').forEach(function(p){p.style.display='none';});
  if(isOpen)return;
  panel.style.display='block';
  // Get current sessions from rendered HTML
  try{
    var cached=JSON.parse(localStorage.getItem('rsk_users_cache')||'[]');
    var u=cached[idx]||{};
    buildSessCheckboxes('sess-edit-wrap-'+uid, u.sessions||'ALL');
    buildClassCheckboxes('cls-edit-wrap-'+uid, u.allowed_classes||'ALL');
  }catch(e){
    buildSessCheckboxes('sess-edit-wrap-'+uid,'ALL');
    buildClassCheckboxes('cls-edit-wrap-'+uid,'ALL');
  }
}

function adminToggleUser(uid, disable){
  // uid here is username (CF Worker uses username)
  fetch(CF_WORKER_URL+'/users/update', {
    method:'POST', headers: cfGetHeaders(true),
    body: JSON.stringify({username: uid, disabled: disable})
  })
    .then(function(){renderAdminUserList();})
    .catch(function(){alert('❌ Update नहीं हुआ — Internet check करें');});
}

function adminSaveUser(uid, uname){
  var expInp=document.getElementById('exp-inp-'+uid);
  var passInp=document.getElementById('pass-inp-'+uid);
  var mobInp=document.getElementById('mob-inp-'+uid);
  var mdevInp=document.getElementById('mdev-inp-'+uid);
  var musrInp=document.getElementById('musr-inp-'+uid);
  var msudevInp=document.getElementById('msudev-inp-'+uid);
  var sessions=getSelectedSessions('sess-edit-wrap-'+uid);
  var allowedClasses=getSelectedClasses('cls-edit-wrap-'+uid);
  var body={sessions:sessions, allowed_session:sessions, allowed_classes:allowedClasses};
  if(expInp) body.expiry=expInp.value||null;
  if(passInp&&passInp.value.trim()) body.password=passInp.value.trim();
  if(mobInp) body.mobile=mobInp.value.trim()||'';
  if(mdevInp) body.max_devices=parseInt(mdevInp.value,10)||0;
  if(musrInp) body.max_users=parseInt(musrInp.value,10)||0;
  if(msudevInp) body.max_sub_devices=parseInt(msudevInp.value,10)||0;
  fetch(CF_WORKER_URL+'/users/update', {
    method:'POST', headers: cfGetHeaders(true),
    body: JSON.stringify(Object.assign({username: uname}, body))
  })
    .then(function(){
      document.getElementById('edit-panel-'+uid).style.display='none';
      var msg=document.getElementById('admin-msg');
      msg.innerHTML='<span class="admin-ok">✓ "'+escH(uname)+'" update हो गया!</span>';
      setTimeout(function(){msg.innerHTML='';},3000);
      renderAdminUserList();
    })
    .catch(function(){alert('❌ Save नहीं हुआ — Internet check करें');});
}

function adminAddUser(){
  var uname=(document.getElementById('new-uname').value||'').trim();
  var upass=(document.getElementById('new-upass').value||'').trim();
  var umobile=(document.getElementById('new-mobile')?document.getElementById('new-mobile').value.trim():'');
  var expiry=(document.getElementById('new-expiry')?document.getElementById('new-expiry').value:'');
  var maxDev=parseInt((document.getElementById('new-max-devices')?document.getElementById('new-max-devices').value:0),10)||0;
  var maxUsr=parseInt((document.getElementById('new-max-users')?document.getElementById('new-max-users').value:0),10)||0;
  var msg=document.getElementById('admin-msg');
  if(!uname||!upass){msg.innerHTML='<span class="admin-err">❌ Username और Password भरें</span>';return;}
  var sessions=getSelectedSessions('new-sess-wrap');
  var allowedClasses=getSelectedClasses('new-class-wrap');
  var body={username:uname,password:upass,disabled:false,is_active:true,sessions:sessions,allowed_session:sessions,allowed_classes:allowedClasses,max_devices:maxDev,max_users:maxUsr,school_name:uname,mobile:umobile};
  if(expiry) body.expiry=expiry;
  fetch(CF_WORKER_URL+'/users/create', {
    method:'POST', headers: cfGetHeaders(true),
    body: JSON.stringify(body)
  })
    .then(function(r){return r.json();})
    .then(function(d){
      if(d.ok){
        document.getElementById('new-uname').value='';
        document.getElementById('new-upass').value='';
        if(document.getElementById('new-mobile')) document.getElementById('new-mobile').value='';
        if(document.getElementById('new-expiry')) document.getElementById('new-expiry').value='';
        if(document.getElementById('new-max-devices')) document.getElementById('new-max-devices').value='';
        msg.innerHTML='<span class="admin-ok">✓ User "'+escH(uname)+'" बन गया!</span>';
        renderAdminUserList();
      } else {
        msg.innerHTML='<span class="admin-err">❌ '+(d.error||'Error')+'</span>';
      }
    })
    .catch(function(){msg.innerHTML='<span class="admin-err">❌ Internet check करें</span>';});
}

function adminDelUser(uid, uname){
  if(!confirm('"'+uname+'" को हटाएं? उनका सारा cloud data भी delete होगा।')) return;
  // Delete user data too
  /* cloudDeleteAll not needed with CF Worker profile keys */
  fetch(CF_WORKER_URL+'/users/delete', {
    method:'POST', headers: cfGetHeaders(true),
    body: JSON.stringify({username: uname})
  })
    .then(function(){renderAdminUserList();})
    .catch(function(){alert('❌ Delete नहीं हुआ');});
}

function escH(s){return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');}
function saveUsersCache(){}

/* ══════════════════════════════════════════════════
   FEE AUTO-DOWNLOAD SYSTEM
   Roz ek baar — jab bhi admin panel khule —
   sabhi schools ka fee data ZIP mein download ho
══════════════════════════════════════════════════ */
var FEE_BACKUP_KEYS = [erpKey('erp_fees'),erpKey('erp_customFees'),erpKey('erp_feeMonths'),erpKey('erp_feeConfig'),erpKey('erp_lastReceiptNo')];
var _feeAutoRunning = false;

function feeAutoDownloadCheck(){
  // Aaj download hua? localStorage mein date check karo
  var today = new Date().toISOString().slice(0,10);
  var lastDl = '';
  try{ lastDl = localStorage.getItem('rsk_fee_dl_date') || ''; }catch(e){}
  if(lastDl === today){
    // Already done today — show quiet status
    _feeShowStatus('✅ आज का Fee Backup already download हो चुका है ('+today+')', '#166534', '#dcfce7');
    return;
  }
  // Auto-trigger download after 2 sec delay (let modal render first)
  setTimeout(function(){ feeAutoDownloadAll(true); }, 2000);
}

function feeAutoDownloadAll(isAuto){
  if(_feeAutoRunning) return;
  if(typeof JSZip === 'undefined'){
    _feeShowStatus('❌ JSZip load नहीं हुई — Page reload करें', '#dc2626', '#fee2e2');
    return;
  }
  _feeAutoRunning = true;
  var today = new Date().toISOString().slice(0,10);
  _feeShowStatus((isAuto?'🔄 Auto':'🔄')+' Fee Backup शुरू हो रहा है...', '#1d4ed8', '#dbeafe');

  // Step 1: Sabhi schools fetch karo
  fetch(CF_WORKER_URL+'/users/list', {headers: cfGetHeaders(true)})
    .then(function(r){ return r.json(); })
    .then(function(d){
      var schools = (d.users||[]).filter(function(u){ return !u.parent_username; });
      if(!schools.length){
        _feeShowStatus('❌ कोई school नहीं मिली', '#dc2626','#fee2e2');
        _feeAutoRunning = false; return;
      }
      _feeShowStatus('⏳ '+schools.length+' schools का fee data fetch हो रहा है...', '#1d4ed8','#dbeafe');

      // Step 2: Sabhi schools ka fee general_data fetch karo
      var promises = schools.map(function(u){
        return fetch(CF_WORKER_URL+'/general?_t='+Date.now(), { headers: cfGetHeaders(true),
          // Trick: admin secret se kisi bhi school ka data nahi milta directly
          // Isliye har school ka token chahiye — lekin admin ke paas nahi hota
          // Alternate: /backup/download-one use karo (admin endpoint)
        }).then(function(){ return null; }) // placeholder
        .catch(function(){ return null; });
      });

      // Better approach: /backup/run first, phir /backup/download-one
      // Pehle backup trigger karo (fee-only v3), phir download
      _feeRunAndDownload(schools, today);
    })
    .catch(function(){
      _feeShowStatus('❌ Schools fetch नहीं हुई — Internet check करें', '#dc2626','#fee2e2');
      _feeAutoRunning = false;
    });
}

async function _feeRunAndDownload(schools, today){
  try {
    // Step 1: Sabhi schools ka fresh backup trigger karo
    _feeShowStatus('🔄 (1/3) Backup trigger हो रहा है...', '#1d4ed8','#dbeafe');
    await fetch(CF_WORKER_URL+'/backup/run', {
      method:'POST', headers: cfGetHeaders(true),
      body: JSON.stringify({})
    });

    // Step 2: JSZip mein pack karo
    _feeShowStatus('⏳ (2/3) Fee data pack हो रहा है...', '#1d4ed8','#dbeafe');
    var zip = new JSZip();
    var folder = zip.folder('RSK_FeeBackup_'+today);
    var ok=0, skip=0;
    var manifest = '=== RSK Fee Backup ===\nDate: '+today+'\nSchools: '+schools.length+'\n\n';

    for(var i=0;i<schools.length;i++){
      var u = schools[i];
      _feeShowStatus('⏳ (2/3) '+(i+1)+'/'+schools.length+' — '+escH(u.username), '#1d4ed8','#dbeafe');
      try {
        var resp = await fetch(
          CF_WORKER_URL+'/backup/download-one?username='+encodeURIComponent(u.username)+'&date='+encodeURIComponent(today),
          {headers: cfGetHeaders(true)}
        );
        var data = await resp.json();
        if(data.ok && data.backup && data.backup.type === 'fee_only' && data.backup.fee_keys && data.backup.fee_keys.length){
          // Build clean fee object
          var feeObj = {
            school_username: u.username,
            school_name: u.school_name || u.username,
            backup_date: today,
            backed_up_at: data.backup.backed_up_at,
          };
          // fee_keys array ko object mein convert karo
          data.backup.fee_keys.forEach(function(item){ feeObj[item.key] = item.value; });
          var safeName = u.username.replace(/[^a-zA-Z0-9_\-]/g,'_');
          folder.file('FEE_'+safeName+'_'+today+'.json', JSON.stringify(feeObj, null, 2));
          manifest += '[OK] '+u.username+(u.school_name&&u.school_name!==u.username?' ('+u.school_name+')':'')+' — '+data.backup.fee_keys.length+' keys\n';
          ok++;
        } else {
          manifest += '[SKIP] '+u.username+' — fee data नहीं था\n';
          skip++;
        }
      } catch(e){
        manifest += '[ERR] '+u.username+' — '+e.message+'\n';
        skip++;
      }
    }

    folder.file('_manifest.txt', manifest);

    // Step 3: ZIP generate + download
    _feeShowStatus('⏳ (3/3) ZIP बन रही है...', '#1d4ed8','#dbeafe');
    var zipBlob = await zip.generateAsync({type:'blob', compression:'DEFLATE', compressionOptions:{level:6}});
    var url = URL.createObjectURL(zipBlob);
    var a = document.createElement('a');
    a.href = url;
    a.download = 'RSK_FeeBackup_'+today+'.zip';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);

    // Mark aaj ka download done
    try{ localStorage.setItem('rsk_fee_dl_date', today); }catch(e){}

    _feeShowStatus('✅ Fee Backup Download हो गई! '+ok+' schools'+(skip?' | '+skip+' skipped':''), '#166534','#dcfce7');
    _feeAutoRunning = false;

    // Backup tab stats bhi refresh karo
    setTimeout(function(){ adminLoadBackupTab(); }, 1000);

  } catch(e) {
    _feeShowStatus('❌ Error: '+escH(e.message), '#dc2626','#fee2e2');
    _feeAutoRunning = false;
  }
}

function _feeShowStatus(msg, color, bg){
  // Backup tab mein show karo
  var el = document.getElementById('adm-bkp-msg');
  if(el) el.innerHTML = '<div style="padding:10px 14px;border-radius:8px;font-size:12px;font-weight:700;color:'+color+';background:'+bg+';border:1.5px solid '+color+'40">'+msg+'</div>';
  // Agar backup tab active nahi hai toh bhi topbar pe show karo
  var tb = document.querySelector('.rsk-save-status');
  if(tb) tb.textContent = msg.replace(/<[^>]*>/g,'');
}

/* ══════════════════════════════════════════════════
   ADMIN PANEL — TAB SWITCHER
══════════════════════════════════════════════════ */
function adminSwitchTab(tab){
  ['users','backup','maintenance'].forEach(function(t){
    var el=document.getElementById('adm-tab-'+t);
    var btn=document.getElementById('adm-tab-'+t+'-btn');
    if(!el||!btn) return;
    if(t===tab){
      el.style.display='block';
      btn.style.borderBottomColor='#1a3a6b';
      btn.style.color='#1a3a6b';
      btn.style.fontWeight='800';
    } else {
      el.style.display='none';
      btn.style.borderBottomColor='transparent';
      btn.style.color='#6b7280';
      btn.style.fontWeight='700';
    }
  });
  if(tab==='backup') adminLoadBackupTab();
  if(tab==='maintenance') adminLoadMaintenanceTab();
}

/* ══════════════════════════════════════════════════
   ADMIN MAINTENANCE TAB
══════════════════════════════════════════════════ */

// Maintenance state (in-memory, also persisted via CF Worker admin key)
var _maintState = { on: false, msg: '', startDt: '', endDt: '', durationText: '' };

function adminLoadMaintenanceTab(){
  // Fetch current maintenance state from CF Worker
  fetch(CF_WORKER_URL+'/admin/maintenance', { headers: cfGetHeaders(true) })
    .then(function(r){ return r.json(); })
    .then(function(d){
      if(d && d.ok && d.data){
        _maintState = Object.assign(_maintState, d.data);
      }
      _maintRenderUI();
    })
    .catch(function(){
      // If no endpoint yet, just render current in-memory state
      _maintRenderUI();
    });
}

function _maintRenderUI(){
  var toggle = document.getElementById('maint-toggle-wrap');
  var knob   = document.getElementById('maint-toggle-knob');
  var status = document.getElementById('maint-status-bar');
  var msgBox = document.getElementById('maint-msg-text');
  var startEl= document.getElementById('maint-start-dt');
  var endEl  = document.getElementById('maint-end-dt');
  var durEl  = document.getElementById('maint-duration-text');

  if(!toggle) return;

  if(_maintState.on){
    toggle.style.background = '#16a34a';
    knob.style.left = '27px';
    status.style.background = '#dcfce7';
    status.style.color = '#166534';
    status.textContent = 'Status: ON — Schools को maintenance screen दिख रही है';
  } else {
    toggle.style.background = '#d1d5db';
    knob.style.left = '3px';
    status.style.background = '#e5e7eb';
    status.style.color = '#374151';
    status.textContent = 'Status: OFF';
  }

  if(msgBox && _maintState.msg)   msgBox.value = _maintState.msg;
  if(startEl && _maintState.startDt) startEl.value = _maintState.startDt;
  if(endEl   && _maintState.endDt)   endEl.value   = _maintState.endDt;
  if(durEl   && _maintState.durationText) durEl.value = _maintState.durationText;
}

function adminToggleMaintenance(){
  _maintState.on = !_maintState.on;
  _maintRenderUI();
}

function adminSaveMaintenance(){
  var msgBox = document.getElementById('maint-msg-text');
  var startEl= document.getElementById('maint-start-dt');
  var endEl  = document.getElementById('maint-end-dt');
  var durEl  = document.getElementById('maint-duration-text');
  var statusEl = document.getElementById('maint-msg-status');

  _maintState.msg          = msgBox ? msgBox.value.trim() : '';
  _maintState.startDt      = startEl ? startEl.value : '';
  _maintState.endDt        = endEl ? endEl.value : '';
  _maintState.durationText = durEl ? durEl.value.trim() : '';

  if(statusEl) statusEl.innerHTML = '<span style="color:#d97706">⏳ Save हो रहा है...</span>';

  fetch(CF_WORKER_URL+'/admin/maintenance', {
    method: 'POST',
    headers: Object.assign({'Content-Type':'application/json'}, cfGetHeaders(true)),
    body: JSON.stringify(_maintState)
  })
  .then(function(r){ return r.json(); })
  .then(function(d){
    if(statusEl){
      if(d && d.ok){
        statusEl.innerHTML = '<span style="color:#16a34a">✅ Maintenance settings saved!</span>';
      } else {
        statusEl.innerHTML = '<span style="color:#dc2626">❌ Save failed: '+(d.error||'Unknown error')+'</span>';
      }
    }
    setTimeout(function(){ if(statusEl) statusEl.innerHTML=''; }, 3000);
  })
  .catch(function(err){
    if(statusEl) statusEl.innerHTML = '<span style="color:#dc2626">❌ Network error. Settings locally updated.</span>';
    setTimeout(function(){ if(statusEl) statusEl.innerHTML=''; }, 3000);
  });
}

function adminTurnOffMaintenance(){
  _maintState.on = false;
  _maintRenderUI();
  // Auto-save with on=false
  fetch(CF_WORKER_URL+'/admin/maintenance', {
    method: 'POST',
    headers: Object.assign({'Content-Type':'application/json'}, cfGetHeaders(true)),
    body: JSON.stringify(_maintState)
  })
  .then(function(r){ return r.json(); })
  .then(function(d){
    var statusEl = document.getElementById('maint-msg-status');
    if(statusEl){
      statusEl.innerHTML = d && d.ok
        ? '<span style="color:#16a34a">✅ Maintenance बंद हो गई!</span>'
        : '<span style="color:#dc2626">❌ Save failed.</span>';
      setTimeout(function(){ statusEl.innerHTML=''; }, 3000);
    }
  })
  .catch(function(){});
}

/* ══════════════════════════════════════════════════
   ADMIN BACKUP TAB — LOAD STATS + SCHOOL LIST
══════════════════════════════════════════════════ */
function adminLoadBackupTab(){
  // Load stats
  var statsEl=document.getElementById('adm-bkp-stats');
  if(statsEl) statsEl.innerHTML='⏳ Stats लोड हो रहे हैं...';
  fetch(CF_WORKER_URL+'/backup/stats', {headers: cfGetHeaders(true)})
    .then(function(r){return r.json();})
    .then(function(d){
      if(d.ok && d.stats && statsEl){
        var s=d.stats;
        statsEl.innerHTML='📊 <b>'+s.schools_backed_up+'</b> schools backed up &nbsp;|&nbsp; <b>'+s.total_backups+'</b> total records &nbsp;|&nbsp; <b>'+s.total_size_mb+' MB</b> used';
      }
    })
    .catch(function(){ if(statsEl) statsEl.innerHTML='📴 Stats load नहीं हुई (offline)'; });

  // Load school list with today's backup status
  var listEl=document.getElementById('adm-bkp-school-list');
  if(listEl) listEl.innerHTML='<div style="padding:12px;color:#888;font-size:12px;text-align:center">⏳ Schools लोड हो रही हैं...</div>';
  var today=new Date().toISOString().slice(0,10);
  fetch(CF_WORKER_URL+'/users/list', {headers: cfGetHeaders(true)})
    .then(function(r){return r.json();})
    .then(function(d){
      var users=(d.users||[]).filter(function(u){return !u.parent_username;});
      if(!users.length){
        if(listEl) listEl.innerHTML='<div style="padding:12px;color:#888;font-size:12px;text-align:center">कोई school नहीं मिली</div>';
        return;
      }
      // For each school, check if today backup exists — use /backup/list
      // Batch: fetch all at once with Promise.all (max 500 schools)
      var promises=users.map(function(u){
        return fetch(CF_WORKER_URL+'/backup/list?username='+encodeURIComponent(u.username), {headers: cfGetHeaders(true)})
          .then(function(r){return r.json();})
          .then(function(bd){
            var backups=bd.backups||[];
            var todayBk=backups.find(function(b){return b.backup_date===today;});
            return {user:u, todayBk:todayBk, allCount:backups.length};
          })
          .catch(function(){return {user:u, todayBk:null, allCount:0};});
      });
      Promise.all(promises).then(function(results){
        var html='<table style="width:100%;border-collapse:collapse;font-size:11px">';
        html+='<tr style="background:#f1f5f9;position:sticky;top:0">';
        html+='<th style="padding:8px 10px;text-align:left;font-weight:800;color:#374151;border-bottom:1.5px solid #e5e7eb">School (Username)</th>';
        html+='<th style="padding:8px 6px;text-align:center;font-weight:800;color:#374151;border-bottom:1.5px solid #e5e7eb">आज का Backup</th>';
        html+='<th style="padding:8px 6px;text-align:center;font-weight:800;color:#374151;border-bottom:1.5px solid #e5e7eb">Saved Days</th>';
        html+='<th style="padding:8px 6px;text-align:center;font-weight:800;color:#374151;border-bottom:1.5px solid #e5e7eb">Action</th>';
        html+='</tr>';
        results.forEach(function(r,idx){
          var u=r.user;
          var hasBk=!!r.todayBk;
          var bkTime=hasBk?r.todayBk.created_at.replace('T',' ').slice(0,16):'—';
          var _bytes=hasBk?(r.todayBk.size_bytes||0):0; var bkSize=hasBk?(_bytes<1024?'<1KB':Math.round(_bytes/1024)+'KB'):'—';
          var statusBadge=hasBk
            ?'<span style="background:#dcfce7;color:#166534;border-radius:4px;padding:2px 8px;font-weight:800">✅ हुआ</span>'
            :'<span style="background:#fee2e2;color:#dc2626;border-radius:4px;padding:2px 8px;font-weight:800">❌ नहीं हुआ</span>';
          var rowBg=idx%2===0?'#fff':'#f9fafb';
          html+='<tr style="background:'+rowBg+';border-bottom:1px solid #f0f0f0">';
          html+='<td style="padding:8px 10px"><b style="color:#1a3a6b">'+escH(u.username)+'</b>';
          if(u.school_name && u.school_name!==u.username) html+='<br><span style="color:#6b7280;font-size:10px">'+escH(u.school_name)+'</span>';
          html+='</td>';
          html+='<td style="padding:8px 6px;text-align:center">'+statusBadge;
          if(hasBk) html+='<br><span style="color:#6b7280;font-size:10px">'+bkTime+'<br>'+bkSize+'</span>';
          html+='</td>';
          html+='<td style="padding:8px 6px;text-align:center;font-weight:700;color:#374151">'+r.allCount+'</td>';
          html+='<td style="padding:8px 6px;text-align:center">';
          html+='<button onclick="adminRunBackupOne(\''+escH(u.username)+'\')" title="अभी backup लो" style="padding:4px 8px;background:#dbeafe;color:#1d4ed8;border:1px solid #bfdbfe;border-radius:5px;font-size:10px;font-weight:800;cursor:pointer;font-family:inherit">🔄</button> ';
          if(hasBk) html+='<button onclick="adminDownloadOneJson(\''+escH(u.username)+'\',\''+today+'\')" title="JSON Download" style="padding:4px 8px;background:#d1fae5;color:#065f46;border:1px solid #6ee7b7;border-radius:5px;font-size:10px;font-weight:800;cursor:pointer;font-family:inherit">⬇️</button>';
          html+='</td></tr>';
        });
        html+='</table>';
        if(listEl) listEl.innerHTML=html;
      });
    })
    .catch(function(){
      if(listEl) listEl.innerHTML='<div style="padding:12px;color:#dc2626;font-size:12px;text-align:center">❌ Load नहीं हुआ — Internet check करें</div>';
    });
}

/* ══════════════════════════════════════════════════
   ADMIN BACKUP — RUN BACKUP (ALL / ONE)
══════════════════════════════════════════════════ */
function adminRunBackupAll(){
  var msg=document.getElementById('adm-bkp-msg');
  if(msg) msg.innerHTML='<span style="color:#1d4ed8">⏳ सभी schools का backup चल रहा है...</span>';
  fetch(CF_WORKER_URL+'/backup/run', {
    method:'POST', headers: cfGetHeaders(true),
    body: JSON.stringify({})
  })
    .then(function(r){return r.json();})
    .then(function(d){
      if(msg){
        var ok=d.results?d.results.filter(function(r){return r.ok;}).length:0;
        var fail=d.results?d.results.filter(function(r){return !r.ok;}).length:0;
        msg.innerHTML='<span style="color:#166534">✅ Backup हो गया! '+ok+' schools OK'+(fail?' | '+fail+' failed':'')+'</span>';
      }
      setTimeout(function(){ adminLoadBackupTab(); },800);
    })
    .catch(function(){
      if(msg) msg.innerHTML='<span style="color:#dc2626">❌ Backup नहीं हुआ — Internet check करें</span>';
    });
}

function adminRunBackupOne(username){
  var msg=document.getElementById('adm-bkp-msg');
  if(msg) msg.innerHTML='<span style="color:#1d4ed8">⏳ '+escH(username)+' का backup चल रहा है...</span>';
  fetch(CF_WORKER_URL+'/backup/run', {
    method:'POST', headers: cfGetHeaders(true),
    body: JSON.stringify({username: username})
  })
    .then(function(r){return r.json();})
    .then(function(d){
      if(msg) msg.innerHTML='<span style="color:#166534">✅ '+escH(username)+' का backup हो गया!</span>';
      setTimeout(function(){ adminLoadBackupTab(); },600);
    })
    .catch(function(){
      if(msg) msg.innerHTML='<span style="color:#dc2626">❌ Backup नहीं हुआ</span>';
    });
}

/* ══════════════════════════════════════════════════
   ADMIN BACKUP — DOWNLOAD ONE SCHOOL JSON
══════════════════════════════════════════════════ */
function adminDownloadOneJson(username, date){
  var msg=document.getElementById('adm-bkp-msg');
  if(msg) msg.innerHTML='<span style="color:#1d4ed8">⏳ '+escH(username)+' की JSON बन रही है...</span>';
  fetch(CF_WORKER_URL+'/backup/download-one?username='+encodeURIComponent(username)+'&date='+encodeURIComponent(date), {
    headers: cfGetHeaders(true)
  })
    .then(function(r){return r.json();})
    .then(function(d){
      if(!d.ok){ if(msg) msg.innerHTML='<span style="color:#dc2626">❌ '+(d.error||'Data नहीं मिला')+'</span>'; return; }
      var blob=new Blob([JSON.stringify(d.backup, null, 2)], {type:'application/json'});
      var url=URL.createObjectURL(blob);
      var a=document.createElement('a');
      a.href=url; a.download='RSK_'+username+'_'+date+'.json'; a.click();
      URL.revokeObjectURL(url);
      if(msg) msg.innerHTML='<span style="color:#166534">✅ '+escH(username)+' की JSON download हो गई!</span>';
    })
    .catch(function(){ if(msg) msg.innerHTML='<span style="color:#dc2626">❌ Download नहीं हुआ</span>'; });
}

/* ══════════════════════════════════════════════════
   ADMIN BACKUP — COMBINED ZIP DOWNLOAD (TODAY)
   सभी schools की JSON → एक ZIP फाइल
══════════════════════════════════════════════════ */
async function adminDownloadCombinedZip(){
  var msg=document.getElementById('adm-bkp-msg');
  var today=new Date().toISOString().slice(0,10);
  // JSZip availability check
  if(typeof JSZip==='undefined'){
    if(msg) msg.innerHTML='<span style="color:#dc2626">❌ JSZip library load नहीं हुई — Page reload करें</span>';
    return;
  }
  if(msg) msg.innerHTML='<span style="color:#1d4ed8">⏳ सभी schools का data fetch हो रहा है...</span>';

  try {
    // Step 1: सभी users लाओ (only main, no sub-users)
    var usersResp = await fetch(CF_WORKER_URL+'/users/list', {headers: cfGetHeaders(true)});
    var usersData = await usersResp.json();
    var schools = (usersData.users||[]).filter(function(u){ return !u.parent_username; });

    if(!schools.length){
      if(msg) msg.innerHTML='<span style="color:#dc2626">❌ कोई school नहीं मिली</span>';
      return;
    }

    var zip = new JSZip();
    var folder = zip.folder('RSK_Backup_'+today);
    var manifest = [];
    var successCount = 0, skipCount = 0;

    if(msg) msg.innerHTML='<span style="color:#1d4ed8">⏳ 0/'+schools.length+' schools process हो रही हैं...</span>';

    // Step 2: हर school का today का backup fetch करो
    for(var i=0;i<schools.length;i++){
      var u = schools[i];
      if(msg) msg.innerHTML='<span style="color:#1d4ed8">⏳ '+(i+1)+'/'+schools.length+' — '+escH(u.username)+'...</span>';
      try {
        var bkResp = await fetch(CF_WORKER_URL+'/backup/download-one?username='+encodeURIComponent(u.username)+'&date='+encodeURIComponent(today), {headers: cfGetHeaders(true)});
        var bkData = await bkResp.json();
        if(bkData.ok && bkData.backup){
          // File naam: SCHOOL_username_date.json — clearly labelled
          var safeName = u.username.replace(/[^a-zA-Z0-9_\-]/g,'_');
          var fileName = 'SCHOOL_'+safeName+'_'+today+'.json';
          folder.file(fileName, JSON.stringify(bkData.backup, null, 2));
          manifest.push({username: u.username, school_name: u.school_name||u.username, file: fileName, status:'ok', profiles: bkData.backup.profiles_count||0, general: bkData.backup.general_count||0, backed_up_at: bkData.backup.backed_up_at||today});
          successCount++;
        } else {
          manifest.push({username: u.username, school_name: u.school_name||u.username, file: null, status:'no_backup', note: 'आज का backup नहीं था'});
          skipCount++;
        }
      } catch(e){
        manifest.push({username: u.username, school_name: u.school_name||u.username, file: null, status:'error', note: e.message});
        skipCount++;
      }
    }

    // Step 3: Manifest file बनाओ
    var manifestTxt = '=== RSK Combined Backup ===\n';
    manifestTxt += 'Date: '+today+'\n';
    manifestTxt += 'Generated: '+new Date().toISOString()+'\n';
    manifestTxt += 'Total Schools: '+schools.length+'\n';
    manifestTxt += 'Backed Up: '+successCount+'\n';
    manifestTxt += 'Skipped/Error: '+skipCount+'\n\n';
    manifestTxt += '--- School List ---\n';
    manifest.forEach(function(m){
      manifestTxt += '\n['+m.status.toUpperCase()+'] '+m.username;
      if(m.school_name && m.school_name!==m.username) manifestTxt += ' ('+m.school_name+')';
      if(m.file) manifestTxt += '\n  File: '+m.file;
      if(m.note) manifestTxt += '\n  Note: '+m.note;
      manifestTxt += '\n';
    });
    folder.file('_manifest.txt', manifestTxt);
    folder.file('_manifest.json', JSON.stringify({date:today, total:schools.length, success:successCount, skipped:skipCount, schools:manifest}, null, 2));

    // Step 4: ZIP generate + download
    if(msg) msg.innerHTML='<span style="color:#1d4ed8">⏳ ZIP बन रही है...</span>';
    var zipBlob = await zip.generateAsync({type:'blob', compression:'DEFLATE', compressionOptions:{level:6}});
    var url = URL.createObjectURL(zipBlob);
    var a = document.createElement('a');
    a.href = url;
    a.download = 'RSK_Backup_'+today+'.zip';
    a.click();
    URL.revokeObjectURL(url);
    if(msg) msg.innerHTML='<span style="color:#166534">✅ ZIP download हो गई! '+successCount+' schools included'+(skipCount?' | '+skipCount+' skipped (backup नहीं था)':'')+'</span>';

  } catch(e){
    if(msg) msg.innerHTML='<span style="color:#dc2626">❌ Error: '+escH(e.message)+'</span>';
  }
}


/* ── Apply View-Only mode visually ── */
function applyViewOnly(expiry){
  VIEW_ONLY = true;
  document.body.classList.add('view-only');
  var b=document.getElementById('vo-banner');
  if(b) b.classList.add('show');
  var t=document.querySelector('.topbar');
  if(t) t.style.top='36px';
  var m=document.querySelector('.main-tabs');
  if(m) m.style.marginTop='36px';
  var et=document.getElementById('vo-exp-txt');
  if(et) et.textContent='Plan समाप्त: '+fmtDate(expiry);
}



