      g('sheet-wrap-rs').innerHTML='<div class="empty"><div class="ei">📜</div><div class="et">परिणाम पत्रक तैयार नहीं है</div></div>';
      g('sm-wrap').innerHTML='<div class="empty"><div class="ei">📊</div><div class="et">सारांश तैयार नहीं है</div></div>';
      g('rc-page').innerHTML='<div class="empty"><div class="ei">📋</div><div class="et">रिपोर्ट कार्ड तैयार नहीं है</div></div>';
      g('sl-wrap').innerHTML='<div class="empty"><div class="ei">📝</div><div class="et">पूरक सूची तैयार नहीं है</div></div>';
