      if(typeof window.feeConfig !== 'undefined') window.feeConfig = {};
      if(typeof window.fees !== 'undefined') window.fees = [];
      if(typeof window._fs4Inited !== 'undefined') window._fs4Inited = false;
            if(typeof window._fs6Inited !== 'undefined') window._fs6Inited = false;
      // Mark as cleared
      try{
        var _clrf=JSON.parse(_lsReal.getItem('rsk_cleared_keys')||'{}');
        _feeKeys.concat(_dynFeeKeys).forEach(function(k){ _clrf[k]=Date.now(); });
        _lsReal.setItem('rsk_cleared_keys', JSON.stringify(_clrf));
      }catch(e){}
      // Hard-clear marker for fee data
      try{ _lsReal.setItem('rsk_fee_hard_cleared','1'); }catch(e){}
      // Cloud se bhi delete karo
