var _dashChartJs=null;
var _dashChartJsLoading=false;
var _dashChartJsCbs=[];

function loadChartJs(cb){
  if(typeof Chart!=='undefined'){ cb(); return; }
  if(_dashChartJsLoading){ _dashChartJsCbs.push(cb); return; }
  _dashChartJsLoading=true;
  _dashChartJsCbs.push(cb);
  var s=document.createElement('script');
  s.src='https://cdnjs.cloudflare.com/ajax/libs/Chart.js/4.4.1/chart.umd.min.js';
  s.onload=function(){ _dashChartJsLoading=false; _dashChartJsCbs.forEach(function(fn){fn();}); _dashChartJsCbs=[]; };
  s.onerror=function(){ _dashChartJsLoading=false; console.warn('Chart.js load failed'); };
  document.head.appendChild(s);
}

function _getDashMark11(ri,si,ph,type){
  var k=ri+'_'+si,v='';
  if(S.marks9&&S.marks9[ph]&&S.marks9[ph][type]) v=S.marks9[ph][type][k]||'';
  if(!v&&S.marks&&S.marks[ph]){v=S.marks[ph][k+'_'+type]||(type==='th'?S.marks[ph][k]||'':'');}
  return (v===null||v===undefined)?'':String(v);
}

