function computeDashStats(){
  var is11=(S.cls==='11'||S.cls==='12');
  var is9=(S.cls==='9'||S.cls==='10');
  var nMain=Math.max(1,(S.nMain||6)-1); // excluding additional
  var WQ=5,WH=5,WA=90;

  var total=0,pass=0,fail=0,abs=0,noData=0;
  var grades={'A+':0,'A':0,'B':0,'C':0,'D':0,'E1':0,'E2':0};
  var rows=[];
  var subMap={}; // subName -> {name, pass, fail, appeared}

  for(var ri=0;ri<S.n;ri++){
    var st=S.stu[ri]||{};
    if(!st.name&&!st.anukra) continue;
    total++;

    var grandTotal=0, pct=0, result='NO_DATA', gr='';
    var q5tot=0, h5tot=0, a90tot=0;

    // ── Class 9/10: Use calc9FullResult (Annual result with grace) ──
    if(is9 && typeof calc9FullResult==='function'){
      try{
        var r9=calc9FullResult(ri,'final');
        if(r9 && r9.hasSomeData){
          grandTotal=r9.grandTotal||0;
          pct=r9.pct||0;
          gr=r9.grade||'';
          result=r9.result||'NO_DATA';
          // Subject map from actual result
          if(r9.subs) r9.subs.forEach(function(s){
            var info=s.info||null;
            var subName=(info&&info.short)||s.code||('Sub '+(s.si+1));
            if(!subName) return;
            if(!subMap[subName]) subMap[subName]={name:subName,pass:0,fail:0,appeared:0};
            if(s.hasA&&!s.isAbsA){ subMap[subName].appeared++; if(s.passed) subMap[subName].pass++; else subMap[subName].fail++; }
          });
          // Phase-wise totals for progress tab
          var maxP=r9.maxPossible||1;
          a90tot=grandTotal; // annual is the final total
        } else { result='NO_DATA'; }
      }catch(e){ result='NO_DATA'; }
    }
    // ── Class 11/12: Use _rs11Cache (from Result Sheet) or recalculate ──
    else if(is11){
      try{
        var subcodes11=[];
        for(var ci=0;ci<nMain;ci++) subcodes11.push(String(st['subcode_'+ci]||'').trim());
        var hasMark11=false, anyAbs11=false, allSubPass11=true, gTotal11=0;
        for(var si11=0;si11<nMain;si11++){
          var code11=subcodes11[si11]||'';
          var sch11=(typeof _DASH11_SCHEME!=='undefined'&&_DASH11_SCHEME[code11])||(typeof _DASH11_DEF!=='undefined'?_DASH11_DEF:{th:85,pr:15,thMin:28,prMin:5});
          var subMax11=sch11.th+sch11.pr;
          var subName11=(typeof _DASH11_NAMES!=='undefined'&&_DASH11_NAMES[code11])||code11||(S.mainSubs&&S.mainSubs[si11])||('Sub '+(si11+1));
          var aTh11=_getDashMark11(ri,si11,'a','th');
          var aPr11=_getDashMark11(ri,si11,'a','pr');
          var qTh11=_getDashMark11(ri,si11,'q','th'); var qPr11=_getDashMark11(ri,si11,'q','pr');
          var hTh11=_getDashMark11(ri,si11,'h','th'); var hPr11=_getDashMark11(ri,si11,'h','pr');
          var aThAbs11=(aTh11==='ABS');
          if(aThAbs11||(aTh11!==''&&!aThAbs11)) hasMark11=true;
          if(aThAbs11){ anyAbs11=true; continue; }
          if(aTh11==='') continue;
          var aThN11=parseFloat(aTh11)||0, aPrN11=parseFloat(aPr11)||0;
          var qTot11=((qTh11!==''||qPr11!=='')?(parseFloat(qTh11)||0)+(parseFloat(qPr11)||0):null);
          var hTot11=((hTh11!==''||hPr11!=='')?(parseFloat(hTh11)||0)+(parseFloat(hPr11)||0):null);
          var q5_11=(subMax11>0&&qTot11!==null)?Math.round(qTot11/subMax11*WQ*100)/100:0;
          var h5_11=(subMax11>0&&hTot11!==null)?Math.round(hTot11/subMax11*WH*100)/100:0;
          var a90_11=subMax11>0?Math.round(aThN11/subMax11*WA*100)/100:0; // Annual TH only for 11th (PR comes from Q+H)
          // For 11th/12th: final = Q5+H5+Annual TH scaled
          var subFinal11=Math.round(q5_11+h5_11+a90_11);
          gTotal11+=subFinal11;
          q5tot+=q5_11; h5tot+=h5_11; a90tot+=a90_11;
          var subPass11=(aThN11>=sch11.thMin&&(sch11.pr===0||(aPrN11>=sch11.prMin)));
          if(!subPass11) allSubPass11=false;
          if(subName11){
            if(!subMap[subName11]) subMap[subName11]={name:subName11,pass:0,fail:0,appeared:0};
            subMap[subName11].appeared++;
            if(subPass11) subMap[subName11].pass++; else subMap[subName11].fail++;
          }
        }
        grandTotal=Math.round(gTotal11);
        var maxTot11=nMain*100;
        pct=hasMark11&&grandTotal>0?Math.round(grandTotal/maxTot11*10000)/100:0;
        var passOk11=hasMark11&&!anyAbs11&&allSubPass11&&pct>=33;
        result=!hasMark11?'NO_DATA':anyAbs11?'ABS':passOk11?'PASS':'FAIL';
        if(hasMark11&&!anyAbs11){ if(pct>=85)gr='A+';else if(pct>=75)gr='A';else if(pct>=60)gr='B';else if(pct>=45)gr='C';else if(pct>=33)gr='D';else if(pct>=20)gr='E1';else gr='E2'; }
      }catch(e){ result='NO_DATA'; }
    }
    // ── Class 1-8: Annual marks (S.marks.a) — main calculation ──
    else {
      try{
        var hasMark18=false, gTotal18=0, gMax18=0, allSubPass18=true, anyAbs18=false;
        var maxA18=S.maxM&&S.maxM.a?S.maxM.a:100;
        var maxM18=S.maxM&&S.maxM.m?S.maxM.m:100;
        var wA18=(S.w&&S.w.a!==undefined)?S.w.a:100;
        var wH18=(S.w&&S.w.h!==undefined)?S.w.h:0;
        for(var si18=0;si18<nMain;si18++){
          var km18=ri+'_'+si18;
          var subName18=(S.mainSubs&&S.mainSubs[si18])||('Sub '+(si18+1));
          var aTh18=(S.marks&&S.marks.a&&S.marks.a[km18]!==undefined)?S.marks.a[km18]:'';
          var hTh18=(S.marks&&S.marks.h&&S.marks.h[km18]!==undefined)?S.marks.h[km18]:'';
          if(aTh18===''&&hTh18==='') continue;
          hasMark18=true;
          var aThAbs18=(aTh18==='ABS'||aTh18==='AB');
          if(aThAbs18){ anyAbs18=true; if(!subMap[subName18]) subMap[subName18]={name:subName18,pass:0,fail:0,appeared:0}; continue; }
          var aThN18=parseFloat(aTh18)||0;
          var hThN18=parseFloat(hTh18)||0;
          var subTotal18=Math.round(aThN18*wA18/100 + hThN18*wH18/100);
          a90tot+=aThN18;
          h5tot+=hThN18;
          gTotal18+=subTotal18;
          gMax18+=maxM18;
          // Pass: annual marks >= 33% of annual max
          var subPass18=aThN18>=(maxA18*0.33);
          if(!subPass18) allSubPass18=false;
          if(!subMap[subName18]) subMap[subName18]={name:subName18,pass:0,fail:0,appeared:0};
          subMap[subName18].appeared++;
          if(subPass18) subMap[subName18].pass++; else subMap[subName18].fail++;
        }
        grandTotal=gTotal18;
        pct=hasMark18&&gMax18>0?Math.round(gTotal18/gMax18*10000)/100:0;
        var passOk18=hasMark18&&!anyAbs18&&allSubPass18&&pct>=33;
        result=!hasMark18?'NO_DATA':anyAbs18?'ABS':passOk18?'PASS':'FAIL';
        if(hasMark18&&!anyAbs18){ if(pct>=85)gr='A+';else if(pct>=75)gr='A';else if(pct>=60)gr='B';else if(pct>=45)gr='C';else if(pct>=33)gr='D';else if(pct>=20)gr='E1';else gr='E2'; }
      }catch(e){ result='NO_DATA'; }
    }

    if(result==='PASS'){ pass++; if(gr) grades[gr]=(grades[gr]||0)+1; }
    else if(result==='FAIL'){ fail++; if(gr) grades[gr]=(grades[gr]||0)+1; }
    else if(result==='ABS') abs++;
    else noData++;

    rows.push({ri:ri,name:st.name||'',anukra:st.anukra||'',total:grandTotal,pct:pct,result:result,gr:gr,
      q5:Math.round(q5tot*100)/100,h5:Math.round(h5tot*100)/100,a90:Math.round(a90tot*100)/100});
  }

  rows.sort(function(a,b){return b.total-a.total;});
  var topper=rows.find(function(r){return r.result==='PASS';});
  var passRows=rows.filter(function(r){return r.result==='PASS';});
  var lowest=passRows.length>0?passRows[passRows.length-1]:rows[rows.length-1];

  // Top/Weak subject across class
  var subKeys=Object.keys(subMap).filter(function(k){return subMap[k].appeared>0;});
  var topSubject='',weakSubject='';
  if(subKeys.length){
    subKeys.sort(function(a,b){return (subMap[b].pass/subMap[b].appeared)-(subMap[a].pass/subMap[a].appeared);});
    topSubject=subKeys[0]; weakSubject=subKeys[subKeys.length-1];
  }

  return {total:total,pass:pass,fail:fail,abs:abs,noData:noData,
    passPercent:total>0?Math.round(pass/total*1000)/10:0,
    grades:grades,topper:topper,lowest:lowest,
    subMap:subMap,rows:rows,topSubject:topSubject,weakSubject:weakSubject};
}

function _getProgressMarks(ri){
  var nMain=Math.max(1,(S.nMain||6)-1);
  var qSum=0,hSum=0,aSum=0,qCnt=0,hCnt=0,aCnt=0;
  var is11=(S.cls==='11'||S.cls==='12'||S.cls==='9'||S.cls==='10');
  for(var si=0;si<nMain;si++){
    var qTh=_getDashMark11(ri,si,'q','th'),qPr=_getDashMark11(ri,si,'q','pr');
    var hTh=_getDashMark11(ri,si,'h','th'),hPr=_getDashMark11(ri,si,'h','pr');
    var aTh=_getDashMark11(ri,si,'a','th'),aPr=_getDashMark11(ri,si,'a','pr');
    if(qTh!==''&&qTh!=='ABS'){qSum+=parseFloat(qTh)||0; qCnt++;}
    if(qPr!==''&&qPr!=='ABS') qSum+=parseFloat(qPr)||0;
    if(hTh!==''&&hTh!=='ABS'){hSum+=parseFloat(hTh)||0; hCnt++;}
    if(hPr!==''&&hPr!=='ABS') hSum+=parseFloat(hPr)||0;
    if(aTh!==''&&aTh!=='ABS'){aSum+=parseFloat(aTh)||0; aCnt++;}
    if(aPr!==''&&aPr!=='ABS') aSum+=parseFloat(aPr)||0;
  }
  return {q:qCnt>0?Math.round(qSum):null, h:hCnt>0?Math.round(hSum):null, a:aCnt>0?Math.round(aSum):null};
}

