/* ── AI Analysis State ── */
var _dashAI = { loading: false, result: '', activeTab: 'overview' };

/* ── Compute extended stats with percentile, trend, risk ── */
function computeDashStatsExtended(stats) {
  var rows = stats.rows.filter(function(r){ return r.result==='PASS'||r.result==='FAIL'; });
  // Percentile for each student
  var sorted = rows.slice().sort(function(a,b){ return a.pct-b.pct; });
  sorted.forEach(function(r,i){ r.percentile = Math.round((i/Math.max(sorted.length-1,1))*100); });

  // Average per subject (Annual phase)
  var subAvg = {};
  Object.keys(stats.subMap).forEach(function(sn){
    var sm = stats.subMap[sn];
    subAvg[sn] = sm.appeared>0 ? Math.round((sm.pass/sm.appeared)*100) : 0;
  });

  // Risk students: fail in 1+ subject OR pct < 40
  var atRisk = rows.filter(function(r){ return r.result==='FAIL' || r.pct < 40; });

  // Score bands
  var bands = { '90-100':0,'75-89':0,'60-74':0,'45-59':0,'33-44':0,'<33':0 };
  rows.forEach(function(r){
    if(r.pct>=90) bands['90-100']++;
    else if(r.pct>=75) bands['75-89']++;
    else if(r.pct>=60) bands['60-74']++;
    else if(r.pct>=45) bands['45-59']++;
    else if(r.pct>=33) bands['33-44']++;
    else bands['<33']++;
  });

  // Average marks
  var sumPct = rows.reduce(function(s,r){ return s+r.pct; },0);
  var avgPct = rows.length>0 ? (sumPct/rows.length).toFixed(1) : 0;

  // Median
  var medPct = 0;
  if(sorted.length>0){
    var mid=Math.floor(sorted.length/2);
    medPct = sorted.length%2===0 ? ((sorted[mid-1].pct+sorted[mid].pct)/2).toFixed(1) : sorted[mid].pct.toFixed(1);
  }

  // Std deviation
  var variance = rows.length>0 ? rows.reduce(function(s,r){ return s+Math.pow(r.pct-parseFloat(avgPct),2); },0)/rows.length : 0;
  var stdDev = Math.sqrt(variance).toFixed(1);

  return { subAvg:subAvg, atRisk:atRisk, bands:bands, avgPct:avgPct, medPct:medPct, stdDev:stdDev };
}

