function _erpSafeLoad(key, fallback) {
  try {
    var raw = localStorage.getItem(key);
    if (!raw) return fallback;
    var dec = (typeof rskDecompress === 'function') ? rskDecompress(raw) : raw;
    return JSON.parse(dec) || fallback;
  } catch(e) { return fallback; }
}
let registry    = _erpSafeLoad(erpKey('erp_students'),   []);
