  localStorage.setItem(erpKey('erp_attendance'), JSON.stringify(attendance));
  localStorage.setItem(erpKey('erp_fees'),       JSON.stringify(fees));
  localStorage.setItem(erpKey('erp_exams'),      JSON.stringify(exams));
