const subjectMap = {};

// ── Name→Code lookup — class-aware (9/10 aur 11/12 ke alag-alag maps) ──
const AF3_NAME_TO_CODE_910 = (function(){
  var map = {};
  Object.values(AF3_SCHEME_9_10).forEach(function(arr){
    if(!Array.isArray(arr)) return;
    arr.forEach(function(s){ map[s.name.toLowerCase()] = s.code; });
  });
  return map;
})();

const AF3_NAME_TO_CODE_1112 = (function(){
  var map = {};
  Object.values(AF3_SCHEME_11_12).forEach(function(arr){
    if(!Array.isArray(arr)) return;
    arr.forEach(function(s){ map[s.name.toLowerCase()] = s.code; });
  });
  return map;
})();

// Classes jinme subject codes NAHI hote — Nursery se Class 8 tak
// Inke liye Subject Codes column mein sirf subject NAAM dikhana hai
const AF3_NO_SUBCODE_CLASSES = ['Nursery','LKG','UKG','KG','Class 1','Class 2','Class 3','Class 4','Class 5','Class 6','Class 7','Class 8'];

// Convert a subject name to code — uses class-specific map
function af3ToCode(val, cls) {
  if(!val || val === '—') return val;
  // Strip suffixes like " (Voc)", " (Add)"
  var clean = val.replace(/\s*\((Voc|Add)\)\s*$/i, '').trim();
  // Nursery to Class 7 — koi subject code nahi hota, sirf subject naam dikhao
  if(AF3_NO_SUBCODE_CLASSES.indexOf(cls) > -1) return clean;
  // If already looks like a pure code (all digits), return as-is
  if(/^\d+$/.test(clean)) return clean;
  // Pick correct map based on class
  var map;
  if(cls === 'Class 11' || cls === 'Class 12') {
    map = AF3_NAME_TO_CODE_1112;
  } else {
    // 9/10 and all others default to 9/10 scheme
    map = AF3_NAME_TO_CODE_910;
  }
  return map[clean.toLowerCase()] || clean;
}

// Convert comma-separated subject string → array of 6 codes (class-aware)
function af3SubjCodes(mainsubj, addsubj, cls) {
  var parts = (mainsubj||'').split(', ').concat((addsubj||'').split(', '))
    .map(function(s){ return s.trim(); }).filter(Boolean)
    .map(function(s){ return af3ToCode(s, cls); });
  while(parts.length < 6) parts.push('');
  return parts.slice(0, 6);
}

