// ── AF3: Calculate Age from DOB ──
function af3CalcAge(dob) {
  var ageEl = document.getElementById('af3_age');
  if (!ageEl) return;
  if (!dob) { ageEl.value = ''; return; }
  var birth = new Date(dob);
  var today = new Date();
  var years = today.getFullYear() - birth.getFullYear();
  var m = today.getMonth() - birth.getMonth();
  if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) years--;
  ageEl.value = years >= 0 ? years : '';
}

// ── AF3 Number field validation ──
function af3ValidateNum(inp, exactLen, label) {
  var errId = 'err_' + inp.id;
  var errEl = document.getElementById(errId);
  if (!errEl) return;
  var val = inp.value.replace(/[^0-9]/g, '');
  inp.value = val; // ensure no non-digits
  if (val.length === 0) {
    // empty = no error shown
    errEl.style.display = 'none';
    inp.style.borderBottom = '';
  } else if (val.length < exactLen) {
    errEl.textContent = '❌ ' + label + ' दर्ज करें (' + val.length + '/' + exactLen + ')';
    errEl.style.display = 'block';
    inp.style.borderBottom = '2px solid #c00';
  } else {
    errEl.style.display = 'none';
    inp.style.borderBottom = '2px solid #16a34a';
  }
}

// ── AF3 Indian Number Format for Income (e.g. 5,67,345/-) ──
function af3FormatIncome(inp) {
  var raw = inp.value.replace(/[^0-9]/g,'');
  if(!raw){ inp.value=''; return; }
  // Indian format: last 3 digits, then groups of 2
  var num = parseInt(raw,10);
  var s = num.toString();
  var result = '';
  if(s.length <= 3) { result = s; }
  else {
    result = s.slice(-3);
    s = s.slice(0,-3);
    while(s.length > 2){ result = s.slice(-2) + ',' + result; s = s.slice(0,-2); }
    if(s.length) result = s + ',' + result;
  }
  inp.value = result + '/-';
  // Move cursor before /-
  try { inp.setSelectionRange(inp.value.length-2, inp.value.length-2); } catch(e){}
}


function af3ValidateEnroll(inp) {
  var v = inp.value.trim();
  var errEl = document.getElementById('err_af3_enroll');
  if (!v) {
    inp.style.borderBottom = '';
    if (errEl) errEl.style.display = 'none';
    return;
  }
  // Format: A26/651016/001 — Letter(s) + digits / 6digits / 3digits
  var valid = /^[A-Z]{1,3}[0-9]{2}\/[0-9]{6}\/[0-9]{3}$/.test(v);
  if (valid) {
    inp.style.borderBottom = '2px solid #16a34a';
    if (errEl) errEl.style.display = 'none';
  } else {
    inp.style.borderBottom = '2px solid #c00';
    if (errEl) { errEl.textContent = '❌ Format: A26/651016/001'; errEl.style.display = 'block'; }
  }
}

function af3ValidateMob(inp) {
  af3ValidateNum(inp, 10, '10 अंक का मोबाइल नंबर');
  if (inp.value.length === 10 && !/^[6-9]/.test(inp.value)) {
    var errEl = document.getElementById('err_' + inp.id);
    if (errEl) { errEl.textContent = '❌ मोबाइल नंबर 6-9 से शुरू होना चाहिए'; errEl.style.display = 'block'; }
    inp.style.borderBottom = '2px solid #c00';
  }
}

// ── Auto-fill defaults when Admission Form 3 tab opens ──
function initAdmForm3Defaults() {
  var yr = document.getElementById("af3_year");
  if(yr) {
    var _sess=(document.getElementById('sc_yr')?document.getElementById('sc_yr').value:'')||getCurrentSession();
    yr.value=_sess; yr._userModified=false;
    yr.readOnly=true; yr.style.background="#f0f4ff";
    yr.style.cursor="not-allowed"; yr.style.color="#1a3a6b";
    yr.title="School Details → Session से auto-fill";
  }
  var fn = document.getElementById("af3_formno");
  if(fn) {
    fn.value = (admList3.length + 1);
    fn.readOnly = true; fn.style.background = "#f0f4ff";
    fn.style.cursor = "not-allowed"; fn.style.color = "#1a3a6b";
  }
  // Auto-generate Admission No
  var ano = document.getElementById("af3_admno");
  if(ano && !ano.value) {
    var _yr = new Date().getFullYear();
    ano.value = 'ADM/' + _yr + '/' + String(admList3.length + 1).padStart(3,'0');
  }
  var sn = document.getElementById("af3_serialno");
  if(sn) {
    sn.value = (admList3.length + 1);
    sn.readOnly = true; sn.style.background = "#f0f4ff";
    sn.style.cursor = "not-allowed"; sn.style.color = "#1a3a6b";
  }
  var _todayStr = new Date().toISOString().split("T")[0];

  // Set max=today on all date fields (no future dates)
  ['af3_dob','af3_admdate2','af3_admdate'].forEach(function(id){
    var el = document.getElementById(id);
    if(el) el.max = _todayStr;
  });
  // DOB minimum date = 01/01/2005
  var dobEl = document.getElementById('af3_dob');
  if(dobEl) dobEl.min = '2005-01-01';
  // Admission Date minimum = 01/02/2026
  ['af3_admdate2','af3_admdate'].forEach(function(id){
    var el = document.getElementById(id);
    if(el) el.min = '2026-02-01';
  });

  var ad = document.getElementById("af3_admdate2");
  if(ad && !ad.value) { ad.value = _todayStr; }
  var sch = document.getElementById("af3_school");
  if(sch) {
    var schName = (SCHOOL_INFO && SCHOOL_INFO.name) || (document.getElementById("sc_name") ? document.getElementById("sc_name").value : "") || "";
    if(schName) {
      sch.value = schName; sch.readOnly = true;
      sch.style.background = "#f0f4ff"; sch.style.cursor = "not-allowed";
      sch.style.color = "#1a3a6b"; sch.style.fontWeight = "600";
    }
  }
  var udise = document.getElementById("af3_udise");
  if(udise) {
    var dise = (SCHOOL_INFO && SCHOOL_INFO.dise) || "";
    if(dise) {
      udise.value = dise; udise.readOnly = true;
      udise.style.background = "#f0f4ff"; udise.style.cursor = "not-allowed"; udise.style.color = "#1a3a6b";
    }
  }
  var dist = document.getElementById("af3_dist");
  if(dist) {
    var distVal = (SCHOOL_INFO && (SCHOOL_INFO.district || SCHOOL_INFO.block)) || (document.getElementById("sc_dist") ? document.getElementById("sc_dist").value : "") || "";
    if(distVal) {
      dist.value = distVal; dist.readOnly = true;
      dist.style.background = "#f0f4ff"; dist.style.cursor = "not-allowed"; dist.style.color = "#1a3a6b";
    }
  }
  var mpbseEl = document.getElementById("af3_mpbse");
  if(mpbseEl) {
    var mpbseVal = (SCHOOL_INFO && SCHOOL_INFO.mpbse) || "";
    mpbseEl.value = mpbseVal;
  }
  var addr = document.getElementById("af3_addr");
  if(addr) {
    var addrVal = (SCHOOL_INFO && SCHOOL_INFO.address) || "";
    if(addrVal) {
      addr.value = addrVal; addr.readOnly = true;
      addr.style.background = "#f0f4ff"; addr.style.cursor = "not-allowed"; addr.style.color = "#1a3a6b";
    }
  }
}
function loadAF3Photo(input) {
  if(!input.files || !input.files[0]) return;
  const reader = new FileReader();
  reader.onload = e => {
    const img = document.getElementById('af3_photoImg');
    const lbl = document.getElementById('af3_photoLabel');
    const rm  = document.getElementById('af3_photoRemoveBtn');
    img.src = e.target.result;
    img.style.display = 'block';
    if(lbl) lbl.style.display = 'none';
    if(rm) rm.style.display = 'block';
  };
  reader.readAsDataURL(input.files[0]);
  // Reset input value so same file can be re-selected after clear/tab-switch
  setTimeout(function(){ input.value = ''; }, 300);
}

function af3RemovePhoto() {
  const img = document.getElementById('af3_photoImg');
  const lbl = document.getElementById('af3_photoLabel');
  const rm  = document.getElementById('af3_photoRemoveBtn');
  const inp = document.getElementById('af3_photoInput');
  if(img){ img.src=''; img.style.display='none'; }
  if(lbl) lbl.style.display='';
  if(rm) rm.style.display='none';
  if(inp) inp.value='';
}

