function showIncompleteFieldsModal(){
  var modal = document.getElementById('incomplete-fields-modal');
  if(modal){ modal.style.display='flex'; }
  // Sync class filter with admission list
  var admCls = document.getElementById('admList3Class');
  var ifCls  = document.getElementById('ifCls');
  if(admCls && ifCls && admCls.value) ifCls.value = admCls.value;
  renderIncompleteTable();
}
function closeIncompleteModal(){
  var modal = document.getElementById('incomplete-fields-modal');
  if(modal) modal.style.display='none';
}

function ifGetFiltered(){
  var cls   = (document.getElementById('ifCls')   ? document.getElementById('ifCls').value   : '').trim();
  var sec   = (document.getElementById('ifSec')   ? document.getElementById('ifSec').value   : '').trim();
  var group = (document.getElementById('ifGroup') ? document.getElementById('ifGroup').value : '').trim();
  var show  = (document.getElementById('ifShow')  ? document.getElementById('ifShow').value  : 'any');

  var _ifGFEN=(typeof isEnglish==='function')?isEnglish():false;
  var _ifBase = _ifGFEN ? IF_FIELDS_EN : IF_FIELDS_HI;
  // Deduplicate
  _ifBase = _ifBase.filter(function(f,i,a){ return a.findIndex(function(x){return x[0]===f[0];})=== i; });
  var fields = _ifBase;
  if(group) fields = _ifBase.filter(function(f){ return f[2]===group; });
  if(show==='critical') fields = fields.filter(function(f){ return f[3]; });

  var data = admList3.filter(function(r){
    if(cls && r.class!==cls) return false;
    if(sec && r.section!==sec) return false;
    return true;
  });

  // For each student, compute which fields are blank
  var rows = [];
  data.forEach(function(r){
    var blanks = fields.filter(function(f){ return !(r[f[0]]||'').toString().trim(); });
    if(blanks.length>0) rows.push({r:r, blanks:blanks, fields:fields});
  });
  return {rows:rows, fields:fields, total:data.length};
}

function renderIncompleteTable(){
  var res = ifGetFiltered();
  var rows = res.rows, fields = res.fields, total = res.total;

  // Summary
  var sumEl = document.getElementById('ifSummary');
  if(sumEl){
    var critCount = rows.filter(function(x){ return x.blanks.some(function(f){return f[3];}); }).length;
    var _ifEN=(typeof isEnglish==='function')?isEnglish():false;
    sumEl.innerHTML = '📊 '+(_ifEN?'Out of':'कुल')+' <b>'+total+'</b> students '+(_ifEN?'—':'में से')+' <b style="color:#b91c1c;">'+rows.length+'</b> students '+(_ifEN?'have incomplete fields.':'के fields अधूरे हैं।')
      +(critCount?' &nbsp;|&nbsp; 🔴 <b>'+critCount+'</b> students '+(_ifEN?'have critical fields empty.':'के critical fields खाली हैं।'):'')
      +(rows.length===0?' &nbsp;<span style="color:#16a34a;font-weight:700;">✅ '+(_ifEN?'All students\' selected fields are complete!':'सभी students के selected fields पूरे हैं!')+'</span>':'');
  }

  // Thead
  var thead = document.getElementById('ifThead');
  if(thead){
    var _ifEN2=(typeof isEnglish==='function')?isEnglish():false;
    var ths = '<tr><th style="padding:8px 10px;text-align:left;min-width:30px;">'+(_ifEN2?'S.No.':'क्र.')+'</th>'
      +'<th style="padding:8px 10px;text-align:left;min-width:80px;">Adm No.</th>'
      +'<th style="padding:8px 10px;text-align:left;min-width:160px;">'+(_ifEN2?'Student Name':'छात्र नाम')+'</th>'
      +'<th style="padding:8px 10px;min-width:80px;">'+(_ifEN2?'Class':'कक्षा')+'</th>'
      +'<th style="padding:8px 10px;min-width:60px;">Sec.</th>';
    fields.forEach(function(f){
      ths += '<th style="padding:6px 8px;min-width:90px;font-size:11px;text-align:center;'+(f[3]?'color:#fca5a5;':'color:#93c5fd;')+'">'+f[1]+(f[3]?' 🔴':'')+'</th>';
    });
    ths += '<th style="padding:8px 10px;min-width:60px;">'+(_ifEN2?'Blank':'कुल खाली')+'</th></tr>';
    thead.innerHTML = ths;
  }

  // Tbody
  var tbody = document.getElementById('ifTbody');
  if(!tbody) return;
  if(!rows.length){
    var _ifEN3=(typeof isEnglish==='function')?isEnglish():false;
    tbody.innerHTML = '<tr><td colspan="'+(fields.length+6)+'" style="text-align:center;padding:40px;color:#16a34a;font-size:15px;font-weight:600;">✅ '+(_ifEN3?'No incomplete data found!':'कोई अधूरी जानकारी नहीं मिली!')+'</td></tr>';
    return;
  }
  var html = '';
  rows.forEach(function(item, i){
    var r = item.r;
    var blankKeys = item.blanks.map(function(f){return f[0];});
    var critBlanks = item.blanks.filter(function(f){return f[3];}).length;
    var rowBg = critBlanks>0 ? '#fff7f7' : (i%2===0?'#fffbeb':'#ffffff');
    html += '<tr style="background:'+rowBg+';" onmouseover="this.style.background=\'#fef3c7\'" onmouseout="this.style.background=\''+rowBg+'\'">';
    html += '<td style="padding:6px 10px;font-size:12px;">'+( i+1)+'</td>';
    html += '<td style="padding:6px 10px;font-weight:600;color:#1d4ed8;font-size:12px;">'+escHtml(r.admno||'—')+'</td>';
    html += '<td style="padding:6px 10px;font-weight:700;font-size:13px;">'+escHtml(r.sname||'—')+'</td>';
    html += '<td style="padding:6px 10px;text-align:center;font-size:12px;">'+escHtml(r.class||'—')+'</td>';
    html += '<td style="padding:6px 10px;text-align:center;font-size:12px;">'+escHtml(r.section||'—')+'</td>';
    fields.forEach(function(f){
      var isEmpty = blankKeys.indexOf(f[0])!==-1;
      if(isEmpty){
        var icon = f[3] ? '🔴' : '🟡';
        var _ifEN4=(typeof isEnglish==='function')?isEnglish():false; html += '<td style="text-align:center;padding:4px;background:'+(f[3]?'#fee2e2':'#fef9c3')+';font-size:14px;" title="'+f[1]+(_ifEN4?' is empty':' खाली है')+'">'+icon+'</td>';
      } else {
        html += '<td style="text-align:center;padding:4px;color:#d1fae5;font-size:12px;">✅</td>';
      }
    });
    var blankCount = item.blanks.length;
    var _ifEN6=(typeof isEnglish==='function')?isEnglish():false;
    html += '<td style="text-align:center;font-weight:700;padding:6px 10px;'+(critBlanks>0?'color:#b91c1c;':'color:#b45309;')+'">'+blankCount+'</td>';
    html += '</tr>';
    // Blank field names row (collapsible feel — always visible)
    if(item.blanks.length){
      html += '<tr style="background:'+(i%2===0?'#fef9c3':'#fff7ed')+';">';
      var _ifEN5=(typeof isEnglish==='function')?isEnglish():false;
      html += '<td colspan="5" style="padding:2px 10px 6px 28px;font-size:11px;color:#6b7280;">'+(_ifEN5?'Blank fields:':'खाली fields:')+'</td>';
      html += '<td colspan="'+(fields.length+1)+'" style="padding:2px 10px 6px 6px;font-size:11px;">';
      html += item.blanks.map(function(f){
        return '<span style="display:inline-block;margin:2px 4px 2px 0;padding:2px 8px;border-radius:10px;background:'+(f[3]?'#fecaca':'#fde68a')+';color:'+(f[3]?'#991b1b':'#78350f')+';font-weight:600;">'+f[1]+'</span>';
      }).join('');
      html += '</td></tr>';
    }
  });
  tbody.innerHTML = html;
}

function exportIncompleteExcel(){
  var res = ifGetFiltered();
  var _ifENx=(typeof isEnglish==='function')?isEnglish():false; if(!res.rows.length) return alert(_ifENx?'No incomplete records found!':'कोई incomplete record नहीं मिला!');
  var exRows = res.rows.map(function(item, i){
    var r = item.r;
    var _ifENxl=(typeof isEnglish==='function')?isEnglish():false;
    var obj = {[_ifENxl?'S.No.':'क्र.']:i+1, 'Adm. No.':r.admno||'', [_ifENxl?'Student Name':'छात्र नाम']:r.sname||'', [_ifENxl?'Class':'कक्षा']:r.class||'', 'Section':r.section||''};
    res.fields.forEach(function(f){
      var isEmpty = !((r[f[0]]||'').toString().trim());
      obj[f[1]] = isEmpty ? (_ifENxl?'❌ Empty':'❌ खाली') : '✅';
    });
    obj[_ifENxl?'Total Blank':'कुल खाली Fields'] = item.blanks.length;
    obj[_ifENxl?'Blank Fields List':'खाली Fields की सूची'] = item.blanks.map(function(f){return f[1];}).join(', ');
    return obj;
  });
  var ws = XLSX.utils.json_to_sheet(exRows);
  var wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, 'Incomplete Fields');
  XLSX.writeFile(wb, 'IncompleteFields_Report.xlsx');
}

function printIncompleteReport(){
  var res = ifGetFiltered();
  if(!res.rows.length) return alert('कोई incomplete record नहीं मिला!');
  var cls = document.getElementById('ifCls') ? document.getElementById('ifCls').value : '';
  var sec = document.getElementById('ifSec') ? document.getElementById('ifSec').value : '';
  var html = '<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Incomplete Fields Report</title>'
    +'<style>body{font-family:Arial,sans-serif;font-size:11pt;margin:20px;}h2{color:#1e3a5f;margin-bottom:4px;}table{width:100%;border-collapse:collapse;margin-top:10px;}th{background:#1e3a5f;color:#fff;padding:6px 8px;text-align:left;font-size:10pt;}td{padding:5px 8px;border-bottom:1px solid #e5e7eb;font-size:10pt;}.crit{background:#fee2e2;color:#991b1b;font-weight:700;}.warn{background:#fef9c3;color:#78350f;font-weight:600;}.ok{color:#16a34a;}tr:nth-child(even){background:#f9fafb;}@media print{button{display:none;}}</style>'
    +'</head><body>';
  html += '<h2>⚠️ Incomplete Fields Report — Admission List</h2>';
  var _prEN=(typeof isEnglish==='function')?isEnglish():false;
  html += '<p style="color:#6b7280;margin:4px 0 12px;">'+(_prEN?'Class:':'कक्षा:')+' <b>'+(cls||(_prEN?'All':'सभी'))+'</b> &nbsp;|&nbsp; Section: <b>'+(sec||(_prEN?'All':'सभी'))+'</b> &nbsp;|&nbsp; '+(_prEN?'Date:':'दिनांक:')+' <b>'+new Date().toLocaleDateString(_prEN?'en-IN':'hi-IN')+'</b></p>';
  html += '<p>'+(_prEN?'Out of':'कुल')+' <b>'+res.total+'</b> students '+(_prEN?'—':'में से')+' <b style="color:#b91c1c;">'+res.rows.length+'</b> students '+(_prEN?'have incomplete fields.':'के fields अधूरे हैं।')+'</p>';
  html += '<table><thead><tr><th>'+(_prEN?'S.No.':'क्र.')+'</th><th>Adm No.</th><th>'+(_prEN?'Student Name':'छात्र नाम')+'</th><th>'+(_prEN?'Class':'कक्षा')+'</th><th>Sec.</th><th>'+(_prEN?'Blank Count':'कुल खाली')+'</th><th>'+(_prEN?'Blank Fields List':'खाली Fields की सूची')+'</th></tr></thead><tbody>';
  res.rows.forEach(function(item,i){
    var r = item.r;
    var hasCrit = item.blanks.some(function(f){return f[3];});
    var critFields = item.blanks.filter(function(f){return f[3];}).map(function(f){return '<span class="crit" style="display:inline-block;margin:1px 3px;padding:1px 6px;border-radius:8px;">'+f[1]+'</span>';}).join('');
    var warnFields = item.blanks.filter(function(f){return !f[3];}).map(function(f){return '<span class="warn" style="display:inline-block;margin:1px 3px;padding:1px 6px;border-radius:8px;">'+f[1]+'</span>';}).join('');
    html += '<tr>'
      +'<td>'+(i+1)+'</td>'
      +'<td style="font-weight:700;color:#1d4ed8;">'+escHtml(r.admno||'—')+'</td>'
      +'<td style="font-weight:700;">'+escHtml(r.sname||'—')+'</td>'
      +'<td style="text-align:center;">'+escHtml(r.class||'—')+'</td>'
      +'<td style="text-align:center;">'+escHtml(r.section||'—')+'</td>'
      +'<td style="text-align:center;font-weight:700;color:'+(hasCrit?'#b91c1c':'#b45309')+';">'+item.blanks.length+'</td>'
      +'<td>'+critFields+warnFields+'</td>'
      +'</tr>';
  });
  html += '</tbody></table>';
  html += '<p style="margin-top:20px;font-size:10pt;color:#6b7280;">🔴 = Critical (अनिवार्य) | 🟡 = Important</p>';
  html += '<script>window.onload=function(){window.print();}<\/script></body></html>';
  var w = window.open('','_blank','width=1000,height=700');
  if(w){ w.document.write(html); w.document.close(); }
}
// ══════════════════════════════════════════════
//  END INCOMPLETE FIELDS TRACKER
// ══════════════════════════════════════════════

function printAdmForm3() {
  const area = document.getElementById('admForm3PrintArea');
  // Update watermark before printing
  var wm = document.getElementById('af3_logo_watermark');
  if(wm){
    if(typeof SCHOOL_LOGO !== 'undefined' && SCHOOL_LOGO){
      wm.innerHTML = '<img src="'+SCHOOL_LOGO+'" style="width:100%;height:100%;object-fit:contain;">';
    } else {
      wm.innerHTML = '';
    }
  }

  // ── Build preview HTML ──
  const printCSS = `
    @page { size: A4; margin: 15mm; }
    body { font-family: 'Times New Roman', serif; font-size: 12pt; color: #000; margin: 0; padding: 0; }
    input[type=text], input:not([type=checkbox]):not([type=radio]):not([type=file]):not([type=date]) { border: none; border-bottom: 1px solid #000 !important; outline: none; background: transparent; }
    input[type=date] { border: none; outline: none; background: transparent; }
    table { border-collapse: collapse; width: 100%; }
    td, th { border: 1px solid #000; padding: 4px 7px; }
    #af3_logo_watermark { position:absolute;top:50%;left:50%;transform:translate(-50%,-50%);width:60%;aspect-ratio:1/1;pointer-events:none;z-index:0;opacity:0.07;display:flex;align-items:center;justify-content:center; }
    #af3_logo_watermark img { width:100%;height:100%;object-fit:contain; }
    #admForm3PrintArea { position:relative;overflow:hidden; }
  `;
  const previewHTML = `<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Admission Form — Print Preview</title><style>${printCSS}</style></head><body>${area.innerHTML}</body></html>`;

  // ── Remove old modal if any ──
  var old = document.getElementById('af3PreviewModal');
  if(old) old.remove();

  // ── Create modal ──
  var modal = document.createElement('div');
  modal.id = 'af3PreviewModal';
  modal.style.cssText = 'position:fixed;inset:0;z-index:99999;background:rgba(0,0,0,0.7);display:flex;flex-direction:column;align-items:center;justify-content:flex-start;padding:16px;box-sizing:border-box;overflow:auto;';

  // toolbar
  var toolbar = document.createElement('div');
  toolbar.style.cssText = 'display:flex;align-items:center;gap:10px;background:#1a237e;color:#fff;padding:10px 18px;border-radius:10px 10px 0 0;width:100%;max-width:860px;box-sizing:border-box;flex-shrink:0;';
  toolbar.innerHTML = `
    <span style="font-size:15px;font-weight:700;flex:1;">🖨️ Print Preview — Admission Form</span>
    <button id="af3PreviewPrintBtn" style="background:#22c55e;color:#fff;border:none;padding:7px 18px;border-radius:6px;font-size:13px;font-weight:700;cursor:pointer;">🖨️ Print / PDF</button>
    <button id="af3PreviewCloseBtn" style="background:#ef4444;color:#fff;border:none;padding:7px 14px;border-radius:6px;font-size:13px;font-weight:700;cursor:pointer;">✕ Close</button>
  `;

  // iframe
  var iframe = document.createElement('iframe');
  iframe.id = 'af3PreviewFrame';
  iframe.style.cssText = 'width:100%;max-width:860px;flex:1;min-height:600px;border:none;background:#fff;border-radius:0 0 10px 10px;box-shadow:0 8px 40px rgba(0,0,0,0.4);';

  modal.appendChild(toolbar);
  modal.appendChild(iframe);
  document.body.appendChild(modal);

  // Write content into iframe
  iframe.onload = function(){};
  iframe.contentDocument.open();
  iframe.contentDocument.write(previewHTML);
  iframe.contentDocument.close();

  // Buttons
  document.getElementById('af3PreviewPrintBtn').onclick = function(){
    iframe.contentWindow.focus();
    iframe.contentWindow.print();
  };
  document.getElementById('af3PreviewCloseBtn').onclick = function(){
    modal.remove();
  };
  // Close on backdrop click
  modal.addEventListener('click', function(e){ if(e.target === modal) modal.remove(); });
}

// ===================== REGISTRY =====================
function renderRegistry() {
  const cls    = document.getElementById('filterClass').value;
  const gender = document.getElementById('filterGender').value;
  const search = (document.getElementById('globalSearch').value || '').toLowerCase();

  let data = registry.filter(s => {
    const matchCls    = !cls    || s.class === cls;
    const matchGender = !gender || s.gender === gender;
    const matchSearch = !search || s.name.toLowerCase().includes(search) || s.admNo.toLowerCase().includes(search);
    return matchCls && matchGender && matchSearch;
  });

  const tbody = document.getElementById('registryBody');
  if (!data.length) { tbody.innerHTML = '<tr><td colspan="14" style="text-align:center;padding:30px;color:#999;">No students found.</td></tr>'; return; }

  tbody.innerHTML = data.map((s, i) => `
    <tr>
      <td>${i+1}</td>
      <td>${s.photo ? `<img src="${s.photo}" style="width:36px;height:36px;object-fit:cover;border-radius:50%;border:2px solid #ddd;">` : '<span style="color:#ccc;">—</span>'}</td>
      <td><b>${s.admNo}</b></td>
      <td><b>${s.name}</b></td>
      <td>${s.class}</td>
      <td>${s.sec||'—'}</td>
      <td><span class="badge ${s.gender==='Male'?'badge-blue':s.gender==='Female'?'badge-red':'badge-orange'}">${s.gender}</span></td>
      <td>${s.dob||'—'}</td>
      <td>${s.father||s.fname||s.fName||'—'}</td>
      <td>${s.fmobile||'—'}</td>
      <td><span class="badge badge-blue">${s.cat}</span></td>
      <td>${s.trans==='Yes'?'🚌 Yes':'—'}</td>
      <td>${s.admFee?'₹'+s.admFee:'—'}</td>
      <td style="white-space:nowrap;">
        <button onclick="viewProfile(${registry.indexOf(s)})" style="background:none;border:none;cursor:pointer;font-size:16px;" title="View">👁️</button>
        <button onclick="editStudent(${registry.indexOf(s)})" style="background:none;border:none;cursor:pointer;font-size:16px;" title="Edit">✏️</button>
        <button onclick="deleteStudent(${registry.indexOf(s)})" style="background:none;border:none;cursor:pointer;font-size:16px;" title="Delete">🗑️</button>
      </td>
    </tr>
  `).join('');
}

function populateClassFilters() {
  // ── allowed_classes filter ──
  var _acStr2 = (currentUser && currentUser.allowed_classes) || 'ALL';
  var _acFilter2 = (_acStr2 && _acStr2 !== 'ALL') ? _acStr2.split(',').map(s=>s.trim()) : null;
  const classes = [...new Set(registry.map(s => s.class))].sort(_classCmp).filter(c => {
    if(!_acFilter2) return true;
    return typeof _isClassAllowed==='function' ? _isClassAllowed(c, _acFilter2) : true;
  });
  ['filterClass','feeClassFilter','examClassFilter','attClass','rptClass','rptExamClass'].forEach(id => {
    const el = document.getElementById(id);
    if (!el) return;
    const cur = el.value;
    el.innerHTML = (id === 'attClass') ? '<option value="">Select Class</option>' : '<option value="">All Classes</option>';
    classes.forEach(c => el.innerHTML += `<option ${c===cur?'selected':''}>${c}</option>`);
  });
}

function viewProfile(idx) {
  const s = registry[idx];
  const body = document.getElementById('profileBody');
  body.innerHTML = `
    <div style="display:grid;grid-template-columns:auto 1fr;gap:20px;align-items:start;">
      <div style="text-align:center;">
        ${s.photo ? `<img src="${s.photo}" style="width:100px;height:100px;object-fit:cover;border-radius:10px;border:3px solid var(--accent);">` : '<div style="width:100px;height:100px;background:#e0e0e0;border-radius:10px;display:flex;align-items:center;justify-content:center;font-size:32px;">👤</div>'}
        <div style="margin-top:8px;font-weight:700;font-size:15px;">${s.name}</div>
        <div style="font-size:12px;color:#666;">${s.admNo}</div>
        <span class="badge badge-blue" style="margin-top:6px;">${s.class}${s.sec?' - '+s.sec:''}</span>
      </div>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;font-size:12px;">
        ${profileRow('DOB', s.dob)} ${profileRow('Age', s.age+' yrs')}
        ${profileRow('Gender', s.gender)} ${profileRow('Blood', s.blood)}
        ${profileRow('Category', s.cat)} ${profileRow('Aadhaar', s.aadhar)}
        ${profileRow("Father", s.fname)} ${profileRow("Father Mobile", s.fmobile)}
        ${profileRow("Mother", s.mname)} ${profileRow("Mother Mobile", s.mmobile)}
        ${profileRow('Address', s.addr+', '+s.city)} ${profileRow('PIN', s.pin)}
        ${profileRow('Transport', s.trans)} ${profileRow('Medium', s.med)}
        ${profileRow('Subjects', s.subs)} ${profileRow('Medical', s.medical||'None')}
        ${profileRow('Adm Date', s.admDate)} ${profileRow('Adm Fee', '₹'+s.admFee)}
      </div>
    </div>`;
  document.getElementById('profileModal').classList.add('open');
}
function profileRow(k, v) { return `<div style="background:#f8f9fa;padding:6px 10px;border-radius:6px;"><span style="color:#999;font-size:10px;">${k}</span><br><b>${v||'—'}</b></div>`; }

function editStudent(idx) {
  const s = registry[idx];
  editingIdx = idx;
  showSection('admission');
  setTimeout(() => {
    ['name','dob','age','nation','religion','aadhar','scholar','apaar','samagra',
     'fname','fmobile','mname','mmobile','gname','grel','addr','city','state','pin',
     'sec','prevSchool','medical','emName','emPhone','busStop','admFee','receipt',
     'declarationDate','verBy','admDate'].forEach(id => {
      const el = document.getElementById(id);
      if (el && s[id] !== undefined) el.value = s[id];
    });
    document.getElementById('gender').value = s.gender;
    document.getElementById('blood').value = s.blood;
    document.getElementById('cat').value = s.cat;
    document.getElementById('classSelect').value = s.class;
    document.getElementById('classSelect').dispatchEvent(new Event('change'));
    document.getElementById('med').value = s.med;
    document.getElementById('trans').value = s.trans;
    document.getElementById('admNo').value = s.admNo;
    if (s.photo) {
      const img = document.getElementById('photoPreview');
      img.src = s.photo; img.style.display = 'block';
    }
    // Tick saved subjects
    setTimeout(() => {
      const saved = (s.subs || '').split(', ');
      document.querySelectorAll('#subjectContainer input[name="subjects"]').forEach(cb => {
        cb.checked = saved.includes(cb.value);
      });
    }, 100);
  }, 100);
}

function deleteStudent(idx) {
  if (!confirm('Delete ' + registry[idx].name + '?')) return;
  registry.splice(idx, 1);
  save(); renderRegistry();
}

// ===================== DASHBOARD =====================
function updateDashboard() {
  const boys = registry.filter(s => s.gender === 'Male').length;
  const girls = registry.filter(s => s.gender === 'Female').length;
  const totalFee = fees.filter(f => f.status === 'Paid').reduce((a, f) => a + (+f.amount||0), 0);
  const dueFee   = fees.filter(f => f.status === 'Due').reduce((a, f) => a + (+f.amount||0), 0);

  document.getElementById('dashStats').innerHTML = `
    ${statCard(registry.length, 'Total Students', '#1976d2')}
    ${statCard(boys, 'Boys', '#1565c0')}
    ${statCard(girls, 'Girls', '#c62828')}
    ${statCard([...new Set(registry.map(s=>s.class))].length, 'Classes', '#2e7d32')}
    ${statCard('₹'+totalFee.toLocaleString(), 'Fee Collected', '#2e7d32')}
    ${statCard('₹'+dueFee.toLocaleString(), 'Fee Pending', '#c62828')}
  `;

  // Class chart
  const classCounts = {};
  registry.forEach(s => { classCounts[s.class] = (classCounts[s.class]||0)+1; });
  const maxC = Math.max(...Object.values(classCounts), 1);
  document.getElementById('classChart').innerHTML = Object.entries(classCounts)
    .sort((a,b) => a[0].localeCompare(b[0])).slice(0,8)
    .map(([cls, cnt]) => `
      <div class="chart-bar-row">
        <span class="chart-bar-label">${cls}</span>
        <div class="chart-bar-bg"><div class="chart-bar-fill" style="width:${(cnt/maxC*100).toFixed(0)}%;background:#1976d2;">${cnt}</div></div>
      </div>`).join('');

  // Fee chart (by month)
  const monthFee = {};
  fees.filter(f=>f.status==='Paid').forEach(f => {
    const m = f.period || f.date?.slice(0,7) || 'N/A';
    monthFee[m] = (monthFee[m]||0) + (+f.amount||0);
  });
  const maxF = Math.max(...Object.values(monthFee), 1);
  document.getElementById('feeChart').innerHTML = Object.entries(monthFee).slice(-6)
    .map(([m, amt]) => `
      <div class="chart-bar-row">
        <span class="chart-bar-label">${m}</span>
        <div class="chart-bar-bg"><div class="chart-bar-fill" style="width:${(amt/maxF*100).toFixed(0)}%;background:#2e7d32;">₹${amt.toLocaleString()}</div></div>
      </div>`).join('') || '<p style="color:#999;font-size:12px;">No fee data yet.</p>';

  // Recent admissions
  const recent = [...registry].slice(-5).reverse();
  document.getElementById('recentBody').innerHTML = recent.map(s => `
    <tr>
      <td><b>${s.admNo}</b></td><td>${s.name}</td><td>${s.class}</td>
      <td>${s.admittedOn||'—'}</td><td>${s.admFee?'₹'+s.admFee:'—'}</td>
    </tr>`).join('') || '<tr><td colspan="5" style="text-align:center;color:#999;">No admissions yet.</td></tr>';
}
function statCard(val, lbl, color) {
  return `<div class="stat-card" style="border-left-color:${color};"><div class="val" style="color:${color};">${val}</div><div class="lbl">${lbl}</div></div>`;
}

// ===================== ATTENDANCE =====================
function setTodayDate() {
  const d = document.getElementById('attDate');
  if (d && !d.value) d.value = new Date().toISOString().split('T')[0];
}
function populateAttClasses() {
  populateClassFilters();
}
function loadAttendance() {
  const cls   = document.getElementById('attClass').value;
  const date  = document.getElementById('attDate').value;
  if (!cls || !date) return;
  const students = (cls === 'all') ? _getAllStudents() : _getAllStudents().filter(s => s.class === cls);
  const key = date + '_' + cls;
  const saved = attendance[key] || {};

  document.getElementById('attendanceList').innerHTML = students.map(s => {
    const status = saved[s.admNo] || 'P';
    return `
      <div class="att-card" style="background:${status==='P'?'#e8f5e9':status==='A'?'#ffebee':'#fff3e0'};">
        <div>
          ${s.photo ? `<img src="${s.photo}" style="width:32px;height:32px;object-fit:cover;border-radius:50%;float:left;margin-right:8px;">` : ''}
          <div style="font-size:13px;font-weight:600;">${s.name}</div>
          <div style="font-size:11px;color:#666;">${s.admNo}</div>
        </div>
        <div class="att-btns">
          <button class="att-btn att-P" onclick="setAtt('${s.admNo}','P',this)" style="font-weight:${status==='P'?'900':'400'};border:${status==='P'?'2px solid #2e7d32':'2px solid transparent'};">P</button>
          <button class="att-btn att-A" onclick="setAtt('${s.admNo}','A',this)" style="font-weight:${status==='A'?'900':'400'};border:${status==='A'?'2px solid #c62828':'2px solid transparent'};">A</button>
          <button class="att-btn att-L" onclick="setAtt('${s.admNo}','L',this)" style="font-weight:${status==='L'?'900':'400'};border:${status==='L'?'2px solid #e65100':'2px solid transparent'};">L</button>
        </div>
      </div>`;
  }).join('');
  updateAttSummary();
}

let attTemp = {};
function setAtt(admNo, status, btn) {
  const date  = document.getElementById('attDate').value;
  const cls   = document.getElementById('attClass').value;
  const key   = date + '_' + cls;
  if (!attendance[key]) attendance[key] = {};
  attendance[key][admNo] = status;
  attTemp[admNo] = status;
  // Update card color
  const card = btn.closest('.att-card');
  card.style.background = status==='P'?'#e8f5e9':status==='A'?'#ffebee':'#fff3e0';
  card.querySelectorAll('.att-btn').forEach(b => {
    const s = b.textContent.trim();
    b.style.fontWeight = s === status ? '900' : '400';
    b.style.border = s === status ? `2px solid ${s==='P'?'#2e7d32':s==='A'?'#c62828':'#e65100'}` : '2px solid transparent';
  });
  updateAttSummary();
}

function markAllPresent() {
  const date  = document.getElementById('attDate').value;
  const cls   = document.getElementById('attClass').value;
  if (!cls||!date) return alert('Select class and date first!');
  const key = date+'_'+cls;
  if (!attendance[key]) attendance[key] = {};
  _getAllStudents().filter(s=>s.class===cls).forEach(s => attendance[key][s.admNo] = 'P');
  loadAttendance();
}

function saveAttendance() {
  const cls   = document.getElementById('attClass').value;
  const date  = document.getElementById('attDate').value;
  if (!cls||!date) return alert('Select class and date!');
  save();
  alert('✅ Attendance saved!');
}

function updateAttSummary() {
  const date  = document.getElementById('attDate').value;
  const cls   = document.getElementById('attClass').value;
  if (!cls||!date) return;
  const key = date+'_'+cls;
  const rec = attendance[key] || {};
  const P = Object.values(rec).filter(v=>v==='P').length;
  const A = Object.values(rec).filter(v=>v==='A').length;
  const L = Object.values(rec).filter(v=>v==='L').length;
  const total = _getAllStudents().filter(s=>s.class===cls).length;
  document.getElementById('attSummary').innerHTML = `
    <div style="display:flex;gap:14px;flex-wrap:wrap;">
      <div class="stat-card" style="border-left-color:#2e7d32;padding:12px 18px;"><div class="val" style="color:#2e7d32;font-size:22px;">${P}</div><div class="lbl">Present</div></div>
      <div class="stat-card" style="border-left-color:#c62828;padding:12px 18px;"><div class="val" style="color:#c62828;font-size:22px;">${A}</div><div class="lbl">Absent</div></div>
      <div class="stat-card" style="border-left-color:#e65100;padding:12px 18px;"><div class="val" style="color:#e65100;font-size:22px;">${L}</div><div class="lbl">Leave</div></div>
      <div class="stat-card" style="border-left-color:#1976d2;padding:12px 18px;"><div class="val" style="color:#1976d2;font-size:22px;">${total}</div><div class="lbl">Total</div></div>
    </div>`;
}

function showAttReport() {
  showSection('reports');
  document.getElementById('rptMonth').value = new Date().toISOString().slice(0,7);
  generateAttReport();
}

// ===================== FEES =====================
function populateFeeFilters() { populateClassFilters(); }

function renderFeeStats() {
  const paid = fees.filter(f=>f.status==='Paid').reduce((a,f)=>a+(+f.amount||0),0);
  const due  = fees.filter(f=>f.status==='Due').reduce((a,f)=>a+(+f.amount||0),0);
  document.getElementById('feeStats').innerHTML =
    statCard('₹'+paid.toLocaleString(),'Total Collected','#2e7d32') +
    statCard('₹'+due.toLocaleString(),'Total Pending','#c62828') +
    statCard(fees.filter(f=>f.status==='Paid').length,'Paid Entries','#1976d2') +
    statCard(fees.filter(f=>f.status==='Due').length,'Due Entries','#e65100');
}

function renderFees() {
  const cls    = document.getElementById('feeClassFilter').value;
  const status = document.getElementById('feeStatusFilter').value;
  const allStudents = _getAllStudents();
  let data = fees.filter(f => {
    const s = allStudents.find(r => r.admNo === f.admNo);
    return (!cls || (s && s.class === cls)) && (!status || f.status === status);
  });
  const tbody = document.getElementById('feeBody');
  if (!data.length) { tbody.innerHTML='<tr><td colspan="10" style="text-align:center;padding:30px;color:#999;">No fee records.</td></tr>'; return; }
  tbody.innerHTML = data.map((f,i) => {
    const s = allStudents.find(r=>r.admNo===f.admNo)||{};
    return `<tr>
      <td><b>${f.admNo}</b></td><td>${s.name||'—'}</td><td>${s.class||'—'}</td>
      <td>${f.period||'—'}</td><td><b>₹${f.amount}</b></td><td>${f.mode||'—'}</td>
      <td>${f.date||'—'}</td><td>${f.receipt||'—'}</td>
      <td><span class="badge ${f.status==='Paid'?'badge-green':'badge-red'}">${f.status}</span></td>
      <td><button onclick="deleteFee(${fees.indexOf(f)})" style="background:none;border:none;cursor:pointer;color:#c62828;font-size:15px;">🗑️</button></td>
    </tr>`;
  }).join('');
}

function openAddFeeModal() {
  updateDropdowns();
  document.getElementById('feeDateModal').value = new Date().toISOString().split('T')[0];
  document.getElementById('feeModal').classList.add('open');
}

function saveFeeEntry() {
  const admNo = document.getElementById('feeStudentSel').value;
  if (!admNo) return alert('Select a student!');
  fees.push({
    admNo, period: document.getElementById('feePeriod').value,
    type: document.getElementById('feeType').value,
    amount: document.getElementById('feeAmt').value,
    mode: document.getElementById('feeModeModal').value,
    receipt: document.getElementById('feeReceiptModal').value,
    date: document.getElementById('feeDateModal').value,
    status: document.getElementById('feeStatusModal').value
  });
  save(); renderFees(); renderFeeStats();
  closeModal('feeModal');
  alert('✅ Fee entry saved!');
}

function deleteFee(idx) {
  if (!confirm('Delete this fee record?')) return;
  fees.splice(idx,1); save(); renderFees(); renderFeeStats();
}

// ===================== EXAMS =====================
function populateExamFilters() { populateClassFilters(); }

function renderExams() {
  const cls  = document.getElementById('examClassFilter').value;
  const exam = document.getElementById('examFilter').value;
  const allStudents = _getAllStudents();
  let data = exams.filter(e => {
    const s = allStudents.find(r=>r.admNo===e.admNo);
    return (!cls||(s&&s.class===cls)) && (!exam||e.examName===exam);
  });
  const tbody = document.getElementById('examBody');
  if (!data.length) { tbody.innerHTML='<tr><td colspan="10" style="text-align:center;padding:30px;color:#999;">No exam records.</td></tr>'; return; }
  tbody.innerHTML = data.map(e => {
    const s = allStudents.find(r=>r.admNo===e.admNo)||{};
    const subsHtml = Object.entries(e.marks||{}).map(([sub,m])=>`<span style="font-size:11px;background:#e3f2fd;padding:2px 6px;border-radius:3px;margin:1px;">${sub}: <b>${m}</b></span>`).join(' ');
    const total = Object.values(e.marks||{}).reduce((a,m)=>a+(+m||0),0);
    const max   = Object.keys(e.marks||{}).length * (+e.maxMarks||100);
    const pct   = max ? ((total/max)*100).toFixed(1) : 0;
    const pass  = pct >= (+e.passPercent||33);
    const grade = pct>=90?'A+':pct>=75?'A':pct>=60?'B':pct>=45?'C':pct>=33?'D':'F';
    return `<tr>
      <td><b>${e.admNo}</b></td><td>${s.name||'—'}</td><td>${s.class||'—'}</td>
      <td>${e.examName}</td><td style="max-width:200px;white-space:normal;">${subsHtml}</td>
      <td><b>${total}/${max}</b></td><td>${pct}%</td>
      <td><span class="badge badge-blue">${grade}</span></td>
      <td><span class="badge ${pass?'badge-green':'badge-red'}">${pass?'Pass':'Fail'}</span></td>
      <td><button onclick="deleteExam(${exams.indexOf(e)})" style="background:none;border:none;cursor:pointer;color:#c62828;font-size:15px;">🗑️</button></td>
    </tr>`;
  }).join('');
}

function openAddMarksModal() {
  updateDropdowns();
  document.getElementById('marksModal').classList.add('open');
}

function loadSubjectsForMarks() {
  const admNo = document.getElementById('marksStudentSel').value;
  const s = _getAllStudents().find(r=>r.admNo===admNo);
  const grid = document.getElementById('marksSubjectGrid');
  if (!s) { grid.innerHTML=''; return; }
  const subs = (s.subs||'').split(',').map(x=>x.trim()).filter(Boolean);
  grid.innerHTML = subs.map(sub => `
    <div class="form-group">
      <label>${sub}</label>
      <input type="number" id="mark_${sub.replace(/\s/g,'_')}" placeholder="Marks" min="0">
    </div>`).join('');
}

function saveMarks() {
  const admNo = document.getElementById('marksStudentSel').value;
  const s = _getAllStudents().find(r=>r.admNo===admNo);
  if (!s) return alert('Select student!');
  const subs = (s.subs||'').split(',').map(x=>x.trim()).filter(Boolean);
  const marks = {};
  subs.forEach(sub => {
    const el = document.getElementById('mark_'+sub.replace(/\s/g,'_'));
    if (el && el.value !== '') marks[sub] = el.value;
  });
  exams.push({
    admNo, examName: document.getElementById('examName').value,
    maxMarks: document.getElementById('maxMarks').value,
    passPercent: document.getElementById('passPercent').value,
    marks, date: new Date().toISOString().split('T')[0]
  });
  save(); renderExams();
  closeModal('marksModal');
  alert('✅ Marks saved!');
}

function deleteExam(idx) {
  if (!confirm('Delete this record?')) return;
  exams.splice(idx,1); save(); renderExams();
}

function exportMarksheet() {
  const cls  = document.getElementById('examClassFilter').value;
  const exam = document.getElementById('examFilter').value;
  if (!exam) return alert('Select an exam to export!');
  const _allStu = _getAllStudents();
  const data = exams.filter(e => {
    const s = _allStu.find(r=>r.admNo===e.admNo);
    return (!cls||(s&&s.class===cls)) && e.examName===exam;
  });
  if (!data.length) return alert('No data for selected filters.');
  const rows = data.map(e => {
    const s = _allStu.find(r=>r.admNo===e.admNo)||{};
    const total = Object.values(e.marks||{}).reduce((a,m)=>a+(+m||0),0);
    const max   = Object.keys(e.marks||{}).length*(+e.maxMarks||100);
    const pct   = max?((total/max)*100).toFixed(1):0;
    return { 'Adm No': e.admNo, Name: s.name, Class: s.class, Exam: e.examName, Total: total, Max: max, '%': pct, Grade: pct>=90?'A+':pct>=75?'A':pct>=60?'B':pct>=45?'C':pct>=33?'D':'F', Result: pct>=(+e.passPercent||33)?'Pass':'Fail' };
  });
  const ws = XLSX.utils.json_to_sheet(rows);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, 'Marksheet');
  XLSX.writeFile(wb, `Marksheet_${exam}.xlsx`);
}

// ===================== ID CARD =====================
function updateDropdowns() {
  const allStudents = _getAllStudents();
  ['idStudentSel','tcStudentSel','feeStudentSel','marksStudentSel'].forEach(id => {
    const el = document.getElementById(id);
    if (!el) return;
    const cur = el.value;
    el.innerHTML = '<option value="">-- Select Student --</option>';
    allStudents.forEach(s => el.innerHTML += `<option value="${s.admNo}" ${s.admNo===cur?'selected':''}>${s.name} (${s.admNo})</option>`);
  });
}

