// ===================== TC GENERATOR =====================
function fillTCForm() {
  const admNo = document.getElementById('tcStudentSel').value;
  const s = _getAllStudents().find(r=>r.admNo===admNo);
  if (s) {
    document.getElementById('tcClass').value = s.class;
    document.getElementById('tcNo').value = 'TC-'+new Date().getFullYear()+'-'+String(Math.floor(Math.random()*900)+100);
    document.getElementById('tcDate').value = new Date().toISOString().split('T')[0];
  }
}

function generateTC() {
  const admNo = document.getElementById('tcStudentSel').value;
  const s = _getAllStudents().find(r=>r.admNo===admNo);
  if (!s) return alert('Select student!');
  const tcNo     = document.getElementById('tcNo').value;
  const tcDate   = document.getElementById('tcDate').value;
  const reason   = document.getElementById('tcReason').value;
  const conduct  = document.getElementById('tcConduct').value;
  const fee      = document.getElementById('tcFee').value;
  const issuedBy = document.getElementById('tcIssuedBy').value;

  document.getElementById('tcPreview').innerHTML = `
    <div id="tcDoc" style="background:#fff;border:2px solid #1a237e;border-radius:8px;padding:40px;max-width:680px;margin:0 auto;font-family:'Times New Roman',serif;">
      <div style="text-align:center;border-bottom:2px solid #1a237e;padding-bottom:16px;margin-bottom:20px;">
        <div style="font-size:22px;font-weight:700;color:#1a237e;">CITY PUBLIC SCHOOL</div>
        <div style="font-size:12px;color:#555;">Affiliated to CBSE | Est. 2000</div>
        <div style="font-size:18px;font-weight:700;margin-top:10px;text-decoration:underline;">TRANSFER CERTIFICATE</div>
      </div>
      <table style="width:100%;border-collapse:collapse;font-size:13px;">
        ${tcRow('TC Number', tcNo)} ${tcRow('Date of Issue', tcDate)}
        ${tcRow('Student Name', `<b>${s.name}</b>`)} ${tcRow('Admission No', s.admNo)}
        ${tcRow("Father's Name", s.fname)} ${tcRow('Mother\'s Name', s.mname)}
        ${tcRow('Date of Birth', s.dob)} ${tcRow('Category', s.cat)}
        ${tcRow('Last Class Attended', s.class)} ${tcRow('Medium', s.med)}
        ${tcRow('Date of Admission', s.admDate||'—')} ${tcRow('Date of Leaving', tcDate)}
        ${tcRow('Reason for Leaving', reason)} ${tcRow('Conduct', conduct)}
        ${tcRow('Fee Status', fee)} ${tcRow('Scholar No', s.scholar||'—')}
      </table>
      <div style="margin-top:30px;font-size:12px;color:#333;line-height:1.8;">
        This is to certify that the above mentioned student was a bonafide student of this institution and has left the school on the date mentioned above.
      </div>
      <div style="margin-top:40px;display:flex;justify-content:space-between;font-size:12px;">
        <div style="text-align:center;">Class Teacher<br><br>_________________</div>
        <div style="text-align:center;font-weight:700;">Principal<br><br>_________________<br>${issuedBy||'Principal'}</div>
      </div>
      <div style="margin-top:20px;font-size:10px;color:#999;text-align:center;border-top:1px solid #ddd;padding-top:10px;">
        Generated on: ${new Date().toLocaleString('en-IN')} | School ERP v4.0
      </div>
    </div>`;
}
function tcRow(k, v) { return `<tr><td style="padding:6px 10px;border:1px solid #ddd;font-weight:600;width:45%;background:#f8f8f8;">${k}</td><td style="padding:6px 10px;border:1px solid #ddd;">${v}</td></tr>`; }

function printTC() {
  const doc = document.getElementById('tcDoc');
  if (!doc) return alert('Generate TC first!');
  const w = window.open('','_blank');
  w.document.write('<html><head><title>TC</title><style>body{font-family:"Times New Roman",serif;padding:20px;}</style></head><body>');
  w.document.write(doc.outerHTML);
  w.document.write('</body></html>');
  w.document.close(); w.print();
}

// ===================== REPORTS =====================
function populateReportFilters() { populateClassFilters(); }

function generateAttReport() {
  const cls   = document.getElementById('rptClass').value;
  const month = document.getElementById('rptMonth').value;
  if (!month) return alert('Select month!');

  const students = _getAllStudents().filter(s => !cls || cls === 'all' || s.class === cls);
  const rows = students.map(s => {
    const keys = Object.keys(attendance).filter(k => k.startsWith(month) && k.endsWith('_'+s.class));
    let P=0,A=0,L=0;
    keys.forEach(k => {
      const rec = attendance[k][s.admNo];
      if (rec==='P') P++; else if (rec==='A') A++; else if (rec==='L') L++;
    });
    const total = P+A+L;
    const pct = total ? ((P/total)*100).toFixed(0) : '—';
    return { name:s.name, admNo:s.admNo, class:s.class, P, A, L, total, pct };
  });

  document.getElementById('attReportOut').innerHTML = `
    <div class="table-wrap"><table>
      <thead><tr><th>Name</th><th>Class</th><th>Present</th><th>Absent</th><th>Leave</th><th>Total</th><th>%</th></tr></thead>
      <tbody>${rows.map(r=>`<tr><td>${r.name}</td><td>${r.class}</td><td style="color:#2e7d32;font-weight:700;">${r.P}</td><td style="color:#c62828;font-weight:700;">${r.A}</td><td style="color:#e65100;">${r.L}</td><td>${r.total}</td><td><b>${r.pct}%</b></td></tr>`).join('')}</tbody>
    </table></div>`;
}

function generateFeeReport() {
  const month = document.getElementById('rptFeeMonth').value;
  if (!month) return alert('Select month!');
  const data = fees.filter(f => (f.period||'').startsWith(month) || (f.date||'').startsWith(month));
  const paid = data.filter(f=>f.status==='Paid').reduce((a,f)=>a+(+f.amount||0),0);
  const due  = data.filter(f=>f.status==='Due').reduce((a,f)=>a+(+f.amount||0),0);
  const allStudents = _getAllStudents();
  document.getElementById('feeReportOut').innerHTML = `
    <div style="display:flex;gap:10px;margin-bottom:10px;">
      ${statCard('₹'+paid.toLocaleString(),'Collected','#2e7d32')}
      ${statCard('₹'+due.toLocaleString(),'Pending','#c62828')}
      ${statCard(data.length,'Entries','#1976d2')}
    </div>
    <div class="table-wrap"><table>
      <thead><tr><th>Adm No</th><th>Name</th><th>Type</th><th>Amount</th><th>Status</th></tr></thead>
      <tbody>${data.map(f=>{const s=allStudents.find(r=>r.admNo===f.admNo)||{};return `<tr><td>${f.admNo}</td><td>${s.name||'—'}</td><td>${f.type||'—'}</td><td>₹${f.amount}</td><td><span class="badge ${f.status==='Paid'?'badge-green':'badge-red'}">${f.status}</span></td></tr>`;}).join('')}</tbody>
    </table></div>`;
}

function generateResultReport() {
  const exam = document.getElementById('rptExam').value;
  const cls  = document.getElementById('rptExamClass').value;
  if (!exam) return alert('Select exam!');
  const allStudents = _getAllStudents();
  const data = exams.filter(e => {
    const s = allStudents.find(r=>r.admNo===e.admNo);
    return e.examName===exam && (!cls||(s&&s.class===cls));
  });
  const pass = data.filter(e => {
    const total = Object.values(e.marks||{}).reduce((a,m)=>a+(+m||0),0);
    const max   = Object.keys(e.marks||{}).length*(+e.maxMarks||100);
    return max && (total/max*100) >= (+e.passPercent||33);
  }).length;
  document.getElementById('resultReportOut').innerHTML = `
    <div style="display:flex;gap:10px;margin-bottom:10px;">
      ${statCard(data.length,'Appeared','#1976d2')}
      ${statCard(pass,'Passed','#2e7d32')}
      ${statCard(data.length-pass,'Failed','#c62828')}
      ${statCard(data.length?((pass/data.length)*100).toFixed(0)+'%':'—','Pass %','#e65100')}
    </div>
    <div class="table-wrap"><table>
      <thead><tr><th>Name</th><th>Class</th><th>Total</th><th>%</th><th>Grade</th><th>Result</th></tr></thead>
      <tbody>${data.map(e=>{
        const s=allStudents.find(r=>r.admNo===e.admNo)||{};
        const total=Object.values(e.marks||{}).reduce((a,m)=>a+(+m||0),0);
        const max=Object.keys(e.marks||{}).length*(+e.maxMarks||100);
        const pct=max?((total/max)*100).toFixed(1):0;
        const pass=pct>=(+e.passPercent||33);
        const grade=pct>=90?'A+':pct>=75?'A':pct>=60?'B':pct>=45?'C':pct>=33?'D':'F';
        return `<tr><td>${s.name||'—'}</td><td>${s.class||'—'}</td><td>${total}/${max}</td><td>${pct}%</td><td><span class="badge badge-blue">${grade}</span></td><td><span class="badge ${pass?'badge-green':'badge-red'}">${pass?'Pass':'Fail'}</span></td></tr>`;
      }).join('')}</tbody>
    </table></div>`;
}

// ===================== EXPORT =====================
function exportExcel() {
  const data = _getAllStudents().map(s => ({
    'Adm No':s.admNo, Name:s.name, Gender:s.gender, DOB:s.dob, Class:s.class,
    Section:s.sec, Category:s.cat, Father:s.fname, Mobile:s.fmobile,
    Address:s.addr+' '+s.city, Transport:s.trans, Fee:'₹'+s.admFee
  }));
  const ws = XLSX.utils.json_to_sheet(data);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, 'Students');
  XLSX.writeFile(wb, 'Student_Registry.xlsx');
}

function exportCSV() {
  const headers = ['Adm No','Name','Gender','DOB','Class','Section','Father','Mobile','Fee'];
  const rows = _getAllStudents().map(s => [s.admNo,s.name,s.gender,s.dob,s.class,s.sec,s.fname,s.fmobile,s.admFee].join(','));
  const blob = new Blob([headers.join(',')+'\n'+rows.join('\n')], {type:'text/csv'});
  const a = document.createElement('a'); a.href = URL.createObjectURL(blob);
  a.download = 'students.csv'; a.click();
}

