// ── Global helper: class names ko sahi ascending order me sort karo ──
// "Class 3" < "Class 8" < "Class 11" < "Class 12" (numeric, not string sort)
// Nursery/LKG/KG/UKG bhi Class 1 se pehle aate hain
function _classSortNum(c) {
  c = String(c || '').trim();
  const m = c.match(/\d+/);
  if (m) return parseInt(m[0], 10);
  const low = c.toLowerCase();
  if (low.indexOf('pre') >= 0 && low.indexOf('nursery') >= 0) return -4;
  if (low.indexOf('nursery') >= 0) return -3;
  if (low.indexOf('lkg') >= 0) return -2;
  if (low.indexOf('ukg') >= 0) return -1;
  if (low.indexOf('kg') >= 0) return -1.5;
  return 999; // unknown labels last
}
function _classCmp(a, b) {
  const na = _classSortNum(a), nb = _classSortNum(b);
  if (na !== nb) return na - nb;
  return String(a).localeCompare(String(b));
}

