// ---- Auto-fill school name & DISE from SCHOOL_INFO in all Fee Management fields ----
function feeAutoFillSchoolInfo() {
  var SI = (typeof SCHOOL_INFO !== 'undefined') ? SCHOOL_INFO : {};
  var schoolName = SI.name || (document.getElementById('sc_name') ? document.getElementById('sc_name').value : '') || '';
  var diseCode   = SI.dise || (document.getElementById('sc_dise') ? document.getElementById('sc_dise').value : '') || '';

  // IDs to fill with school name (readonly)
  var schoolIds = ['fs1School','fs2School','fs6School','fs8School','fs10School','ov_fs6School'];
  // IDs to fill with DISE/UDISE code (readonly)
  var diseIds   = ['fs1Udise','fs6Udise','fs10Udise','ov_fs6Udise'];

  var rdStyle = 'background:#f0f4ff;color:#1a237e;font-weight:600;border:1px solid #c5cae9;cursor:default;';

  schoolIds.forEach(function(id) {
    var el = document.getElementById(id);
    if (el && schoolName) {
      el.value = schoolName;
      el.readOnly = true;
      if (id !== 'fs2School') {
        el.setAttribute('style', rdStyle);
      } else {
        // fs2School is hidden — update the display span
        var disp = document.getElementById('fs2SchoolDisplay');
        if (disp) disp.textContent = schoolName;
      }
      el.title = 'School Details से auto-fill — School Details tab में बदलें';
    }
  });

  diseIds.forEach(function(id) {
    var el = document.getElementById(id);
    if (el && diseCode) {
      el.value = diseCode;
      el.readOnly = true;
      el.setAttribute('style', rdStyle);
      el.title = 'School Details से auto-fill — School Details tab में बदलें';
    }
  });
  var _fSess=(document.getElementById('sc_yr')?document.getElementById('sc_yr').value:'')||getCurrentSession();
  var _fSessStyle='background:#f0f4ff;color:#5b21b6;font-weight:700;border:1px solid #c4b5fd;cursor:default;';
  ['fs1Session','fs6Session','fs8Session','fs10Session','ov_fs6Session'].forEach(function(id){
    var el=document.getElementById(id);
    if(el){ el.value=_fSess; el.readOnly=true; el.setAttribute('style',_fSessStyle); el.title='School Details → Session से auto-sync'; }
  });
}

// ── Fee tab flush debounce — rapid switching handle karo ──
var _feeTabFlushTimer = null;
function showFsTab(id, btn) {
  document.querySelectorAll('.fs-panel').forEach(p => p.style.display = 'none');
  document.querySelectorAll('.fs-tab').forEach(b => { b.classList.remove('btn-primary'); b.classList.add('btn-outline'); });
  document.getElementById(id).style.display = 'block';
  btn.classList.remove('btn-outline'); btn.classList.add('btn-primary');
  if (id === 'fs1') renderFs1();
  if (id === 'fs2') initFs2();
  if (id === 'fs4') initFs4();
  if (id === 'fs8') initFs8();
  if (id === 'fs9') initFs9();
  if (id === 'fs6')  { initFs6(); }
  if (id === 'fs10') { fs10PopulateFilters(); renderFs10(); }
  if (id === 'fs11') initF11();
  // Auto-fill school info after tab renders
  setTimeout(feeAutoFillSchoolInfo, 50);
  // ── Dirty check: sirf tab change pe flush karo agar data change hua ho ──
  // Teacher sirf padhta hai → _rskDirty false → koi request nahi ✅
  // Teacher ne kuch save kiya → _rskDirty true → flush karo ✅
  if(window._rskDirty && typeof gdFlushQueue === 'function' && Object.keys(_gdPendingQueue||{}).length){
    clearTimeout(_feeTabFlushTimer);
    _feeTabFlushTimer = setTimeout(function(){
      if(window._rskDirty && Object.keys(_gdPendingQueue||{}).length){
        gdFlushQueue();
      }
    }, 3000); // 3 sec debounce — rapid switching mein sirf ek flush
  }
}

