var fs1CustomFees = _erpSafeLoad(erpKey('erp_customFees'), []);

function syncFeeTypesWithCustom() {
  FS_FEE_TYPES = FS_FEE_TYPES.filter(f => !f._custom);
  fs1CustomFees.forEach((cf, ci) => {
    FS_FEE_TYPES.push({ label: cf.label, period: cf.period||'', amt: cf.amt||'', _custom: true, _cIdx: ci });
  });
}

function addFs1CustomFee() {
  const label  = (document.getElementById('fs1CustomLabel')?.value||'').trim();
  const period = (document.getElementById('fs1CustomPeriod')?.value||'').trim();
  const amt    = (document.getElementById('fs1CustomAmt')?.value||'').trim();
  if (!label) return alert('शुल्क का नाम भरें!');
  fs1CustomFees.push({ label, period, amt });
  localStorage.setItem(erpKey('erp_customFees'), JSON.stringify(fs1CustomFees)); smartSave(erpKey('erp_customFees'), fs1CustomFees);
  if(document.getElementById('fs1CustomLabel')) document.getElementById('fs1CustomLabel').value = '';
  if(document.getElementById('fs1CustomPeriod')) document.getElementById('fs1CustomPeriod').value = '';
  if(document.getElementById('fs1CustomAmt')) document.getElementById('fs1CustomAmt').value = '';
  syncFeeTypesWithCustom();
  renderFs1();
  saveFs1();
}

function addFs1InlineFee() {
  const label = (document.getElementById('fs1InlineLabel')?.value||'').trim();
  if (!label) { document.getElementById('fs1InlineLabel')?.focus(); return; }
  fs1CustomFees.push({ label, period:'', amt:'' });
  localStorage.setItem(erpKey('erp_customFees'), JSON.stringify(fs1CustomFees)); smartSave(erpKey('erp_customFees'), fs1CustomFees);
  syncFeeTypesWithCustom();
  renderFs1();
  saveFs1();
  // focus back on the new inline row
  setTimeout(() => document.getElementById('fs1InlineLabel')?.focus(), 100);
}

function renameCustomFee(ci, newLabel) {
  if(fs1CustomFees[ci]) fs1CustomFees[ci].label = newLabel;
  localStorage.setItem(erpKey('erp_customFees'), JSON.stringify(fs1CustomFees)); smartSave(erpKey('erp_customFees'), fs1CustomFees);
  syncFeeTypesWithCustom();
  saveFs1();
}

function updateCustomFeeAmt(ci, newAmt) {
  if(fs1CustomFees[ci]) fs1CustomFees[ci].amt = newAmt;
  localStorage.setItem(erpKey('erp_customFees'), JSON.stringify(fs1CustomFees)); smartSave(erpKey('erp_customFees'), fs1CustomFees);
  syncFeeTypesWithCustom();
  saveFs1();
}

// ── F1 Remove: Confirmation + Password verify ──
function _f1VerifyAndRemove(callback) {
  var _en = isEnglish();
  if (!confirm(_en ? 'Are you sure you want to remove this fee?' : 'क्या आप इस शुल्क को हटाना चाहते हैं?')) return;
  var pwd = prompt(_en ? 'Enter your login password to confirm:' : 'पुष्टि के लिए अपना login password दर्ज करें:');
  if (pwd === null || pwd === '') return;
  try {
    var _usr = typeof currentUser !== 'undefined' ? currentUser : null;
    if (!_usr) { alert(_en ? 'User not found. Please re-login.' : 'User नहीं मिला।'); return; }
    var _storedPwd = _usr.password || _usr.pwd || '';
    if (!_storedPwd) {
      try { var _uData = JSON.parse(localStorage.getItem('rsk_user_'+(_usr.username||''))||'{}'); _storedPwd = _uData.password||''; } catch(e){}
    }
    if (pwd !== _storedPwd) {
      alert(_en ? '❌ Wrong password! Fee not removed.' : '❌ गलत password! शुल्क नहीं हटाया गया।');
      return;
    }
  } catch(e) { alert('Error: ' + e.message); return; }
  callback();
}

function deleteFs1CustomFee(ci) {
  _f1VerifyAndRemove(function(){
    var removed = fs1CustomFees.splice(ci, 1)[0];
    // If it was a predefined fee added via dropdown, reset feeConfig too
    if (removed && removed._predefinedIdx !== undefined) {
      if (feeConfig[removed._predefinedIdx]) {
        feeConfig[removed._predefinedIdx].active = 'no';
        localStorage.setItem(erpKey('erp_feeConfig'), JSON.stringify(feeConfig)); smartSave(erpKey('erp_feeConfig'), feeConfig);
      }
    }
    localStorage.setItem(erpKey('erp_customFees'), JSON.stringify(fs1CustomFees)); smartSave(erpKey('erp_customFees'), fs1CustomFees);
    syncFeeTypesWithCustom();
    renderFs1();
    saveFs1();
  });
}

function renderFs1CustomList() {
  const el = document.getElementById('fs1CustomList');
  if (!el) return;
  if (!fs1CustomFees.length) { el.innerHTML = `<div style="font-size:12px;color:#aaa;">${isEnglish() ? 'No custom fees added yet.' : 'अभी कोई custom fee नहीं है।'}</div>`; return; }
  el.innerHTML = '<div style="font-size:12px;font-weight:600;color:#555;margin-bottom:6px;">Added Custom Fees:</div>' +
    fs1CustomFees.map((cf, ci) => `
      <div style="display:flex;align-items:center;gap:8px;padding:5px 10px;background:#fff;border:1px solid #ddd;border-radius:6px;margin-bottom:4px;font-size:12px;">
        <span style="flex:1;font-weight:600;color:#1a237e;">${cf.label}</span>
        <span style="color:#888;">${cf.period||'—'}</span>
        <span style="color:#2e7d32;font-weight:700;">${cf.amt ? '₹'+cf.amt : '—'}</span>
        <button onclick="deleteFs1CustomFee(${ci})" style="background:#ffebee;border:1px solid #ffcdd2;color:#c62828;border-radius:4px;padding:2px 8px;cursor:pointer;font-size:12px;">✕ Remove</button>
      </div>`).join('');
}
