// ── HELPER: registry + admList3 dono se combined student list ──
function _getAllStudents() {
  // Single source of truth: admList3 — sirf current session ke students
  var _gaSess = (document.getElementById('sc_yr')?document.getElementById('sc_yr').value:'')||getCurrentSession();
  var combined = [];
  var seen = {};
  var adm = [];
  try{
    if(typeof admList3 !== 'undefined' && Array.isArray(admList3) && admList3.length>0) adm=admList3;
    else adm = JSON.parse(localStorage.getItem(erpKey('admList3'))||'[]');
  }catch(e){}
  adm.forEach(function(s){
    if(!s.sname) return;
    // Session filter — sirf current session ke students
    if(s.session && s.session !== _gaSess) return;
    var admNo = s.admno || s.formno || ('ADM'+s.id);
    if(seen[admNo]) return;
    seen[admNo]=true;
    combined.push({ admNo:admNo, name:s.sname, class:s.class||'', sec:s.section||'', section:s.section||'', medium:s.medium||'', father:s.fname||s.father||'', fname:s.fname||s.father||'', mother:s.mname||'', fmobile:s.fmob||'', mobile:s.mob||'', dob:s.dob||'', gender:s.gender||'', cat:s.category||'', scholar:s.scholar||'', samagra:s.samagra||'', aadhar:s.aadhar||'', apaar:s.apaar||'', enroll:s.enroll||'' });
  });
  return combined;
}

function initFs4() {
  populateClassFilters();
  const sel = document.getElementById('fs4Class');
  if (!sel) return;

  _applyFs4Lang();

  // Har baar fresh populate karo (admList3 updated ho sakti hai)
  sel.innerHTML = '<option value="">-- Select Class --</option><option value="all">All Classes</option>';
  [...new Set(_getAllStudents().map(s=>s.class).filter(Boolean))].sort(_classCmp).forEach(c => sel.innerHTML += `<option>${c}</option>`);
  if (!_fs4Inited) {
    sel.addEventListener('change', () => {
      if (sel.value) {
        // Koi class ya All Classes select kiya - data dikhao
        renderFs4();
        document.getElementById('fs4TableWrap').style.display = 'block';
        document.getElementById('fs4FooterSign').style.display = 'block';
      } else {
        // -- Select Class -- choose kiya - hide karo
        document.getElementById('fs4TableWrap').style.display = 'none';
        document.getElementById('fs4FooterSign').style.display = 'none';
        document.getElementById('fs4Body').innerHTML = '';
      }
    });
    _fs4Inited = true;
  } else {
    // Doosre tab se wapas aaya - reset karo
    sel.value = '';
    document.getElementById('fs4TableWrap').style.display = 'none';
    document.getElementById('fs4FooterSign').style.display = 'none';
    document.getElementById('fs4Body').innerHTML = '';
  }
}

function renderFs4() {
  var en = isEnglish();
  const cls   = document.getElementById('fs4Class').value;
  const tbody = document.getElementById('fs4Body');
  const students = _getAllStudents().filter(s => !cls || cls === 'all' || s.class === cls);

  if (!students.length) {
    tbody.innerHTML = `<tr><td colspan="4" style="text-align:center;padding:24px;color:#999;">${en ? 'No students found' : 'कोई छात्र नहीं मिला'}</td></tr>`;
    return;
  }

  const rows = [];

  students.forEach(s => {
    let totalDueAmt = 0;
    const fs2Data = JSON.parse(localStorage.getItem(erpKey('erp_fs2_') + s.admNo) || 'null');

    if (fs2Data) {
      // Part-B: tuition + transport month-wise bakaya
      if (fs2Data.partB) {
        fs2Data.partB.forEach(row => {
          const tBal  = parseFloat(row.tDue  || 0) - parseFloat(row.tPaid  || 0);
          const trBal = parseFloat(row.trDue || 0) - parseFloat(row.trPaid || 0);
          if (tBal  > 0) totalDueAmt += tBal;
          if (trBal > 0) totalDueAmt += trBal;
        });
      }
      // Part-A: other fees (Sports, Computer, Exam etc.) bakaya
      if (fs2Data.partA) {
        fs2Data.partA.forEach(row => {
          const isTuition   = (row.label||'').includes('ट्यूशन')  || (row.label||'').includes('Tuition');
          const isTransport = (row.label||'').includes('परिवहन') || (row.label||'').includes('Transport');
          if (isTuition || isTransport) return;
          const bal = parseFloat(row.due||0) - parseFloat(row.paid||0);
          if (bal > 0) totalDueAmt += bal;
        });
      }
    }

    // Fee Management module dues
    fees.filter(f => f.admNo === s.admNo && f.status === 'Due')
        .forEach(f => totalDueAmt += (+f.amount || 0));

    if (totalDueAmt > 0) rows.push({ s, totalDueAmt });
  });

  if (!rows.length) {
    tbody.innerHTML = `<tr><td colspan="4" style="text-align:center;padding:24px;color:#2e7d32;font-weight:600;">✅ ${en ? 'No defaulters found' : 'कोई बकायादार नहीं मिला'}</td></tr>`;
    return;
  }

  tbody.innerHTML = rows.map((r, i) => `
    <tr>
      <td>${i+1}</td>
      <td><b style="color:#1a237e;cursor:pointer;text-decoration:underline;" onclick="showDefaulterDetail('${r.s.admNo}')">${r.s.name}</b></td>
      <td>${r.s.class}${r.s.sec ? ' - '+r.s.sec : ''}</td>
      <td style="color:#c62828;font-weight:700;font-size:14px;">₹${r.totalDueAmt.toLocaleString()}</td>
    </tr>`).join('');
}

function printDefaulterDetail() {
  const body = document.getElementById('defaulterDetailBody');
  if (!body) return;
  const w = window.open('', '_blank');
  w.document.write(`<html><head><title>शुल्क विवरण</title><style>
    body{font-family:Arial,sans-serif;padding:24px;font-size:13px;}
    table{width:100%;border-collapse:collapse;margin-bottom:14px;}
    th,td{border:1px solid #aaa;padding:7px 12px;}
    th{background:#1a237e;color:#fff;}
    .no-print,.btn-row{display:none!important;}
    .summary-boxes{display:flex;gap:12px;margin-bottom:12px;}
    .summary-box{flex:1;border:1px solid #ccc;border-radius:6px;padding:10px;text-align:center;}
  </style></head><body>`);
  w.document.write('<h2 style="color:#1a237e;text-align:center;margin-bottom:16px;">⚠️ बकाया शुल्क विवरण</h2>');
  w.document.write(body.innerHTML);
  w.document.write('</body></html>');
  w.document.close();
  setTimeout(() => w.print(), 300);
}

function fs2ShowAnnualStatement() {
  const admNo = document.getElementById('fs2Adm')?.value;
  if (!admNo) { alert('कृपया पहले छात्र चुनें!'); return; }
  // Update modal title to Annual Statement
  document.querySelector('#defaulterDetailModal .modal-header h3').textContent = '📋 वार्षिक शुल्क विवरण / Annual Fee Statement';
  document.querySelector('#defaulterDetailModal .modal-header').style.background = '#1a237e';
  showDefaulterDetail(admNo);
}

function showDefaulterDetail(admNo) {
  // Reset header to defaulter style (may be changed by fs2ShowAnnualStatement)
  const hdr = document.querySelector('#defaulterDetailModal .modal-header');
  const hdrtitle = document.querySelector('#defaulterDetailModal .modal-header h3');
  if (hdr) hdr.style.background = '#c62828';
  if (hdrtitle) hdrtitle.textContent = isEnglish() ? '📋 Fee Detail' : '📋 शुल्क विवरण / Fee Detail';
  const s = _getAllStudents().find(r => r.admNo === admNo);
  if (!s) return;
  const fs2Data = JSON.parse(localStorage.getItem(erpKey('erp_fs2_') + admNo) || 'null');
  const savedMonths = _erpSafeLoad(erpKey('erp_feeMonths'), []);
  const allOrder = ['April','May','June','July','August','September','October','November','December','January','February','March'];
  const allMonthsMap = {'April':'अप्रैल','May':'मई','June':'जून','July':'जुलाई','August':'अगस्त','September':'सितम्बर','October':'अक्टूबर','November':'नवम्बर','December':'दिसम्बर','January':'जनवरी','February':'फरवरी','March':'मार्च'};
  const activeMonths = savedMonths.length > 0 ? allOrder.filter(m => savedMonths.includes(m)) : allOrder;

  let grandDue = 0, grandPaid = 0;
  let rows = '';

  // --- Part-B: tuition + transport month-wise ---
  if (fs2Data && fs2Data.partB && fs2Data.partB.length > 0) {
    rows += `<tr style="background:#e8eaf6;"><td colspan="4" style="padding:8px 12px;font-weight:700;color:#1a237e;">📅 ${isEnglish()?'Tuition Fee + Transport Fee (Monthly)':'ट्यूशन फीस + परिवहन फीस (माहवार)'}</td></tr>`;
    fs2Data.partB.forEach((row, idx) => {
      const mHi   = allMonthsMap[activeMonths[idx]] || activeMonths[idx] || '';
      const tDue  = parseFloat(row.tDue  || 0);
      const tPaid = parseFloat(row.tPaid || 0);
      const trDue = parseFloat(row.trDue || 0);
      const trPaid= parseFloat(row.trPaid|| 0);
      const due   = tDue + trDue;
      const paid  = tPaid + trPaid;
      const bal   = due - paid;
      if (due === 0) return;
      grandDue  += due;
      grandPaid += paid;
      rows += `<tr>
        <td style="padding:6px 12px;">${isEnglish() ? (activeMonths[idx]||'') : mHi}</td>
        <td style="padding:6px 12px;text-align:right;">₹${due.toLocaleString()}</td>
        <td style="padding:6px 12px;text-align:right;color:#2e7d32;">₹${paid.toLocaleString()}</td>
        <td style="padding:6px 12px;text-align:right;color:${bal>0?'#c62828':'#2e7d32'};font-weight:${bal>0?'700':'400'};">${bal>0?'₹'+bal.toLocaleString():'✓'}</td>
      </tr>`;
    });
  }

  // --- Part-A: other fees ---
  if (fs2Data && fs2Data.partA) {
    const otherFees = fs2Data.partA.filter(row => {
      const isTuition   = (row.label||'').includes('ट्यूशन')  || (row.label||'').includes('Tuition');
      const isTransport = (row.label||'').includes('परिवहन') || (row.label||'').includes('Transport');
      return !isTuition && !isTransport && parseFloat(row.due||0) > 0;
    });
    if (otherFees.length > 0) {
      rows += `<tr style="background:#e8eaf6;"><td colspan="4" style="padding:8px 12px;font-weight:700;color:#1a237e;">📌 ${isEnglish()?'Other Fees':'अन्य शुल्क'}</td></tr>`;
      otherFees.forEach(row => {
        const due  = parseFloat(row.due  || 0);
        const paid = parseFloat(row.paid || 0);
        const bal  = due - paid;
        grandDue  += due;
        grandPaid += paid;
        const rawLabel = (row.label||'').split('(')[0].trim();
        const displayLabel = isEnglish()
          ? (FS_FEE_TYPES.find(ft => ft.label.split('(')[0].trim() === rawLabel || rawLabel.includes(ft.label.split('(')[0].trim()) || ft.label.includes(rawLabel))?.labelEn || rawLabel)
          : rawLabel;
        rows += `<tr>
          <td style="padding:6px 12px;">${displayLabel}</td>
          <td style="padding:6px 12px;text-align:right;">₹${due.toLocaleString()}</td>
          <td style="padding:6px 12px;text-align:right;color:#2e7d32;">₹${paid.toLocaleString()}</td>
          <td style="padding:6px 12px;text-align:right;color:${bal>0?'#c62828':'#2e7d32'};font-weight:${bal>0?'700':'400'};">${bal>0?'₹'+bal.toLocaleString():'✓'}</td>
        </tr>`;
      });
    }
  }

  const grandBal = grandDue - grandPaid;

  document.getElementById('defaulterDetailBody').innerHTML = `
    <!-- Student info -->
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;font-size:12px;background:#f5f5f5;padding:10px;border-radius:6px;margin-bottom:14px;">
      <div><b>${isEnglish()?'Student':'छात्र'}:</b> ${s.name}</div>
      <div><b>${isEnglish()?'Adm. No.':'प्रवेश क्र.'}:</b> ${admNo}</div>
      <div><b>${isEnglish()?'Class':'कक्षा'}:</b> ${s.class}${s.sec?' - '+s.sec:''}</div>
      <div><b>${isEnglish()?'Father':'पिता'}:</b> ${s.father||s.fname||s.fName||'—'}</div>
      <div><b>${isEnglish()?'Mobile':'मोबाइल'}:</b> ${s.fmobile||'—'}</div>
    </div>

    <!-- Fee detail table -->
    <table style="width:100%;border-collapse:collapse;font-size:13px;margin-bottom:14px;">
      <thead>
        <tr style="background:#1a237e;color:#fff;">
          <th style="padding:8px 12px;text-align:left;">${isEnglish()?'Description':'विवरण'}</th>
          <th style="padding:8px 12px;text-align:right;">${isEnglish()?'Total Due (₹)':'कुल देय (₹)'}</th>
          <th style="padding:8px 12px;text-align:right;">${isEnglish()?'Paid (₹)':'जमा (₹)'}</th>
          <th style="padding:8px 12px;text-align:right;">${isEnglish()?'Balance (₹)':'बकाया (₹)'}</th>
        </tr>
      </thead>
      <tbody>${rows || '<tr><td colspan="4" style="text-align:center;padding:16px;color:#999;">'+(isEnglish()?'No data':'कोई डेटा नहीं')+'</td></tr>'}</tbody>
      <tfoot>
        <tr style="background:#e8eaf6;font-weight:700;font-size:13px;border-top:2px solid #1a237e;">
          <td style="padding:8px 12px;">${isEnglish()?'Grand Total':'कुल योग / Grand Total'}</td>
          <td style="padding:8px 12px;text-align:right;">₹${grandDue.toLocaleString()}</td>
          <td style="padding:8px 12px;text-align:right;color:#2e7d32;">₹${grandPaid.toLocaleString()}</td>
          <td style="padding:8px 12px;text-align:right;color:#c62828;font-size:15px;">₹${grandBal.toLocaleString()}</td>
        </tr>
      </tfoot>
    </table>

    <!-- Summary boxes -->
    <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px;margin-bottom:12px;">
      <div style="background:#e3f2fd;border-radius:8px;padding:12px;text-align:center;">
        <div style="font-size:11px;color:#555;">${isEnglish()?'Total Due':'कुल देय'}</div>
        <div style="font-size:18px;font-weight:800;color:#1a237e;">₹${grandDue.toLocaleString()}</div>
      </div>
      <div style="background:#e8f5e9;border-radius:8px;padding:12px;text-align:center;">
        <div style="font-size:11px;color:#555;">${isEnglish()?'Amount Paid':'जमा राशि'}</div>
        <div style="font-size:18px;font-weight:800;color:#2e7d32;">₹${grandPaid.toLocaleString()}</div>
      </div>
      <div style="background:#ffebee;border-radius:8px;padding:12px;text-align:center;">
        <div style="font-size:11px;color:#555;">${isEnglish()?'Total Balance':'कुल बकाया'}</div>
        <div style="font-size:18px;font-weight:800;color:#c62828;">₹${grandBal.toLocaleString()}</div>
      </div>
    </div>
    <div class="btn-row">
      <button class="btn btn-orange" onclick="printDefaulterDetail()">🖨️ Print</button>
      <button class="btn btn-outline" onclick="closeModal('defaulterDetailModal')">✕ ${isEnglish()?'Close':'बंद करें'}</button>
    </div>`;

  document.getElementById('defaulterDetailModal').classList.add('open');
}

