function toggleFs6MonthPicker(e) {
  e.stopPropagation();
  const dd = document.getElementById('fs6MonthDropdown');
  dd.style.display = dd.style.display === 'block' ? 'none' : 'block';
}
function updateFs6MonthLabel() {
  const checked = [...document.querySelectorAll('#fs6MonthBoxes input:checked')].map(c => c.value);
  const lbl = document.getElementById('fs6MonthLabel');
  if (lbl) {
    if (!checked.length) {
      lbl.textContent = isEnglish() ? 'Select Month' : 'माह चुनें';
    } else if (checked.length === 12) {
      lbl.textContent = isEnglish() ? 'All Months' : 'सभी माह';
    } else {
      var hiToEn = {'अप्रैल':'April','मई':'May','जून':'June','जुलाई':'July','अगस्त':'August','सितम्बर':'September','अक्टूबर':'October','नवम्बर':'November','दिसम्बर':'December','जनवरी':'January','फरवरी':'February','मार्च':'March'};
      lbl.textContent = isEnglish() ? checked.map(v => hiToEn[v] || v).join(', ') : checked.join(', ');
    }
  }
  document.querySelectorAll('#fs6MonthBoxes label').forEach(l => {
    const cb = l.querySelector('input');
    l.style.borderColor = cb.checked ? '#1976d2' : '#ddd';
    l.style.background  = cb.checked ? '#e3f2fd' : '';
  });
  // Always render — no month = all months by default
  const tableWrap = document.getElementById('fs6TableWrap');
  const footSign  = document.getElementById('fs6FooterSign');
  if (tableWrap) tableWrap.style.display = 'block';
  if (footSign)  footSign.style.display  = 'flex';
  renderFs6();
}
function fs6SelectAllMonths(val) {
  document.querySelectorAll('#fs6MonthBoxes input').forEach(cb => { cb.checked = val; });
  updateFs6MonthLabel();
}

function initFs6() {
  // Label reset — no month = all months
  var lbl = document.getElementById('fs6MonthLabel');
  if (lbl) lbl.textContent = isEnglish() ? 'All Months' : 'सभी माह';
  // Uncheck all (unchecked = all months included by renderFs6 logic)
  document.querySelectorAll('#fs6MonthBoxes input').forEach(cb => { cb.checked = false; });
  document.querySelectorAll('#fs6MonthBoxes label').forEach(l => {
    l.style.borderColor = '#ddd'; l.style.background = '';
  });
  // Show table immediately with all months
  var wrap = document.getElementById('fs6TableWrap');
  if (wrap) wrap.style.display = 'block';
  var foot = document.getElementById('fs6FooterSign');
  if (foot) foot.style.display = 'flex';
  renderFs6();
}

function renderFs6(opts) {
  // opts = { filterClass, filterSec, filterStudent } (optional, used by OV-F6)
  opts = opts || {};
  const filterCls    = opts.filterClass  || '';
  const filterSec    = opts.filterSec    || '';
  const filterStu    = opts.filterStudent || '';
  const _headId      = opts.headId      || 'fs6Head';
  const _bodyId      = opts.bodyId      || 'fs6Body';
  const _footId      = opts.footId      || 'fs6Foot';
  const _footSignId  = opts.footSignId  || 'fs6FooterSign';
  const _tableWrapId = opts.tableWrapId || 'fs6TableWrap';

  // Base student list - apply class/section/student filter if given
  let baseRegistry = _getAllStudents();
  if (filterCls) baseRegistry = baseRegistry.filter(s => s.class === filterCls);
  if (filterSec) baseRegistry = baseRegistry.filter(s => s.sec === filterSec || s.anusec === filterSec || s.section === filterSec);
  if (filterStu) baseRegistry = baseRegistry.filter(s => s.admNo === filterStu);

  const classes      = filterCls
    ? [filterCls]
    : [...new Set(baseRegistry.map(s => s.class))].sort(_classCmp);
  const activeFees   = FS_FEE_TYPES.filter((ft, i) => { if(i < 2) return !feeConfig[i] || feeConfig[i].active !== 'no'; if(ft._custom) return !feeConfig[i] || feeConfig[i].active !== 'no'; return feeConfig[i] && feeConfig[i].active === 'yes'; });

  // Get selected months (Hindi) → convert to date prefixes
  const selectedMonths = [...document.querySelectorAll('#fs6MonthBoxes input:checked')].map(c => c.value);
  const allMonthsHi    = ['अप्रैल','मई','जून','जुलाई','अगस्त','सितम्बर','अक्टूबर','नवम्बर','दिसम्बर','जनवरी','फरवरी','मार्च'];
  // Month index → date month number (April=04, May=05 ... March=03)
  const monthNums      = ['04','05','06','07','08','09','10','11','12','01','02','03'];

  // Which month numbers to include
  const activeMonthNums = selectedMonths.length > 0
    ? selectedMonths.map(mHi => monthNums[allMonthsHi.indexOf(mHi)]).filter(Boolean)
    : monthNums; // all if none selected

  // Get all F5 keys from localStorage
  const allF5Keys = Object.keys(localStorage).filter(k => k.startsWith(sessKey('erp_fs5_')));

  // ── Helper: calculate defaulter (pending) amount for a student ──
  function _getDefaulterAmt(admNo) {
    let due = 0;
    const fs2Data = JSON.parse(localStorage.getItem(erpKey('erp_fs2_') + admNo) || 'null');
    if (fs2Data) {
      if (fs2Data.partB) {
        fs2Data.partB.forEach(row => {
          const tBal  = parseFloat(row.tDue  || 0) - parseFloat(row.tPaid  || 0);
          const trBal = parseFloat(row.trDue || 0) - parseFloat(row.trPaid || 0);
          if (tBal  > 0) due += tBal;
          if (trBal > 0) due += trBal;
        });
      }
      if (fs2Data.partA) {
        fs2Data.partA.forEach(row => {
          const isTuition   = (row.label||'').includes('ट्यूशन')  || (row.label||'').includes('Tuition');
          const isTransport = (row.label||'').includes('परिवहन') || (row.label||'').includes('Transport');
          if (isTuition || isTransport) return;
          const bal = parseFloat(row.due||0) - parseFloat(row.paid||0);
          if (bal > 0) due += bal;
        });
      }
    }
    // Fee module dues
    if (typeof fees !== 'undefined') {
      fees.filter(f => f.admNo === admNo && f.status === 'Due')
          .forEach(f => due += (+f.amount || 0));
    }
    return due;
  }

  // Pre-compute defaulter amounts for all students in view
  const defaulterMap = {};
  let hasAnyDefaulter = false;
  baseRegistry.forEach(s => {
    const d = _getDefaulterAmt(s.admNo);
    if (d > 0) { defaulterMap[s.admNo] = d; hasAnyDefaulter = true; }
  });

  // ── Fallback: agar F5 (daily collection) me data nahi hai, F2 (Fee Receipt) se direct nikaalo ──
  function _getFs2FeeAmounts(admNo) {
    const amts = new Array(activeFees.length).fill(0);
    const fs2Data = JSON.parse(localStorage.getItem(erpKey('erp_fs2_') + admNo) || 'null');
    if (!fs2Data) return amts;
    if (fs2Data.partB) {
      fs2Data.partB.forEach((row, idx) => {
        const mNum = monthNums[idx];
        if (!activeMonthNums.includes(mNum)) return;
        amts[0] += parseFloat(row.tPaid  || 0);
        amts[1] += parseFloat(row.trPaid || 0);
      });
    }
    if (fs2Data.partA) {
      fs2Data.partA.forEach(row => {
        const isTuition   = (row.label||'').includes('ट्यूशन')  || (row.label||'').includes('Tuition');
        const isTransport = (row.label||'').includes('परिवहन') || (row.label||'').includes('Transport');
        if (isTuition || isTransport) return;
        const idx = activeFees.findIndex(ft => ft.label === row.label);
        if (idx >= 0) amts[idx] += parseFloat(row.paid || 0);
      });
    }
    return amts;
  }

  // Dynamic header
  const thead = document.getElementById(opts.headId || 'fs6Head');
  const showStu = !!filterStu;
  const showSec = !!filterSec && !showStu;
  const en = isEnglish();
  if (thead) thead.innerHTML = `<tr>
    <th>${en ? 'S.No.' : 'क्र.'}</th><th>${en ? 'Class' : 'कक्षा'}</th>
    ${showStu ? `<th>${en ? 'Adm.No.' : 'प्र.क्र.'}</th><th>${en ? 'Name of Student' : 'छात्र का नाम'}</th>` : ''}
    ${showSec && !showStu ? `<th>${en ? 'Section' : 'अनुभाग'}</th>` : ''}
    ${!showStu ? `<th>${en ? 'Name of Student' : 'छात्र का नाम'}</th>` : ''}
    ${activeFees.map(ft => `<th>${(en && ft.labelEn) ? ft.labelEn : ft.label.split('(')[0].trim()} (₹)</th>`).join('')}
    <th>${en ? 'Total Collection (₹)' : 'कुल संग्रह (₹)'}</th>
    ${hasAnyDefaulter ? `<th style="color:#c62828;">${en ? 'Defaulter (₹)' : 'बकाया (₹)'}</th>` : ''}
  </tr>`;

  const grandFee = new Array(activeFees.length).fill(0);
  let grandTotal = 0;
  let grandDefaulter = 0;
  let srNo = 0;

  // Build per-student rows
  const allRows = [];
  classes.forEach(cls => {
    const students = baseRegistry.filter(s => s.class === cls);
    const clsKeys = allF5Keys.filter(k => {
      const parts = k.replace('erp_fs5_','').split('_');
      const dateStr = parts[parts.length - 1];
      const clsPart = parts.slice(0, parts.length - 1).join('_');
      const monthNum = dateStr.split('-')[1];
      return clsPart === cls && activeMonthNums.includes(monthNum);
    });

    // Build F5 day-data map for this class
    const clsDayData = {};
    clsKeys.forEach(key => {
      const dayData = JSON.parse(localStorage.getItem(key) || '{}');
      Object.keys(dayData).forEach(admNo => {
        if (!clsDayData[admNo]) clsDayData[admNo] = new Array(activeFees.length).fill(0);
        activeFees.forEach((ft, j) => {
          clsDayData[admNo][j] += parseFloat((dayData[admNo]||{})[`f${j}`] || 0);
        });
      });
    });

    students.forEach(s => {
      srNo++;
      const stuFeeAmts = new Array(activeFees.length).fill(0);

      // Source: F5 per-student day-wise data (F5 already auto-fills from F2)
      if (clsDayData[s.admNo]) {
        clsDayData[s.admNo].forEach((v, j) => { stuFeeAmts[j] += v; });
      } else {
        // F5 me entry nahi hai — F2 (Fee Receipt) se direct paid amounts lo
        _getFs2FeeAmounts(s.admNo).forEach((v, j) => { stuFeeAmts[j] += v; });
      }

      const stuTotal = stuFeeAmts.reduce((a, b) => a + b, 0);
      grandTotal += stuTotal;
      stuFeeAmts.forEach((v, j) => grandFee[j] += v);

      const dueAmt = defaulterMap[s.admNo] || 0;
      if (dueAmt > 0) grandDefaulter += dueAmt;

      const stuName = s.name || s.nameHi || s.nameEn || s.admNo || '—';
      const sec = s.section || s.sec || '';
      allRows.push(`<tr${dueAmt > 0 ? ' style="background:#fff8f8;"' : ''}>
        <td>${srNo}</td>
        <td><b>${cls}</b></td>
        ${showStu ? `<td>${s.admNo||''}</td><td>${stuName}</td>` : ''}
        ${showSec ? `<td>${sec}</td>` : ''}
        ${!showStu ? `<td style="font-size:11px;">${stuName}</td>` : ''}
        ${stuFeeAmts.map(amt => `<td style="text-align:right;">${amt > 0 ? '₹'+amt.toLocaleString() : '—'}</td>`).join('')}
        <td style="text-align:right;color:#2e7d32;font-weight:700;">₹${stuTotal.toLocaleString()}</td>
        ${hasAnyDefaulter ? `<td style="text-align:right;font-weight:700;color:${dueAmt > 0 ? '#c62828' : '#888'};">${dueAmt > 0 ? '⚠️ ₹'+dueAmt.toLocaleString() : '✅'}</td>` : ''}
      </tr>`);
    });
  });

  const _bodyEl = document.getElementById(_bodyId);
  if (_bodyEl) _bodyEl.innerHTML = allRows.join('');

  const monthNote = selectedMonths.length
    ? `(${selectedMonths.join(', ')})`
    : (en ? '(All Months)' : '(सभी माह)');
  const footLabel = en ? `School Grand Total ${monthNote}` : `कुल विद्यालय योग ${monthNote}`;
  const extraCols = (showStu ? 1 : 0) + (showSec && !showStu ? 1 : 0);
  const _footEl2 = document.getElementById(_footId);
  if (_footEl2) _footEl2.innerHTML = `
    <tr style="background:#e8eaf6;font-weight:700;font-size:13px;">
      <td colspan="${3 + extraCols}">${footLabel}</td>
      ${grandFee.map(amt => `<td style="text-align:right;">₹${amt.toLocaleString()}</td>`).join('')}
      <td style="text-align:right;color:#2e7d32;font-size:14px;">₹${grandTotal.toLocaleString()}</td>
      ${hasAnyDefaulter ? `<td style="text-align:right;color:#c62828;font-size:14px;">₹${grandDefaulter.toLocaleString()}</td>` : ''}
    </tr>`;
}






// ---- FS6: Excel Export (SheetJS) ----
function _fs6ExportExcel(ids) {
  // ids = { school, monthLabel, session, udise, head, body, foot }
  try {
    var schoolName = (document.getElementById(ids.school) || {}).value || 'School';
    var monthLabel = (document.getElementById(ids.monthLabel) || {}).textContent || 'All Months';
    var session    = (document.getElementById(ids.session)  || {}).value || '';
    var udise      = (document.getElementById(ids.udise)    || {}).value || '';
    var thead = document.getElementById(ids.head);
    var tbody = document.getElementById(ids.body);
    var tfoot = document.getElementById(ids.foot);
    if (!thead || !tbody || !tbody.children.length) { alert('पहले डेटा लोड करें।'); return; }

    var en = typeof isEnglish === 'function' ? isEnglish() : false;
    var title = en ? 'Monthly / Annual Fee Statement (F6)' : 'माहवार / वार्षिक फीस विवरण (F6)';

    // Parse headers
    var headers = [];
    thead.querySelectorAll('th').forEach(function(th) {
      headers.push(th.innerText.replace(/\n/g,' ').trim());
    });

    // Parse data rows
    var dataRows = [];
    tbody.querySelectorAll('tr').forEach(function(tr) {
      var row = [];
      tr.querySelectorAll('td').forEach(function(td) {
        var txt = td.innerText.replace(/[₹⚠️✅]/g,'').replace(/,/g,'').trim();
        var num = parseFloat(txt);
        row.push(isNaN(num) ? txt : num);
      });
      if(row.length) dataRows.push(row);
    });

    // Parse footer
    var footRow = [];
    if(tfoot) {
      tfoot.querySelectorAll('td').forEach(function(td) {
        var txt = td.innerText.replace(/[₹⚠️✅]/g,'').replace(/,/g,'').trim();
        var num = parseFloat(txt);
        footRow.push(isNaN(num) ? txt : num);
      });
    }

    // Load SheetJS dynamically if not loaded
    function doExport() {
      var XLSX = window.XLSX;
      var wb = XLSX.utils.book_new();
      var wsData = [];

      // Row 1: Title (merged feel via colspan — SheetJS handles as single cell)
      wsData.push([title]);
      // Row 2: Info
      wsData.push([schoolName + ' | ' + (en?'Session: ':'सत्र: ') + session + ' | UDISE: ' + udise + ' | ' + (en?'Month: ':'माह: ') + monthLabel]);
      // Row 3: blank
      wsData.push([]);
      // Row 4: Headers
      wsData.push(headers);
      // Data rows
      dataRows.forEach(function(r){ wsData.push(r); });
      // Footer
      if(footRow.length) wsData.push(footRow);

      var ws = XLSX.utils.aoa_to_sheet(wsData);

      // ── Column widths (auto based on content) ──
      var colCount = headers.length;
      var colWidths = new Array(colCount).fill(10);
      // Check headers
      headers.forEach(function(h,i){ if(h.length > colWidths[i]) colWidths[i] = h.length; });
      // Check data
      dataRows.forEach(function(row){
        row.forEach(function(cell,i){
          var len = String(cell).length;
          if(len > colWidths[i]) colWidths[i] = len;
        });
      });
      // Check footer
      footRow.forEach(function(cell,i){
        var len = String(cell).length;
        if(len > colWidths[i]) colWidths[i] = len;
      });
      ws['!cols'] = colWidths.map(function(w){ return { wch: Math.min(w + 4, 40) }; });

      // ── Merge title and info rows across all columns ──
      var colLetter = XLSX.utils.encode_col(colCount - 1);
      ws['!merges'] = [
        { s:{r:0,c:0}, e:{r:0,c:colCount-1} },
        { s:{r:1,c:0}, e:{r:1,c:colCount-1} }
      ];

      // ── Cell styles via SheetJS-style (basic) ──
      // Title row bold center
      if(ws['A1']) { ws['A1'].s = { font:{bold:true,sz:14,color:{rgb:'FFFFFF'}}, fill:{fgColor:{rgb:'1A237E'}}, alignment:{horizontal:'center',vertical:'center'} }; }
      if(ws['A2']) { ws['A2'].s = { fill:{fgColor:{rgb:'E8EAF6'}}, alignment:{horizontal:'center'} }; }
      // Header row
      headers.forEach(function(_,i){
        var cell = ws[XLSX.utils.encode_cell({r:3,c:i})];
        if(cell) cell.s = { font:{bold:true,color:{rgb:'FFFFFF'}}, fill:{fgColor:{rgb:'283593'}}, alignment:{horizontal:'center',wrapText:true} };
      });
      // Footer row
      var footRowIdx = 4 + dataRows.length;
      if(footRow.length) {
        footRow.forEach(function(_,i){
          var cell = ws[XLSX.utils.encode_cell({r:footRowIdx,c:i})];
          if(cell) cell.s = { font:{bold:true}, fill:{fgColor:{rgb:'E8EAF6'}} };
        });
      }
      // Number cells right-align
      dataRows.forEach(function(row, ri){
        row.forEach(function(cell,ci){
          if(typeof cell === 'number'){
            var c = ws[XLSX.utils.encode_cell({r:4+ri,c:ci})];
            if(c) c.s = { alignment:{horizontal:'right'} };
          }
        });
      });

      XLSX.utils.book_append_sheet(wb, ws, 'F6 Fee Statement');
      XLSX.writeFile(wb, 'F6_Fee_Statement_' + monthLabel.replace(/[^a-zA-Z0-9]/g,'_') + '_' + session + '.xlsx');
    }

    // Load SheetJS if not present
    if(typeof window.XLSX !== 'undefined') {
      doExport();
    } else {
      var s = document.createElement('script');
      s.src = 'https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js';
      s.onload = doExport;
      s.onerror = function(){ alert('SheetJS load failed. Check internet connection.'); };
      document.head.appendChild(s);
    }
  } catch(ex) { alert('Export error: ' + ex.message); }
}

// ════════════════════════════════════════════════════════════
//  EXPORT ALL FEE SHEETS (F1–F7) — EK EXCEL FILE, 7 SHEETS
//  F1: Fee Config  F2: Receipts  F3: Defaulters  F4: Demand
//  F5: Clearance   F6: Annual    F7: Fee Statement
// ════════════════════════════════════════════════════════════
function exportFeeAllSheets() {
  function doExport() {
    try {
      var XLSX = window.XLSX;
      var en = isEnglish();
      var school = (typeof getSchoolInfo === 'function' ? getSchoolInfo().name : '') || 'School';
      var session = (document.getElementById('fs1Session') || {}).value || '';
      var udise   = (document.getElementById('fs1Udise')   || {}).value || '';
      var wb = XLSX.utils.book_new();

      // ── Helper: style header rows ──
      function styleSheet(ws, titleRow, subRow, headerRow, colCount, hdrColor) {
        ws['!merges'] = ws['!merges'] || [];
        ws['!merges'].push({s:{r:titleRow,c:0},e:{r:titleRow,c:colCount-1}});
        ws['!merges'].push({s:{r:subRow,c:0},e:{r:subRow,c:colCount-1}});
        var tc = XLSX.utils.encode_cell({r:titleRow,c:0});
        var sc = XLSX.utils.encode_cell({r:subRow,c:0});
        if(ws[tc]) ws[tc].s = {font:{bold:true,sz:13,color:{rgb:'FFFFFF'}},fill:{fgColor:{rgb:hdrColor}},alignment:{horizontal:'center'}};
        if(ws[sc]) ws[sc].s = {fill:{fgColor:{rgb:'F8F9FA'}},alignment:{horizontal:'center'}};
        for(var ci=0; ci<colCount; ci++){
          var hc = XLSX.utils.encode_cell({r:headerRow,c:ci});
          if(ws[hc]) ws[hc].s = {font:{bold:true,color:{rgb:'FFFFFF'}},fill:{fgColor:{rgb:hdrColor}},alignment:{horizontal:'center',wrapText:true}};
        }
      }

      // ── F1: Fee Configuration ──
      (function(){
        var wsData = [];
        wsData.push([en ? 'F1: School Fee Configuration' : 'F1: विद्यालय शुल्क संरचना']);
        wsData.push([school + (session ? '  |  ' + (en?'Session: ':'सत्र: ') + session : '') + (udise ? '  |  UDISE: ' + udise : '')]);
        wsData.push([]);
        wsData.push([en?'S.No.':'क्र.', en?'Fee Type':'शुल्क प्रकार', en?'Amount (₹)':'राशि (₹)', en?'Active':'संचालित', en?'Period':'अवधि']);
        var feeConf = (typeof feeConfig !== 'undefined') ? feeConfig : {};
        var feeTypes = (typeof FS_FEE_TYPES !== 'undefined') ? FS_FEE_TYPES : [];
        feeTypes.forEach(function(ft, i){
          var cfg = feeConf[i] || {};
          wsData.push([
            i+1,
            (en && ft.labelEn) ? ft.labelEn : ft.label,
            parseFloat(cfg.amt) || '',
            cfg.active === 'yes' ? (en?'Yes':'हाँ') : (en?'No':'नहीं'),
            cfg.period || ft.period || ''
          ]);
        });
        // Selected months
        var months = (typeof _erpSafeLoad === 'function') ? _erpSafeLoad(erpKey('erp_feeMonths'),[]) : [];
        wsData.push([]);
        wsData.push([en?'Selected Months:':'चयनित माह:', months.join(', ')]);
        var ws = XLSX.utils.aoa_to_sheet(wsData);
        ws['!cols'] = [{wch:6},{wch:28},{wch:14},{wch:12},{wch:14}];
        styleSheet(ws, 0, 1, 3, 5, '1565C0');
        XLSX.utils.book_append_sheet(wb, ws, en?'F1 Fee Config':'F1 शुल्क संरचना');
      })();

      // ── F2: All Receipts ──
      (function(){
        var allFees = (typeof fees !== 'undefined') ? fees : [];
        var allStudents = (typeof registry !== 'undefined') ? registry : (typeof _getAllStudents==='function' ? _getAllStudents() : []);
        var wsData = [];
        wsData.push([en?'F2: Fee Receipts / Payment Register':'F2: शुल्क रसीद / भुगतान रजिस्टर']);
        wsData.push([school + (session ? '  |  ' + (en?'Session: ':'सत्र: ') + session : '') + '  |  ' + (en?'Total Records: ':'कुल रिकॉर्ड: ') + allFees.length]);
        wsData.push([]);
        wsData.push([en?'S.No.':'क्र.', en?'Adm. No.':'क्र.सं.', en?'Student Name':'छात्र नाम', en?'Class':'कक्षा', en?'Fee Type':'शुल्क प्रकार', en?'Period':'अवधि', en?'Amount (₹)':'राशि (₹)', en?'Mode':'मोड', en?'Receipt No.':'रसीद क्र.', en?'Date':'दिनांक', en?'Status':'स्थिति']);
        allFees.forEach(function(f, i){
          var stu = allStudents.find(function(s){ return s.admNo === f.admNo; }) || {};
          wsData.push([
            i+1, f.admNo||'', stu.name||'', stu.class||'',
            f.type||'', f.period||'', parseFloat(f.amount)||0,
            f.mode||'', f.receipt||'', f.date||'', f.status||''
          ]);
        });
        // Summary
        var paid = allFees.filter(function(f){return f.status==='Paid';}).reduce(function(a,f){return a+(+f.amount||0);},0);
        var due  = allFees.filter(function(f){return f.status==='Due'; }).reduce(function(a,f){return a+(+f.amount||0);},0);
        wsData.push([]);
        wsData.push([en?'Total Paid:':'कुल जमा:','','','','','',paid]);
        wsData.push([en?'Total Due:':'कुल बकाया:','','','','','',due]);
        var ws = XLSX.utils.aoa_to_sheet(wsData);
        ws['!cols'] = [{wch:6},{wch:10},{wch:24},{wch:8},{wch:18},{wch:14},{wch:12},{wch:10},{wch:12},{wch:12},{wch:10}];
        styleSheet(ws, 0, 1, 3, 11, '1B7E3B');
        XLSX.utils.book_append_sheet(wb, ws, en?'F2 Receipts':'F2 रसीद');
      })();

      // ── F3: Defaulters (DOM se) ──
      (function(){
        var tbody = document.getElementById('fs4Body');
        var wsData = [];
        var cls = (document.getElementById('fs4Class')||{}).value || (en?'All Classes':'सभी कक्षाएं');
        wsData.push([en?'F3: Fee Defaulters List':'F3: बकाया फीस सूची']);
        wsData.push([school + '  |  ' + (en?'Class: ':'कक्षा: ') + cls + (session?'  |  '+(en?'Session: ':'सत्र: ')+session:'')]);
        wsData.push([]);
        wsData.push([en?'S.No.':'क्र.', en?'Student Name':'छात्र नाम', en?'Class':'कक्षा', en?'Total Due (₹)':'कुल बकाया (₹)']);
        if(tbody && tbody.children.length){
          tbody.querySelectorAll('tr').forEach(function(tr,i){
            var cells = tr.querySelectorAll('td');
            if(cells.length>=4) wsData.push([i+1, cells[1].innerText.trim(), cells[2].innerText.trim(), parseFloat(cells[3].innerText.replace(/[₹,]/g,'').trim())||0]);
          });
        } else {
          wsData.push([en?'(Open F3 tab first to load data)':'(पहले F3 tab खोलें)']);
        }
        var ws = XLSX.utils.aoa_to_sheet(wsData);
        ws['!cols'] = [{wch:6},{wch:28},{wch:12},{wch:18}];
        styleSheet(ws, 0, 1, 3, 4, 'C62828');
        XLSX.utils.book_append_sheet(wb, ws, en?'F3 Defaulters':'F3 बकाया सूची');
      })();

      // ── F4: Demand Notice list (DOM se) ──
      (function(){
        var tbody = document.getElementById('fs8Body') || document.querySelector('#fs8 tbody');
        var wsData = [];
        wsData.push([en?'F4: Demand Notice Register':'F4: मांग नोटिस रजिस्टर']);
        wsData.push([school + (session?'  |  '+(en?'Session: ':'सत्र: ')+session:'')]);
        wsData.push([]);
        wsData.push([en?'S.No.':'क्र.', en?'Student Name':'छात्र नाम', en?'Class':'कक्षा', en?'Due Amount (₹)':'बकाया राशि (₹)', en?'Notice Date':'नोटिस दिनांक']);
        if(tbody && tbody.children.length){
          tbody.querySelectorAll('tr').forEach(function(tr,i){
            var row = [i+1];
            tr.querySelectorAll('td').forEach(function(td){ row.push(td.innerText.replace(/[₹,]/g,'').trim()); });
            wsData.push(row);
          });
        } else {
          wsData.push([en?'(Open F4 tab first to load data)':'(पहले F4 tab खोलें)']);
        }
        var ws = XLSX.utils.aoa_to_sheet(wsData);
        ws['!cols'] = [{wch:6},{wch:28},{wch:12},{wch:16},{wch:14}];
        styleSheet(ws, 0, 1, 3, 5, '6A1E9A');
        XLSX.utils.book_append_sheet(wb, ws, en?'F4 Demand Notice':'F4 मांग नोटिस');
      })();

      // ── F5: Clearance list (DOM se) ──
      (function(){
        var tbody = document.getElementById('fs9Body') || document.querySelector('#fs9 tbody');
        var wsData = [];
        wsData.push([en?'F5: Fee Clearance List':'F5: शुल्क निकासी सूची']);
        wsData.push([school + (session?'  |  '+(en?'Session: ':'सत्र: ')+session:'')]);
        wsData.push([]);
        wsData.push([en?'S.No.':'क्र.', en?'Student Name':'छात्र नाम', en?'Class':'कक्षा', en?'Total Paid (₹)':'कुल जमा (₹)', en?'Status':'स्थिति']);
        if(tbody && tbody.children.length){
          tbody.querySelectorAll('tr').forEach(function(tr,i){
            var row = [i+1];
            tr.querySelectorAll('td').forEach(function(td){ row.push(td.innerText.replace(/[₹,✅⚠️]/g,'').trim()); });
            wsData.push(row);
          });
        } else {
          wsData.push([en?'(Open F5 tab first to load data)':'(पहले F5 tab खोलें)']);
        }
        var ws = XLSX.utils.aoa_to_sheet(wsData);
        ws['!cols'] = [{wch:6},{wch:28},{wch:12},{wch:16},{wch:12}];
        styleSheet(ws, 0, 1, 3, 5, '0D7647');
        XLSX.utils.book_append_sheet(wb, ws, en?'F5 Clearance':'F5 निकासी');
      })();

      // ── F6: Annual Statement (DOM se) ──
      (function(){
        var tbody = document.getElementById('fs10Body') || document.querySelector('#fs10 tbody');
        var tfoot = document.getElementById('fs10Foot') || document.querySelector('#fs10 tfoot');
        var wsData = [];
        wsData.push([en?'F6: Annual Fee Statement':'F6: वार्षिक शुल्क विवरण']);
        wsData.push([school + (session?'  |  '+(en?'Session: ':'सत्र: ')+session:'')]);
        wsData.push([]);
        if(tbody && tbody.children.length){
          var headers = [];
          (document.querySelector('#fs10 thead') || {querySelectorAll:function(){return [];}}).querySelectorAll('th').forEach(function(th){ headers.push(th.innerText.trim()); });
          if(headers.length) wsData.push(headers);
          tbody.querySelectorAll('tr').forEach(function(tr){
            var row = [];
            tr.querySelectorAll('td').forEach(function(td){ var t=td.innerText.replace(/[₹,]/g,'').trim(); row.push(isNaN(parseFloat(t))?t:parseFloat(t)); });
            if(row.length) wsData.push(row);
          });
          if(tfoot) tfoot.querySelectorAll('tr').forEach(function(tr){
            var row = [];
            tr.querySelectorAll('td').forEach(function(td){ var t=td.innerText.replace(/[₹,]/g,'').trim(); row.push(isNaN(parseFloat(t))?t:parseFloat(t)); });
            if(row.length) wsData.push(row);
          });
        } else {
          wsData.push([en?'(Open F6 tab first to load data)':'(पहले F6 tab खोलें)']);
        }
        var ws = XLSX.utils.aoa_to_sheet(wsData);
        ws['!cols'] = Array(12).fill({wch:14});
        styleSheet(ws, 0, 1, 3, 10, 'F57F17');
        XLSX.utils.book_append_sheet(wb, ws, en?'F6 Annual Stmt':'F6 वार्षिक विवरण');
      })();

      // ── F7: Fee Statement (DOM se) ──
      (function(){
        var tbody = document.getElementById('f11BodyTuition') || document.getElementById('fs11Body') || document.querySelector('#fs11 tbody');
        var tfoot = document.getElementById('f11FootTuition') || document.getElementById('fs11Foot') || document.querySelector('#fs11 tfoot');
        var wsData = [];
        wsData.push([en?'F7: Fee Statement':'F7: शुल्क विवरण']);
        wsData.push([school + (session?'  |  '+(en?'Session: ':'सत्र: ')+session:'')]);
        wsData.push([]);
        if(tbody && tbody.children.length){
          var headers = [];
          var thead = document.getElementById('f11TableTuition') || document.querySelector('#fs11 table');
          if(thead) thead.querySelectorAll('thead th').forEach(function(th){ headers.push(th.innerText.trim()); });
          if(headers.length) wsData.push(headers);
          tbody.querySelectorAll('tr').forEach(function(tr){
            var row = [];
            tr.querySelectorAll('td').forEach(function(td,i){ var t=td.innerText.replace(/[₹,⚠️✅]/g,'').trim(); row.push((i>=4&&!isNaN(parseFloat(t)))?parseFloat(t):t); });
            if(row.length) wsData.push(row);
          });
          if(tfoot) tfoot.querySelectorAll('tr').forEach(function(tr){
            var row = [];
            tr.querySelectorAll('td').forEach(function(td){ var t=td.innerText.replace(/[₹,]/g,'').trim(); row.push(isNaN(parseFloat(t))?t:parseFloat(t)); });
            if(row.length) wsData.push(row);
          });
        } else {
          wsData.push([en?'(Open F7 tab first to load data)':'(पहले F7 tab खोलें)']);
        }
        var ws = XLSX.utils.aoa_to_sheet(wsData);
        ws['!cols'] = Array(10).fill({wch:14});
        styleSheet(ws, 0, 1, 3, 9, '1565C0');
        XLSX.utils.book_append_sheet(wb, ws, en?'F7 Fee Stmt':'F7 शुल्क विवरण');
      })();

      // ── Download ──
      var today = new Date().toISOString().slice(0,10);
      XLSX.writeFile(wb, 'FeeManagement_'+school.replace(/[^a-zA-Z0-9]/g,'_')+'_'+today+'.xlsx');

    } catch(ex) { alert('Export error: ' + ex.message); }
  }

  if(typeof window.XLSX !== 'undefined'){ doExport(); }
  else {
    var s = document.createElement('script');
    s.src = 'https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js';
    s.onload = doExport;
    s.onerror = function(){ alert('SheetJS load नहीं हुई।'); };
    document.head.appendChild(s);
  }
}

