// ---- F11 Tuition Fee Excel Export ----
function exportF11TuitionExcel() {
  try {
    var en = isEnglish();
    var school = (typeof getSchoolInfo === 'function' ? getSchoolInfo().name : '') || 'School';
    var cls    = (document.getElementById('f11TuClass')   || {}).value || '';
    var sec    = (document.getElementById('f11TuSec')     || {}).value || '';
    var stu    = (document.getElementById('f11TuStudent') || {}).value || '';
    var monthLabel = (document.getElementById('f11TuMonthLabel') || {}).textContent || (en ? 'All Months' : 'सभी माह');
    var tbody  = document.getElementById('f11BodyTuition');
    var tfoot  = document.getElementById('f11FootTuition');
    if (!tbody || !tbody.children.length) { alert(en ? 'No data. Please load Tuition tab first.' : 'डेटा नहीं मिला।'); return; }

    function doExport() {
      var XLSX = window.XLSX;
      var wb = XLSX.utils.book_new();
      var wsData = [];
      var title = en ? 'Tuition Fee Statement (F7)' : 'ट्यूशन शुल्क विवरण (F7)';
      var filterLabel = stu ? stu : (cls ? (en ? 'Class: ' : 'कक्षा: ') + cls + (sec ? ' / ' + sec : '') : (en ? 'All Students' : 'सभी छात्र'));
      wsData.push([title]);
      wsData.push([school + ' | ' + (en ? 'Month: ' : 'माह: ') + monthLabel + ' | ' + filterLabel]);
      wsData.push([]);
      // Headers
      var headers = [];
      document.querySelectorAll('#f11TableTuition thead th').forEach(function(th) { headers.push(th.innerText.trim()); });
      wsData.push(headers);
      // Data rows
      tbody.querySelectorAll('tr').forEach(function(tr) {
        var row = [];
        tr.querySelectorAll('td').forEach(function(td, i) {
          var txt = td.innerText.replace(/[₹⚠️✅]/g,'').replace(/,/g,'').trim();
          var num = parseFloat(txt);
          // S.No. (0), Due (4), Paid (5), Balance (6) are numeric
          row.push((i === 0 || i === 4 || i === 5 || i === 6) && !isNaN(num) ? num : txt);
        });
        if (row.length) wsData.push(row);
      });
      // Footer
      if (tfoot) {
        tfoot.querySelectorAll('tr').forEach(function(tr) {
          var row = [];
          tr.querySelectorAll('td').forEach(function(td) {
            var txt = td.innerText.replace(/[₹⚠️✅]/g,'').replace(/,/g,'').trim();
            var num = parseFloat(txt);
            row.push(isNaN(num) ? txt : num);
          });
          if (row.length) wsData.push(row);
        });
      }

      var colCount = headers.length || 9;
      var ws = XLSX.utils.aoa_to_sheet(wsData);
      ws['!cols'] = [{wch:6},{wch:12},{wch:24},{wch:10},{wch:14},{wch:14},{wch:14},{wch:14},{wch:10}];
      ws['!merges'] = [
        {s:{r:0,c:0},e:{r:0,c:colCount-1}},
        {s:{r:1,c:0},e:{r:1,c:colCount-1}}
      ];
      if (ws['A1']) ws['A1'].s = {font:{bold:true,sz:13,color:{rgb:'FFFFFF'}},fill:{fgColor:{rgb:'1565C0'}},alignment:{horizontal:'center'}};
      if (ws['A2']) ws['A2'].s = {fill:{fgColor:{rgb:'E3F2FD'}},alignment:{horizontal:'center'}};
      headers.forEach(function(_, i) {
        var cell = ws[XLSX.utils.encode_cell({r:3,c:i})];
        if (cell) cell.s = {font:{bold:true,color:{rgb:'FFFFFF'}},fill:{fgColor:{rgb:'1565C0'}},alignment:{horizontal:'center',wrapText:true}};
      });
      XLSX.utils.book_append_sheet(wb, ws, en ? 'F7 Tuition Fee' : 'F7 ट्यूशन फीस');
      XLSX.writeFile(wb, 'F7_Tuition_Fee_' + monthLabel.replace(/[^a-zA-Z0-9]/g,'_') + '.xlsx');
    }
    if (typeof window.XLSX !== 'undefined') { doExport(); }
    else {
      var s = document.createElement('script');
      s.src = 'https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js';
      s.onload = doExport;
      s.onerror = function() { alert('SheetJS load failed.'); };
      document.head.appendChild(s);
    }
  } catch(ex) { alert('Export error: ' + ex.message); }
}

