      if (ws['A2']) ws['A2'].s = {fill:{fgColor:{rgb:'FFEBEE'}},alignment:{horizontal:'center'}};
      [0,1,2,3].forEach(function(ci) {
        var cell = ws[XLSX.utils.encode_cell({r:3,c:ci})];
        if (cell) cell.s = {font:{bold:true,color:{rgb:'FFFFFF'}},fill:{fgColor:{rgb:'B71C1C'}},alignment:{horizontal:'center'}};
      });
      XLSX.utils.book_append_sheet(wb, ws, en ? 'F3 Defaulters' : 'F3 बकाया सूची');
