function initFs8() {
  const sel = document.getElementById('fs8Student');
  sel.innerHTML = '<option value="">-- Select Student --</option>';
  _getAllStudents().forEach(function(s){ sel.innerHTML += '<option value="'+s.admNo+'">'+s.name+' ('+s.admNo+')</option>'; });
  document.getElementById('fs8Date').value = new Date().toISOString().split('T')[0];
  // Reset all filled fields
  ['fs8Class','fs8Parent','fs8PalyaName','fs8PalyaClass'].forEach(id => {
    const el = document.getElementById(id); if (el) el.value = '';
  });
  const feeStmt = document.getElementById('fs8FeeStatement');
  if (feeStmt) feeStmt.style.display = 'none';
  document.getElementById('fs8Days').addEventListener('input', function() {
    document.getElementById('fs8DaysDisplay').textContent = this.value;
  });
  _applyFs8Lang();
}

function fillFs8Student() {
  const admNo = document.getElementById('fs8Student').value;
  const s = _getAllStudents().find(r => r.admNo === admNo);
  if (s) {
    document.getElementById('fs8Class').value = s.class || '';
    document.getElementById('fs8Parent').value = s.fname || '';
    document.getElementById('fs8PalyaName').value = s.name || '';
    document.getElementById('fs8PalyaClass').value = s.class || '';
  }
  // Fee statement auto-load करें
  renderFs8FeeStatement(admNo);
}

function renderFs8FeeStatement(admNo) {
  var en = isEnglish();
  const stmtDiv = document.getElementById('fs8FeeStatement');
  if (!stmtDiv) return;

  if (!admNo) {
    stmtDiv.style.display = 'none';
    stmtDiv.innerHTML = '';
    return;
  }

  const s = _getAllStudents().find(r => r.admNo === admNo);
  if (!s) { stmtDiv.style.display = 'none'; return; }

  const fs2Data = JSON.parse(localStorage.getItem(erpKey('erp_fs2_') + admNo) || 'null');
  const savedMonths = _erpSafeLoad(erpKey('erp_feeMonths'), []);
  const allOrder = ['April','May','June','July','August','September','October','November','December','January','February','March'];
  const allMonthsMap = {'April':'अप्रैल','May':'मई','June':'जून','July':'जुलाई','August':'अगस्त','September':'सितम्बर','October':'अक्टूबर','November':'नवम्बर','December':'दिसम्बर','January':'जनवरी','February':'फरवरी','March':'मार्च'};
  const activeMonths = savedMonths.length > 0 ? allOrder.filter(m => savedMonths.includes(m)) : allOrder;

  let grandDue = 0, grandPaid = 0;
  let rows = '';

  // Part-B: ट्यूशन + परिवहन माहवार
  if (fs2Data && fs2Data.partB && fs2Data.partB.length > 0) {
    rows += `<tr style="background:#fff3e0;"><td colspan="4" style="padding:8px 12px;font-weight:700;color:#e65100;">📅 ${en ? 'Tuition Fee + Transport Fee (Monthly)' : 'ट्यूशन फीस + परिवहन फीस (माहवार)'}</td></tr>`;
    fs2Data.partB.forEach((row, idx) => {
      const mLabel = en ? (activeMonths[idx] || '') : (allMonthsMap[activeMonths[idx]] || activeMonths[idx] || '');
      const tDue  = parseFloat(row.tDue  || 0);
      const tPaid = parseFloat(row.tPaid || 0);
      const trDue = parseFloat(row.trDue || 0);
      const trPaid= parseFloat(row.trPaid|| 0);
      const due   = tDue + trDue;
      const paid  = tPaid + trPaid;
      const bal   = due - paid;
      if (due === 0) return;
      grandDue  += due;
      grandPaid += paid;
      rows += `<tr>
        <td style="padding:6px 12px;">${mLabel}</td>
        <td style="padding:6px 12px;text-align:right;">₹${due.toLocaleString()}</td>
        <td style="padding:6px 12px;text-align:right;color:#2e7d32;">₹${paid.toLocaleString()}</td>
        <td style="padding:6px 12px;text-align:right;color:${bal>0?'#c62828':'#2e7d32'};font-weight:${bal>0?'700':'400'};">${bal>0?'₹'+bal.toLocaleString():(en?'✓ Paid':'✓ जमा')}</td>
      </tr>`;
    });
  }

  // Part-A: अन्य शुल्क
  if (fs2Data && fs2Data.partA) {
    const otherFees = fs2Data.partA.filter(row => {
      const isTuition   = (row.label||'').includes('ट्यूशन')  || (row.label||'').includes('Tuition');
      const isTransport = (row.label||'').includes('परिवहन') || (row.label||'').includes('Transport');
      return !isTuition && !isTransport && parseFloat(row.due||0) > 0;
    });
    if (otherFees.length > 0) {
      rows += `<tr style="background:#fff3e0;"><td colspan="4" style="padding:8px 12px;font-weight:700;color:#e65100;">📌 ${en ? 'Other Fees' : 'अन्य शुल्क'}</td></tr>`;
      otherFees.forEach(row => {
        const due  = parseFloat(row.due  || 0);
        const paid = parseFloat(row.paid || 0);
        const bal  = due - paid;
        grandDue  += due;
        grandPaid += paid;
        const rawLabel = (row.label||'').split('(')[0].trim();
        const displayLabel = en
          ? (FS_FEE_TYPES.find(ft => ft.label.split('(')[0].trim() === rawLabel || ft.label.includes(rawLabel) || rawLabel.includes(ft.label.split('(')[0].trim()))?.labelEn || rawLabel)
          : rawLabel;
        rows += `<tr>
          <td style="padding:6px 12px;">${displayLabel}</td>
          <td style="padding:6px 12px;text-align:right;">₹${due.toLocaleString()}</td>
          <td style="padding:6px 12px;text-align:right;color:#2e7d32;">₹${paid.toLocaleString()}</td>
          <td style="padding:6px 12px;text-align:right;color:${bal>0?'#c62828':'#2e7d32'};font-weight:${bal>0?'700':'400'};">${bal>0?'₹'+bal.toLocaleString():(en?'✓ Paid':'✓ जमा')}</td>
        </tr>`;
      });
    }
  }

  const grandBal = grandDue - grandPaid;

  if (!rows) {
    stmtDiv.style.display = 'block';
    stmtDiv.innerHTML = `
      <div style="background:#fff8e1;border:1px dashed #f9a825;border-radius:8px;padding:16px;text-align:center;color:#f57f17;font-size:13px;font-weight:600;margin-top:16px;">
        ⚠️ ${en ? 'No fee data entered for this student in F2.' : 'इस छात्र का F2 में कोई शुल्क डेटा दर्ज नहीं है।'}
      </div>`;
    return;
  }

  stmtDiv.style.display = 'block';
  stmtDiv.innerHTML = `
    <div style="margin-top:20px;border-top:2px dashed #e65100;padding-top:16px;">
      <div style="font-size:13px;font-weight:700;color:#e65100;margin-bottom:10px;display:flex;align-items:center;gap:8px;">
        <span style="font-size:16px;">📊</span> ${en ? 'Student Fee Statement' : 'छात्र का शुल्क विवरण (Fee Statement)'}
        <span style="font-size:11px;font-weight:400;color:#888;margin-left:8px;">${en ? '— Auto-filled from F2 data' : '— F2 डेटा से स्वतः भरा गया'}</span>
      </div>

      <!-- Student info strip -->
      <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:6px;font-size:11px;background:#fff8e1;padding:8px 12px;border-radius:6px;margin-bottom:10px;border:1px solid #ffe082;">
        <div><b>${en?'Student:':'छात्र:'}</b> ${s.name}</div>
        <div><b>${en?'Adm. No.:':'प्रवेश क्र.:'}</b> ${admNo}</div>
        <div><b>${en?'Class:':'कक्षा:'}</b> ${s.class}${s.sec?' - '+s.sec:''}</div>
        <div><b>${en?'Father:':'पिता:'}</b> ${s.father||s.fname||s.fName||'—'}</div>
      </div>

      <!-- Fee detail table -->
      <div class="table-wrap" style="margin-bottom:12px;">
        <table style="font-size:12px;">
          <thead>
            <tr style="background:#e65100;color:#fff;">
              <th style="padding:8px 12px;text-align:left;">${en ? 'Description / Month' : 'विवरण / माह'}</th>
              <th style="padding:8px 12px;text-align:right;">${en ? 'Total Due (₹)' : 'कुल देय (₹)'}</th>
              <th style="padding:8px 12px;text-align:right;">${en ? 'Paid Amount (₹)' : 'जमा राशि (₹)'}</th>
              <th style="padding:8px 12px;text-align:right;">${en ? 'Balance (₹)' : 'बकाया (₹)'}</th>
            </tr>
          </thead>
          <tbody>${rows}</tbody>
          <tfoot>
            <tr style="background:#fff3e0;font-weight:700;font-size:13px;border-top:2px solid #e65100;">
              <td style="padding:8px 12px;">${en ? 'Grand Total' : 'कुल योग / Grand Total'}</td>
              <td style="padding:8px 12px;text-align:right;">₹${grandDue.toLocaleString()}</td>
              <td style="padding:8px 12px;text-align:right;color:#2e7d32;">₹${grandPaid.toLocaleString()}</td>
              <td style="padding:8px 12px;text-align:right;color:${grandBal>0?'#c62828':'#2e7d32'};font-size:15px;">${grandBal>0?'₹'+grandBal.toLocaleString():(en?'✓ Clear':'✓ क्लियर')}</td>
            </tr>
          </tfoot>
        </table>
      </div>

      <!-- Summary boxes -->
      <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px;margin-bottom:4px;">
        <div style="background:#e3f2fd;border-radius:8px;padding:10px;text-align:center;">
          <div style="font-size:10px;color:#555;">${en ? 'Total Due' : 'कुल देय'}</div>
          <div style="font-size:17px;font-weight:800;color:#1a237e;">₹${grandDue.toLocaleString()}</div>
        </div>
        <div style="background:#e8f5e9;border-radius:8px;padding:10px;text-align:center;">
          <div style="font-size:10px;color:#555;">${en ? 'Paid Amount' : 'जमा राशि'}</div>
          <div style="font-size:17px;font-weight:800;color:#2e7d32;">₹${grandPaid.toLocaleString()}</div>
        </div>
        <div style="background:#ffebee;border-radius:8px;padding:10px;text-align:center;">
          <div style="font-size:10px;color:#555;">${en ? 'Total Balance' : 'कुल बकाया'}</div>
          <div style="font-size:17px;font-weight:800;color:#c62828;">₹${grandBal.toLocaleString()}</div>
        </div>
      </div>
    </div>`;
}

