function initFs9() {
  const sel = document.getElementById('fs9Student');
  sel.innerHTML = '<option value="">-- Select Student --</option>';
  _getAllStudents().forEach(function(s){ sel.innerHTML += '<option value="'+s.admNo+'">'+s.name+' ('+s.admNo+')</option>'; });
  document.getElementById('fs9Date').value = new Date().toISOString().split('T')[0];
  // Reset all filled fields
  ['fs9Parent','fs9Class','fs9Sec','fs9Adm'].forEach(id => {
    const el = document.getElementById(id); if (el) el.value = '';
  });
  // Hide messages and table
  document.getElementById('fs9ClearMsg').style.display = 'none';
  document.getElementById('fs9DueMsg').style.display   = 'none';
  document.getElementById('fs9TableWrap').style.display = 'none';
  document.getElementById('fs9TableBody').innerHTML = '';
  _applyFs9Lang();
}

function fillFs9Student() {
  var en = isEnglish();
  const admNo = document.getElementById('fs9Student').value;
  const s = _getAllStudents().find(r => r.admNo === admNo);
  if (s) {
    document.getElementById('fs9Parent').value = s.fname || s.mname || '';
    document.getElementById('fs9Class').value = s.class;
    document.getElementById('fs9Sec').value = s.sec || '';
    document.getElementById('fs9Adm').value = s.admNo;
    document.getElementById('fs9NameDisplay').textContent = s.name;
    document.getElementById('fs9ParentDisplay').textContent = s.fname || s.mname || '___';
    document.getElementById('fs9ClassDisplay').textContent = s.class;
    document.getElementById('fs9NameDisplay2').textContent = s.name;
    document.getElementById('fs9ClassDisplay2').textContent = s.class;
  }

  // F2 data से table auto-fill
  const tbody = document.getElementById('fs9TableBody');
  if (!tbody || !admNo) return;

  const fs2Data = JSON.parse(localStorage.getItem(erpKey('erp_fs2_') + admNo) || 'null');

  if (!fs2Data) {
    tbody.innerHTML = `<tr><td colspan="6" style="text-align:center;padding:16px;color:#999;">${en ? 'No F2 data found for this student' : 'F2 में इस छात्र का कोई डेटा नहीं मिला'}</td></tr>`;
    return;
  }

  // सभी fee types collect करें
  const feeRows = [];

  // Part-B: ट्यूशन + परिवहन (माहवार total)
  if (fs2Data.partB && fs2Data.partB.length > 0) {
    let tDueTotal = 0, tPaidTotal = 0, trDueTotal = 0, trPaidTotal = 0;
    fs2Data.partB.forEach(row => {
      tDueTotal  += parseFloat(row.tDue  || 0);
      tPaidTotal += parseFloat(row.tPaid || 0);
      trDueTotal += parseFloat(row.trDue || 0);
      trPaidTotal+= parseFloat(row.trPaid|| 0);
    });
    if (tDueTotal > 0 || tPaidTotal > 0)
      feeRows.push({ label: en ? 'Tuition Fee' : 'ट्यूशन फीस / Tuition Fee',    due: tDueTotal,  paid: tPaidTotal  });
    if (trDueTotal > 0 || trPaidTotal > 0)
      feeRows.push({ label: en ? 'Transport Fee' : 'परिवहन फीस / Transport Fee',   due: trDueTotal, paid: trPaidTotal });
  }

  // Part-A: अन्य शुल्क
  if (fs2Data.partA) {
    fs2Data.partA.forEach(row => {
      const isTuition   = (row.label||'').includes('ट्यूशन')  || (row.label||'').includes('Tuition');
      const isTransport = (row.label||'').includes('परिवहन') || (row.label||'').includes('Transport');
      if (isTuition || isTransport) return;
      const due  = parseFloat(row.due  || 0);
      const paid = parseFloat(row.paid || 0);
      const rawLabel = (row.label||'').split('(')[0].trim();
      const displayLabel = en
        ? (FS_FEE_TYPES.find(ft => ft.label.split('(')[0].trim() === rawLabel || ft.label.includes(rawLabel) || rawLabel.includes(ft.label.split('(')[0].trim()))?.labelEn || rawLabel)
        : rawLabel;
      if (due > 0 || paid > 0)
        feeRows.push({ label: displayLabel, due, paid });
    });
  }

  if (!feeRows.length) {
    tbody.innerHTML = `<tr><td colspan="6" style="text-align:center;padding:16px;color:#999;">${en ? 'No fee data found' : 'कोई शुल्क डेटा नहीं मिला'}</td></tr>`;
    document.getElementById('fs9TableWrap').style.display = 'none';
    return;
  }

  let grandDue = 0, grandPaid = 0;
  // Pehle grandDue/grandPaid calculate karo (allClear ke liye)
  feeRows.forEach(r => { grandDue += r.due; grandPaid += r.paid; });

  // Sirf woh rows dikhao jinka bakaya hai (cleared rows hide)
  let sno = 0;
  let html = feeRows.map((r) => {
    const bal = r.due - r.paid;
    if (bal <= 0) return ''; // cleared — skip
    sno++;
    return `<tr>
      <td>${sno}</td>
      <td>${r.label}</td>
      <td style="text-align:right;">₹${r.due.toLocaleString()}</td>
      <td style="text-align:right;color:#2e7d32;font-weight:600;">₹${r.paid.toLocaleString()}</td>
      <td style="text-align:right;color:#c62828;font-weight:700;">₹${bal.toLocaleString()}</td>
      <td><span class="badge badge-red">⚠️ ${en ? 'Pending' : 'बकाया'}</span></td>
    </tr>`;
  }).join('');

  const grandBal = grandDue - grandPaid;
  const allClear = grandBal <= 0;
  // Grand Total row sirf tab dikhao jab koi pending ho aur ek se zyada fee types pending hon
  if (!allClear && feeRows.filter(r => (r.due - r.paid) > 0).length > 1) {
    html += `<tr style="background:#e8f5e9;font-weight:700;">
    <td colspan="2">${en ? 'Grand Total →' : 'कुल योग →'}</td>
    <td style="text-align:right;">₹${grandDue.toLocaleString()}</td>
    <td style="text-align:right;color:#2e7d32;">₹${grandPaid.toLocaleString()}</td>
    <td style="text-align:right;color:#c62828;">₹${grandBal.toLocaleString()}</td>
    <td><span class="badge badge-red">⚠️ ${en ? 'Pending' : 'बकाया'}</span></td>
  </tr>`;
  }

  document.getElementById('fs9TableBody').innerHTML = html;

  // Clear / Bakaya message toggle
  const clearMsg = document.getElementById('fs9ClearMsg');
  const dueMsg   = document.getElementById('fs9DueMsg');
  if (allClear) {
    // Sabki fees clear — sirf message dikhao, table hide karo
    clearMsg.style.display = 'block';
    dueMsg.style.display   = 'none';
    document.getElementById('fs9TableWrap').style.display = 'none';
  } else {
    // Kuch baaki — table dikhao
    clearMsg.style.display = 'none';
    dueMsg.style.display   = 'block';
    document.getElementById('fs9TableWrap').style.display = 'block';
  }
}

