// ---- F6 Filter helpers ----
function fs10PopulateFilters() {
  var classEl  = document.getElementById('fs10FilterClass');
  var secEl    = document.getElementById('fs10FilterSec');
  var studEl   = document.getElementById('fs10FilterStudent');
  if (!classEl) return;

  // admList3 — sirf current session ke students
  var _adSess1=(document.getElementById('sc_yr')?document.getElementById('sc_yr').value:'')||getCurrentSession();
  var admData = ((typeof admList3 !== 'undefined' && Array.isArray(admList3)) ? admList3
              : JSON.parse(localStorage.getItem(erpKey('admList3')) || '[]')).filter(function(r){return r.session===_adSess1;});

  var classes = [...new Set(admData.map(r => r.class||'').filter(Boolean))]
                  .sort((a,b) => a.localeCompare(b, undefined, {numeric:true}));
  var prevClass = classEl.value;
  classEl.innerHTML = '<option value="">-- All Classes --</option>'
    + classes.map(c => `<option value="${c}">${c}</option>`).join('');
  if (prevClass) classEl.value = prevClass;

  fs10PopulateSectionDrop(classEl.value);
}

function fs10PopulateSectionDrop(cls) {
  var secEl  = document.getElementById('fs10FilterSec');
  var studEl = document.getElementById('fs10FilterStudent');
  if (!secEl) return;
  var _adSess2=(document.getElementById('sc_yr')?document.getElementById('sc_yr').value:'')||getCurrentSession();
  var admData = ((typeof admList3 !== 'undefined' && Array.isArray(admList3)) ? admList3
              : JSON.parse(localStorage.getItem(erpKey('admList3')) || '[]')).filter(function(r){return r.session===_adSess2;});
  var rows = cls ? admData.filter(r => (r.class||'') === cls) : admData;
  var secs = [...new Set(rows.map(r => r.section||'').filter(Boolean))].sort();
  secEl.innerHTML = '<option value="">-- All Sections --</option>'
    + secs.map(s => `<option value="${s}">${s}</option>`).join('');
  fs10PopulateStudentDrop(cls, '');
}

function fs10PopulateStudentDrop(cls, sec) {
  var studEl = document.getElementById('fs10FilterStudent');
  if (!studEl) return;
  var _adSess3=(document.getElementById('sc_yr')?document.getElementById('sc_yr').value:'')||getCurrentSession();
  var admData = ((typeof admList3 !== 'undefined' && Array.isArray(admList3)) ? admList3
              : JSON.parse(localStorage.getItem(erpKey('admList3')) || '[]')).filter(function(r){return r.session===_adSess3;});
  var rows = admData.filter(r =>
    (!cls || (r.class||'') === cls) &&
    (!sec || (r.section||'') === sec)
  );
  studEl.innerHTML = '<option value="">-- All Students --</option>'
    + rows.map(r => {
        var admno = r.admno || r.id || '';
        var label = (r.sname||'—') + ' (' + (r.class||'') + (r.section ? '-'+r.section : '') + ')';
        return `<option value="${admno}">${label}</option>`;
      }).join('');
}

function fs10OnClassChange() {
  var cls = document.getElementById('fs10FilterClass').value;
  document.getElementById('fs10FilterSec').value = '';
  fs10PopulateSectionDrop(cls);
  document.getElementById('fs10FilterStudent').value = '';
  renderFs10();
}

function fs10OnSecChange() {
  var cls = document.getElementById('fs10FilterClass').value;
  var sec = document.getElementById('fs10FilterSec').value;
  fs10PopulateStudentDrop(cls, sec);
  document.getElementById('fs10FilterStudent').value = '';
  renderFs10();
}

function fs10ClearFilters() {
  document.getElementById('fs10FilterClass').value   = '';
  document.getElementById('fs10FilterSec').value     = '';
  fs10PopulateSectionDrop('');
  document.getElementById('fs10FilterStudent').value = '';
  renderFs10();
}

function renderFs10() {
  var en = isEnglish();
  // Read active filters
  var filterClass   = (document.getElementById('fs10FilterClass')   || {}).value || '';
  var filterSec     = (document.getElementById('fs10FilterSec')     || {}).value || '';
  var filterStudent = (document.getElementById('fs10FilterStudent') || {}).value || '';

  // Month labels and indices Apr=0..Mar=11
  const monthsHi  = ['अप्रैल','मई','जून','जुलाई','अगस्त','सितम्बर','अक्टूबर','नवम्बर','दिसम्बर','जनवरी','फरवरी','मार्च'];
  const monthsEn  = ['April','May','June','July','August','September','October','November','December','January','February','March'];
  const monthNums = ['04','05','06','07','08','09','10','11','12','01','02','03'];

  // Current session year (Apr-Mar)
  const now = new Date();
  const m = now.getMonth();
  const y = now.getFullYear();
  const sessionStart = m >= 3 ? y : y - 1;
  const sessionEnd   = sessionStart + 1;
  const monthYears = ['04','05','06','07','08','09','10','11','12'].map(() => sessionStart)
                   .concat(['01','02','03'].map(() => sessionEnd));

  // Get admission data for filtering
  var _adSessX=(document.getElementById('sc_yr')?document.getElementById('sc_yr').value:'')||getCurrentSession();
  var admData = ((typeof admList3 !== 'undefined' && Array.isArray(admList3)) ? admList3
              : JSON.parse(localStorage.getItem(erpKey('admList3')) || '[]')).filter(function(r){return r.session===_adSessX;});

  // Build set of matching admno keys
  var allF2Keys;
  if (filterStudent) {
    // Single student — direct key match
    allF2Keys = ['erp_fs2_' + filterStudent];
  } else if (filterClass || filterSec) {
    // Filter admissions by class/section, collect their admno
    var matchedAdmNos = new Set(
      admData
        .filter(r =>
          (!filterClass || (r.class||'') === filterClass) &&
          (!filterSec   || (r.section||'') === filterSec)
        )
        .map(r => r.admno || r.id || '')
        .filter(Boolean)
    );
    allF2Keys = Object.keys(localStorage)
      .filter(k => k.startsWith(erpKey('erp_fs2_')) && matchedAdmNos.has(k.replace('erp_fs2_', '')));
  } else {
    // All students
    allF2Keys = Object.keys(localStorage).filter(k => k.startsWith(erpKey('erp_fs2_')));
  }

  const activeFees = FS_FEE_TYPES.filter((ft, i) => { if(i < 2) return !feeConfig[i] || feeConfig[i].active !== 'no'; if(ft._custom) return !feeConfig[i] || feeConfig[i].active !== 'no'; return feeConfig[i] && feeConfig[i].active === 'yes'; });

  // Per-month totals
  const due  = Array(12).fill(0);
  const paid = Array(12).fill(0);

  const tDue  = Array(12).fill(0), tPaid  = Array(12).fill(0);
  const trDue = Array(12).fill(0), trPaid = Array(12).fill(0);
  const otherFees = activeFees.filter(ft => !ft.label.includes('ट्यूशन') && !ft.label.includes('Tuition') && !ft.label.includes('परिवहन') && !ft.label.includes('Transport'));
  const otherDue  = otherFees.map(() => Array(12).fill(0));
  const otherPaid = otherFees.map(() => Array(12).fill(0));

  allF2Keys.forEach(key => {
    const fs2 = JSON.parse(localStorage.getItem(key) || 'null');
    if (!fs2) return;
    (fs2.partB || []).forEach((row, idx) => {
      if (idx >= 12) return;
      const td  = parseFloat(row.tDue   || 0);
      const tp  = parseFloat(row.tPaid  || 0);
      const trd = parseFloat(row.trDue  || 0);
      const trp = parseFloat(row.trPaid || 0);
      tDue[idx]  += td;  tPaid[idx]  += tp;
      trDue[idx] += trd; trPaid[idx] += trp;
      due[idx]   += td + trd;
      paid[idx]  += tp + trp;
    });
    (fs2.partA || []).forEach((row, j) => {
      const ft = activeFees[j];
      if (!ft) return;
      const isTuition   = (row.label||'').includes('ट्यूशन')  || (row.label||'').includes('Tuition');
      const isTransport = (row.label||'').includes('परिवहन') || (row.label||'').includes('Transport');
      if (isTuition || isTransport) return;
      const oIdx = otherFees.findIndex(of => of.label === ft.label);
      if (oIdx === -1) return;
      otherDue[oIdx][0]  += parseFloat(row.due  || 0);
      otherPaid[oIdx][0] += parseFloat(row.paid || 0);
      due[0]  += parseFloat(row.due  || 0);
      paid[0] += parseFloat(row.paid || 0);
    });
  });

  const colspan = 14;
  let html = '';

  // Show active filter info banner
  if (filterClass || filterSec || filterStudent) {
    var admList2 = typeof getAdmList === 'function' ? getAdmList() : (window.admissionList || []);
    var filterLabel = '';
    if (filterStudent) {
      var stud = admList2.find(r => (r.adm||r.sno||r.id||'') === filterStudent);
      filterLabel = stud ? `👤 ${stud.name} (${stud.class||''}${stud.section?'-'+stud.section:''})` : `Student: ${filterStudent}`;
    } else {
      filterLabel = `${filterClass ? '📚 Class: '+filterClass : ''}${filterSec ? '  📂 Section: '+filterSec : ''}`;
    }
    html += `<tr><td colspan="${colspan}" style="background:#fff8e1;padding:6px 12px;font-size:11px;color:#e65100;font-weight:600;border-bottom:2px solid #ffcc02;">🔍 Filtered: ${filterLabel} — (${allF2Keys.length} student record(s))</td></tr>`;
  }

  // Section (क)/(A): माहवार देय राशि
  html += `<tr style="background:#e8eaf6;"><td colspan="${colspan}" style="font-weight:700;padding:8px 12px;">${en ? '(A) Monthly Payable Amount' : '(क) माहवार देय राशि (Monthly Payable Amount)'}</td></tr>`;

  const tDueTotal = tDue.reduce((a,b)=>a+b,0);
  html += `<tr><td style="padding-left:16px;">${en ? 'Tuition Fee' : 'ट्यूशन फीस'}</td>${tDue.map(v=>`<td style="text-align:right;">${v?'₹'+v.toLocaleString():'—'}</td>`).join('')}<td style="font-weight:700;text-align:right;">₹${tDueTotal.toLocaleString()}</td></tr>`;

  const trDueTotal = trDue.reduce((a,b)=>a+b,0);
  html += `<tr><td style="padding-left:16px;">${en ? 'Transport Fee' : 'परिवहन फीस'}</td>${trDue.map(v=>`<td style="text-align:right;">${v?'₹'+v.toLocaleString():'—'}</td>`).join('')}<td style="font-weight:700;text-align:right;">₹${trDueTotal.toLocaleString()}</td></tr>`;

  otherFees.forEach((ft, oi) => {
    const rowTotal = otherDue[oi].reduce((a,b)=>a+b,0);
    if (!rowTotal) return;
    html += `<tr><td style="padding-left:16px;">${(en && ft.labelEn) ? ft.labelEn : ft.label.split('(')[0].trim()}</td>${otherDue[oi].map(v=>`<td style="text-align:right;">${v?'₹'+v.toLocaleString():'—'}</td>`).join('')}<td style="font-weight:700;text-align:right;">₹${rowTotal.toLocaleString()}</td></tr>`;
  });

  const grandDueArr = monthNums.map((_,i) => tDue[i] + trDue[i] + otherFees.reduce((s,_,oi)=>s+otherDue[oi][i],0));
  const grandDueTotal = grandDueArr.reduce((a,b)=>a+b,0);
  html += `<tr style="background:#f5f5f5;font-weight:700;"><td>${en ? 'Total Due' : 'कुल देय'}</td>${grandDueArr.map(v=>`<td style="text-align:right;">₹${v.toLocaleString()}</td>`).join('')}<td style="text-align:right;">₹${grandDueTotal.toLocaleString()}</td></tr>`;

  // Section (ख)/(B): माहवार जमा राशि
  html += `<tr style="background:#e8eaf6;"><td colspan="${colspan}" style="font-weight:700;padding:8px 12px;">${en ? '(B) Monthly Collected Amount' : '(ख) माहवार जमा राशि (Monthly Collected Amount)'}</td></tr>`;

  const tPaidTotal = tPaid.reduce((a,b)=>a+b,0);
  html += `<tr><td style="padding-left:16px;">${en ? 'Tuition Fee' : 'ट्यूशन फीस'}</td>${tPaid.map(v=>`<td style="text-align:right;">${v?'₹'+v.toLocaleString():'—'}</td>`).join('')}<td style="font-weight:700;text-align:right;">₹${tPaidTotal.toLocaleString()}</td></tr>`;

  const trPaidTotal = trPaid.reduce((a,b)=>a+b,0);
  html += `<tr><td style="padding-left:16px;">${en ? 'Transport Fee' : 'परिवहन फीस'}</td>${trPaid.map(v=>`<td style="text-align:right;">${v?'₹'+v.toLocaleString():'—'}</td>`).join('')}<td style="font-weight:700;text-align:right;">₹${trPaidTotal.toLocaleString()}</td></tr>`;

  otherFees.forEach((ft, oi) => {
    const rowTotal = otherPaid[oi].reduce((a,b)=>a+b,0);
    if (!rowTotal) return;
    html += `<tr><td style="padding-left:16px;">${(en && ft.labelEn) ? ft.labelEn : ft.label.split('(')[0].trim()}</td>${otherPaid[oi].map(v=>`<td style="text-align:right;">${v?'₹'+v.toLocaleString():'—'}</td>`).join('')}<td style="font-weight:700;text-align:right;">₹${rowTotal.toLocaleString()}</td></tr>`;
  });

  const grandPaidArr = monthNums.map((_,i) => tPaid[i] + trPaid[i] + otherFees.reduce((s,_,oi)=>s+otherPaid[oi][i],0));
  const grandPaidTotal = grandPaidArr.reduce((a,b)=>a+b,0);
  html += `<tr style="background:#f5f5f5;font-weight:700;"><td>${en ? 'Total Collected' : 'कुल जमा'}</td>${grandPaidArr.map(v=>`<td style="text-align:right;">₹${v.toLocaleString()}</td>`).join('')}<td style="text-align:right;">₹${grandPaidTotal.toLocaleString()}</td></tr>`;

  // Section (ग)/(C): माहवार बकाया
  html += `<tr style="background:#e8eaf6;"><td colspan="${colspan}" style="font-weight:700;padding:8px 12px;">${en ? '(C) Monthly Balance' : '(ग) माहवार बकाया (Monthly Balance)'}</td></tr>`;
  const balArr = monthNums.map((_,i) => grandDueArr[i] - grandPaidArr[i]);
  const balTotal = balArr.reduce((a,b)=>a+b,0);
  html += `<tr><td>${en ? 'Monthly Balance' : 'माहवार बकाया'}</td>${balArr.map(v=>`<td style="text-align:right;color:${v>0?'#c62828':'#2e7d32'};">₹${v.toLocaleString()}</td>`).join('')}<td style="font-weight:700;text-align:right;color:${balTotal>0?'#c62828':'#2e7d32'};">₹${balTotal.toLocaleString()}</td></tr>`;

  document.getElementById('fs10Body').innerHTML = html;
  document.getElementById('fs10AnnualDue').textContent  = '₹' + grandDueTotal.toLocaleString();
  document.getElementById('fs10AnnualPaid').textContent = '₹' + grandPaidTotal.toLocaleString();
  document.getElementById('fs10AnnualBal').textContent  = '₹' + (grandDueTotal - grandPaidTotal).toLocaleString();
  // Apply static labels
  _applyFs10Lang();
}

// ---- Print FS ----
function printFs(panelId) {
  const panel = document.getElementById(panelId);
  if (!panel) return;
  const w = window.open('', '_blank');
  w.document.write(`<html><head><title>Fee Structure</title><style>
    body{font-family:Arial,sans-serif;font-size:12px;padding:20px;}
    table{width:100%;border-collapse:collapse;margin-bottom:16px;}
    th,td{border:1px solid #aaa;padding:6px 8px;}
    th{background:#1a237e;color:#fff;}
    .no-print{display:none;}
    input{border:none;background:transparent;width:100%;font-size:12px;}
    select{border:none;background:transparent;font-size:12px;}
    @media print{.no-print{display:none!important;}}
  </style></head><body>`);
  w.document.write(panel.innerHTML);
  w.document.write('</body></html>');
  w.document.close();
  setTimeout(() => w.print(), 400);
}

// Print Preview for currently active FS panel
function fsPrintPreview() {
  // Find the visible fs-panel
  var panels = document.querySelectorAll('.fs-panel');
  var activePanel = null;
  var activeId = 'fs1';
  panels.forEach(function(p) {
    if (p.style.display !== 'none') { activePanel = p; activeId = p.id; }
  });
  if (!activePanel) {
    // fallback to fs1
    activePanel = document.getElementById('fs1');
    activeId = 'fs1';
  }
  // Tab label mapping
  var tabLabels = {
    fs1: 'F1: Fee Config (शुल्क विन्यास)',
    fs2: 'F2: Fee Receipt (शुल्क रसीद)',
    fs4: 'F3: Defaulters (बकाया सूची)',
    fs8: 'F4: Demand Notice (मांग पत्र)',
    fs9: 'F5: Clearance Cert (क्लियरेंस प्रमाण-पत्र)',
    fs10: 'F6: Annual Statement (वार्षिक विवरण)',
    fs11: 'F7: Fee Statement (शुल्क विवरण)'
  };
  var title = tabLabels[activeId] || activeId;
  var w = window.open('', '_blank');
  w.document.write('<html><head><title>' + title + '</title><style>\n' +
    'body{font-family:Arial,sans-serif;font-size:12px;padding:20px;}\n' +
    'table{width:100%;border-collapse:collapse;margin-bottom:16px;}\n' +
    'th,td{border:1px solid #aaa;padding:6px 8px;}\n' +
    'th{background:#1a237e;color:#fff;}\n' +
    '.no-print{display:none!important;}\n' +
    'input{border:none;background:transparent;width:100%;font-size:12px;}\n' +
    'select{border:none;background:transparent;font-size:12px;}\n' +
    '.fs-preview-topbar{background:#1a237e;color:#fff;padding:10px 20px;display:flex;align-items:center;justify-content:space-between;margin:-20px -20px 20px;}\n' +
    '.fs-preview-topbar button{background:#fff;color:#1a237e;border:none;border-radius:4px;padding:6px 16px;font-weight:700;font-size:12px;cursor:pointer;margin-left:8px;}\n' +
    '.fs-preview-topbar button:hover{background:#e3e8f0;}\n' +
    '@media print{.fs-preview-topbar{display:none!important;}.no-print{display:none!important;}}\n' +
    '</style></head><body>\n' +
    '<div class="fs-preview-topbar no-print">' +
    '<span style="font-weight:700;font-size:13px;">👁️ Print Preview — ' + title + '</span>' +
    '<div>' +
    '<button onclick="window.print()">🖨️ Print</button>' +
    '<button onclick="window.close()">✕ Close</button>' +
    '</div>' +
    '</div>');
  w.document.write(activePanel.innerHTML);
  w.document.write('</body></html>');
  w.document.close();
}

