// ===================== PERSISTENT SAVE / LOAD =====================

// All simple input IDs that should auto-save/load
const PERSIST_IDS = [
  // School / F1
  'fs1School','fs1Udise','fs1Principal',
  // F2 Part-A
  'fs2School','fs2Receipt','fs2Date',
  // F5
  // F6
  'fs6School','fs6Udise',
  // F8
  'fs8School','fs8Days',
  // F10
  'fs10School','fs10Udise',
];

function persistSave() {
  const data = {};
  PERSIST_IDS.forEach(id => {
    const el = document.getElementById(id);
    if (el) data[id] = el.value;
  });
  localStorage.setItem(erpKey('erp_persist'), JSON.stringify(data)); smartSave(erpKey('erp_persist'), data);
}

function persistLoad() {
  const data = JSON.parse(localStorage.getItem(erpKey('erp_persist')) || '{}');
  PERSIST_IDS.forEach(id => {
    const el = document.getElementById(id);
    if (el && data[id] !== undefined) el.value = data[id];
  });
}

// Auto-save on any input change across the page
document.addEventListener('input', function(e) {
  if (PERSIST_IDS.includes(e.target.id)) persistSave();
});
document.addEventListener('change', function(e) {
  if (PERSIST_IDS.includes(e.target.id)) persistSave();
});

// ===================== INIT =====================
document.addEventListener('DOMContentLoaded', function() {
  var _an=document.getElementById('admNo'); if(_an && typeof generateAdmNo==='function') _an.value=generateAdmNo();
  var _ad=document.getElementById('admDate'); if(_ad) _ad.value=new Date().toISOString().split('T')[0];
  var _dd=document.getElementById('declarationDate'); if(_dd) _dd.value=new Date().toISOString().split('T')[0];

  // Auto-calculate current session (April-March)
  const now = new Date();
  const m   = now.getMonth(); // 0=Jan
  const y   = now.getFullYear();
  const sessionStart = m >= 3 ? y : y - 1;   // April(3) onwards = current year
  const sessionEnd   = sessionStart + 1;
  const session = `${sessionStart}-${String(sessionEnd).slice(2)}`; // e.g. 2026-27

  const sessionIds = ['fs1Session','fs4Session','fs6Session','fs9Session','fs10Session'];
  sessionIds.forEach(id => {
    const el = document.getElementById(id);
    if (el) el.value = session;
  });

  // Load all persisted simple fields
  persistLoad();

  // Load leave data
  if(typeof leaveRegistry!=='undefined') leaveRegistry=JSON.parse(localStorage.getItem(sessKey('erp_leave'))||'[]');
});

