let _f11ActiveTab = 'overall';

function _baseInitF11() {
  // ── Update month label text based on school medium ──
  var _en = isEnglish();
  var moHI = ['अप्रैल','मई','जून','जुलाई','अगस्त','सितम्बर','अक्टूबर','नवम्बर','दिसम्बर','जनवरी','फरवरी','मार्च'];
  var moEN = ['April','May','June','July','August','September','October','November','December','January','February','March'];
  ['f11TuMonthBoxes','f11TrMonthBoxes'].forEach(function(boxId) {
    var labels = document.querySelectorAll('#' + boxId + ' label');
    labels.forEach(function(lbl, i) {
      var nodes = lbl.childNodes;
      for (var n = nodes.length - 1; n >= 0; n--) {
        if (nodes[n].nodeType === 3) {
          nodes[n].textContent = ' ' + (_en ? moEN[i] : moHI[i]);
          break;
        }
      }
    });
  });
  // Populate Tuition class dropdown
  const allStu = (typeof _getAllStudents === 'function') ? _getAllStudents() : (registry||[]);
  const tuClsSel = document.getElementById('f11TuClass');
  if (tuClsSel) {
    const curCls = tuClsSel.value;
    tuClsSel.innerHTML = `<option value="">-- All Classes --</option>`;
    [...new Set(allStu.map(s => s.class).filter(Boolean))].sort(_classCmp).forEach(c => {
      tuClsSel.innerHTML += `<option value="${c}"${c===curCls?' selected':''}>${c}</option>`;
    });
  }
  // Populate Transport class dropdown
  const trClsSel = document.getElementById('f11TrClass');
  if (trClsSel) {
    const curCls = trClsSel.value;
    trClsSel.innerHTML = `<option value="">-- ${_en ? 'All Classes' : 'All Classes'} --</option>`;
    [...new Set(allStu.map(s => s.class).filter(Boolean))].sort(_classCmp).forEach(c => {
      trClsSel.innerHTML += `<option value="${c}"${c===curCls?' selected':''}>${c}</option>`;
    });
  }
  renderF11();
  // Hide tables on initial load
  var _tuW = document.getElementById("f11TuTableWrap"); if (_tuW) _tuW.style.display = "none";
  var _trW = document.getElementById("f11TrTableWrap"); if (_trW) _trW.style.display = "none";
}

function switchF11Tab(tab) {
  _f11ActiveTab = tab;
  ['overall','tuition','transport'].forEach(t => {
    document.getElementById('f11Panel' + t.charAt(0).toUpperCase() + t.slice(1)).style.display = (t === tab) ? '' : 'none';
    const btn = document.getElementById('f11Tab' + t.charAt(0).toUpperCase() + t.slice(1));
    btn.className = (t === tab) ? 'btn btn-primary btn-sm f11-tab' : 'btn btn-outline btn-sm f11-tab';
  });
}

function _f11FilterFees(feeType) {
  const cls   = 'all';
  const from  = '';
  const to    = '';
  return fees.filter(f => {
    if (feeType) {
      const ft = (f.type || f.feeType || '').toLowerCase();
      if (!ft.includes(feeType.toLowerCase())) return false;
    }
    if (cls !== 'all') {
      const stu = _getAllStudents().find(s => s.admNo === f.admNo);
      if (!stu || stu.class !== cls) return false;
    }
    const period = f.period || (f.date ? f.date.slice(0,7) : '');
    if (from && period && period < from) return false;
    if (to   && period && period > to)   return false;
    return true;
  });
}

function _f11AmtCell(n) {
  return n ? '₹' + (+n).toLocaleString('en-IN') : '₹0';
}

