function slpGetMonthHindi(m) {
  var map = {
    'January':'जनवरी','February':'फरवरी','March':'मार्च','April':'अप्रैल',
    'May':'मई','June':'जून','July':'जुलाई','August':'अगस्त',
    'September':'सितंबर','October':'अक्टूबर','November':'नवंबर','December':'दिसंबर'
  };
  return map[m] || m;
}

