function slpEmpRow(l1, v1, l2, v2, shade) {
  const bg = shade ? '#EEF3FB' : '#fff';
  const lStyle = `background:${bg};font-weight:600;padding:6px 10px;border:1px solid #ddd;font-size:12.5px;color:#555;width:22%;`;
  const vStyle = `background:${bg};padding:6px 10px;border:1px solid #ddd;font-size:12.5px;width:28%;`;
  return `<tr><td style="${lStyle}">${l1}</td><td style="${vStyle}">${v1||'—'}</td><td style="${lStyle}">${l2}</td><td style="${vStyle}">${v2||'—'}</td></tr>`;
}

function slpEDRow(earn, earnAmt, ded, dedAmt, shade) {
  const bgE = shade ? '#EEF3FB' : '#fff';
  const bgD = shade ? '#FDF0EE' : '#fff';
  const fmt = n => (n && n !== 0) ? Number(n).toLocaleString('en-IN') : '—';
  return `<tr>
    <td style="background:${bgE};padding:6px 8px;border:1px solid #ddd;font-size:12.5px;width:38%;">${earn}</td>
    <td style="background:${bgE};padding:6px 8px;border:1px solid #ddd;text-align:right;font-size:12.5px;width:12%;">${fmt(earnAmt)}</td>
    <td style="background:${bgD};padding:6px 8px;border:1px solid #ddd;font-size:12.5px;width:38%;">${ded}</td>
    <td style="background:${bgD};padding:6px 8px;border:1px solid #ddd;text-align:right;font-size:12.5px;width:12%;">${ded ? fmt(dedAmt) : ''}</td>
  </tr>`;
}

function slpPrint() {
  const preview = document.getElementById('slpPreview');
  if (!preview || preview.innerHTML.includes('Fill the form')) {
    return alert('Pehle "Generate Slip" click karein!');
  }
  const w = window.open('', '_blank');
  w.document.write(`<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Salary Slip</title>
    <style>
      body { margin: 0; padding: 0; font-family: Arial, sans-serif; }
      @page { size: A4; margin: 12mm 14mm; }
      @media print { body { -webkit-print-color-adjust: exact; print-color-adjust: exact; } }
    </style>
  </head><body>${preview.innerHTML}</body></html>`);
  w.document.close();
  setTimeout(() => { w.focus(); w.print(); }, 400);
}

function slpClear() {
  ['slpName','slpEmpId','slpDesig','slpDept','slpDOJ','slpPAN','slpBank','slpBankName','slpIFSC','slpPF'].forEach(id => {
    const el = document.getElementById(id); if (el) el.value = '';
  });
  ['slpBasic','slpHRA','slpDA','slpMedAllow','slpTransAllow','slpSpAllow','slpBonus','slpArrears',
   'slpPFded','slpTDS','slpESI','slpAdvance','slpOtherDed','slpLOP','slpLeavePaid'].forEach(id => {
    const el = document.getElementById(id); if (el) el.value = 0;
  });
  document.getElementById('slpPT').value = 200;
  document.getElementById('slpPresent').value = 26;
  document.getElementById('slpStaffSel').value = '';
  document.getElementById('slpPreview').innerHTML = isEnglish()
    ? `<div style="text-align:center;padding:40px;color:#bbb;"><div style="font-size:40px;">💵</div><div style="font-size:14px;margin-top:8px;">Fill the form and click "Generate Slip"</div></div>`
    : `<div style="text-align:center;padding:40px;color:#bbb;"><div style="font-size:40px;">💵</div><div style="font-size:14px;margin-top:8px;">फॉर्म भरें और "वेतन पर्ची बनाएं" बटन दबाएं</div></div>`;
  document.getElementById('slpGrossDisplay').textContent = '₹ 0';
  document.getElementById('slpDedDisplay').textContent = '₹ 0';
}


