function resetStaffFilters() {
  ['staffFilterDesig','staffFilterGender','staffFilterService'].forEach(id=>{
    const el=document.getElementById(id); if(el) el.value='';
  });
  const se=document.getElementById('staffSearch'); if(se) se.value='';
  document.querySelectorAll('#srk_staff_filter_row .rsk-finput').forEach(el=>el.value='');
  renderStaffRegistry();
}

function rskStaffFilter() {
  // Per-column filter using data-sf attribute
  const inputs = document.querySelectorAll('#srk_staff_filter_row .rsk-finput');
  const filters = {};
  inputs.forEach(inp => { const v=inp.value.trim().toLowerCase(); if(v) filters[inp.dataset.sf]=v; });
  const desig   = (document.getElementById('staffFilterDesig')||{}).value || '';
  const gender  = (document.getElementById('staffFilterGender')||{}).value || '';
  const service = (document.getElementById('staffFilterService')||{}).value || '';
  const search  = ((document.getElementById('staffSearch')||{}).value||'').toLowerCase();
  const data = staffRegistry.filter(s => {
    // top-bar filters
    if(desig   && s.desig!==desig) return false;
    if(gender  && !(s.gender||'').includes(gender.split('/')[0].trim())) return false;
    if(service && !(s.serviceType||'').includes(service.split('/')[0].trim())) return false;
    if(search  && !(s.nameEn||'').toLowerCase().includes(search)
               && !(s.nameHi||'').includes(search)
               && !(s.staffId||'').toLowerCase().includes(search)
               && !(s.mobile||'').includes(search)) return false;
    // per-column filters
    for(const f in filters) {
      const val = String(s[f]||'').toLowerCase();
      if(!val.includes(filters[f])) return false;
    }
    return true;
  });
  const tbody = document.getElementById('staffRegistryBody');
  if (!data.length) {
    tbody.innerHTML = '<tr><td colspan="69" style="text-align:center;padding:40px;color:#999;font-style:italic;">'+( isEnglish()?'No records found.':'कोई रिकॉर्ड नहीं मिला।')+'</td></tr>';
    return;
  }
  const ed = (s,i,f) => s.edu && s.edu[i] ? (s.edu[i][f]||'—') : '—';
  tbody.innerHTML = data.map((s,i) => {
    const idx = staffRegistry.indexOf(s);
    const photoCell = s.photo
      ? `<img src="${s.photo}" style="width:38px;height:38px;object-fit:cover;border-radius:50%;border:2px solid #9dc3e6;display:block;margin:auto;">`
      : `<span style="font-size:22px;display:block;text-align:center;">👤</span>`;
    return `<tr ondblclick="staffLoadForEdit(${idx})" style="cursor:pointer;" onmouseover="this.style.background='#eff6ff'" onmouseout="this.style.background=''" title="Double-click → Form में Load करें">
      <td>${i+1}</td><td>${photoCell}</td>
      <td><b>${s.staffId||'—'}</b></td><td><b>${s.nameEn||'—'}</b></td><td>${s.nameHi||'—'}</td>
      <td>${s.fatherName||'—'}</td><td>${s.motherName||'—'}</td><td>${s.dob||'—'}</td>
      <td><span class="badge ${(s.gender||'').includes('Male')?'badge-blue':(s.gender||'').includes('Female')?'badge-red':'badge-orange'}">${s.gender||'—'}</span></td>
      <td>${s.blood||'—'}</td><td>${s.marital||'—'}</td><td>${s.religion||'—'}</td>
      <td><span class="badge badge-orange">${s.cat||'—'}</span></td>
      <td>${s.nationality||'—'}</td><td>${s.pwd||'No'}</td>
      <td>${s.aadhar||'—'}</td><td>${s.pan||'—'}</td><td>${s.samagra||'—'}</td>
      <td>${s.addrCurr||'—'}</td><td>${s.addrPerm||'—'}</td>
      <td>${s.district||'—'}</td><td>${s.tehsil||'—'}</td><td>${s.pin||'—'}</td><td>${s.state||'—'}</td>
      <td>${s.mobile||'—'}</td><td>${s.mobile2||'—'}</td><td>${s.email||'—'}</td><td>${s.whatsapp||'—'}</td>
      <td>${ed(s,0,'board')}</td><td>${ed(s,0,'year')}</td><td>${ed(s,0,'pct')}</td>
      <td>${ed(s,1,'board')}</td><td>${ed(s,1,'year')}</td><td>${ed(s,1,'pct')}</td>
      <td>${ed(s,2,'board')}</td><td>${ed(s,2,'year')}</td><td>${ed(s,2,'pct')}</td>
      <td>${ed(s,3,'board')}</td><td>${ed(s,3,'year')}</td><td>${ed(s,3,'pct')}</td>
      <td>${ed(s,4,'board')}</td><td>${ed(s,4,'year')}</td><td>${ed(s,4,'pct')}</td>
      <td>${ed(s,5,'board')}</td><td>${ed(s,5,'year')}</td><td>${ed(s,5,'pct')}</td>
      <td><span class="badge badge-blue">${s.desig||'—'}</span></td>
      <td>${s.cadre||'—'}</td><td>${s.subject||'—'}</td><td>${s.joinDate||'—'}</td>
      <td>${s.serviceType||'—'}</td><td>${s.postingDate||'—'}</td><td>${s.postingYear||'—'}</td>
      <td>${s.prevSchool||'—'}</td><td>${s.prevService||'—'}</td><td>${s.totalService||'—'}</td>
      <td>${s.bank||'—'}</td><td>${s.account||'—'}</td><td>${s.ifsc||'—'}</td><td>${s.branch||'—'}</td>
      <td>${s.basicPay||'—'}</td><td>${s.gradePay||'—'}</td><td>${s.gpf||'—'}</td>
      <td>${s.emName||'—'}</td><td>${s.emRel||'—'}</td><td>${s.emMobile||'—'}</td>
      <td>${s.emAlt||'—'}</td><td>${s.declDate||'—'}</td><td>${s.declPlace||'—'}</td>
      <td style="white-space:nowrap;">
        <button onclick="viewStaffProfile(${idx})" style="background:none;border:none;cursor:pointer;font-size:16px;" title="View">👁️</button>
        <button onclick="editStaff(${idx})" style="background:none;border:none;cursor:pointer;font-size:16px;" title="Edit">✏️</button>
        <button onclick="previewStaffPrintIdx(${idx})" style="background:none;border:none;cursor:pointer;font-size:16px;" title="Print">🖨️</button>
        <button onclick="deleteStaff(${idx})" style="background:none;border:none;cursor:pointer;font-size:16px;color:#c62828;" title="Delete">🗑️</button>
      </td>
    </tr>`;
  }).join('');
}

function editStaff(idx) {
  const s = staffRegistry[idx];
  staffEditingIdx = idx;
  const setV = (id, val) => { const el = document.getElementById(id); if (el) el.value = val||''; };
  setV('sf_nameHi', s.nameHi); setV('sf_nameEn', s.nameEn);
  setV('sf_fatherName', s.fatherName); setV('sf_motherName', s.motherName);
  setV('sf_dob', s.dob); setV('sf_religion', s.religion);
  setV('sf_aadhar', s.aadhar); setV('sf_pan', s.pan); setV('sf_samagra', s.samagra);
  setV('sf_addrCurr', s.addrCurr); setV('sf_addrPerm', s.addrPerm);
  setV('sf_district', s.district); setV('sf_tehsil', s.tehsil);
  setV('sf_pin', s.pin); setV('sf_state', s.state);
  setV('sf_mobile', s.mobile); setV('sf_mobile2', s.mobile2);
  setV('sf_email', s.email); setV('sf_whatsapp', s.whatsapp);
  setV('sf_staffId', s.staffId); setV('sf_cadre', s.cadre); setV('sf_subject', s.subject);
  setV('sf_joinDate', s.joinDate); setV('sf_postingDate', s.postingDate);
  setV('sf_postingYear', s.postingYear); setV('sf_prevSchool', s.prevSchool);
  setV('sf_prevService', s.prevService); setV('sf_totalService', s.totalService);
  setV('sf_bank', s.bank); setV('sf_account', s.account); setV('sf_ifsc', s.ifsc);
  setV('sf_branch', s.branch); setV('sf_basicPay', s.basicPay); setV('sf_gradePay', s.gradePay);
  setV('sf_gpf', s.gpf); setV('sf_emName', s.emName); setV('sf_emRel', s.emRel);
  setV('sf_emMobile', s.emMobile); setV('sf_emAlt', s.emAlt);
  setV('sf_declDate', s.declDate); setV('sf_declPlace', s.declPlace);
  setV('sf_nationality', s.nationality || 'भारतीय / Indian');
  ['gender','blood','marital','cat','pwd','desig','serviceType'].forEach(f => setV('sf_'+f, s[f]));
  (s.edu||[]).forEach((e,i)=>{
    setV('sf_edu_board_'+i, e.board); setV('sf_edu_year_'+i, e.year);
    setV('sf_edu_pct_'+i, e.pct); setV('sf_edu_div_'+i, e.div);
  });
  if (s.photo) {
    const img = document.getElementById('sf_photoPreview');
    img.src = s.photo; img.style.display = 'block';
    document.getElementById('sf_photoPlaceholder').style.display = 'none';
  }
  switchStaffTab('form');
}

function deleteStaff(idx) {
  if (!confirm('Delete this staff record?')) return;
  staffRegistry.splice(idx, 1); saveStaffData(); renderStaffRegistry(); updateStaffStats();
}

// ── Staff Form Edit Mode UI Toggle ──
function sfSetEditingMode(isEditing) {
  var saveBtn   = document.getElementById('sf_saveBtn');
  var updateBtn = document.getElementById('sf_updateBtn');
  var deleteBtn = document.getElementById('sf_deleteBtn');
  var editBadge = document.getElementById('sf_editingBadge');
  if (isEditing) {
    if (saveBtn)   saveBtn.style.display   = 'none';
    if (updateBtn) updateBtn.style.display = '';
    if (deleteBtn) deleteBtn.style.display = '';
    if (editBadge) editBadge.style.display = '';
  } else {
    if (saveBtn)   saveBtn.style.display   = '';
    if (updateBtn) updateBtn.style.display = 'none';
    if (deleteBtn) deleteBtn.style.display = 'none';
    if (editBadge) editBadge.style.display = 'none';
  }
}

// ── Double-click from registry → load in staff form ──
function staffLoadForEdit(idx) {
  editStaff(idx);
  srSetRegistryEditMode(true);
  switchStaffTab('form');
  setTimeout(function(){
    sfSetEditingMode(true);
    var topEl = document.getElementById('page-staff') || document.body;
    window.scrollTo(0, topEl.offsetTop - 60);
  }, 80);
}

// ── Registry bottom bar edit mode toggle ──
function srSetRegistryEditMode(isEditing) {
  var upBtn  = document.getElementById('sr_updateBtn');
  var delBtn = document.getElementById('sr_deleteBtn');
  var badge  = document.getElementById('sr_editingBadge');
  if (isEditing) {
    if (upBtn)  upBtn.style.display  = '';
    if (delBtn) delBtn.style.display = '';
    if (badge)  badge.style.display  = '';
  } else {
    if (upBtn)  upBtn.style.display  = 'none';
    if (delBtn) delBtn.style.display = 'none';
    if (badge)  badge.style.display  = 'none';
  }
}

// ── Registry bottom Search button ──
function srSearchStaff() {
  var q = prompt('नाम / ID / Mobile खोजें:');
  if (!q) return;
  var s = document.getElementById('staffSearch');
  if (s) { s.value = q; renderStaffRegistry(); }
}

// ── Registry bottom Update button ──
function srUpdateRecord() {
  if (staffEditingIdx < 0) return alert('पहले किसी row पर Double-click करके record load करें!');
  switchStaffTab('form');
  setTimeout(function(){
    sfUpdateRecord();
    srSetRegistryEditMode(false);
  }, 150);
}

// ── Registry bottom Delete button ──
function srDeleteRecord() {
  if (staffEditingIdx < 0) return alert('पहले किसी row पर Double-click करके record load करें!');
  var name = staffRegistry[staffEditingIdx]?.nameEn || staffRegistry[staffEditingIdx]?.nameHi || 'this record';
  if (!confirm('⚠️ "' + name + '" का record delete होगा। Sure?')) return;
  staffRegistry.splice(staffEditingIdx, 1);
  staffEditingIdx = -1;
  saveStaffData(); renderStaffRegistry(); updateStaffStats();
  sfSetEditingMode(false);
  srSetRegistryEditMode(false);
  clearStaffForm();
  alert('🗑️ Staff record deleted!');
}

// ── Update current loaded staff record ──
function sfUpdateRecord() {
  if (staffEditingIdx < 0) return alert('कोई record edit mode में नहीं है!');
  const d = getStaffFormData();
  if (!d.nameEn && !d.nameHi) return alert('कृपया नाम भरें!');
  staffRegistry[staffEditingIdx] = d;
  staffEditingIdx = -1;
  saveStaffData(); updateStaffStats();
  sfSetEditingMode(false);
  srSetRegistryEditMode(false);
  renderStaffRegistry();
  alert('✅ Staff record updated successfully!');
}

// ── Delete current loaded staff record ──
function sfDeleteCurrentRecord() {
  if (staffEditingIdx < 0) return;
  const name = staffRegistry[staffEditingIdx]?.nameEn || staffRegistry[staffEditingIdx]?.nameHi || 'this record';
  if (!confirm('⚠️ "' + name + '" का record delete होगा। Sure?')) return;
  staffRegistry.splice(staffEditingIdx, 1);
  staffEditingIdx = -1;
  saveStaffData(); renderStaffRegistry(); updateStaffStats();
  clearStaffForm();
  sfSetEditingMode(false);
  srSetRegistryEditMode(false);
  alert('🗑️ Staff record deleted!');
}

// ── Search staff by name / ID ──
function staffSearchByName() {
  const q = prompt('Staff का नाम या ID दर्ज करें:');
  if (!q) return;
  const ql = q.trim().toLowerCase();
  const idx = staffRegistry.findIndex(s =>
    (s.nameEn||'').toLowerCase().includes(ql) ||
    (s.nameHi||'').includes(q.trim()) ||
    (s.staffId||'').toLowerCase().includes(ql) ||
    (s.mobile||'').includes(q.trim())
  );
  if (idx < 0) return alert('❌ कोई record नहीं मिला: "' + q + '"');
  staffLoadForEdit(idx);
}

function updateStaffStats() {
  const el = document.getElementById('staffStats');
  if (!el) return;
  const total = staffRegistry.length;
  const male  = staffRegistry.filter(s => (s.gender||'').includes('Male')).length;
  const female= staffRegistry.filter(s => (s.gender||'').includes('Female')).length;
  const reg   = staffRegistry.filter(s => (s.serviceType||'').includes('Regular')).length;
  const guest = staffRegistry.filter(s => (s.serviceType||'').includes('Guest')).length;
  el.innerHTML =
    statCard(total,'Total Staff','#1976d2') +
    statCard(male,'Male Staff','#1565c0') +
    statCard(female,'Female Staff','#c62828') +
    statCard(reg,'Regular','#2e7d32') +
    statCard(guest,'Guest Teacher','#e65100');
}

function viewStaffProfile(idx) {
  const s = staffRegistry[idx];
  const w = window.open('','_blank');
  w.document.write(buildStaffPrintHTML(s));
  w.document.close();
  setTimeout(() => w.print(), 400);
}

function previewStaffPrint() {
  const s = getStaffFormData();
  openStaffPrintModal(s);
}

function previewStaffPrintIdx(idx) {
  openStaffPrintModal(staffRegistry[idx]);
}

function openStaffPrintModal(s) {
  document.getElementById('staffPrintBody').innerHTML = `
    <div style="padding:10px;display:flex;gap:10px;background:#f5f5f5;border-bottom:1px solid #ddd;">
      <button class="btn btn-primary btn-sm" onclick="printStaffFormNow()">🖨️ Print</button>
      <button class="btn btn-outline btn-sm" onclick="closeModal('staffPrintModal')">✕ Close</button>
    </div>
    <div id="staffPrintPreview" style="padding:0;">${buildStaffPrintHTML(s, true)}</div>`;
  document.getElementById('staffPrintModal').classList.add('open');
}

function printStaffFormNow() {
  const html = document.getElementById('staffPrintPreview').innerHTML;
  const w = window.open('','_blank');
  w.document.write('<html><head><title>Staff Profile Form</title></head><body>'+html+'</body></html>');
  w.document.close();
  setTimeout(() => w.print(), 400);
}

function buildStaffPrintHTML(s, inline) {
  const edu = (s.edu||[]);
  const en = isEnglish();
  const eduDegs = en
    ? ['High School / 10th','Higher Secondary / 12th','Graduation','Post Graduation','B.Ed / D.Ed / Other','Other']
    : ['हाईस्कूल / 10th','हायर सेकेंडरी / 12th','स्नातक / Graduation','स्नातकोत्तर / Post Grad','B.Ed / D.Ed / अन्य','अन्य / Other'];

  const LBL = 'font-weight:700;font-size:11px;color:#222;padding:6px 10px;border:1px solid #ccc;vertical-align:top;background:#fff;';
  const VAL = 'font-size:11px;color:#333;padding:6px 10px;border:1px solid #ccc;vertical-align:top;background:#fff;';

  const f1 = (l,v) => `<tr>
    <td style="${LBL}width:28%;">${l}</td>
    <td colspan="3" style="${VAL}">${v||''}</td>
  </tr>`;

  const f2 = (l1,v1,l2,v2) => `<tr>
    <td style="${LBL}width:22%;">${l1}</td>
    <td style="${VAL}width:28%;">${v1||''}</td>
    <td style="${LBL}width:22%;">${l2}</td>
    <td style="${VAL}width:28%;">${v2||''}</td>
  </tr>`;

  const sh = (txt, bg, tc) => `
    <div style="background:${bg};color:${tc||'#fff'};font-weight:700;font-size:11.5px;
      padding:7px 12px;margin:14px 0 0;">
      ${txt}
    </div>`;

  const pageFtr = `<div style="margin-top:18px;border-top:1px solid #ddd;padding-top:5px;
    text-align:center;font-size:9px;color:#aaa;font-style:italic;">
    School ERP v4.0 &nbsp;|&nbsp; Developed for MP Government Schools &nbsp;|&nbsp; गोपनीय / Confidential
  </div>`;

  const pageTop = (pg) => `<div style="text-align:right;font-size:9.5px;color:#666;
    border-bottom:1.5px solid #1a237e;padding-bottom:5px;margin-bottom:10px;">
    &#9633; Staff Profile Form &nbsp;|&nbsp; MP Education Dept. &nbsp;|&nbsp; 2026-27 &nbsp;|&nbsp; Page: <b>${pg}</b>
  </div>`;

  const eduRows = eduDegs.map((deg,i)=>{
    const e = edu[i]||{};
    const bg = i%2===1 ? '#F5EEFF' : '#fff';
    return `<tr>
      <td style="text-align:center;padding:5px 7px;border:1px solid #ddd;background:${bg};font-size:10.5px;">${i+1}.</td>
      <td style="padding:5px 9px;border:1px solid #ddd;background:${bg};font-size:10.5px;color:#5b21b6;font-weight:600;">${deg}</td>
      <td style="padding:5px 9px;border:1px solid #ddd;background:${bg};font-size:10.5px;">${e.board||''}</td>
      <td style="text-align:center;padding:5px 7px;border:1px solid #ddd;background:${bg};font-size:10.5px;">${e.year||''}</td>
      <td style="text-align:center;padding:5px 7px;border:1px solid #ddd;background:${bg};font-size:10.5px;">${e.pct||''}</td>
      <td style="text-align:center;padding:5px 7px;border:1px solid #ddd;background:${bg};font-size:10.5px;">${e.div||''}</td>
    </tr>`;
  }).join('');

  const photoBox = s.photo
    ? `<img src="${s.photo}" style="width:105px;height:130px;object-fit:cover;border:1px solid #bbb;display:block;">`
    : `<div style="width:105px;height:130px;border:1px solid #bbb;display:flex;flex-direction:column;
          align-items:center;justify-content:center;background:#f9f9f9;">
        <div style="font-size:26px;color:#ccc;">&#128247;</div>
        <div style="font-size:9px;color:#bbb;margin-top:5px;font-style:italic;">${en ? 'Photo' : 'फोटो / Photo'}</div>
        <div style="font-size:8px;color:#ccc;">(3.5 x 4.5 cm)</div>
      </div>`;

  return `
<style>
  *{box-sizing:border-box;margin:0;padding:0;}
  body{font-family:Arial,sans-serif;font-size:11px;background:#e0e0e0;}
  .pg{width:210mm;min-height:297mm;padding:11mm 13mm 13mm;background:#fff;
      page-break-after:always;margin:0 auto ${inline?'14px':'0'};
      box-shadow:${inline?'0 3px 16px rgba(0,0,0,.18)':'none'};}
  table{width:100%;border-collapse:collapse;}
  @media print{body{background:#fff;}.pg{box-shadow:none;margin:0;page-break-after:always;}}
</style>

<!-- PAGE 1 -->
<div class="pg">
  ${pageTop(1)}

  <div style="background:#1a237e;color:#fff;text-align:center;padding:13px 16px;border-radius:3px;">
    <div style="font-size:10px;opacity:.8;margin-bottom:4px;">${en ? 'Madhya Pradesh Government — Department of Education' : 'मध्य प्रदेश शासन — शिक्षा विभाग'}</div>
    <div style="font-size:19px;font-weight:700;letter-spacing:.3px;">${en ? 'STAFF PROFILE FORM' : 'स्टाफ प्रोफाइल पत्र / STAFF PROFILE FORM'}</div>
    <div style="font-size:10px;opacity:.75;margin-top:4px;">${en ? 'Government School, Madhya Pradesh &nbsp;|&nbsp; Academic Year 2026-27' : 'सरकारी विद्यालय, मध्य प्रदेश &nbsp;।&nbsp; शैक्षणिक वर्ष 2026-27'}</div>
  </div>

  <div style="display:flex;justify-content:flex-end;margin:10px 0 2px;">
    <div style="width:107px;">${photoBox}</div>
  </div>

  ${sh(en ? 'A. &nbsp; Personal Information' : 'A. &nbsp; व्यक्तिगत जानकारी &nbsp; (Personal Information)', '#3f51b5')}
  <table style="margin-top:0;">
    ${f1(en ? 'Full Name (Hindi) *' : 'पूरा नाम (हिंदी में) *', s.nameHi)}
    ${f1('Full Name (English) *', s.nameEn)}
    ${f1(en ? 'Father / Husband Name' : 'पिता / पति का नाम', s.fatherName)}
    ${f1(en ? 'Mother Name' : 'माता का नाम', s.motherName)}
    ${f2(en ? 'Date of Birth *' : 'जन्म तिथि / DOB *',s.dob, en ? 'Gender *' : 'लिंग / Gender *',s.gender)}
    ${f2(en ? 'Blood Group' : 'रक्त समूह / Blood Group',s.blood, en ? 'Marital Status' : 'वैवाहिक स्थिति',s.marital)}
    ${f2(en ? 'Religion' : 'धर्म / Religion',s.religion, en ? 'Caste / Category' : 'जाति वर्ग / Category',s.cat)}
    ${f2(en ? 'Nationality' : 'राष्ट्रीयता',s.nationality, en ? 'PwD / Divyang' : 'दिव्यांग / PwD',s.pwd)}
    ${f1(en ? 'Aadhaar No. *' : 'आधार संख्या / Aadhaar No. *', s.aadhar)}
    ${f1(en ? 'PAN Number' : 'पैन नं. / PAN Number', s.pan)}
    ${f1(en ? 'Samagra ID' : 'समग्र आईडी / Samagra ID', s.samagra)}
  </table>

  ${sh(en ? 'B. &nbsp; Address' : 'B. &nbsp; पता / Address', '#388e3c')}
  <table style="margin-top:0;">
    ${f1(en ? 'Current Address' : 'वर्तमान पता / Current Address', s.addrCurr)}
    ${f1(en ? 'Permanent Address' : 'स्थायी पता / Permanent Address', s.addrPerm)}
    ${f2(en ? 'District' : 'जिला / District',s.district, en ? 'Tehsil' : 'तहसील / Tehsil',s.tehsil)}
    ${f2(en ? 'PIN Code' : 'पिनकोड / PIN',s.pin, en ? 'State' : 'राज्य / State',s.state)}
    ${f2(en ? 'Mobile No. *' : 'मोबाइल नं. *',s.mobile, en ? 'Alt. No.' : 'वैकल्पिक नं.',s.mobile2)}
    ${f2(en ? 'Email' : 'ईमेल / Email',s.email, en ? 'WhatsApp No.' : 'व्हाट्सएप नं.',s.whatsapp)}
  </table>

  ${sh(en ? 'C. &nbsp; Educational Qualifications' : 'C. &nbsp; शैक्षिक योग्यता &nbsp; (Educational Qualifications)', '#6a1b9a')}
  <table style="margin-top:0;border-collapse:collapse;">
    <thead><tr>
      <th style="background:#7b2fbe;color:#fff;padding:6px 7px;border:1px solid #bbb;font-size:10.5px;width:5%;text-align:center;">${en ? 'S.No.' : 'क्र.'}</th>
      <th style="background:#7b2fbe;color:#fff;padding:6px 7px;border:1px solid #bbb;font-size:10.5px;width:24%;">${en ? 'Degree / Exam' : 'परीक्षा / Degree'}</th>
      <th style="background:#7b2fbe;color:#fff;padding:6px 7px;border:1px solid #bbb;font-size:10.5px;">${en ? 'University / Board' : 'विश्वविद्यालय / Board'}</th>
      <th style="background:#7b2fbe;color:#fff;padding:6px 7px;border:1px solid #bbb;font-size:10.5px;width:11%;text-align:center;">${en ? 'Pass Year' : 'उत्तीर्ण वर्ष'}</th>
      <th style="background:#7b2fbe;color:#fff;padding:6px 7px;border:1px solid #bbb;font-size:10.5px;width:10%;text-align:center;">${en ? 'Marks %' : 'प्रतिशत %'}</th>
      <th style="background:#7b2fbe;color:#fff;padding:6px 7px;border:1px solid #bbb;font-size:10.5px;width:13%;text-align:center;">${en ? 'Division' : 'विषय / Division'}</th>
    </tr></thead>
    <tbody>${eduRows}</tbody>
  </table>

  ${pageFtr}
</div>

<!-- PAGE 2 -->
<div class="pg">
  ${pageTop(2)}

  ${sh(en ? 'D. &nbsp; Service Details' : 'D. &nbsp; सेवा जानकारी &nbsp; (Service Details)', '#e65100')}
  <table style="margin-top:0;">
    ${f2(en ? 'Staff ID' : 'कर्मचारी आईडी / Staff ID',s.staffId, en ? 'Designation *' : 'पद / Designation *',s.desig)}
    ${f2(en ? 'Cadre' : 'संवर्ग / Cadre',s.cadre, en ? 'Subject *' : 'विषय / Subject *',s.subject)}
    ${f2(en ? 'Appointment Date' : 'नियुक्ति दिनांक',s.joinDate, en ? 'Service Type' : 'सेवा प्रकार',s.serviceType)}
    ${f2(en ? 'Joining Date at School' : 'विद्यालय में योगदान दिनांक',s.postingDate, en ? 'Current Posting Year' : 'वर्तमान पोस्टिंग वर्ष',s.postingYear)}
    ${f1(en ? 'Previous School' : 'पिछला विद्यालय / Previous School',s.prevSchool)}
    ${f1(en ? 'Service at Previous School' : 'पिछले विद्यालय में कुल सेवा अवधि',s.prevService)}
    ${f1(en ? 'Total Service' : 'कुल सेवा अवधि / Total Service',s.totalService)}
  </table>

  ${sh(en ? 'E. &nbsp; Bank &amp; Finance Information' : 'E. &nbsp; बैंक एवं वित्तीय जानकारी &nbsp; (Bank &amp; Finance)', '#00838f')}
  <table style="margin-top:0;">
    ${f1(en ? 'Bank Name' : 'बैंक का नाम / Bank Name',s.bank)}
    ${f1(en ? 'Account No.' : 'खाता संख्या / Account No.',s.account)}
    ${f2('IFSC Code',s.ifsc, en ? 'Branch' : 'शाखा / Branch',s.branch)}
    ${f2(en ? 'Basic Pay (₹)' : 'मूल वेतन / Basic Pay (₹)',s.basicPay, en ? 'Grade Pay (₹)' : 'ग्रेड पे / Grade Pay (₹)',s.gradePay)}
    ${f1(en ? 'GPF / NPS Account No.' : 'GPF / NPS खाता संख्या',s.gpf)}
  </table>

  ${sh(en ? 'F. &nbsp; Emergency Contact' : 'F. &nbsp; आपातकालीन संपर्क &nbsp; (Emergency Contact)', '#c62828')}
  <table style="margin-top:0;">
    ${f2(en ? 'Contact Person Name' : 'संपर्क व्यक्ति का नाम',s.emName, en ? 'Relation' : 'संबंध / Relation',s.emRel)}
    ${f2(en ? 'Mobile No.' : 'मोबाइल नं.',s.emMobile, en ? 'Alt. No.' : 'वैकल्पिक नं.',s.emAlt)}
  </table>

  <div style="margin-top:16px;border:1.5px solid #c5e1a5;border-radius:2px;padding:11px 14px;background:#f9fbe7;">
    <div style="font-weight:700;font-size:11.5px;color:#558b2f;margin-bottom:6px;">${en ? 'Declaration' : 'घोषणा / Declaration'}</div>
    <div style="font-size:10.5px;line-height:1.85;color:#333;">
      ${en
        ? 'I hereby declare that all the information furnished above is true and correct to the best of my knowledge and belief. In case any information is found to be false, I shall be liable for departmental action.'
        : 'मैं घोषणा करता/करती हूँ कि उपरोक्त समस्त जानकारी मेरी जानकारी और विश्वास के अनुसार सत्य एवं सही है। किसी भी जानकारी के असत्य पाए जाने पर मैं विभागीय कार्यवाही के लिए उत्तरदायी रहूँगा/रहूँगी।<br><em style="color:#777;font-size:10px;">I hereby declare that all the information furnished above is true and correct to the best of my knowledge and belief.</em>'
      }
    </div>
  </div>

  <div style="margin-top:8px;font-size:10.5px;">
    <b>${en ? 'Date:' : 'दिनांक / Date:'}</b> &nbsp;${s.declDate||'_______________'}
    &nbsp;&nbsp;&nbsp;&nbsp;
    <b>${en ? 'Place:' : 'स्थान / Place:'}</b> &nbsp;${s.declPlace||'_______________'}
  </div>

  <div style="display:flex;justify-content:space-between;align-items:flex-end;margin-top:38px;gap:20px;">
    <div style="flex:1;text-align:center;">
      <div style="height:38px;"></div>
      <div style="border-top:1px solid #555;padding-top:5px;">
        <div style="font-weight:700;font-size:10.5px;">${en ? 'Signature of Staff' : 'कर्मचारी के हस्ताक्षर'}</div>
        <div style="font-size:9.5px;color:#777;font-style:italic;">${en ? '' : 'Signature of Staff'}</div>
        <div style="font-size:9.5px;color:#999;margin-top:3px;">${en ? 'Date: ___________' : 'दिनांक: ___________'}</div>
      </div>
    </div>
    <div style="flex:1;text-align:center;">
      <div style="height:38px;"></div>
      <div style="border-top:1px solid #555;padding-top:5px;">
        <div style="font-weight:700;font-size:10.5px;">${en ? 'Head Master / Principal' : 'प्रधानाध्यापक / प्राचार्य'}</div>
        <div style="font-size:9.5px;color:#777;font-style:italic;">${en ? '' : 'Head Master / Principal'}</div>
        <div style="font-size:9.5px;color:#999;margin-top:3px;">${en ? 'Date: ___________' : 'दिनांक: ___________'}</div>
      </div>
    </div>
    <div style="width:110px;height:85px;border:1px solid #ccc;display:flex;
        flex-direction:column;align-items:center;justify-content:center;background:#fafafa;">
      <div style="font-size:9px;color:#ccc;font-style:italic;text-align:center;line-height:1.7;">
        ${en ? 'Official Seal' : 'कार्यालय मुहर<br>Official Seal'}
      </div>
    </div>
  </div>

  ${pageFtr}
</div>`;
}

// ===================== LEAVE MANAGEMENT =====================

var leaveRegistry = _erpSafeLoad(sessKey('erp_leave'), []);

function saveLeaveData() {
  localStorage.setItem(sessKey('erp_leave'), JSON.stringify(leaveRegistry)); smartSave(sessKey('erp_leave'), leaveRegistry);
}

function switchLeaveTab(tab) {
  ['apply','records','ledger'].forEach(t => {
    document.getElementById('leavePanel-'+t).style.display = t===tab ? '' : 'none';
    const btn = document.getElementById('leaveTab-'+t);
    if (btn) btn.className = t===tab ? 'stab active' : 'stab';
  });
  if (tab === 'records') { lvPopulateFilters(); renderLeaveRecords(); }
  if (tab === 'ledger')  { lvPopulateLedgerDropdown(); }
}

function lvPopulateFilters() {
  const sel = document.getElementById('lvFilterStaff');
  if (!sel) return;
  const names = [...new Set(leaveRegistry.map(l => l.nameEn||l.nameHi).filter(Boolean))];
  sel.innerHTML = '<option value="">All Staff</option>' + names.map(n=>`<option>${n}</option>`).join('');
}

function lvPopulateLedgerDropdown() {
  const sel = document.getElementById('ledgerStaffSel');
  if (!sel) return;
  const staffList = staffRegistry.length > 0
    ? staffRegistry.map(s => ({ id: s.staffId, name: s.nameEn||s.nameHi }))
    : [...new Set(leaveRegistry.map(l => ({ id: l.staffId, name: l.nameEn||l.nameHi })))];
  sel.innerHTML = '<option value="">-- Select Staff --</option>' +
    staffList.map(s=>`<option value="${s.id}">${s.name}${s.id?' ('+s.id+')':''}</option>`).join('');
}

function lvLoadFromRegistry() {
  const sel = document.getElementById('lv_staffSel');
  if (!sel || !sel.value) return;
  const s = staffRegistry.find(x => x.staffId === sel.value);
  if (!s) return;
  const setV = (id, val) => { const el = document.getElementById(id); if (el) el.value = val||''; };
  setV('lv_nameHi', s.nameHi);
  setV('lv_nameEn', s.nameEn);
  setV('lv_desig', s.desig);
  setV('lv_subject', s.subject);
  setV('lv_mobile', s.mobile);
  setV('lv_joinDate', s.joinDate);
  setV('lv_serviceType', s.serviceType);
  lvUpdateBalance();
}

function lvCalcDays() {
  const from = document.getElementById('lv_fromDate').value;
  const to   = document.getElementById('lv_toDate').value;
  if (from && to) {
    const d1 = new Date(from), d2 = new Date(to);
    const diff = Math.round((d2 - d1) / 86400000) + 1;
    document.getElementById('lv_totalDays').value = diff > 0 ? diff : 0;
  }
}

function lvUpdateBalance() {
  const type = document.querySelector('input[name="lvLeaveType"]:checked')?.value;
  const staffId = document.getElementById('lv_staffSel')?.value;
  if (!type || !staffId) { document.getElementById('lv_balance').value = ''; return; }

  // Default balances
  const defaults = { CL: 15, EL: 30, ML: 20, Maternity: 180, Paternity: 15, Other: 10 };
  const maxBal = defaults[type] || 10;

  // Count used leaves of this type for this staff
  const used = leaveRegistry
    .filter(l => l.staffId === staffId && l.leaveType === type && l.status === 'Approved')
    .reduce((sum, l) => sum + (parseInt(l.totalDays)||0), 0);

  const balance = Math.max(0, maxBal - used);
  document.getElementById('lv_balance').value = balance + ' days remaining';
}

function saveLeaveApplication() {
  const type = document.querySelector('input[name="lvLeaveType"]:checked')?.value;
  const nameEn = document.getElementById('lv_nameEn').value.trim();
  const nameHi = document.getElementById('lv_nameHi').value.trim();
  if (!nameEn && !nameHi) return alert('कृपया शिक्षक का नाम भरें!');
  if (!type) return alert('कृपया अवकाश प्रकार चुनें!');
  if (!document.getElementById('lv_fromDate').value) return alert('From Date भरें!');
  if (!document.getElementById('lv_toDate').value) return alert('To Date भरें!');

  const v = id => document.getElementById(id)?.value || '';
  const appNo = v('lv_appNo') || ('LV' + String(leaveRegistry.length+1).padStart(4,'0'));

  const record = {
    appNo, session: v('lv_session'),
    staffId: document.getElementById('lv_staffSel')?.value || '',
    empId: v('lv_empId'),
    nameHi, nameEn,
    desig: v('lv_desig'), subject: v('lv_subject'),
    mobile: v('lv_mobile'), joinDate: v('lv_joinDate'),
    serviceType: document.querySelector('input[name="lvServiceType"]:checked')?.value || '',
    dept: v('lv_dept'),
    classAssigned: v('lv_classAssigned'),
    leaveType: type,
    fromDate: v('lv_fromDate'), toDate: v('lv_toDate'),
    totalDays: v('lv_totalDays'),
    balance: v('lv_balance'),
    reason: v('lv_reason'), details: v('lv_details'),
    subTeacher: v('lv_subTeacher'), subMobile: v('lv_subMobile'),
    arrangements: v('lv_arrangements'),
    receivedDate: v('lv_receivedDate'), forwardedDate: v('lv_forwardedDate'),
    recommendation: document.querySelector('input[name="lvRecommend"]:checked')?.value || '',
    decision: document.querySelector('input[name="lvFinalDec"]:checked')?.value || '',
    daysApproved: v('lv_daysApproved'),
    rejectReason: v('lv_rejectReason'),
    remarks: v('lv_remarks'),
    status: v('lv_status') || 'Pending',
    appDate: v('lv_appDate') || new Date().toISOString().split('T')[0],
    savedOn: new Date().toLocaleDateString('en-IN')
  };

  if (lvEditingIdx >= 0) {
    leaveRegistry[lvEditingIdx] = record; lvEditingIdx = -1;
    alert('✅ Leave record updated!');
  } else {
    leaveRegistry.push(record);
    document.getElementById('lv_appNo').value = appNo;
    alert('✅ Leave application saved: ' + appNo);
  }
  saveLeaveData();
  updateLeaveStats();
}

let lvEditingIdx = -1;

function clearLeaveForm() {
  lvEditingIdx = -1;
  lvSetEditingMode(false);
  ['lv_appNo','lv_session','lv_nameHi','lv_nameEn','lv_empId','lv_desig','lv_subject','lv_mobile',
   'lv_joinDate','lv_dept','lv_classAssigned','lv_fromDate','lv_toDate','lv_totalDays',
   'lv_balance','lv_reason','lv_details','lv_subTeacher','lv_subMobile','lv_arrangements',
   'lv_receivedDate','lv_forwardedDate','lv_daysApproved','lv_rejectReason','lv_remarks']
    .forEach(id => { const el = document.getElementById(id); if (el) el.value = ''; });
  document.querySelectorAll('input[name="lvLeaveType"]').forEach(r => r.checked = false);
  document.querySelectorAll('input[name="lvServiceType"]').forEach(r => r.checked = false);
  document.querySelectorAll('input[name="lvRecommend"]').forEach(r => r.checked = false);
  document.querySelectorAll('input[name="lvFinalDec"]').forEach(r => r.checked = false);
  const sel = document.getElementById('lv_staffSel'); if (sel) sel.value = '';
  const st = document.getElementById('lv_status'); if (st) st.value = 'Pending';
  const dt = document.getElementById('lv_appDate'); if (dt) dt.value = new Date().toISOString().split('T')[0];
  document.getElementById('lv_session').value = '2026-27';
}

function updateLeaveStats() {
  const el = document.getElementById('leaveStats');
  if (!el) return;
  const total    = leaveRegistry.length;
  const pending  = leaveRegistry.filter(l => l.status === 'Pending').length;
  const approved = leaveRegistry.filter(l => l.status === 'Approved').length;
  const rejected = leaveRegistry.filter(l => l.status === 'Rejected').length;
  const clCount  = leaveRegistry.filter(l => l.leaveType === 'CL').length;
  const elCount  = leaveRegistry.filter(l => l.leaveType === 'EL').length;
  el.innerHTML =
    statCard(total,   'Total Applications', '#1976d2') +
    statCard(pending, 'Pending',            '#e65100') +
    statCard(approved,'Approved',           '#2e7d32') +
    statCard(rejected,'Rejected',           '#c62828') +
    statCard(clCount, 'CL Applications',   '#6a1b9a') +
    statCard(elCount, 'EL Applications',   '#00838f');
}

function _lvGetFiltered(extraColFilters) {
  const sStaff  = document.getElementById('lvFilterStaff')?.value  || '';
  const sType   = document.getElementById('lvFilterType')?.value   || '';
  const sStatus = document.getElementById('lvFilterStatus')?.value || '';
  const sText   = (document.getElementById('lvSearch')?.value || '').toLowerCase();
  return leaveRegistry.filter(l => {
    if (sStaff  && !(l.nameEn||l.nameHi||'').includes(sStaff)) return false;
    if (sType   && l.leaveType !== sType) return false;
    if (sStatus && l.status !== sStatus) return false;
    if (sText   && !(l.nameEn||l.nameHi||'').toLowerCase().includes(sText) && !(l.appNo||'').toLowerCase().includes(sText)) return false;
    if (extraColFilters) {
      for (const f in extraColFilters) {
        if (!String(l[f]||'').toLowerCase().includes(extraColFilters[f])) return false;
      }
    }
    return true;
  });
}

function _lvRenderRows(data) {
  const tbody = document.getElementById('leaveRecordsBody');
  if (!tbody) return;
  // Stats
  const statsEl = document.getElementById('leaveRecordStats');
  if (statsEl) {
    const total    = leaveRegistry.length;
    const shown    = data.length;
    const pending  = leaveRegistry.filter(l=>l.status==='Pending').length;
    const approved = leaveRegistry.filter(l=>l.status==='Approved').length;
    const rejected = leaveRegistry.filter(l=>l.status==='Rejected').length;
    const mk=(label,val,color)=>`<span style="background:${color};color:#fff;padding:5px 14px;border-radius:20px;font-size:12px;font-weight:700;">${label}: <b>${val}</b></span>`;
    var _lrEn = isEnglish();
    statsEl.innerHTML = mk(_lrEn?'Total':'कुल',total,'#1a237e')+mk(_lrEn?'Showing':'दिख रहे',shown,'#0d47a1')
      +mk('Pending',pending,'#e65100')+mk('Approved',approved,'#1b5e20')+mk('Rejected',rejected,'#b71c1c');
  }
  if (!data.length) {
    tbody.innerHTML = '<tr><td colspan="34" style="text-align:center;padding:40px;color:#999;font-style:italic;">'+(isEnglish()?'No applications found.':'कोई आवेदन नहीं मिला।')+'</td></tr>';
    return;
  }
  const statusBadge = l => ({
    Pending:  '<span class="badge badge-orange">⏳ Pending</span>',
    Approved: '<span class="badge badge-green">✅ Approved</span>',
    Rejected: '<span class="badge badge-red">❌ Rejected</span>',
    Partial:  '<span class="badge badge-blue">⚠️ Partial</span>',
  }[l.status] || `<span class="badge badge-orange">${l.status||'—'}</span>`);
  const typeCls = t => ({CL:'badge-blue',EL:'badge-green',ML:'badge-orange',Maternity:'badge-red',Paternity:'badge-blue',Other:'badge-orange'}[t]||'badge-blue');
  tbody.innerHTML = data.map((l,i) => {
    const idx = leaveRegistry.indexOf(l);
    return `<tr ondblclick="lvEditRecord(${idx})" style="cursor:pointer;" onmouseover="this.style.outline='2px solid #1976d2'" onmouseout="this.style.outline=''" title="Double-click to load & edit">
      <td>${i+1}</td>
      <td><b>${l.appNo||'—'}</b></td>
      <td>${l.session||'—'}</td>
      <td>${l.appDate||'—'}</td>
      <td>${l.staffId||'—'}</td>
      <td>${l.empId||'—'}</td>
      <td><b>${l.nameEn||'—'}</b></td>
      <td>${l.nameHi||'—'}</td>
      <td><span class="badge badge-blue">${l.desig||'—'}</span></td>
      <td>${l.subject||'—'}</td>
      <td>${l.mobile||'—'}</td>
      <td>${l.joinDate||'—'}</td>
      <td>${l.serviceType||'—'}</td>
      <td>${l.dept||'—'}</td>
      <td>${l.classAssigned||'—'}</td>
      <td><span class="badge ${typeCls(l.leaveType)}">${l.leaveType||'—'}</span></td>
      <td>${l.fromDate||'—'}</td>
      <td>${l.toDate||'—'}</td>
      <td style="text-align:center;font-weight:700;color:#1565c0;">${l.totalDays||'—'}</td>
      <td>${l.balance||'—'}</td>
      <td title="${l.reason||''}">${l.reason||'—'}</td>
      <td title="${l.details||''}">${l.details||'—'}</td>
      <td>${l.subTeacher||'—'}</td>
      <td>${l.subMobile||'—'}</td>
      <td title="${l.arrangements||''}">${l.arrangements||'—'}</td>
      <td>${l.receivedDate||'—'}</td>
      <td>${l.forwardedDate||'—'}</td>
      <td>${l.recommendation||'—'}</td>
      <td>${l.decision||'—'}</td>
      <td style="text-align:center;font-weight:700;">${l.daysApproved||'—'}</td>
      <td title="${l.rejectReason||''}">${l.rejectReason||'—'}</td>
      <td title="${l.remarks||''}">${l.remarks||'—'}</td>
      <td>${statusBadge(l)}</td>
      <td style="white-space:nowrap;">
        <button onclick="lvApprove(${idx})" style="background:none;border:none;cursor:pointer;font-size:15px;" title="Approve">✅</button>
        <button onclick="lvPrintRecord(${idx})" style="background:none;border:none;cursor:pointer;font-size:15px;" title="Print">🖨️</button>
        <button onclick="lvDeleteRecord(${idx})" style="background:none;border:none;cursor:pointer;font-size:15px;color:#c62828;" title="Delete">🗑️</button>
      </td>
    </tr>`;
  }).join('');
}

function renderLeaveRecords() {
  _lvRenderRows(_lvGetFiltered());
}

function rskLeaveFilter() {
  const inputs = document.querySelectorAll('#lrk_leave_filter_row .rsk-finput');
  const colFilters = {};
  inputs.forEach(inp => { const v=inp.value.trim().toLowerCase(); if(v) colFilters[inp.dataset.lf]=v; });
  _lvRenderRows(_lvGetFiltered(colFilters));
}

function resetLeaveFilters() {
  ['lvFilterStaff','lvFilterType','lvFilterStatus'].forEach(id=>{ const el=document.getElementById(id); if(el) el.value=''; });
  const se=document.getElementById('lvSearch'); if(se) se.value='';
  document.querySelectorAll('#lrk_leave_filter_row .rsk-finput').forEach(el=>el.value='');
  renderLeaveRecords();
}

function lvApprove(idx) {
  const days = prompt('स्वीकृत दिन कितने? / Days to approve:', leaveRegistry[idx].totalDays || '1');
  if (days === null) return;
  leaveRegistry[idx].status = 'Approved';
  leaveRegistry[idx].daysApproved = days;
  leaveRegistry[idx].decision = 'स्वीकृत / Approved';
  saveLeaveData();
  renderLeaveRecords();
  updateLeaveStats();
  alert('✅ Leave Approved for ' + days + ' days!');
}

// ── Leave Editing Mode UI Toggle ──
function lvSetEditingMode(isEditing) {
  var saveBtn   = document.getElementById('lv_saveBtn');
  var updateBtn = document.getElementById('lv_updateBtn');
  var deleteBtn = document.getElementById('lv_deleteBtn');
  var editBadge = document.getElementById('lv_editingBadge');
  var newBadge  = document.getElementById('lv_newBadge');
  if (isEditing) {
    if (saveBtn)   { saveBtn.style.display   = 'none'; }
    if (updateBtn) { updateBtn.style.display = ''; }
    if (deleteBtn) { deleteBtn.style.display = ''; }
    if (editBadge) { editBadge.style.display = ''; }
    if (newBadge)  { newBadge.style.display  = 'none'; }
  } else {
    if (saveBtn)   { saveBtn.style.display   = ''; }
    if (updateBtn) { updateBtn.style.display = 'none'; }
    if (deleteBtn) { deleteBtn.style.display = 'none'; }
    if (editBadge) { editBadge.style.display = 'none'; }
    if (newBadge)  { newBadge.style.display  = ''; }
  }
}

function lvUpdateRecord() {
  if (lvEditingIdx < 0) return alert('कोई record edit mode में नहीं है!');
  const type = document.querySelector('input[name="lvLeaveType"]:checked')?.value;
  if (!type) return alert('कृपया अवकाश प्रकार चुनें!');
  const v = id => document.getElementById(id)?.value || '';
  const record = leaveRegistry[lvEditingIdx];
  // Update all fields
  record.appNo = v('lv_appNo'); record.session = v('lv_session'); record.appDate = v('lv_appDate');
  record.nameHi = v('lv_nameHi'); record.nameEn = v('lv_nameEn'); record.empId = v('lv_empId');
  record.desig = v('lv_desig'); record.subject = v('lv_subject'); record.mobile = v('lv_mobile');
  record.joinDate = v('lv_joinDate'); record.dept = v('lv_dept'); record.classAssigned = v('lv_classAssigned');
  record.fromDate = v('lv_fromDate'); record.toDate = v('lv_toDate');
  record.totalDays = v('lv_totalDays'); record.balance = v('lv_balance');
  record.reason = v('lv_reason'); record.details = v('lv_details');
  record.subTeacher = v('lv_subTeacher'); record.subMobile = v('lv_subMobile');
  record.arrangements = v('lv_arrangements');
  record.receivedDate = v('lv_receivedDate'); record.forwardedDate = v('lv_forwardedDate');
  record.daysApproved = v('lv_daysApproved'); record.rejectReason = v('lv_rejectReason');
  record.remarks = v('lv_remarks'); record.status = v('lv_status') || 'Pending';
  record.leaveType = type;
  record.serviceType = document.querySelector('input[name="lvServiceType"]:checked')?.value || record.serviceType;
  record.recommendation = document.querySelector('input[name="lvRecommend"]:checked')?.value || record.recommendation;
  record.decision = document.querySelector('input[name="lvFinalDec"]:checked')?.value || record.decision;
  record.staffId = document.getElementById('lv_staffSel')?.value || record.staffId;
  leaveRegistry[lvEditingIdx] = record;
  saveLeaveData(); updateLeaveStats();
  alert('✅ Record updated successfully!');
  clearLeaveForm();
}

function lvDeleteCurrentRecord() {
  if (lvEditingIdx < 0) return;
  const name = leaveRegistry[lvEditingIdx]?.nameEn || leaveRegistry[lvEditingIdx]?.nameHi || 'this record';
  if (!confirm('⚠️ "' + name + '" का यह leave record delete होगा। Sure?')) return;
  leaveRegistry.splice(lvEditingIdx, 1);
  saveLeaveData(); renderLeaveRecords(); updateLeaveStats();
  clearLeaveForm();
  alert('🗑️ Record deleted!');
}

function lvEditRecord(idx) {
  const l = leaveRegistry[idx];
  lvEditingIdx = idx;
  clearLeaveForm();
  const setV = (id, val) => { const el = document.getElementById(id); if (el) el.value = val||''; };
  setV('lv_appNo', l.appNo); setV('lv_session', l.session); setV('lv_appDate', l.appDate);
  setV('lv_nameHi', l.nameHi); setV('lv_nameEn', l.nameEn); setV('lv_empId', l.empId);
  setV('lv_desig', l.desig); setV('lv_subject', l.subject); setV('lv_mobile', l.mobile);
  setV('lv_joinDate', l.joinDate); setV('lv_dept', l.dept); setV('lv_classAssigned', l.classAssigned);
  setV('lv_fromDate', l.fromDate); setV('lv_toDate', l.toDate);
  setV('lv_totalDays', l.totalDays); setV('lv_balance', l.balance);
  setV('lv_reason', l.reason); setV('lv_details', l.details);
  setV('lv_subTeacher', l.subTeacher); setV('lv_subMobile', l.subMobile);
  setV('lv_arrangements', l.arrangements);
  setV('lv_receivedDate', l.receivedDate); setV('lv_forwardedDate', l.forwardedDate);
  setV('lv_daysApproved', l.daysApproved); setV('lv_rejectReason', l.rejectReason);
  setV('lv_remarks', l.remarks);
  setV('lv_status', l.status || 'Pending');
  const staffSel = document.getElementById('lv_staffSel');
  if (staffSel) staffSel.value = l.staffId || '';
  if (l.serviceType) {
    const r = document.querySelector(`input[name="lvServiceType"][value="${l.serviceType}"]`);
    if (r) r.checked = true;
  }
  if (l.recommendation) {
    const r = document.querySelector(`input[name="lvRecommend"][value="${l.recommendation}"]`);
    if (r) r.checked = true;
  }
  if (l.decision) {
    const r = document.querySelector(`input[name="lvFinalDec"][value="${l.decision}"]`);
    if (r) r.checked = true;
  }
  if (l.leaveType) {
    const radio = document.querySelector(`input[name="lvLeaveType"][value="${l.leaveType}"]`);
    if (radio) radio.checked = true;
  }
  lvSetEditingMode(true);
  switchLeaveTab('apply');
}

function lvDeleteRecord(idx) {
  if (!confirm('इस आवेदन को delete करें?')) return;
  leaveRegistry.splice(idx, 1);
  saveLeaveData();
  renderLeaveRecords();
  updateLeaveStats();
}

function exportLeaveExcel() {
  if (!leaveRegistry.length) return alert('कोई record नहीं है!');
  const data = leaveRegistry.map((l,idx) => ({
    'क्र.': idx+1,
    'App No': l.appNo, 'Session': l.session, 'Application Date': l.appDate,
    'Staff ID': l.staffId, 'Emp ID': l.empId, 'Name (EN)': l.nameEn, 'Name (HI)': l.nameHi,
    'Designation': l.desig, 'Subject': l.subject, 'Mobile': l.mobile,
    'Join Date': l.joinDate, 'Service Type': l.serviceType,
    'Department': l.dept, 'Class Assigned': l.classAssigned,
    'Leave Type': l.leaveType, 'From Date': l.fromDate, 'To Date': l.toDate,
    'Total Days': l.totalDays, 'Balance': l.balance,
    'Reason': l.reason, 'Details': l.details,
    'Sub Teacher': l.subTeacher, 'Sub Mobile': l.subMobile,
    'Arrangements': l.arrangements,
    'Received Date': l.receivedDate, 'Forwarded Date': l.forwardedDate,
    'Recommendation': l.recommendation, 'Decision': l.decision,
    'Days Approved': l.daysApproved, 'Reject Reason': l.rejectReason,
    'Remarks': l.remarks, 'Status': l.status, 'Saved On': l.savedOn
  }));
  const ws = XLSX.utils.json_to_sheet(data);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, 'Leave Records');
  XLSX.writeFile(wb, 'Leave_Records_Full.xlsx');
}

function renderLedger() {
  const staffId = document.getElementById('ledgerStaffSel').value;
  const session = document.getElementById('ledgerSession').value || '2026-27';
  const el = document.getElementById('ledgerContent');
  if (!staffId) {
    el.innerHTML = '<div style="text-align:center;padding:40px;color:#999;font-size:14px;">'+(isEnglish()?'👆 Select Teacher above — Ledger will auto generate':'👆 ऊपर से Teacher select करें — Ledger auto generate होगा')+'</div>';
    return;
  }
  const staffRec = staffRegistry.find(s => s.staffId === staffId);
  const staffName = staffRec ? (staffRec.nameEn||staffRec.nameHi) : staffId;
  const desig = staffRec ? (staffRec.desig||'') : '';

  // Get all leave records for this staff
  const records = leaveRegistry.filter(l => l.staffId === staffId || l.nameEn === staffId);

  // Monthly data (Apr=0 to Mar=11)
  const _ldgEn = isEnglish();
  const months = _ldgEn
    ? ['April','May','June','July','August','September','October','November','December','January','February','March']
    : ['अप्रैल','मई','जून','जुलाई','अगस्त','सितंबर','अक्टूबर','नवंबर','दिसंबर','जनवरी','फरवरी','मार्च'];
  const monthNums = ['04','05','06','07','08','09','10','11','12','01','02','03'];

  function getMonthIdx(dateStr) {
    if (!dateStr) return -1;
    const m = dateStr.substring(5, 7);
    return monthNums.indexOf(m);
  }

  // Build monthly summary
  const monthData = months.map((_, mi) => {
    const mLeaves = records.filter(l => getMonthIdx(l.fromDate) === mi && l.status === 'Approved');
    const cl = mLeaves.filter(l=>l.leaveType==='CL').reduce((s,l)=>s+(parseInt(l.daysApproved||l.totalDays)||0),0);
    const el2 = mLeaves.filter(l=>l.leaveType==='EL').reduce((s,l)=>s+(parseInt(l.daysApproved||l.totalDays)||0),0);
    const ml = mLeaves.filter(l=>l.leaveType==='ML').reduce((s,l)=>s+(parseInt(l.daysApproved||l.totalDays)||0),0);
    const absent = mLeaves.filter(l=>['Other','Paternity','Maternity'].includes(l.leaveType)).reduce((s,l)=>s+(parseInt(l.daysApproved||l.totalDays)||0),0);
    const totalLeave = cl+el2+ml+absent;
    const workDays = 26; // default
    const present = workDays - totalLeave;
    return { cl, el: el2, ml, absent, totalLeave, workDays, present };
  });

  // Leave summary totals
  const defaults = { CL:15, EL:30, ML:20, Maternity:180, Paternity:15, Other:10 };
  const leaveTypes = ['CL','EL','ML','Maternity','Paternity','Other'];
  const leaveLabels = _ldgEn
    ? { CL:'Casual / CL', EL:'Earned / EL', ML:'Medical / ML', Maternity:'Maternity', Paternity:'Paternity', Other:'Other' }
    : { CL:'आकस्मिक / CL', EL:'अर्जित / EL', ML:'चिकित्सा / ML', Maternity:'प्रसूति / Maternity', Paternity:'पितृत्व / Paternity', Other:'अन्य / Other' };

  const monthRows = monthData.map((d, i) => `
    <tr style="background:${i%2===0?'#f5f8ff':'#fff'};">
      <td style="text-align:center;padding:7px 8px;">${i+1}</td>
      <td style="padding:7px 10px;font-weight:${d.totalLeave>0?'600':'400'};color:${d.totalLeave>0?'#1565c0':'#333'};">${months[i]}</td>
      <td style="text-align:center;padding:7px 8px;">${d.workDays}</td>
      <td style="text-align:center;padding:7px 8px;color:#2e7d32;font-weight:600;">${d.present}</td>
      <td style="text-align:center;padding:7px 8px;color:${d.cl>0?'#6a1b9a':'#999'};">${d.cl||'—'}</td>
      <td style="text-align:center;padding:7px 8px;color:${d.el>0?'#1565c0':'#999'};">${d.el||'—'}</td>
      <td style="text-align:center;padding:7px 8px;color:${d.ml>0?'#e65100':'#999'};">${d.ml||'—'}</td>
      <td style="text-align:center;padding:7px 8px;color:${d.absent>0?'#c62828':'#999'};">${d.absent||'—'}</td>
      <td style="padding:7px 8px;color:#888;font-size:11px;">${
        records.filter(l => getMonthIdx(l.fromDate)===i).map(l=>l.reason||'').filter(Boolean).join('; ').slice(0,40) || '—'
      }</td>
    </tr>`).join('');

  const totals = monthData.reduce((a,d)=>({ cl:a.cl+d.cl, el:a.el+d.el, ml:a.ml+d.ml, absent:a.absent+d.absent, totalLeave:a.totalLeave+d.totalLeave, workDays:a.workDays+d.workDays, present:a.present+d.present }), {cl:0,el:0,ml:0,absent:0,totalLeave:0,workDays:0,present:0});

  const summaryRows = leaveTypes.map(type => {
    const opening = defaults[type]||10;
    const used = records.filter(l=>l.leaveType===type&&l.status==='Approved').reduce((s,l)=>s+(parseInt(l.daysApproved||l.totalDays)||0),0);
    const closing = Math.max(0, opening - used);
    return `<tr style="background:#fff3e0;">
      <td style="padding:8px 12px;font-weight:600;">${leaveLabels[type]}</td>
      <td style="text-align:center;padding:8px;">${opening}</td>
      <td style="text-align:center;padding:8px;">0</td>
      <td style="text-align:center;padding:8px;color:#c62828;font-weight:600;">${used}</td>
      <td style="text-align:center;padding:8px;color:#2e7d32;font-weight:600;">${closing}</td>
      <td style="padding:8px 12px;font-size:11px;color:#888;">${records.filter(l=>l.leaveType===type).map(l=>l.fromDate).join(', ').slice(0,40)||'—'}</td>
    </tr>`;
  }).join('');

  const wordStyle = `
    <style>
      .ldgr-wrap { font-family: 'Calibri', Arial, sans-serif; font-size: 12px; color: #111; background: #fff; padding: 18px 22px; border: 2.5px solid #1b5e20; border-radius: 6px; }
      .ldgr-title-bar { background: #1b5e20; color: #fff; text-align: center; padding: 12px 18px; border-bottom: 3px solid #4caf50; }
      .ldgr-title-bar .ldgr-main-title { font-size: 16px; font-weight: 700; letter-spacing: 0.5px; }
      .ldgr-title-bar .ldgr-sub-title { font-size: 11px; opacity: 0.88; margin-top: 3px; }
      /* Info table */
      .ldgr-info-table { width: 100%; border-collapse: collapse; margin-top: 0; border: 1.5px solid #1b5e20; border-top: none; }
      .ldgr-info-table td { padding: 6px 12px; font-size: 11.5px; border: 1px solid #a5d6a7; vertical-align: middle; }
      .ldgr-info-table td.ldgr-lbl { background: #e8f5e9; font-weight: 700; color: #1b5e20; width: 18%; white-space: nowrap; }
      /* Section heading */
      .ldgr-section-head { background: #1b5e20; color: #fff; font-weight: 700; font-size: 11.5px; padding: 6px 14px; margin-top: 14px; border-left: 4px solid #4caf50; letter-spacing: 0.3px; }
      /* Tables */
      .ldgr-table { width: 100%; border-collapse: collapse; font-size: 11.5px; }
      .ldgr-table thead tr { background: #2e7d32; color: #fff; }
      .ldgr-table thead th { padding: 7px 10px; border: 1px solid #1b5e20; font-weight: 700; text-align: center; white-space: nowrap; font-size: 11px; }
      .ldgr-table thead th.ldgr-th-left { text-align: left; }
      .ldgr-table tbody tr:nth-child(odd)  td { background: #f1f8f1; }
      .ldgr-table tbody tr:nth-child(even) td { background: #ffffff; }
      .ldgr-table tbody tr:hover td { background: #c8e6c9 !important; }
      .ldgr-table tbody td { padding: 6px 10px; border: 1px solid #c8e6c9; text-align: center; vertical-align: middle; }
      .ldgr-table tbody td.ldgr-td-left { text-align: left; font-weight: 600; }
      .ldgr-table tbody td.ldgr-td-month { text-align: left; font-size: 12px; }
      .ldgr-table tfoot tr { background: #1b5e20; color: #fff; font-weight: 700; }
      .ldgr-table tfoot td { padding: 7px 10px; border: 1px solid #145214; text-align: center; font-size: 11.5px; }
      /* Signature */
      .ldgr-sig-row { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 30px; margin-top: 28px; padding: 0 10px; }
      .ldgr-sig-cell { text-align: center; border-top: 1.5px solid #333; padding-top: 6px; font-size: 11px; font-weight: 700; color: #333; }
      /* border accents */
      .ldgr-table-wrap { border-left: 4px solid #1b5e20; border-right: 4px solid #1b5e20; }
    </style>`;

  const monthRowsNew = monthData.map((d, i) => `
    <tr>
      <td>${i+1}</td>
      <td class="ldgr-td-month" style="font-weight:${d.totalLeave>0?'700':'400'};color:${d.totalLeave>0?'#1565c0':'#222'};">${months[i]}</td>
      <td>${d.workDays}</td>
      <td style="color:#2e7d32;font-weight:700;">${d.present}</td>
      <td style="color:${d.cl>0?'#6a1b9a':'#aaa'};font-weight:${d.cl>0?'700':'400'};">${d.cl||'—'}</td>
      <td style="color:${d.el>0?'#1565c0':'#aaa'};font-weight:${d.el>0?'700':'400'};">${d.el||'—'}</td>
      <td style="color:${d.ml>0?'#e65100':'#aaa'};font-weight:${d.ml>0?'700':'400'};">${d.ml||'—'}</td>
      <td style="color:${d.absent>0?'#b71c1c':'#aaa'};font-weight:${d.absent>0?'700':'400'};">${d.absent||'—'}</td>
      <td style="text-align:left;color:#555;font-size:11px;">${records.filter(l=>getMonthIdx(l.fromDate)===i).map(l=>l.reason||'').filter(Boolean).join('; ').slice(0,40)||'—'}</td>
    </tr>`).join('');

  const summaryRowsNew = leaveTypes.map((type, i) => {
    const opening = defaults[type]||10;
    const used = records.filter(l=>l.leaveType===type&&l.status==='Approved').reduce((s,l)=>s+(parseInt(l.daysApproved||l.totalDays)||0),0);
    const closing = Math.max(0, opening - used);
    const clr = used > 0 ? '#b71c1c' : '#aaa';
    return `<tr>
      <td class="ldgr-td-left">${leaveLabels[type]}</td>
      <td>${opening}</td>
      <td>0</td>
      <td style="color:${clr};font-weight:${used>0?'700':'400'};">${used||'—'}</td>
      <td style="color:${closing>0?'#2e7d32':'#aaa'};font-weight:700;">${closing}</td>
      <td style="text-align:left;color:#555;font-size:11px;">${records.filter(l=>l.leaveType===type).map(l=>l.fromDate).join(', ').slice(0,40)||'—'}</td>
    </tr>`;
  }).join('');

  el.innerHTML = wordStyle + `
    <div class="ldgr-wrap">

      <!-- Title Bar -->
      <div class="ldgr-title-bar">
        <div class="ldgr-main-title">${_ldgEn ? 'Annual Leave Ledger' : 'वार्षिक अवकाश खाता &nbsp;/&nbsp; Annual Leave Ledger'}</div>
        <div class="ldgr-sub-title">${_ldgEn ? 'Academic Session: ' : 'शैक्षणिक सत्र / Academic Session : '}${session}</div>
      </div>

      <!-- Staff Info Table -->
      <table class="ldgr-info-table">
        <tr>
          <td class="ldgr-lbl">${_ldgEn ? 'Teacher Name' : 'शिक्षक का नाम'}</td>
          <td style="font-weight:700;color:#1a237e;">${staffName}</td>
          <td class="ldgr-lbl">${_ldgEn ? 'Employee ID' : 'कर्मचारी ID'}</td>
          <td>${staffId}</td>
        </tr>
        <tr>
          <td class="ldgr-lbl">Designation${_ldgEn ? '' : ' / पदनाम'}</td>
          <td>${desig||'—'}</td>
          <td class="ldgr-lbl">${_ldgEn ? 'Total Applications' : 'कुल आवेदन'}</td>
          <td style="font-weight:700;color:#1565c0;">${records.length}</td>
        </tr>
        <tr>
          <td class="ldgr-lbl">${_ldgEn ? 'Dept' : 'विभाग / Dept'}</td>
          <td>${staffRec&&staffRec.dept||'—'}</td>
          <td class="ldgr-lbl">${_ldgEn ? 'Subject' : 'विषय / Subject'}</td>
          <td>${staffRec&&staffRec.subject||'—'}</td>
        </tr>
      </table>

      <!-- Monthly Table -->
      <div class="ldgr-section-head">📅 ${_ldgEn ? "Monthly Attendance &amp; Leave Record" : "मासिक उपस्थिति एवं अवकाश विवरण &nbsp;/&nbsp; Monthly Attendance &amp; Leave Record"}</div>
      <div class="ldgr-table-wrap">
        <table class="ldgr-table">
          <thead>
            <tr>
              <th>${_ldgEn ? 'S.No.' : 'क्र.'}</th>
              <th class="ldgr-th-left">${_ldgEn ? 'Month' : 'माह / Month'}</th>
              <th>${_ldgEn ? 'Working Days' : 'कुल कार्य<br>दिवस'}</th>
              <th>${_ldgEn ? 'Present' : 'उपस्थित<br>Present'}</th>
              <th>CL${_ldgEn ? '' : '<br>आकस्मिक'}</th>
              <th>EL${_ldgEn ? '' : '<br>अर्जित'}</th>
              <th>ML${_ldgEn ? '' : '<br>चिकित्सा'}</th>
              <th>${_ldgEn ? 'Absent' : 'अनुपस्थित<br>Absent'}</th>
              <th class="ldgr-th-left">${_ldgEn ? 'Remarks' : 'टिप्पणी / Remarks'}</th>
            </tr>
          </thead>
          <tbody>${monthRowsNew}</tbody>
          <tfoot>
            <tr>
              <td colspan="2">${_ldgEn ? 'Annual Total' : 'वार्षिक योग / Annual Total'}</td>
              <td>${totals.workDays}</td>
              <td>${totals.present}</td>
              <td>${totals.cl||'—'}</td>
              <td>${totals.el||'—'}</td>
              <td>${totals.ml||'—'}</td>
              <td>${totals.absent||'—'}</td>
              <td></td>
            </tr>
          </tfoot>
        </table>
      </div>

      <!-- Leave Summary Table -->
      <div class="ldgr-section-head">📋 ${_ldgEn ? "Leave Balance Summary" : "अवकाश सारांश &nbsp;/&nbsp; Leave Balance Summary"}</div>
      <div class="ldgr-table-wrap">
        <table class="ldgr-table">
          <thead>
            <tr>
              <th class="ldgr-th-left">${_ldgEn ? 'Leave Type' : 'अवकाश प्रकार / Leave Type'}</th>
              <th>${_ldgEn ? 'Opening Balance' : 'प्रारम्भिक शेष<br>Opening Balance'}</th>
              <th>${_ldgEn ? 'Earned' : 'अर्जित<br>Earned'}</th>
              <th>${_ldgEn ? 'Used' : 'उपभोग<br>Used'}</th>
              <th>${_ldgEn ? 'Closing Balance' : 'समाप्त शेष<br>Closing Balance'}</th>
              <th class="ldgr-th-left">${_ldgEn ? 'Dates' : 'तिथियाँ / Dates'}</th>
            </tr>
          </thead>
          <tbody>${summaryRowsNew}</tbody>
        </table>
      </div>

      <!-- Signature Row -->
      <div class="ldgr-sig-row">
        <div class="ldgr-sig-cell">${_ldgEn ? 'Teacher Signature' : 'शिक्षक के हस्ताक्षर<br>Teacher Signature'}</div>
        <div class="ldgr-sig-cell">${_ldgEn ? 'Office Seal' : 'कार्यालय मुहर<br>Office Seal'}</div>
        <div class="ldgr-sig-cell">${_ldgEn ? 'Principal &amp; Seal' : 'प्राचार्य हस्ताक्षर एवं मुहर<br>Principal &amp; Seal'}</div>
      </div>

    </div>`;
}

function printLedger() {
  const content = document.getElementById('ledgerContent').innerHTML;
  if (!content || content.includes('👆')) return alert('पहले Teacher select करें!');
  const w = window.open('','_blank');
  w.document.write(`<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Annual Leave Ledger</title>
    <style>body{font-family:Arial,sans-serif;padding:20px;font-size:12px;}table{width:100%;border-collapse:collapse;}th,td{border:1px solid #ddd;padding:6px 8px;}th{background:#1a237e;color:#fff;}tr:nth-child(even){background:#f5f5f5;}@media print{body{padding:10px;}}</style>
    </head><body>${content}</body></html>`);
  w.document.close();
  setTimeout(()=>w.print(), 400);
}

