function exportStaffExcel() {
  if (!staffRegistry.length) return alert('No staff records to export!');
  const ed=(s,i,f)=>s.edu&&s.edu[i]?(s.edu[i][f]||''):''
  const data = staffRegistry.map((s,idx) => ({
    'क्र.': idx+1,
    'Staff ID': s.staffId, 'नाम EN': s.nameEn, 'नाम HI': s.nameHi,
    'पिता/पति नाम': s.fatherName, 'माता नाम': s.motherName,
    'DOB': s.dob, 'Gender': s.gender, 'Blood Group': s.blood,
    'Marital': s.marital, 'Religion': s.religion, 'Category': s.cat,
    'Nationality': s.nationality, 'PwD': s.pwd,
    'Aadhaar': s.aadhar, 'PAN': s.pan, 'Samagra ID': s.samagra,
    'Current Address': s.addrCurr, 'Permanent Address': s.addrPerm,
    'District': s.district, 'Tehsil': s.tehsil, 'PIN': s.pin, 'State': s.state,
    'Mobile': s.mobile, 'Alt Mobile': s.mobile2, 'Email': s.email, 'WhatsApp': s.whatsapp,
    '10th Board': ed(s,0,'board'),'10th Year': ed(s,0,'year'),'10th %': ed(s,0,'pct'),'10th Div': ed(s,0,'div'),
    '12th Board': ed(s,1,'board'),'12th Year': ed(s,1,'year'),'12th %': ed(s,1,'pct'),'12th Div': ed(s,1,'div'),
    'Grad Board': ed(s,2,'board'),'Grad Year': ed(s,2,'year'),'Grad %': ed(s,2,'pct'),'Grad Div': ed(s,2,'div'),
    'PG Board': ed(s,3,'board'),'PG Year': ed(s,3,'year'),'PG %': ed(s,3,'pct'),'PG Div': ed(s,3,'div'),
    'B.Ed Board': ed(s,4,'board'),'B.Ed Year': ed(s,4,'year'),'B.Ed %': ed(s,4,'pct'),'B.Ed Div': ed(s,4,'div'),
    'Other Edu Board': ed(s,5,'board'),'Other Year': ed(s,5,'year'),'Other %': ed(s,5,'pct'),
    'Designation': s.desig, 'Cadre': s.cadre, 'Subject': s.subject,
    'Join Date': s.joinDate, 'Service Type': s.serviceType,
    'Posting Date': s.postingDate, 'Posting Year': s.postingYear,
    'Prev School': s.prevSchool, 'Prev Service': s.prevService, 'Total Service': s.totalService,
    'Bank': s.bank, 'Account No': s.account, 'IFSC': s.ifsc, 'Branch': s.branch,
    'Basic Pay': s.basicPay, 'Grade Pay': s.gradePay, 'GPF/NPS': s.gpf,
    'Em Name': s.emName, 'Em Rel': s.emRel, 'Em Mobile': s.emMobile, 'Em Alt': s.emAlt,
    'Saved On': s.savedOn
  }));
  const ws = XLSX.utils.json_to_sheet(data);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, 'Staff Registry');
  XLSX.writeFile(wb, 'Staff_Registry_Full.xlsx');
}

function printF11() {
  const session = '';
  const cls     = 'all';
  const from    = '';
  const to      = '';
  const tabName = {overall:'समग्र शुल्क विवरण', tuition:'ट्यूशन शुल्क विवरण', transport:'परिवहन शुल्क विवरण'}[_f11ActiveTab];
  const tableId = {overall:'f11TableOverall', tuition:'f11TableTuition', transport:'f11TableTransport'}[_f11ActiveTab];
  const tbl     = document.getElementById(tableId);
  if (!tbl) return;
  const w = window.open('', '_blank');
  w.document.write(`<!DOCTYPE html><html><head><meta charset="UTF-8">
    <title>F11 Fee Statement</title>
    <style>
      body{font-family:'Arial',sans-serif;font-size:12px;padding:20px;}
      h2{color:#1a237e;text-align:center;margin-bottom:4px;}
      p{text-align:center;color:#555;margin-bottom:14px;font-size:11px;}
      table{width:100%;border-collapse:collapse;font-size:11px;}
      th{background:#1a237e;color:#fff;padding:7px 8px;text-align:left;}
      td{padding:6px 8px;border-bottom:1px solid #e0e0e0;}
      tfoot td{background:#1a237e;color:#fff;font-weight:700;padding:7px 8px;}
      tr:nth-child(even){background:#f5f8ff;}
      .sig{margin-top:30px;display:flex;gap:60px;font-size:11px;}
      @media print{body{padding:10px;}}
    </style>
  </head><body>
    <h2>📑 फॉर्मेट 11 : ${tabName}</h2>
    <p>सत्र: ${session} | कक्षा: ${cls === 'all' ? 'सभी' : cls} | अवधि: ${from || '—'} से ${to || '—'}</p>
    ${tbl.outerHTML}
    <div class="sig">
      <span>लेखाकार: _______________________</span>
      <span>कक्षाध्यापक: _______________________</span>
      <span>प्राचार्य एवं मुहर: _______________________</span>
    </div>
  </body></html>`);
  w.document.close();
  setTimeout(() => { w.print(); }, 400);
}


