/* ── Secret Tab Toggle: hold Ctrl+Z for 5s to show/hide ── */
(function(){
  var _czTimer=null, _czVisible=false;

  /* IDs of all secret tabs */
  var SECRET_IDS = ['rdrop-conv','rdrop-scheme','rdrop-grading'];

  function setSecretVisible(show){
    SECRET_IDS.forEach(function(id){
      var el=document.getElementById(id);
      if(!el) return;
      el.style.display=show?'':'none';
    });
    _czVisible=show;
  }

  /* Hide on load */
  window.addEventListener('DOMContentLoaded',function(){
    setSecretVisible(false);
  });
  /* Also hide after a short delay in case DOM is late */
  setTimeout(function(){ setSecretVisible(false); },500);

  document.addEventListener('keydown',function(e){
    if(e.ctrlKey && (e.key==='z'||e.key==='Z')){
      e.preventDefault();
      setSecretVisible(!_czVisible);
    }
  });
})();

