  if(typeof renderQRRC === 'function') try{ renderQRRC(); }catch(e){}
  // Merit List (Class 1-8 ML, Class 9/10 ML9, Class 11/12 NB11)
  if(typeof renderML === 'function') try{ renderML(); }catch(e){}
  if(typeof renderML9 === 'function') try{ renderML9(); }catch(e){}
  if(typeof renderNB === 'function') try{ renderNB(); }catch(e){}
  if(typeof renderNB11 === 'function') try{ renderNB11(); }catch(e){}
  // School Register (SR → internally calls SR9/SR11 based on class)
  if(typeof renderSR === 'function') try{ renderSR(); }catch(e){}
  // Marksheet Class 9/10
  if(typeof renderMkSheet9 === 'function') try{ renderMkSheet9(); }catch(e){}
  // Admit Card
  if(typeof renderAC === 'function') try{ renderAC(); }catch(e){}
  // Attendance Register
  if(typeof renderAtt === 'function') try{ renderAtt(); }catch(e){}
  // Transfer Certificate
  if(typeof renderTC === 'function') try{ renderTC(); }catch(e){}
  // Annual Result Sheet
  if(typeof renderRS === 'function') try{ renderRS(); }catch(e){}
  // Co-Scholastic / PSG
  if(typeof renderCC === 'function') try{ renderCC(); }catch(e){}
  // Fail Subject List
  if(typeof renderSL === 'function') try{ renderSL(); }catch(e){}
  // Summary
