function sealHandleDrop(e){
  e.preventDefault();
  document.getElementById('seal-drop-zone').style.background = 'rgba(255,255,255,.06)';
  var file = e.dataTransfer.files[0];
  if(file && file.type.startsWith('image/')) sealHandleFile(file);
}

function sealHandleFile(file){
  if(!file) return;
  var reader = new FileReader();
  reader.onload = function(ev){
    _sealRawData = ev.target.result;
    // Show preview with background removed
    var tmpImg = new Image();
    tmpImg.onload = function(){
      var cleanCanvas = _removeBackground(tmpImg, 600, 300);
      var previewImg = document.getElementById('seal-preview-img');
      previewImg.src = cleanCanvas.toDataURL('image/png');
      document.getElementById('seal-preview-wrap').style.display = 'block';
      document.getElementById('seal-drop-label').innerHTML = '🖼️ <b>'+file.name+'</b> — Background हट गई ✨';
      sealUpdatePreview();
    };
    tmpImg.src = _sealRawData;
    document.getElementById('seal-preview-wrap').style.display = 'block';
    document.getElementById('seal-drop-label').innerHTML = '⏳ Processing...';
  };
  reader.readAsDataURL(file);
}

function sealUpdatePreview(){
  var img = document.getElementById('seal-preview-img');
  if(!img) return;
  img.style.opacity = document.getElementById('seal-opacity').value / 100;
  img.style.maxHeight = document.getElementById('seal-size').value + 'px';
}

function _removeBackground(img, maxW, maxH){
  // Draw image on canvas, then replace near-white/light-grey pixels with transparent
  var w = img.naturalWidth, h = img.naturalHeight;
  if(w > maxW){ h = Math.round(h * maxW / w); w = maxW; }
  if(h > maxH){ w = Math.round(w * maxH / h); h = maxH; }
  var c = document.createElement('canvas');
  c.width = w; c.height = h;
  var ctx = c.getContext('2d');
  ctx.drawImage(img, 0, 0, w, h);
  var imageData = ctx.getImageData(0, 0, w, h);
  var data = imageData.data;
  // Sample corner pixels to detect background color
  var corners = [
    [data[0], data[1], data[2]],                          // top-left
    [data[(w-1)*4], data[(w-1)*4+1], data[(w-1)*4+2]],   // top-right
    [data[(h-1)*w*4], data[(h-1)*w*4+1], data[(h-1)*w*4+2]], // bottom-left
    [data[((h-1)*w+(w-1))*4], data[((h-1)*w+(w-1))*4+1], data[((h-1)*w+(w-1))*4+2]] // bottom-right
  ];
  // Average background color from corners
  var bgR = Math.round((corners[0][0]+corners[1][0]+corners[2][0]+corners[3][0])/4);
  var bgG = Math.round((corners[0][1]+corners[1][1]+corners[2][1]+corners[3][1])/4);
  var bgB = Math.round((corners[0][2]+corners[1][2]+corners[2][2]+corners[3][2])/4);
  // Threshold — pixels within 40 units of background color become transparent
  var threshold = 40;
  for(var i = 0; i < data.length; i += 4){
    var r = data[i], g = data[i+1], b = data[i+2];
    var dr = Math.abs(r - bgR), dg = Math.abs(g - bgG), db = Math.abs(b - bgB);
    if(dr < threshold && dg < threshold && db < threshold){
      data[i+3] = 0; // fully transparent
    }
  }
  ctx.putImageData(imageData, 0, 0);
  return c;
}

function _compressToJpeg(img, opacity, maxW, maxH, quality){
  // Remove background, then draw on white canvas, then compress as JPEG
  var cleanCanvas = _removeBackground(img, maxW, maxH);
  var w = cleanCanvas.width, h = cleanCanvas.height;
  var c = document.createElement('canvas');
  c.width = w; c.height = h;
  var ctx = c.getContext('2d');
  // White background for JPEG
  ctx.fillStyle = '#ffffff';
  ctx.fillRect(0, 0, w, h);
  ctx.globalAlpha = opacity;
  ctx.drawImage(cleanCanvas, 0, 0);
  return c.toDataURL('image/jpeg', quality);
}

function _safeLsSet(key, data){
  // Try JPEG at decreasing quality until it fits in localStorage (~4MB limit)
  var qualities = [0.8, 0.6, 0.45, 0.3];
  // Try the data as-is first
  try { localStorage.setItem(key, data); return true; } catch(e){}
  return false; // caller will handle with compressed version
}

function sealApplySlot(){
  if(!_sealRawData){ alert('पहले image select करें।'); return; }
  var tempImg = new Image();
  tempImg.onload = function(){
    var opacityVal = document.getElementById('seal-opacity').value / 100;
    // Always compress to JPEG — max 400x200px, quality 0.75
    // This keeps signature image small (~30-80KB vs 500KB+ PNG)
    var finalData = _compressToJpeg(tempImg, opacityVal, 400, 200, 0.75);

    var isTeacher = _sealSlot && _sealSlot.indexOf('teacher_') === 0;
    var slotLabel = '';
    var lsKey = '';

    if(isTeacher){
      var cls = _teacherSealClass;
      window[_teacherSealWinKey(cls)] = finalData;
      lsKey = _teacherSealLsKey(cls);
      slotLabel = (_clsLabel[cls]||cls)+' Class Teacher Sign';
    } else {
      var cfg = _sealSlots[_sealSlot];
      window[cfg.winKey] = finalData;
      lsKey = cfg.key;
      slotLabel = cfg.name;
    }

    // Try saving; if still too large, compress more aggressively
    var saved = false;
    var qualities = [0.75, 0.55, 0.4, 0.25];
    var maxSizes = [[400,200],[300,150],[250,120],[200,100]];
    for(var i=0; i<qualities.length; i++){
      var attempt = _compressToJpeg(tempImg, opacityVal, maxSizes[i][0], maxSizes[i][1], qualities[i]);
      try{
        localStorage.setItem(lsKey, attempt);
        smartSave(lsKey, attempt);
        // Update window key with the version that actually saved
        if(isTeacher) window[_teacherSealWinKey(_teacherSealClass)] = attempt;
        else window[_sealSlots[_sealSlot].winKey] = attempt;
        saved = true;
        break;
      }catch(e){ continue; }
    }

    _sealRefreshCards();
    var st = document.getElementById('seal-status');
    st.style.display = 'block';
    if(saved){
      st.textContent = '✅ ' + slotLabel + ' — Report Cards में apply हो गई!';
      // Upload to Cloudinary if enabled
      if(r2Enabled()){
        var schoolId = (currentUser&&(currentUser.username||currentUser.user))||'school';
        var pubId = schoolId+'_'+lsKey.replace('rsk_','');
        var sealData = isTeacher ? window[_teacherSealWinKey(_teacherSealClass)] : window[_sealSlots[_sealSlot].winKey];
        if(sealData){
          r2UploadBase64(sealData, 'rsk_seals', pubId).then(function(url){
            if(url){
              // Store URL instead of base64
              try{ localStorage.setItem(lsKey, url); smartSave(lsKey, url); }catch(e){}
              if(isTeacher) window[_teacherSealWinKey(_teacherSealClass)] = url;
              else window[_sealSlots[_sealSlot].winKey] = url;
              console.log('[SEAL] Cloudinary uploaded: '+url);
            }
          });
        }
      }
    } else {
      st.style.background = 'rgba(220,38,38,.2)';
      st.style.borderColor = '#f87171';
      st.style.color = '#fecaca';
      st.textContent = '⚠️ Image बहुत बड़ी है — छोटी/cleaner image use करें। (Memory full)';
    }
    setTimeout(function(){
      sealCloseUpload();
      if(!isTeacher) closeSealModal();
    }, saved ? 1200 : 2500);
  };
  tempImg.src = _sealRawData;
}

function sealClearSlot(){
  var isTeacher = _sealSlot && _sealSlot.indexOf('teacher_') === 0;
  if(isTeacher){
    var cls = _teacherSealClass;
    window[_teacherSealWinKey(cls)] = null;
    localStorage.removeItem(_teacherSealLsKey(cls));
  } else {
    var cfg = _sealSlots[_sealSlot];
    if(cfg){ window[cfg.winKey] = null; localStorage.removeItem(cfg.key); }
  }
  _sealRawData = null;
  document.getElementById('seal-preview-wrap').style.display = 'none';
  document.getElementById('seal-preview-img').src = '';
  document.getElementById('seal-drop-label').innerHTML = '📁 Click करें या image drag करें<br><span style="font-size:10px;opacity:.65;font-weight:400">PNG / JPG / WebP — transparent background best</span>';
  document.getElementById('seal-status').style.display = 'none';
  _sealRefreshCards();
}

function sealClearAll(){
  if(!confirm('सभी Signatures (Principal, Exam, और सभी Classes की Teacher) हटा दी जाएंगी — confirm करें?')) return;
  Object.keys(_sealSlots).forEach(function(slot){
    var cfg = _sealSlots[slot];
    window[cfg.winKey] = null;
    localStorage.removeItem(cfg.key);
  });
  // Clear all class-wise teacher seals too
  _teacherClasses.forEach(function(cls){
    window[_teacherSealWinKey(cls)] = null;
    localStorage.removeItem(_teacherSealLsKey(cls));
  });
  _sealRawData = null;
  _sealRefreshCards();
  _sealUpdateBadges();
  closeSealModal();
}

// Close modals on backdrop click
document.getElementById('seal-select-modal').addEventListener('click', function(e){
  if(e.target === this) closeSealModal();
});
document.getElementById('seal-upload-modal').addEventListener('click', function(e){
  if(e.target === this){ sealCloseUpload(); }
});
document.getElementById('seal-class-picker-modal').addEventListener('click', function(e){
  if(e.target === this){ sealCloseClassPicker(); }
});


