      (function(){
        window.showSptTab = function(id, btn){
          var sections = ['s1','s2','s3','s4','s5','s6','s7','s8'];
          sections.forEach(function(s){
            var el = document.getElementById('spt-sec-'+s);
            if(el) el.style.display = (s===id)?'block':'none';
          });
          document.querySelectorAll('.spt-tab').forEach(function(b){ b.classList.remove('active','btn-primary'); b.classList.add('btn-outline'); });
          if(btn){ btn.classList.remove('btn-outline'); btn.classList.add('active','btn-primary'); }
        };
        setTimeout(function(){ window.showSptTab('s1', document.querySelector('.spt-tab')); },100);
      })();
      

