      // ══ S1 Dynamic House Management ══
      (function(){
        var _houseColors = [
          {color:'#dc2626', bg:'#fef2f2', label:'🔴 Red',   hex:'#dc2626'},
          {color:'#1d4ed8', bg:'#eff6ff', label:'🔵 Blue',  hex:'#1d4ed8'},
          {color:'#15803d', bg:'#f0fdf4', label:'🟢 Green', hex:'#15803d'},
          {color:'#b45309', bg:'#fefce8', label:'🟡 Yellow',hex:'#b45309'},
          {color:'#7c3aed', bg:'#f5f3ff', label:'🟣 Purple',hex:'#7c3aed'},
          {color:'#0369a1', bg:'#f0f9ff', label:'🩵 Sky',   hex:'#0369a1'}
        ];
        var _defaultNames = ['Shivaji House','Ashok House','Gandhi House','Tagore House','Patel House','Nehru House'];
        function _sptEsc(v){ return (typeof escHtml==='function') ? escHtml(v) : v; }

        // Init house name inputs based on selected count
        window.s1InitHouseInputs = function(){
          var count = parseInt(document.getElementById('s1-house-count').value) || 4;
          var wrap = document.getElementById('s1-house-inputs');
          var existing = wrap.querySelectorAll('.s1-house-card');
          var existingCount = existing.length;

          // Add new cards if count increased
          for(var i=existingCount; i<count; i++){
            var c = _houseColors[i] || _houseColors[0];
            var savedName  = mgmtGetVal('sports','s1','h'+i+'_name');
            var savedColor = mgmtGetVal('sports','s1','h'+i+'_color');
            var savedCnt   = mgmtGetVal('sports','s1','h'+i+'_cnt');
            var nameVal  = (savedName!=='') ? savedName : (_defaultNames[i]||'');
            var colorIdx = (savedColor!=='') ? parseInt(savedColor) : i;
            var cntVal   = (savedCnt!=='') ? savedCnt : '8';
            var card = document.createElement('div');
            card.className = 's1-house-card';
            card.setAttribute('data-idx', i);
            card.style.cssText = 'background:rgba(255,255,255,0.06);border:1.5px solid rgba(255,255,255,0.12);border-radius:10px;padding:10px 12px;display:flex;flex-direction:column;gap:8px;';
            card.innerHTML =
              '<div style="color:#f0c040;font-size:12px;font-weight:700;">House '+(i+1)+'</div>'+
              '<div style="display:flex;gap:8px;align-items:center;">'+
                '<span style="color:#94a3b8;font-size:12px;min-width:42px;">नाम:</span>'+
                '<input class="s1-hname spt-inp" data-idx="'+i+'" placeholder="'+(_defaultNames[i]||'House '+(i+1))+'" value="'+_sptEsc(nameVal)+'" onchange="mgmtSetVal(\'sports\',\'s1\',\'h'+i+'_name\',this.value)" style="flex:1;font-size:13px;font-weight:700;">'+
              '</div>'+
              '<div style="display:flex;gap:8px;align-items:center;">'+
                '<span style="color:#94a3b8;font-size:12px;min-width:42px;">रंग:</span>'+
                '<select class="s1-hcolor spt-inp" data-idx="'+i+'" onchange="mgmtSetVal(\'sports\',\'s1\',\'h'+i+'_color\',this.value)" style="flex:1;font-size:12px;">'+
                  _houseColors.map(function(cl,ci){
                    return '<option value="'+ci+'" '+(ci===colorIdx?'selected':'')+'>'+cl.label+'</option>';
                  }).join('')+
                '</select>'+
              '</div>'+
              '<div style="display:flex;gap:8px;align-items:center;">'+
                '<span style="color:#94a3b8;font-size:12px;min-width:42px;">बच्चे:</span>'+
                '<input class="s1-hcount spt-inp" data-idx="'+i+'" type="number" min="1" max="60" value="'+_sptEsc(cntVal)+'" onchange="mgmtSetVal(\'sports\',\'s1\',\'h'+i+'_cnt\',this.value)" style="width:70px;font-size:13px;font-weight:700;">'+
                '<span style="color:#64748b;font-size:11px;">students</span>'+
              '</div>';
            wrap.appendChild(card);
          }

          // Remove extra cards if count decreased
          var allCards = wrap.querySelectorAll('.s1-house-card');
          for(var j=count; j<allCards.length; j++){
            wrap.removeChild(allCards[j]);
          }
        };

        // Generate house tables
        var _s1Counter = 0, _s1CurHouse = 0;
        function spi(){
          var k='f'+(_s1Counter++);
          var v=mgmtGetVal('sports','s1h'+_s1CurHouse,k);
          return '<input class="spt-inp" style="width:100%" value="'+_sptEsc(v)+'" onchange="mgmtSetVal(\'sports\',\'s1h'+_s1CurHouse+'\',\''+k+'\',this.value)">';
        }
        function spsel(){
          var k='f'+(_s1Counter++);
          var v=mgmtGetVal('sports','s1h'+_s1CurHouse,k);
          var opts=['','M','F'];
          var oh=''; opts.forEach(function(o){ oh+='<option'+(o===v?' selected':'')+'>'+o+'</option>'; });
          return '<select class="spt-inp" style="width:100%" onchange="mgmtSetVal(\'sports\',\'s1h'+_s1CurHouse+'\',\''+k+'\',this.value)">'+oh+'</select>';
        }
        window.s1GenerateHouseTables = function(){
          var count = parseInt(document.getElementById('s1-house-count').value) || 4;
          var nameInputs  = document.querySelectorAll('.s1-hname');
          var colorInputs = document.querySelectorAll('.s1-hcolor');
          var countInputs = document.querySelectorAll('.s1-hcount');
          var output = document.getElementById('s1-houses-output');
          var out = '';

          // Build badge row
          out += '<div style="display:flex;gap:10px;flex-wrap:wrap;margin-bottom:16px;">';

          var houses = [];
          for(var i=0; i<count; i++){
            var nm  = (nameInputs[i]  ? nameInputs[i].value.trim()  : '') || _defaultNames[i] || ('House '+(i+1));
            var ci  = (colorInputs[i] ? parseInt(colorInputs[i].value) : i) % _houseColors.length;
            var cnt = (countInputs[i] ? parseInt(countInputs[i].value) : 8) || 8;
            var col = _houseColors[ci];
            houses.push({name:nm, color:col.color, bg:col.bg, count:cnt, label:col.label});
            out += '<span style="font-size:12px;padding:4px 12px;border-radius:20px;background:'+col.color+';color:#fff;font-weight:700;">'+col.label.split(' ')[0]+' '+nm+'</span>';
          }
          out += '</div>';

          // Build each house table
          houses.forEach(function(h, idx){
            _s1CurHouse = idx; _s1Counter = 0; // per-house field counter for save/restore keys
            out += '<div style="margin-bottom:24px;">';
            out += '<div style="font-weight:800;font-size:13px;color:'+h.color+';padding:8px 14px;background:'+h.bg+';border-left:4px solid '+h.color+';border-radius:6px;margin-bottom:8px;display:flex;justify-content:space-between;align-items:center;">';
            out += '<span>'+(idx+1)+'. '+h.name+'</span>';
            out += '<span style="font-size:11px;opacity:0.8;">Total Students: '+h.count+'</span>';
            out += '</div>';
            out += '<div class="table-wrap"><table><thead><tr>';
            out += '<th style="width:36px">S.N.</th>';
            out += '<th style="width:85px">Enroll No.</th>';
            out += '<th>Student Name / छात्र का नाम</th>';
            out += '<th style="width:60px">Class</th>';
            out += '<th style="width:55px">Gender</th>';
            out += '<th>Sports Speciality</th>';
            out += '</tr></thead><tbody>';
            for(var r=1; r<=h.count; r++){
              out += '<tr>';
              out += '<td style="text-align:center;font-weight:600;">'+r+'</td>';
              out += '<td>'+spi()+'</td>';
              out += '<td>'+spi()+'</td>';
              out += '<td>'+spi()+'</td>';
              out += '<td>'+spsel()+'</td>';
              out += '<td>'+spi()+'</td>';
              out += '</tr>';
            }
            out += '<tr style="background:'+h.bg+';">';
            out += '<td colspan="2" style="font-weight:800;text-align:right;padding-right:10px;color:'+h.color+';">कुल / Total</td>';
            out += '<td colspan="4" style="font-weight:700;color:'+h.color+';">'+h.count+' Students &nbsp;|&nbsp; House: '+h.name+'</td>';
            out += '</tr>';
            out += '</tbody></table></div></div>';
          });

          output.innerHTML = out;
          document.getElementById('s1-setup-msg').textContent = '✅ '+count+' Houses generate हो गए!';
          setTimeout(function(){ document.getElementById('s1-setup-msg').textContent=''; }, 3000);
        };

        // Reset
        window.s1ResetSetup = function(){
          document.getElementById('s1-houses-output').innerHTML='';
          document.getElementById('s1-house-inputs').innerHTML='';
          document.getElementById('s1-house-count').value='4';
          s1InitHouseInputs();
          document.getElementById('s1-setup-msg').textContent='🔄 Reset हो गया!';
          setTimeout(function(){ document.getElementById('s1-setup-msg').textContent=''; }, 2000);
        };

        // Auto-init on load — saved count/names/colors restore karo, phir tables rebuild karo
        window.s1AutoRestore = function s1AutoRestore(){
          var savedCount = mgmtGetVal('sports','s1','count');
          if(savedCount) document.getElementById('s1-house-count').value = savedCount;
          s1InitHouseInputs();
          if(savedCount) s1GenerateHouseTables();
        }
        document.addEventListener('DOMContentLoaded', function(){ s1AutoRestore(); });
        setTimeout(function(){ s1AutoRestore(); }, 300);
      })();
      

