      // ══ S2: Dynamic Sports Schedule ══
      (function(){
        // Default columns definition
        var S2_DEFAULT_COLS = [
          { id:'event',    label:'Event / स्पर्धा',   type:'text',       active:true,  removable:false },
          { id:'category', label:'Category',           type:'select-cat', active:true,  removable:true  },
          { id:'ageLimit', label:'Age Limit',          type:'text',       active:true,  removable:true  },
          { id:'date',     label:'Date',               type:'date',       active:true,  removable:true  },
          { id:'time',     label:'Time',               type:'time',       active:true,  removable:true  },
          { id:'venue',    label:'Venue / स्थान',      type:'text',       active:true,  removable:true  },
          { id:'remarks',  label:'Remarks',            type:'text',       active:false, removable:true  },
        ];

        var S2_DEFAULT_IND_EVENTS  = ['100m Race','200m Race','400m Race','800m Race','Long Jump','High Jump','Shot Put','Discus Throw','Javelin Throw'];
        var S2_DEFAULT_TEAM_EVENTS = ['Cricket','Kabaddi','Kho-Kho','Volleyball','Football','Basketball','Hockey'];

        // State
        var s2Cols = JSON.parse(localStorage.getItem(sessKey('spt_s2_cols')) || 'null');
        if(!s2Cols) s2Cols = JSON.parse(JSON.stringify(S2_DEFAULT_COLS));
        window._s2ColsRef = s2Cols; // expose to S3

        function saveS2Cols(){ localStorage.setItem(sessKey('spt_s2_cols'), JSON.stringify(s2Cols)); window._s2ColsRef = s2Cols; clearTimeout(_s2ColsSaveTimer); _s2ColsSaveTimer=setTimeout(function(){ if(typeof smartSave==='function') smartSave(sessKey('spt_s2_cols'), s2Cols); },700); }
        var _s2ColsSaveTimer=null;
        function getActiveCols(){ return s2Cols.filter(function(c){ return c.active; }); }

        // ── S2 row data persistence: event names + per-column cell values ──
        function s2DataKey(){ return sessKey('spt_s2_data'); }
        function s2LoadData(){ var d=JSON.parse(localStorage.getItem(s2DataKey())||'null'); return d || {ind:[],team:[]}; }
        var _s2Data = s2LoadData();
        var _s2DataSaveTimer=null;
        function s2SaveData(){
          localStorage.setItem(s2DataKey(), JSON.stringify(_s2Data));
          clearTimeout(_s2DataSaveTimer);
          _s2DataSaveTimer=setTimeout(function(){ if(typeof smartSave==='function') smartSave(s2DataKey(), _s2Data); },700);
        }
        // Rebuild _s2Data[type] from the current DOM (called on any cell change / row add / row remove)
        function s2SyncDataFromDOM(type){
          var tbody = document.getElementById('s2-'+type+'-body');
          if(!tbody) return;
          var activeCols = getActiveCols();
          var arr=[];
          tbody.querySelectorAll('tr').forEach(function(tr){
            var tds=tr.querySelectorAll('td');
            var nameInp = tds[1] ? tds[1].querySelector('input') : null;
            var row={name: nameInp?nameInp.value:'', cells:{}};
            activeCols.forEach(function(col,ci){
              if(col.id==='event') return;
              var td=tds[ci+1]; if(!td) return;
              var el=td.querySelector('input,select');
              if(el) row.cells[col.id]=el.value;
            });
            arr.push(row);
          });
          _s2Data[type]=arr;
          s2SaveData();
        }

        // ── Build column toggle buttons ──
        function buildColToggles(){
          var wrap = document.getElementById('s2-col-toggles');
          if(!wrap) return;
          wrap.innerHTML = '';
          s2Cols.forEach(function(col, idx){
            var btn = document.createElement('button');
            btn.style.cssText = 'padding:5px 12px;border-radius:20px;font-size:11px;font-weight:700;cursor:pointer;border:1.5px solid;display:flex;align-items:center;gap:5px;transition:all 0.2s;';
            if(col.active){
              btn.style.background='#16a34a'; btn.style.color='#fff'; btn.style.borderColor='#15803d';
              btn.innerHTML = '✓ ' + col.label;
            } else {
              btn.style.background='rgba(255,255,255,0.08)'; btn.style.color='#94a3b8'; btn.style.borderColor='rgba(255,255,255,0.15)';
              btn.innerHTML = '+ ' + col.label;
            }
            // Toggle active
            btn.onclick = function(){
              if(col.removable === false && col.active) return; // Event column can't be hidden
              col.active = !col.active;
              saveS2Cols();
              buildColToggles();
              buildS2Tables();
            };
            // Remove button for removable cols
            if(col.removable && idx >= S2_DEFAULT_COLS.length){ // custom cols only get ✕
              var rm = document.createElement('span');
              rm.textContent = ' ✕';
              rm.style.cssText = 'color:#fca5a5;font-size:11px;font-weight:900;margin-left:2px;';
              rm.onclick = function(e){
                e.stopPropagation();
                s2Cols.splice(idx,1);
                saveS2Cols();
                buildColToggles();
                buildS2Tables();
              };
              btn.appendChild(rm);
            }
            wrap.appendChild(btn);
          });
        }

        // ── Build table head ──
        function buildHead(headEl){
          var activeCols = getActiveCols();
          var tr = '<tr><th style="width:32px;text-align:center;">S.N.</th>';
          activeCols.forEach(function(col){
            var w = col.id==='event'?'170px':col.id==='date'||col.id==='time'?'90px':col.id==='ageLimit'?'80px':'';
            tr += '<th' + (w?' style="width:'+w+'"':'') + '>' + col.label + '</th>';
          });
          tr += '<th style="width:36px;text-align:center;" class="no-print">✕</th></tr>';
          headEl.innerHTML = tr;
        }

        // ── Build a single data row ──
        function buildRow(tbodyEl, eventName, rowIdx, type){
          var activeCols = getActiveCols();
          var savedRow = (_s2Data[type] && _s2Data[type][rowIdx]) || null;
          var tr = document.createElement('tr');
          tr.setAttribute('data-row', rowIdx);

          // S.N.
          var tdSn = document.createElement('td');
          tdSn.style.textAlign='center'; tdSn.style.fontWeight='700';
          tdSn.textContent = rowIdx+1;
          tr.appendChild(tdSn);

          activeCols.forEach(function(col){
            var td = document.createElement('td');
            var cv = (savedRow && savedRow.cells) ? (savedRow.cells[col.id]||'') : '';
            if(col.type === 'select-cat'){
              td.innerHTML = '<select class="spt-inp" style="width:100%"><option'+(cv==='Boys'?' selected':'')+'>Boys</option><option'+(cv==='Girls'?' selected':'')+'>Girls</option><option'+(cv==='Both'?' selected':'')+'>Both</option></select>';
            } else if(col.type === 'date'){
              td.innerHTML = '<input class="spt-inp" type="date" style="width:100%" value="'+cv+'">';
            } else if(col.type === 'time'){
              td.innerHTML = '<input class="spt-inp" type="time" style="width:100%" value="'+cv+'">';
            } else if(col.type === 'number'){
              td.innerHTML = '<input class="spt-inp" type="number" style="width:100%" value="'+cv+'">';
            } else {
              var val = (col.id==='event') ? (eventName || (savedRow ? savedRow.name : '') || '') : cv;
              td.innerHTML = '<input class="spt-inp" style="width:100%" value="'+val+'"' + (col.id==='event'?' style="font-weight:700;width:100%"':'style="width:100%"') + '>';
            }
            tr.appendChild(td);
          });

          // Delete row button
          var tdDel = document.createElement('td');
          tdDel.className = 'no-print';
          tdDel.style.textAlign='center';
          var delBtn = document.createElement('button');
          delBtn.textContent = '✕';
          delBtn.style.cssText = 'background:none;border:none;color:#ef4444;font-size:14px;cursor:pointer;font-weight:900;padding:0;line-height:1;';
          delBtn.onclick = function(){ tr.remove(); renumberRows(tbodyEl); s2SyncDataFromDOM(type); };
          tdDel.appendChild(delBtn);
          tr.appendChild(tdDel);

          tbodyEl.appendChild(tr);
        }

        function renumberRows(tbody){
          var rows = tbody.querySelectorAll('tr');
          rows.forEach(function(r,i){ var sn=r.querySelector('td:first-child'); if(sn) sn.textContent=i+1; });
        }

        // ── Build full tables ──
        var _s2ListenersBound = false;
        function buildS2Tables(){
          var indHead  = document.getElementById('s2-ind-head');
          var indBody  = document.getElementById('s2-ind-body');
          var teamHead = document.getElementById('s2-team-head');
          var teamBody = document.getElementById('s2-team-body');
          if(!indHead) return;

          // Preserve existing event names before rebuild
          var indNames=[], teamNames=[];
          indBody.querySelectorAll('tr').forEach(function(tr){
            var inp = tr.querySelector('td:nth-child(2) input');
            indNames.push(inp ? inp.value : '');
          });
          teamBody.querySelectorAll('tr').forEach(function(tr){
            var inp = tr.querySelector('td:nth-child(2) input');
            teamNames.push(inp ? inp.value : '');
          });

          buildHead(indHead);
          buildHead(teamHead);
          indBody.innerHTML='';
          teamBody.innerHTML='';

          // If first build, derive from saved data (+ defaults for any extra rows)
          if(indNames.length===0){
            var nI = Math.max(S2_DEFAULT_IND_EVENTS.length, _s2Data.ind.length);
            for(var i=0;i<nI;i++) indNames.push((_s2Data.ind[i]&&_s2Data.ind[i].name) || S2_DEFAULT_IND_EVENTS[i] || '');
          }
          if(teamNames.length===0){
            var nT = Math.max(S2_DEFAULT_TEAM_EVENTS.length, _s2Data.team.length);
            for(var t=0;t<nT;t++) teamNames.push((_s2Data.team[t]&&_s2Data.team[t].name) || S2_DEFAULT_TEAM_EVENTS[t] || '');
          }

          indNames.forEach(function(e,i){ buildRow(indBody, e, i, 'ind'); });
          teamNames.forEach(function(e,i){ buildRow(teamBody, e, i, 'team'); });

          // Save current state so newly-derived default rows persist too
          s2SyncDataFromDOM('ind');
          s2SyncDataFromDOM('team');

          // Bind delegated change listeners once — persist any cell edit
          if(!_s2ListenersBound){
            indBody.addEventListener('change', function(){ s2SyncDataFromDOM('ind'); });
            teamBody.addEventListener('change', function(){ s2SyncDataFromDOM('team'); });
            _s2ListenersBound = true;
          }
        }

        // ── Public functions ──
        window.s2AddEventRow = function(type){
          var tbody = document.getElementById('s2-'+type+'-body');
          if(!tbody) return;
          var rowCount = tbody.querySelectorAll('tr').length;
          buildRow(tbody, '', rowCount, type);
        };

        window.s2AddCustomCol = function(){
          var nameEl = document.getElementById('s2-custom-col-name');
          var typeEl = document.getElementById('s2-custom-col-type');
          var msgEl  = document.getElementById('s2-col-msg');
          var name = nameEl.value.trim();
          if(!name){ msgEl.textContent='⚠️ Column name likhein!'; setTimeout(function(){ msgEl.textContent=''; },2000); return; }
          // Check duplicate
          if(s2Cols.some(function(c){ return c.label.toLowerCase()===name.toLowerCase(); })){
            msgEl.textContent='⚠️ Already exists!'; setTimeout(function(){ msgEl.textContent=''; },2000); return;
          }
          s2Cols.push({ id:'custom_'+Date.now(), label:name, type:typeEl.value, active:true, removable:true });
          saveS2Cols();
          buildColToggles();
          buildS2Tables();
          nameEl.value='';
          msgEl.textContent='✅ Column added!'; setTimeout(function(){ msgEl.textContent=''; },2000);
        };

        // ── Cross-device sync: reload cols+data from (possibly cloud-refreshed)
        // localStorage and re-render if S2 tab is currently visible ──
        window.s2AutoRestore = function(){
          var freshCols = JSON.parse(localStorage.getItem(sessKey('spt_s2_cols')) || 'null');
          s2Cols = freshCols || JSON.parse(JSON.stringify(S2_DEFAULT_COLS));
          window._s2ColsRef = s2Cols;
          _s2Data = s2LoadData();
          if(document.getElementById('spt-sec-s2') && document.getElementById('spt-sec-s2').style.display !== 'none'){
            buildColToggles();
            buildS2Tables();
          }
        };

        // Auto-fill school/session from schoolInfo if available
        function s2AutoFill(){
          if(typeof schoolInfo !== 'undefined'){
            var schEl = document.getElementById('s2School');
            var sesEl = document.getElementById('s2Session');
            if(schEl && !schEl.value && schoolInfo.name) schEl.value = schoolInfo.name;
            if(sesEl && !sesEl.value && schoolInfo.session) sesEl.value = schoolInfo.session;
          }
        }

        // Populate class dropdown from registry if available
        function s2PopulateClasses(){
          var sel = document.getElementById('s2Class');
          if(!sel) return;
          if(typeof _getAllStudents === 'function'){
            var classes = [...new Set(_getAllStudents().map(function(s){ return s.class; }).filter(Boolean))].sort(_classCmp);
            if(classes.length > 0){
              sel.innerHTML = '<option value="">-- All Classes --</option>' +
                classes.map(function(c){ return '<option>'+c+'</option>'; }).join('') +
                '<option>All Classes</option>';
            }
          }
        }

        // Init on tab show
        var _s2Inited = false;
        var origShowSptTab = window.showSptTab;
        window.showSptTab = function(id, btn){
          if(typeof origShowSptTab === 'function') origShowSptTab(id, btn);
          if(id === 's2'){
            if(!_s2Inited){
              buildColToggles();
              buildS2Tables();
              s2AutoFill();
              s2PopulateClasses();
              _s2Inited = true;
            }
          }
        };

        // Also init if already on s2 tab
        setTimeout(function(){
          if(document.getElementById('spt-sec-s2') && document.getElementById('spt-sec-s2').style.display !== 'none'){
            if(!_s2Inited){ buildColToggles(); buildS2Tables(); s2AutoFill(); s2PopulateClasses(); _s2Inited=true; }
          }
        },300);

      })();
      

// ===================================================================
// BLOCK 25  (originally inline <script> at source line 58250)
// ===================================================================

      (function(){
        function s3DataKey(){ return sessKey('spt_s3_data'); } // cloud-sync key: { eventKey: { eventName, category, date, students:[], teacher } }

        // ── Load saved data ──
        function s3Load(){ return JSON.parse(localStorage.getItem(s3DataKey()) || '{}'); }
        var _s3SaveTimer=null;
        function s3Save(data){
          localStorage.setItem(s3DataKey(), JSON.stringify(data));
          clearTimeout(_s3SaveTimer);
          _s3SaveTimer=setTimeout(function(){ if(typeof smartSave==='function') smartSave(s3DataKey(), data); },700);
        }

        // ── Get S2 active col index by col.id ──
        function s3GetColIndex(colId){
          var cols = window._s2ColsRef;
          if(!cols) return -1;
          var active = cols.filter(function(c){ return c.active; });
          for(var i=0;i<active.length;i++){
            if(active[i].id === colId) return i + 1; // +1 for S.N. td[0]
          }
          return -1;
        }

        // ── Get all events from S2 DOM (with category & date) ──
        function s3GetS2Events(){
          var events = [];
          var catIdx  = s3GetColIndex('category');
          var dateIdx = s3GetColIndex('date');

          function readRows(tbody, type){
            if(!tbody) return;
            tbody.querySelectorAll('tr').forEach(function(tr){
              var tds = tr.querySelectorAll('td');
              var nameInp = tds[1] ? tds[1].querySelector('input') : null;
              if(!nameInp || !nameInp.value.trim()) return;
              var cat = '', date = '';
              if(catIdx >= 1 && tds[catIdx]){
                var cs = tds[catIdx].querySelector('select'); if(cs) cat = cs.value;
              }
              if(dateIdx >= 1 && tds[dateIdx]){
                var di = tds[dateIdx].querySelector('input'); if(di) date = di.value;
              }
              events.push({ name: nameInp.value.trim(), type: type, category: cat, date: date });
            });
          }

          readRows(document.getElementById('s2-ind-body'),  'Individual');
          readRows(document.getElementById('s2-team-body'), 'Team');

          if(events.length === 0){
            ['100m Race','200m Race','400m Race','800m Race','Long Jump','High Jump','Shot Put','Discus Throw','Javelin Throw',
             'Cricket','Kabaddi','Kho-Kho','Volleyball','Football','Basketball','Hockey'].forEach(function(e){
              events.push({ name: e, type: '', category: '', date: '' });
            });
          }
          return events;
        }

        // ── Populate event dropdown ──
        window.s3PopulateEvents = function(){
          var sel = document.getElementById('s3EventSel');
          if(!sel) return;
          var events = s3GetS2Events();
          var current = sel.value;
          sel.innerHTML = '<option value="">-- Event चुनें --</option>';
          events.forEach(function(ev){
            var opt = document.createElement('option');
            opt.value = ev.name;
            opt.textContent = ev.name + (ev.type ? ' (' + ev.type + ')' : '');
            opt.setAttribute('data-cat',  ev.category || '');
            opt.setAttribute('data-date', ev.date     || '');
            sel.appendChild(opt);
          });
          if(current) sel.value = current;
        };

        // ── Auto-fill category & date when event selected ──
        window.s3OnEventChange = function(){
          var sel     = document.getElementById('s3EventSel');
          var catSel  = document.getElementById('s3CatSel');
          var dateInp = document.getElementById('s3DateInp');
          var msgEl   = document.getElementById('s3Msg');
          if(!sel || !sel.value) return;
          var opt  = sel.options[sel.selectedIndex];
          var cat  = opt.getAttribute('data-cat')  || '';
          var date = opt.getAttribute('data-date') || '';
          if(cat  && catSel)  catSel.value  = cat;
          if(date && dateInp) dateInp.value = date;
          if((cat || date) && msgEl){
            msgEl.style.color = '#86efac';
            msgEl.textContent = '\u2705 S2 se auto-fill: ' + (cat ? 'Category "' + cat + '"' : '') + (cat && date ? ', ' : '') + (date ? 'Date "' + date + '"' : '');
            setTimeout(function(){ msgEl.textContent=''; }, 3000);
          }
        };

        // ── Generate entry table ──
        window.s3GenerateTable = function(){
          var eventName = document.getElementById('s3EventSel').value.trim();
          var cat       = document.getElementById('s3CatSel').value;
          var date      = document.getElementById('s3DateInp').value;
          var count     = parseInt(document.getElementById('s3CountInp').value) || 20;
          var msg       = document.getElementById('s3Msg');

          if(!eventName){ msg.style.color='#fca5a5'; msg.textContent='⚠️ पहले Event चुनें!'; setTimeout(function(){ msg.textContent=''; },2500); return; }
          if(count < 1 || count > 200){ msg.style.color='#fca5a5'; msg.textContent='⚠️ 1–200 के बीच संख्या दें।'; setTimeout(function(){ msg.textContent=''; },2500); return; }

          // Check if this event+cat combo has saved data — prefill if yes
          var data = s3Load();
          var key  = eventName + '||' + cat;
          var saved = data[key];

          var tbody = document.getElementById('s3EntryBody');
          tbody.innerHTML = '';

          // Houses from S1 or default
          var houses = s3GetHouses();

          for(var i = 0; i < count; i++){
            var savedRow = (saved && saved.students && saved.students[i]) ? saved.students[i] : null;
            var tr = document.createElement('tr');
            tr.innerHTML =
              '<td style="text-align:center;font-weight:700;color:#7c3aed;">' + (i+1) + '</td>' +
              '<td><input class="spt-inp" style="width:100%;" value="' + (savedRow ? _esc(savedRow.admNo||'') : '') + '"></td>' +
              '<td><input class="spt-inp" style="width:100%;font-weight:600;" value="' + (savedRow ? _esc(savedRow.name||'') : '') + '"></td>' +
              '<td><input class="spt-inp" style="width:100%;" value="' + (savedRow ? _esc(savedRow.cls||'') : '') + '"></td>' +
              '<td><select class="spt-inp" style="width:100%;">' + houses.map(function(h){ return '<option' + (savedRow && savedRow.house===h?' selected':'') + '>' + h + '</option>'; }).join('') + '</select></td>' +
              '<td style="text-align:center;"><select class="spt-inp" style="width:100%;text-align:center;">' +
                '<option value=""' + (!savedRow||!savedRow.part?' selected':'') + '></option>' +
                '<option value="✓"' + (savedRow&&savedRow.part==="✓"?' selected':'') + '>✓</option>' +
                '<option value="✗"' + (savedRow&&savedRow.part==="✗"?' selected':'') + '>✗</option>' +
              '</select></td>' +
              '<td></td>';
            tbody.appendChild(tr);
          }

          // Update participant count live
          tbody.addEventListener('change', s3UpdateCount);
          s3UpdateCount();

          // Title
          document.getElementById('s3TableTitle').textContent = '🏅 ' + eventName + ' — ' + cat + (date ? ' | ' + date : '');
          document.getElementById('s3TableArea').style.display = '';
          if(saved && saved.teacher) document.getElementById('s3Teacher').value = saved.teacher;
          document.getElementById('s3DateInp').value = date || (saved && saved.date ? saved.date : '');
          msg.style.color='#86efac'; msg.textContent='✅ Table ready! Data fill करें फिर Save करें।';
          setTimeout(function(){ msg.textContent=''; }, 3000);
        };

        function _esc(s){ return String(s).replace(/"/g,'&quot;').replace(/</g,'&lt;'); }

        function s3UpdateCount(){
          var count = 0;
          document.querySelectorAll('#s3EntryBody tr').forEach(function(tr){
            var sel = tr.querySelectorAll('td')[5];
            if(sel && sel.querySelector('select') && sel.querySelector('select').value === '✓') count++;
          });
          var el = document.getElementById('s3TotalCount');
          if(el) el.textContent = count;
        }

        // Get houses from S1 or fallback
        function s3GetHouses(){
          var h1 = document.getElementById('spt-house-name-1');
          if(h1 && h1.value){
            var houses = [];
                      var _f8bn = (window._rskRC&&window._rskRC.f8b)||4;
          h+='<div style="display:flex;align-items:center;gap:8px;margin:6px 0 8px;background:#f8faff;padding:6px 12px;border-radius:8px">';
          h+='<span style="font-size:12px;font-weight:700;color:#dc2626">'+(en?'Improvements:':'सुधार:')+'</span>';
          h+='<input id="rc-f8b" type="number" min="1" max="500" value="'+_f8bn+'" style="width:60px;padding:3px 6px;border:1.5px solid #dc2626;border-radius:6px;font-size:13px;font-weight:800;text-align:center">';
          h+='<button onclick="(function(){window._rskRC=window._rskRC||{};window._rskRC.f8b=parseInt(document.getElementById(\'rc-f8b\').value)||4;renderFuncSection(\'f8\');})()" style="background:#dc2626;color:#fff;border:none;padding:4px 12px;border-radius:6px;font-size:12px;font-weight:700;cursor:pointer">Build ▶</button>';
          h+='</div>';
          for(var i=1;i<=_f8bn;i++){
              var el = document.getElementById('spt-house-name-'+i);
              if(el && el.value.trim()) houses.push(el.value.trim());
            }
            if(houses.length > 0) return [''].concat(houses);
          }
          return ['','Shivaji','Ashok','Gandhi','Tagore'];
        }

        // ── Save list ──
        window.s3SaveList = function(){
          var eventName = document.getElementById('s3EventSel').value.trim();
          var cat       = document.getElementById('s3CatSel').value;
          var date      = document.getElementById('s3DateInp').value;
          var teacher   = document.getElementById('s3Teacher').value;
          if(!eventName){ alert('Event चुनें पहले।'); return; }

          var students = [];
          document.querySelectorAll('#s3EntryBody tr').forEach(function(tr){
            var tds = tr.querySelectorAll('td');
            students.push({
              admNo: tds[1] ? (tds[1].querySelector('input')||{}).value||'' : '',
              name:  tds[2] ? (tds[2].querySelector('input')||{}).value||'' : '',
              cls:   tds[3] ? (tds[3].querySelector('input')||{}).value||'' : '',
              house: tds[4] ? (tds[4].querySelector('select')||{}).value||'' : '',
              part:  tds[5] ? (tds[5].querySelector('select')||{}).value||'' : ''
            });
          });

          var data = s3Load();
          var key  = eventName + '||' + cat;
          data[key] = { eventName: eventName, category: cat, date: date, teacher: teacher, students: students, savedAt: new Date().toLocaleString('en-IN') };
          s3Save(data);

          // Hide entry area, refresh lists
          document.getElementById('s3TableArea').style.display = 'none';
          var msg = document.getElementById('s3Msg');
          msg.style.color='#86efac'; msg.textContent='✅ List save हो गई!';
          setTimeout(function(){ msg.textContent=''; }, 2500);
          s3RenderSavedLists();
        };

        window.s3CancelEntry = function(){
          document.getElementById('s3TableArea').style.display = 'none';
          document.getElementById('s3EntryBody').innerHTML = '';
        };

        // ── Delete a saved list ──
        window.s3DeleteList = function(key){
          if(!confirm('इस list को delete करें?\n' + key)) return;
          var data = s3Load();
          delete data[key];
          s3Save(data);
          s3RenderSavedLists();
        };

        // ── Edit a saved list ──
        window.s3EditList = function(key){
          var data = s3Load();
          var rec  = data[key];
          if(!rec) return;
          // Pre-fill form
          document.getElementById('s3EventSel').value  = rec.eventName || '';
          document.getElementById('s3CatSel').value    = rec.category  || 'Boys';
          document.getElementById('s3DateInp').value   = rec.date      || '';
          document.getElementById('s3CountInp').value  = rec.students  ? rec.students.length : 20;
          s3GenerateTable();
        };

        // ── Render all saved lists ──
        window.s3RenderSavedLists = function(){
          var container = document.getElementById('s3SavedLists');
          if(!container) return;
          var data = s3Load();
          var keys = Object.keys(data);
          if(!keys.length){
            container.innerHTML = '<div style="text-align:center;padding:20px;color:#94a3b8;font-size:13px;">अभी कोई list save नहीं हुई। ऊपर event चुनकर table बनाएं।</div>';
            return;
          }

          var html = '';
          keys.forEach(function(key){
            var rec = data[key];
            var students = rec.students || [];
            var participated = students.filter(function(s){ return s.part === '✓'; }).length;
            var total = students.filter(function(s){ return s.name && s.name.trim(); }).length;

            html += '<div style="margin-bottom:22px;border:1.5px solid #e2e8f0;border-radius:10px;overflow:hidden;">';
            // Header bar
            html += '<div style="background:linear-gradient(135deg,#1a237e,#283593);color:#fff;padding:10px 16px;display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px;">';
            html += '<div><span style="font-size:14px;font-weight:800;">🏅 ' + _escH(rec.eventName) + '</span>';
            html += '<span style="margin-left:10px;background:rgba(255,255,255,0.15);padding:2px 10px;border-radius:12px;font-size:11px;font-weight:700;">' + _escH(rec.category) + '</span>';
            if(rec.date) html += '<span style="margin-left:8px;font-size:11px;color:#c5cae9;">📅 ' + rec.date + '</span>';
            html += '</div>';
            html += '<div style="display:flex;gap:6px;">';
            html += '<button onclick="s3EditList(' + JSON.stringify(key) + ')" style="background:#f0c040;color:#1a1a1a;border:none;border-radius:5px;padding:4px 12px;font-size:11px;font-weight:800;cursor:pointer;">✏️ Edit</button>';
            html += '<button onclick="s3DeleteList(' + JSON.stringify(key) + ')" style="background:#ef4444;color:#fff;border:none;border-radius:5px;padding:4px 12px;font-size:11px;font-weight:700;cursor:pointer;">🗑️ Delete</button>';
            html += '</div></div>';

            // Stats bar
            html += '<div style="background:#f8faff;padding:8px 16px;font-size:12px;display:flex;gap:16px;flex-wrap:wrap;border-bottom:1px solid #e2e8f0;">';
            html += '<span>👥 Total Entries: <b>' + students.length + '</b></span>';
            html += '<span style="color:#16a34a;">✓ Participated: <b>' + participated + '</b></span>';
            html += '<span style="color:#dc2626;">✗ Absent: <b>' + (total - participated) + '</b></span>';
            if(rec.teacher) html += '<span style="color:#555;">🏫 Teacher: <b>' + _escH(rec.teacher) + '</b></span>';
            if(rec.savedAt) html += '<span style="color:#94a3b8;font-size:11px;">Saved: ' + rec.savedAt + '</span>';
            html += '</div>';

            // Table
            html += '<div style="overflow-x:auto;"><table style="font-size:11px;width:100%;border-collapse:collapse;">';
            html += '<thead><tr style="background:#e8eaf6;">';
            html += '<th style="padding:6px 8px;text-align:center;width:36px;">S.N.</th>';
            html += '<th style="padding:6px 8px;width:80px;">Enroll No.</th>';
            html += '<th style="padding:6px 8px;">Student Name</th>';
            html += '<th style="padding:6px 8px;width:60px;">Class</th>';
            html += '<th style="padding:6px 8px;width:85px;">House</th>';
            html += '<th style="padding:6px 8px;width:80px;text-align:center;">Participation</th>';
            html += '</tr></thead><tbody>';

            students.forEach(function(s, idx){
              var isParticipated = s.part === '✓';
              var isAbsent = s.part === '✗';
              var rowBg = isParticipated ? 'background:#f0fdf4;' : (isAbsent ? 'background:#fff8f8;' : '');
              html += '<tr style="' + rowBg + '">';
              html += '<td style="padding:5px 8px;text-align:center;color:#7c3aed;font-weight:700;">' + (idx+1) + '</td>';
              html += '<td style="padding:5px 8px;">' + _escH(s.admNo||'') + '</td>';
              html += '<td style="padding:5px 8px;font-weight:600;">' + _escH(s.name||'') + '</td>';
              html += '<td style="padding:5px 8px;text-align:center;">' + _escH(s.cls||'') + '</td>';
              html += '<td style="padding:5px 8px;">' + _escH(s.house||'') + '</td>';
              html += '<td style="padding:5px 8px;text-align:center;font-size:14px;">' + (isParticipated ? '<span style="color:#16a34a;font-weight:800;">✓</span>' : (isAbsent ? '<span style="color:#dc2626;font-weight:800;">✗</span>' : '—')) + '</td>';
              html += '</tr>';
            });

            html += '</tbody></table></div>';
            html += '</div>'; // end card
          });

          container.innerHTML = html;
        };

        function _escH(s){ return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

        // ── Cross-device sync: re-render saved lists + event dropdown if S3 tab visible ──
        window.s3AutoRestore = function(){
          if(document.getElementById('spt-sec-s3') && document.getElementById('spt-sec-s3').style.display !== 'none'){
            s3PopulateEvents();
            s3RenderSavedLists();
          }
        };

        // ── Init on S3 tab open ──
        var origShowSptTabS3 = window.showSptTab;
        window.showSptTab = function(id, btn){
          if(typeof origShowSptTabS3 === 'function') origShowSptTabS3(id, btn);
          if(id === 's3'){
            s3PopulateEvents();
            s3RenderSavedLists();
            // Set today's date
            var di = document.getElementById('s3DateInp');
            if(di && !di.value) di.value = new Date().toISOString().split('T')[0];
          }
          if(id === 's4'){
            if(typeof _srsLoadS2Events === 'function') _srsLoadS2Events();
          }
          if(id === 's5'){
            if(typeof _s5LoadEvents === 'function') _s5LoadEvents();
          }
          if(id === 's6'){
            if(typeof _s6LoadEvents === 'function') _s6LoadEvents();
          }
          if(id === 's8'){
            if(typeof _s8LoadEvents === 'function') _s8LoadEvents();
          }
        };

      })();
      

