          (function(){
            // ── Load events from S2 into dropdown ──
            window._srsLoadS2Events = function(){
              var sel = document.getElementById('srs-event-name');
              if(!sel) return;
              var current = sel.value;
              sel.innerHTML = '<option value="">-- Select Event --</option>';
              // Get S2 events via s3GetS2Events if available (same function S3 uses)
              var events = [];
              if(typeof s3GetS2Events === 'function'){
                events = s3GetS2Events();
              } else {
                // Fallback: read directly from S2 bodies
                var allBodies = [document.getElementById('s2-ind-body'), document.getElementById('s2-team-body')];
                allBodies.forEach(function(body){
                  if(!body) return;
                  body.querySelectorAll('tr').forEach(function(tr){
                    var tds = tr.querySelectorAll('td');
                    if(!tds.length) return;
                    var inp = tds[0] && tds[0].querySelector('input');
                    if(inp && inp.value.trim()){
                      var dateInp = null, timeInp = null, catSel = null;
                      tds.forEach(function(td){
                        var i = td.querySelector('input[type=date]'); if(i) dateInp = i;
                        var t = td.querySelector('input[type=time]'); if(t) timeInp = t;
                        var s = td.querySelector('select'); if(s) catSel = s;
                      });
                      events.push({
                        name: inp.value.trim(),
                        date: dateInp ? dateInp.value : '',
                        time: timeInp ? timeInp.value : '',
                        category: catSel ? catSel.value : ''
                      });
                    }
                  });
                });
              }
              if(!events.length){
                // Default fallback
                ['100m Race','200m Race','400m Race','Long Jump','High Jump','Shot Put','Cricket','Kabaddi','Kho-Kho','Volleyball','Football','Basketball','Hockey'].forEach(function(e){
                  events.push({name:e,date:'',time:'',category:''});
                });
              }
              events.forEach(function(ev){
                var opt = document.createElement('option');
                opt.value = ev.name;
                opt.textContent = ev.name;
                opt.setAttribute('data-date', ev.date||'');
                opt.setAttribute('data-time', ev.time||'');
                opt.setAttribute('data-cat',  ev.category||'');
                sel.appendChild(opt);
              });
              if(current) sel.value = current;
            };

            // ── Auto-fill date/time/category from S2 when event selected ──
            window._srsAutoFillFromS2 = function(){
              var sel = document.getElementById('srs-event-name');
              if(!sel) return;
              var opt = sel.options[sel.selectedIndex];
              if(!opt || !opt.value) return;
              var date = opt.getAttribute('data-date')||'';
              var time = opt.getAttribute('data-time')||'';
              var cat  = opt.getAttribute('data-cat') ||'';
              var dEl = document.getElementById('srs-date');
              var tEl = document.getElementById('srs-time');
              var cEl = document.getElementById('srs-category');
              if(dEl && date) dEl.value = date;
              if(tEl && time) tEl.value = time;
              if(cEl && cat){
                for(var i=0;i<cEl.options.length;i++){
                  if(cEl.options[i].value===cat||cEl.options[i].text===cat){ cEl.selectedIndex=i; break; }
                }
              }
              // Rebuild Table B based on event name (sport type detection)
              _srsRebuildB();
            };

            // ── Build Table A ──
            window._srsRebuildA = function(){
              var n = parseInt(document.getElementById('srs-winners-count').value)||10;
              if(n<1) n=1; if(n>100) n=100;
              var tbody = document.getElementById('srs-tbody-a');
              if(!tbody) return;
              var out='';
              for(var i=1;i<=n;i++){
                out+='<tr><td style="text-align:center">'+i+'</td>';
                out+='<td><input class="spt-inp" style="width:100%"></td>';
                out+='<td><input class="spt-inp" style="width:100%"></td>';
                out+='<td><input class="spt-inp" style="width:100%"></td>';
                out+='<td><select class="spt-inp" style="width:100%"><option></option><option>Shivaji</option><option>Ashok</option><option>Gandhi</option><option>Tagore</option></select></td>';
                out+='<td><input class="spt-inp" style="width:100%"></td>';
                out+='<td><select class="spt-inp" style="width:100%"><option></option><option>1st 🥇</option><option>2nd 🥈</option><option>3rd 🥉</option><option>Part.</option></select></td>';
                out+='<td><input class="spt-inp" style="width:100%" type="number" min="0"></td></tr>';
              }
              out+='<tr style="background:#fefce8"><td colspan="2" style="font-weight:800;text-align:center;font-size:13px">Medal Winners</td>';
              out+='<td colspan="2" style="font-weight:700">🥇 Gold: <input class="spt-inp" style="width:120px"></td>';
              out+='<td colspan="2" style="font-weight:700">🥈 Silver: <input class="spt-inp" style="width:120px"></td>';
              out+='<td colspan="2" style="font-weight:700">🥉 Bronze: <input class="spt-inp" style="width:120px"></td></tr>';
              tbody.innerHTML = out;
            };

            // ── Build Table B (sport-specific columns based on event name) ──
            window._srsRebuildB = function(){
              var evName = ((document.getElementById('srs-event-name')||{}).value||'').toLowerCase();
              var sport = 'general';
              if(/cricket/.test(evName)) sport='cricket';
              else if(/football|soccer/.test(evName)) sport='football';
              else if(/volleyball/.test(evName)) sport='volleyball';
              else if(/kabaddi/.test(evName)) sport='kabaddi';
              else if(/kho/.test(evName)) sport='kho-kho';
              else if(/basketball/.test(evName)) sport='basketball';
              else if(/hockey/.test(evName)) sport='hockey';
              else if(/badminton/.test(evName)) sport='badminton';
              var wrap = document.getElementById('srs-table-b-wrap');
              if(!wrap) return;

              // Sport → columns config
              var cols = {
                cricket:    [{l:'Overs'},{l:'Runs'},{l:'Wickets'},{l:'Extras'},{l:'Total'}],
                football:   [{l:'1st Half'},{l:'2nd Half'},{l:'Extra Time'},{l:'Total Goals'}],
                volleyball: [{l:'Set 1'},{l:'Set 2'},{l:'Set 3'},{l:'Total Sets Won'}],
                kabaddi:    [{l:'1st Half'},{l:'2nd Half'},{l:'Total Points'}],
                'kho-kho':  [{l:'1st Innings'},{l:'2nd Innings'},{l:'Total Points'}],
                basketball: [{l:'Q1'},{l:'Q2'},{l:'Q3'},{l:'Q4'},{l:'Total'}],
                hockey:     [{l:'1st Half'},{l:'2nd Half'},{l:'Extra Time'},{l:'Total Goals'}],
                badminton:  [{l:'Game 1'},{l:'Game 2'},{l:'Game 3'},{l:'Total Games Won'}],
                general:    [{l:'Score 1'},{l:'Score 2'},{l:'Total'}]
              };
              var sportCols = cols[sport]||cols.general;

              var thCols = sportCols.map(function(c){ return '<th>'+c.l+'</th>'; }).join('');
              var tdCols = sportCols.map(function(){ return '<td><input class="spt-inp" style="width:100%"></td>'; }).join('');

              var colCount = 2 + sportCols.length + 1; // Team + cols + W/L/D

              var html = '<table><thead><tr><th style="min-width:150px">Team</th>'+thCols+'<th style="width:70px">Result<br>W/L/D</th></tr></thead><tbody>';
              html += '<tr><td><select class="spt-inp" style="width:100%"><option>Shivaji House</option><option>Ashok House</option><option>Gandhi House</option><option>Tagore House</option></select></td>'+tdCols+'<td><select class="spt-inp" style="width:100%"><option></option><option>W</option><option>L</option><option>D</option></select></td></tr>';
              html += '<tr><td><select class="spt-inp" style="width:100%"><option>Ashok House</option><option>Shivaji House</option><option>Gandhi House</option><option>Tagore House</option></select></td>'+tdCols+'<td><select class="spt-inp" style="width:100%"><option></option><option>W</option><option>L</option><option>D</option></select></td></tr>';
              html += '<tr style="background:#f8fafc"><td colspan="2" style="font-weight:700">Referee: <input class="spt-inp" style="width:160px"></td><td colspan="'+(colCount-2)+'" style="font-weight:700">Signature: <input class="spt-inp" style="width:160px"></td></tr>';
              html += '</tbody></table>';
              wrap.innerHTML = html;
            };

            // ── Init on load ──
            _srsLoadS2Events();
            _srsRebuildA();
            _srsRebuildB();
          })();
          

