      (function(){
        // ── Load events from S2 into checkboxes ──
        window._s5LoadEvents = function(){
          var wrap = document.getElementById('s5-event-chks');
          if(!wrap) return;
          var events = [];
          if(typeof s3GetS2Events === 'function'){
            s3GetS2Events().forEach(function(e){ if(e.name) events.push(e.name); });
          }
          if(!events.length){
            ['100m Race','200m Race','400m Race','Long Jump','High Jump','Shot Put',
             'Cricket','Kabaddi','Kho-Kho','Volleyball','Football','Basketball',
             'Hockey','Relay Race','Cultural Program'].forEach(function(e){ events.push(e); });
          }
          // Keep previously checked state
          var prevChecked = {};
          wrap.querySelectorAll('input[type=checkbox]').forEach(function(cb){ prevChecked[cb.value] = cb.checked; });

          wrap.innerHTML = '';
          events.forEach(function(ev){
            var lbl = document.createElement('label');
            lbl.style.cssText = 'display:flex;align-items:center;gap:6px;background:rgba(255,255,255,0.1);border:1.5px solid rgba(255,255,255,0.2);border-radius:20px;padding:5px 12px;cursor:pointer;color:#e2e8f0;font-size:12px;font-weight:600;transition:all 0.15s';
            var cb = document.createElement('input');
            cb.type = 'checkbox';
            cb.value = ev;
            cb.checked = (ev in prevChecked) ? prevChecked[ev] : true; // default: all checked
            cb.style.cssText = 'width:14px;height:14px;cursor:pointer;accent-color:#f59e0b';
            cb.onchange = function(){
              lbl.style.background = cb.checked ? 'rgba(245,158,11,0.25)' : 'rgba(255,255,255,0.08)';
              lbl.style.borderColor = cb.checked ? '#f59e0b' : 'rgba(255,255,255,0.2)';
              lbl.style.color = cb.checked ? '#fde68a' : '#94a3b8';
            };
            if(cb.checked){ lbl.style.background='rgba(245,158,11,0.25)'; lbl.style.borderColor='#f59e0b'; lbl.style.color='#fde68a'; }
            lbl.appendChild(cb);
            lbl.appendChild(document.createTextNode(' '+ev));
            wrap.appendChild(lbl);
          });
        };

        window._s5SelectAll = function(val){
          var wrap = document.getElementById('s5-event-chks');
          if(!wrap) return;
          wrap.querySelectorAll('input[type=checkbox]').forEach(function(cb){
            cb.checked = val;
            cb.onchange();
          });
        };

        // ── Build tally table from selected events ──
        window._s5BuildTable = function(){
          var wrap = document.getElementById('s5-event-chks');
          var tableWrap = document.getElementById('s5-table-wrap');
          var champBar = document.getElementById('s5-champion-bar');
          if(!wrap || !tableWrap) return;
          var selected = [];
          wrap.querySelectorAll('input[type=checkbox]:checked').forEach(function(cb){ selected.push(cb.value); });
          if(!selected.length){
            tableWrap.innerHTML = '<div style="text-align:center;padding:20px;color:#dc2626;font-weight:700">⚠️ Please select at least one event!</div>';
            return;
          }
          var h = '<table><thead><tr>';
          h += '<th>Event</th>';
          h += '<th style="background:#fef2f2;color:#dc2626">Shivaji 🔴</th>';
          h += '<th style="background:#eff6ff;color:#1d4ed8">Ashok 🔵</th>';
          h += '<th style="background:#f0fdf4;color:#15803d">Gandhi 🟢</th>';
          h += '<th style="background:#fefce8;color:#b45309">Tagore 🟡</th>';
          h += '<th>Total</th>';
          h += '</tr></thead><tbody>';

          selected.forEach(function(ev){
            h += '<tr><td style="font-weight:600">'+ev+'</td>';
            for(var c=0;c<4;c++){
              h += '<td><input class="spt-inp s5-pts" type="number" min="0" style="width:60px;text-align:center" oninput="_s5CalcRow(this)"></td>';
            }
            h += '<td class="s5-row-total" style="font-weight:700;text-align:center">—</td></tr>';
          });

          // Grand Total row
          h += '<tr style="background:#1a237e;color:#fff;font-weight:800"><td>Grand Total</td>';
          for(var c=0;c<4;c++) h += '<td style="text-align:center" class="s5-grand-'+c+'">0</td>';
          h += '<td></td></tr>';

          // Rank row
          h += '<tr style="background:#fbbf24;color:#1a237e;font-weight:800"><td>Rank</td>';
          for(var c=0;c<4;c++) h += '<td style="text-align:center" class="s5-rank-'+c+'">—</td>';
          h += '<td></td></tr>';

          h += '</tbody></table>';
          tableWrap.innerHTML = h;
          if(champBar) champBar.style.display = '';

          // Attach input listeners for auto-total
          tableWrap.querySelectorAll('.s5-pts').forEach(function(inp){
            inp.addEventListener('input', function(){ _s5CalcTotals(); });
          });
        };

        // ── Calc row total + grand totals + ranks ──
        window._s5CalcTotals = function(){
          var tableWrap = document.getElementById('s5-table-wrap');
          if(!tableWrap) return;
          var rows = tableWrap.querySelectorAll('tbody tr');
          var colTotals = [0,0,0,0];
          rows.forEach(function(tr){
            var inputs = tr.querySelectorAll('.s5-pts');
            if(!inputs.length) return;
            var rowSum = 0;
            inputs.forEach(function(inp, ci){
              var v = parseFloat(inp.value)||0;
              rowSum += v;
              colTotals[ci] += v;
            });
            var rtd = tr.querySelector('.s5-row-total');
            if(rtd) rtd.textContent = rowSum||'—';
          });
          // Update grand totals
          for(var c=0;c<4;c++){
            var gtd = tableWrap.querySelector('.s5-grand-'+c);
            if(gtd) gtd.textContent = colTotals[c];
          }
          // Compute ranks
          var ranked = colTotals.map(function(v,i){ return {v:v,i:i}; }).sort(function(a,b){ return b.v-a.v; });
          var rankArr = [0,0,0,0];
          ranked.forEach(function(r,ri){ rankArr[r.i] = ri+1; });
          for(var c=0;c<4;c++){
            var rd = tableWrap.querySelector('.s5-rank-'+c);
            if(rd) rd.textContent = rankArr[c] ? (rankArr[c]===1?'🥇 1st':rankArr[c]===2?'🥈 2nd':rankArr[c]===3?'🥉 3rd':rankArr[c]+'th') : '—';
          }
          // Auto-fill champion
          var champInp = document.getElementById('s5-champion');
          if(champInp && ranked[0]){
            var houseNames = ['Shivaji','Ashok','Gandhi','Tagore'];
            champInp.value = ranked[0].v > 0 ? houseNames[ranked[0].i] : '';
          }
        };
        window._s5CalcRow = function(){ _s5CalcTotals(); };

        // Init
        _s5LoadEvents();
      })();
      

