        var _activeCalTab='k1';
        var _calCounter = 0; // per-section field counter for save/restore keys

        function buildTabBar(){
          var en=calEN(), bar=document.getElementById('calTabs');
          if(!bar) return; bar.innerHTML='';
          TABS.forEach(function(id){
            var btn=document.createElement('button');
            btn.className='btn btn-sm cal-tab'+(id===_activeCalTab?' btn-primary active':' btn-outline');
            btn.textContent=TAB_LABELS[id][en?'en':'hi'];
            btn.onclick=function(){ showCalTab(id,btn); };
            bar.appendChild(btn);
          });
        }

        window.showCalTab=function(id,btn){
          _activeCalTab=id;
          TABS.forEach(function(s){ var el=document.getElementById('cal-sec-'+s); if(el) el.style.display=(s===id)?'block':'none'; });
          document.querySelectorAll('.cal-tab').forEach(function(b){ b.classList.remove('active','btn-primary'); b.classList.add('btn-outline'); });
          if(btn){ btn.classList.remove('btn-outline'); btn.classList.add('active','btn-primary'); }
          renderCalSection(id);
        };

        window.renderCalMgmt=function(){ buildTabBar(); renderCalSection(_activeCalTab); };

        window.renderCalSection = function renderCalSection(id){
          var en=calEN(), el=document.getElementById('cal-sec-'+id); if(!el) return;
          _calCounter = 0; // reset per-section field counter for stable save/restore keys
          var fn={k1:rK1,k2:rK2,k3:rK3,k4:rK4,k5:rK5,k6:rK6,k7:rK7,k8:rK8,k9:rK9,k10:rK10,k11:rK11}[id];
          if(fn) el.innerHTML=fn(en);
          if(typeof _rskRestoreAllIn==='function') _rskRestoreAllIn(el);
        }

        function _calEsc(v){ return (typeof escHtml==='function') ? escHtml(v) : v; }
        function ci(w,v,ph){
          var k='f'+(_calCounter++);
          var sv=mgmtGetVal('cal',_activeCalTab,k);
          var dv=(sv!=='')?sv:(v!==undefined?v:'');
          return '<input class="cal-inp"'+(w?' style="width:'+w+'"':'')+(dv!==''?' value="'+_calEsc(dv)+'"':'')+(ph?' placeholder="'+ph+'"':'')+' onchange="mgmtSetVal(\'cal\',\''+_activeCalTab+'\',\''+k+'\',this.value)">';
        }
        function cd(){
          var k='f'+(_calCounter++);
          var v=mgmtGetVal('cal',_activeCalTab,k);
          return '<input class="cal-inp" type="date" value="'+_calEsc(v)+'" onchange="mgmtSetVal(\'cal\',\''+_activeCalTab+'\',\''+k+'\',this.value)">';
        }
        function cta(ph){
          var k='f'+(_calCounter++);
          var v=mgmtGetVal('cal',_activeCalTab,k);
          return '<textarea class="cal-inp" style="width:100%;height:60px;resize:vertical;border:1px solid #2e703944;border-radius:4px;padding:6px;font-size:12px;" placeholder="'+(ph||'')+'" onchange="mgmtSetVal(\'cal\',\''+_activeCalTab+'\',\''+k+'\',this.value)">'+_calEsc(v)+'</textarea>';
        }
        function chead(txt){ return '<div style="font-size:12px;font-weight:700;color:#2e7039;margin:14px 0 6px;">'+txt+'</div>'; }
        function cprint(n){ return '<div style="text-align:right;margin-top:14px"><button class="btn btn-outline btn-sm" onclick="rskMgmtPrintPreviewById(\'page-calmgmt\',\'School Calendar\')">👁️ Print Preview '+n+'</button></div>'; }

