(function(){
'use strict';

// ── DEBOUNCE UTILITY ──────────────────────────────────
function debounce(fn, delay){
  var timer = null;
  return function(){
    var args = arguments, ctx = this;
    clearTimeout(timer);
    timer = setTimeout(function(){ fn.apply(ctx, args); }, delay);
  };
}

// ── SEARCH INPUT DEBOUNCE (300ms) ─────────────────────
var _admSearchEl = document.getElementById('admList3Search');
if(_admSearchEl){
  _admSearchEl.removeAttribute('oninput');
  _admSearchEl.addEventListener('input', debounce(function(){
    if(typeof renderAdmList3 === 'function') renderAdmList3();
  }, 300));
}

var _staffSearchEl = document.getElementById('staffSearch');
if(_staffSearchEl){
  _staffSearchEl.removeAttribute('oninput');
  _staffSearchEl.addEventListener('input', debounce(function(){
    if(typeof renderStaffRegistry === 'function') renderStaffRegistry();
  }, 300));
}

var _lvSearchEl = document.getElementById('lvSearch');
if(_lvSearchEl){
  _lvSearchEl.removeAttribute('oninput');
  _lvSearchEl.addEventListener('input', debounce(function(){
    if(typeof renderLeaveRecords === 'function') renderLeaveRecords();
  }, 300));
}

// ── MEMORY LEAK FIX ───────────────────────────────────
var _tabListeners = [];

var _origSwitchTab = window.switchTab;
window.switchTab = function(tab){
  _tabListeners.forEach(function(item){
    try { item.el.removeEventListener(item.evt, item.fn); } catch(e){}
  });
  _tabListeners = [];
  if(typeof _origSwitchTab === 'function') _origSwitchTab(tab);
};

window.addTabListener = function(el, evt, fn){
  if(!el) return;
  el.addEventListener(evt, fn);
  _tabListeners.push({ el: el, evt: evt, fn: fn });
};

console.log('[Debounce+MemFix] v1.0 loaded');
})();

