// ══════════════════════════════════════════════════════
// RSK Vehicle V3/V4/V5/V6 — Save & Restore Fix
// Problem: makeVehRows() was rebuilding blank rows on every
// page load, wiping all typed data. Now data is saved to
// localStorage (and cloud via smartSave) on every input
// change, and restored after rows are created.
// ══════════════════════════════════════════════════════
(function(){

  // ── Storage key helper (school-prefix aware) ──
  function vKey(id){
    return (typeof erpKey==='function') ? erpKey('veh_tbl_'+id) : 'veh_tbl_'+id;
  }

  // ── Save all input values in a tbody to localStorage ──
  function saveTbody(tbodyId){
    var tbody = document.getElementById(tbodyId);
    if(!tbody) return;
    var inputs = tbody.querySelectorAll('input');
    var vals = [];
    inputs.forEach(function(inp){ vals.push(inp.value); });
    var key = vKey(tbodyId);
    try{
      localStorage.setItem(key, JSON.stringify(vals));
      if(typeof smartSave==='function') smartSave(key, vals);
    }catch(e){}
  }

  // ── Restore saved values into tbody inputs ──
  function restoreTbody(tbodyId){
    var tbody = document.getElementById(tbodyId);
    if(!tbody) return;
    var key = vKey(tbodyId);
    var vals = null;
    try{
      var raw = localStorage.getItem(key);
      if(raw) vals = JSON.parse(raw);
    }catch(e){}
    if(!vals || !vals.length) return;
    var inputs = tbody.querySelectorAll('input');
    inputs.forEach(function(inp, i){
      if(i < vals.length && vals[i] !== undefined) inp.value = vals[i];
    });
  }

  // ── Attach change listeners so every keystroke auto-saves ──
  function attachSaveListeners(tbodyId){
    var tbody = document.getElementById(tbodyId);
    if(!tbody) return;
    tbody.querySelectorAll('input').forEach(function(inp){
      inp.addEventListener('input', function(){ saveTbody(tbodyId); });
      inp.addEventListener('change', function(){ saveTbody(tbodyId); });
    });
  }

  // ── Save all V3/V4/V5 header inputs (not in tbody) ──
  function saveHeaderInputs(sectionId){
    var sec = document.getElementById('veh-sec-'+sectionId);
    if(!sec) return;
    // Only save inputs NOT inside a tbody (header/footer fields)
    var allInputs = sec.querySelectorAll('input');
    var tbodyInputs = new Set();
    sec.querySelectorAll('tbody input').forEach(function(el){ tbodyInputs.add(el); });
    var vals = [];
    allInputs.forEach(function(inp){
      if(!tbodyInputs.has(inp)) vals.push(inp.value);
    });
    var key = vKey('hdr_'+sectionId);
    try{
      localStorage.setItem(key, JSON.stringify(vals));
      if(typeof smartSave==='function') smartSave(key, vals);
    }catch(e){}
  }

  function restoreHeaderInputs(sectionId){
    var sec = document.getElementById('veh-sec-'+sectionId);
    if(!sec) return;
    var key = vKey('hdr_'+sectionId);
    var vals = null;
    try{ var raw=localStorage.getItem(key); if(raw) vals=JSON.parse(raw); }catch(e){}
    if(!vals||!vals.length) return;
    var allInputs = sec.querySelectorAll('input');
    var tbodyInputs = new Set();
    sec.querySelectorAll('tbody input').forEach(function(el){ tbodyInputs.add(el); });
    var idx = 0;
    allInputs.forEach(function(inp){
      if(!tbodyInputs.has(inp) && idx < vals.length){
        inp.value = vals[idx++] || '';
      }
    });
  }

  function attachHeaderSaveListeners(sectionId){
    var sec = document.getElementById('veh-sec-'+sectionId);
    if(!sec) return;
    var tbodyInputs = new Set();
    sec.querySelectorAll('tbody input').forEach(function(el){ tbodyInputs.add(el); });
    sec.querySelectorAll('input').forEach(function(inp){
      if(!tbodyInputs.has(inp)){
        inp.addEventListener('input', function(){ saveHeaderInputs(sectionId); });
        inp.addEventListener('change', function(){ saveHeaderInputs(sectionId); });
      }
    });
  }

  // ── Build rows then restore saved data ──
  function makeVehRows(tbodyId, cols, count){
    var tbody = document.getElementById(tbodyId);
    if(!tbody) return;
    var html = '';
    for(var i=1;i<=count;i++){
      html += '<tr>';
      html += '<td style="text-align:center;font-weight:700;">'+i+'</td>';
      for(var c=0;c<cols;c++) html += '<td><input class="veh-inp" style="width:100%;min-width:60px;box-sizing:border-box;"></td>';
      html += '</tr>';
    }
    tbody.innerHTML = html;
    // Restore saved data immediately after creating rows
    restoreTbody(tbodyId);
    // Attach auto-save listeners
    attachSaveListeners(tbodyId);
  }

  // ── Cloud restore helper: pull from cloud then repopulate ──
  async function cloudRestoreTbody(tbodyId){
    var key = vKey(tbodyId);
    try{
      var CF_URL = (typeof CF_WORKER_URL!=='undefined') ? CF_WORKER_URL : '';
      if(!CF_URL) return;
      var headers = (typeof cfGetHeaders==='function') ? cfGetHeaders(false) : {};
      var resp = await fetch(CF_URL+'/general?key='+encodeURIComponent(key), {headers:headers});
      if(!resp.ok) return;
      var data = await resp.json();
      if(data && data.value){
        var dec = (typeof rskDecompress==='function') ? rskDecompress(data.value) : data.value;
        localStorage.setItem(key, dec);
        restoreTbody(tbodyId);
      }
    }catch(e){}
  }

  async function cloudRestoreHeader(sectionId){
    var key = vKey('hdr_'+sectionId);
    try{
      var CF_URL = (typeof CF_WORKER_URL!=='undefined') ? CF_WORKER_URL : '';
      if(!CF_URL) return;
      var headers = (typeof cfGetHeaders==='function') ? cfGetHeaders(false) : {};
      var resp = await fetch(CF_URL+'/general?key='+encodeURIComponent(key), {headers:headers});
      if(!resp.ok) return;
      var data = await resp.json();
      if(data && data.value){
        var dec = (typeof rskDecompress==='function') ? rskDecompress(data.value) : data.value;
        localStorage.setItem(key, dec);
        restoreHeaderInputs(sectionId);
      }
    }catch(e){}
  }

  // ── Run after login is complete (rsk-ready) so erpKey uses correct username ──
  function vehInitTablesAndRestore(){
    // V2 (students table) has its own save/load — keep as before
    (function(){
      var tbody2 = document.getElementById('veh-v2-tbody');
      if(!tbody2) return;
      var html = '';
      for(var i=1;i<=20;i++){
        html += '<tr><td style="text-align:center;font-weight:700;">'+i+'</td>';
        for(var c=0;c<9;c++) html += '<td><input class="veh-inp" style="width:100%;min-width:60px;box-sizing:border-box;"></td>';
        html += '</tr>';
      }
      tbody2.innerHTML = html;
    })();

    // V3, V4, V5 — build rows + restore saved data + attach listeners
    makeVehRows('veh-v3-tbody', 10, 26);
    makeVehRows('veh-v4-tbody', 7, 18);
    makeVehRows('veh-v5-tbody', 7, 12);

    // Restore + attach listeners for header inputs
    ['v3','v4','v5'].forEach(function(sid){
      restoreHeaderInputs(sid);
      attachHeaderSaveListeners(sid);
    });

    // Cloud restore (async) as fallback if localStorage is empty/stale
    ['veh-v3-tbody','veh-v4-tbody','veh-v5-tbody'].forEach(function(id){
      cloudRestoreTbody(id);
    });
    ['v3','v4','v5'].forEach(function(sid){ cloudRestoreHeader(sid); });

    // V6: tbody is dynamic (vehicle-driven), restore session/incharge header
    var v6sec = document.getElementById('veh-sec-v6');
    if(v6sec){
      var v6hdrKey = vKey('hdr_v6');
      try{
        var raw6 = localStorage.getItem(v6hdrKey);
        if(raw6){
          var v6vals = JSON.parse(raw6);
          var sesEl = document.getElementById('v6_session');
          var incEl = document.getElementById('v6_incharge');
          if(sesEl && v6vals[0]!==undefined) sesEl.value = v6vals[0]||'';
          if(incEl && v6vals[1]!==undefined) incEl.value = v6vals[1]||'';
        }
      }catch(e){}
      // Attach save listeners for v6 header inputs
      ['v6_session','v6_incharge'].forEach(function(fldId){
        var el = document.getElementById(fldId);
        if(!el) return;
        el.addEventListener('input', function(){
          try{
            var vals=[
              (document.getElementById('v6_session')||{}).value||'',
              (document.getElementById('v6_incharge')||{}).value||''
            ];
            localStorage.setItem(vKey('hdr_v6'), JSON.stringify(vals));
            if(typeof smartSave==='function') smartSave(vKey('hdr_v6'), vals);
          }catch(e){}
        });
      });
    }
  }

  // ── Wait for rsk-ready (login complete) before building rows ──
  // This ensures erpKey() uses the correct logged-in username,
  // not 'GUEST', so save/restore keys always match.
  var _vehTablesBuilt = false;
  function _vehBuildOnce(){
    if(_vehTablesBuilt) return;
    _vehTablesBuilt = true;
    setTimeout(vehInitTablesAndRestore, 200);
  }
  document.addEventListener('rsk-ready', _vehBuildOnce);
  // Fallback: if already logged in (e.g. page refresh with session), run after DOM ready
  setTimeout(function(){
    if(!_vehTablesBuilt && typeof _activeUserPrefix !== 'undefined' && _activeUserPrefix && _activeUserPrefix !== 'guest'){
      _vehBuildOnce();
    }
  }, 1500);

  // ── Expose save functions globally so Print/Export can trigger a final flush ──
  // ── Expose save functions globally so Print/Export can trigger a final flush ──
  window.vehSaveAllTables = function(){
    ['veh-v3-tbody','veh-v4-tbody','veh-v5-tbody'].forEach(function(id){ saveTbody(id); });
    ['v3','v4','v5'].forEach(function(sid){ saveHeaderInputs(sid); });
  };

})();

