  /**
   * rskMgmtPrintPreview(sectionEl, title)
   * Opens a styled print preview popup for any management section.
   * @param {HTMLElement|string} sectionEl - element or CSS selector of content to print
   * @param {string} title - Title shown in the preview toolbar
   */
  window.rskMgmtPrintPreview = function(sectionEl, title) {
    var el = (typeof sectionEl === 'string') ? document.querySelector(sectionEl) : sectionEl;
    if (!el) { alert('Print section not found!'); return; }

    // Collect all styles from the page
    var styleContent = '';
    document.querySelectorAll('style').forEach(function(s){ styleContent += s.textContent + '\n'; });

    var contentHTML = el.outerHTML;
    var pw = window.open('', '_blank', 'width=1100,height=800,scrollbars=yes,resizable=yes');
    if (!pw) { alert('Popup blocked! कृपया popup allow करें।'); return; }

    pw.document.write('<!DOCTYPE html><html><head><meta charset="UTF-8">');
    pw.document.write('<title>🖨️ Print Preview — ' + (title || 'Management') + '</title>');
    pw.document.write('<style>' + styleContent + '</style>');
    pw.document.write('<style>');
    pw.document.write('*{box-sizing:border-box;}');
    pw.document.write('body{background:#c8c8c8;margin:0;padding:0;font-family:Arial,sans-serif;}');
    pw.document.write('.rsk-pv-toolbar{position:fixed;top:0;left:0;right:0;height:54px;background:linear-gradient(135deg,#0a1628,#1a3a6b);display:flex;align-items:center;gap:10px;padding:0 20px;z-index:9999;box-shadow:0 2px 12px rgba(0,0,0,.5);}');
    pw.document.write('.rsk-pv-toolbar h3{color:#fff;font-size:13px;font-weight:800;margin:0;flex:1;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;}');
    pw.document.write('.rsk-pv-btn{padding:7px 20px;border:none;border-radius:7px;cursor:pointer;font-size:13px;font-weight:800;font-family:inherit;transition:.15s;}');
    pw.document.write('.rsk-pv-btn:hover{filter:brightness(.88);}');
    pw.document.write('.rsk-pv-print{background:#16a34a;color:#fff;}');
    pw.document.write('.rsk-pv-close{background:#dc2626;color:#fff;}');
    pw.document.write('.rsk-pv-body{padding:70px 24px 40px;display:flex;justify-content:center;}');
    pw.document.write('.rsk-pv-sheet{background:#fff;box-shadow:0 4px 24px rgba(0,0,0,.3);border-radius:4px;padding:20px;max-width:1050px;width:100%;}');
    // No-print overrides
    pw.document.write('@media print{');
    pw.document.write('  .rsk-pv-toolbar{display:none!important;}');
    pw.document.write('  body{background:#fff!important;padding:0!important;margin:0!important;}');
    pw.document.write('  .rsk-pv-body{padding:0!important;display:block!important;}');
    pw.document.write('  .rsk-pv-sheet{box-shadow:none!important;border-radius:0!important;padding:6mm!important;max-width:100%!important;}');
    pw.document.write('  .btn-row,.no-print,.rsk-pv-btn{display:none!important;}');
    pw.document.write('}');
    pw.document.write('</style>');
    pw.document.write('</head><body>');
    pw.document.write('<div class="rsk-pv-toolbar">');
    pw.document.write('<h3>👁️ Print Preview — ' + (title || 'Management') + '</h3>');
    pw.document.write('<button class="rsk-pv-btn rsk-pv-print" onclick="window.print()">🖨️ Print / Save PDF</button>');
    pw.document.write('<button class="rsk-pv-btn rsk-pv-close" onclick="window.close()">✕ बंद करें</button>');
    pw.document.write('</div>');
    pw.document.write('<div class="rsk-pv-body"><div class="rsk-pv-sheet">');
    pw.document.write(contentHTML);
    pw.document.write('</div></div></body></html>');
    pw.document.close();
  };

  /**
   * rskMgmtPrintPreviewById(id, title)
   * Convenience wrapper using element ID.
   */
  window.rskMgmtPrintPreviewById = function(id, title) {
    var el = document.getElementById(id);
    window.rskMgmtPrintPreview(el, title);
  };

  /**
   * rskMgmtPrintPreviewSection(sectionId, title)
   * For tabs with sub-sections — finds closest visible form-card inside the section.
   */
  window.rskMgmtPrintPreviewSection = function(sectionId, title) {
    var sec = document.getElementById(sectionId);
    if (!sec) { alert('Section not found: ' + sectionId); return; }
    // Try to find the currently visible content
    var card = sec.querySelector('.form-card');
    window.rskMgmtPrintPreview(card || sec, title);
  };
  

