  (function(){
    'use strict';

    // ── 1. Auto-flush fee data to Cloudflare after any fee save ──
    // Debounce: 20 seconds after last change, then flush
    var _feeAutoFlushTimer = null;
    var _FEE_AUTO_FLUSH_DELAY = 20000; // 20 sec

    function scheduleFeeCloudFlush(source){
      clearTimeout(_feeAutoFlushTimer);
      _feeAutoFlushTimer = setTimeout(function(){
        if(!navigator.onLine) return; // offline — skip, will be queued
        if(typeof gdFlushQueue === 'function' && Object.keys(window._gdPendingQueue||{}).length){
          gdFlushQueue();
          console.log('[FeeSync] Auto-flushed to Cloudflare from:', source);
        }
      }, _FEE_AUTO_FLUSH_DELAY);
    }

    // ── 2. Patch saveFs1() to also trigger cloud flush ──
    document.addEventListener('rsk-ready', function(){
      var _origSaveFs1 = window.saveFs1;
      if(typeof _origSaveFs1 === 'function'){
        window.saveFs1 = function(){
          _origSaveFs1.apply(this, arguments);
          // feeConfig critical hai — 2s mein cloud flush (20s nahi)
          clearTimeout(_feeAutoFlushTimer);
          _feeAutoFlushTimer = setTimeout(function(){
            if(!navigator.onLine) return;
            if(typeof gdFlushQueue === 'function' && Object.keys(window._gdPendingQueue||{}).length){
              gdFlushQueue();
              console.log('[FeeSync] F1-Config: feeConfig immediately flushed to cloud');
            }
          }, 2000);
        };
      }

      var _origSaveFs2Silent = (typeof saveFs2Silent==="function") ? saveFs2Silent : null;
      if(typeof _origSaveFs2Silent === 'function'){
        window.saveFs2Silent = function(){
          _origSaveFs2Silent.apply(this, arguments);
          // Queue BOTH class-prefixed key AND plain admNo key immediately
          // FIX Bug2b: Pehle sirf plain key queue hoti thi — class-prefixed miss ho jaati thi
          try{
            var admNo = document.getElementById && document.getElementById('fs2Adm') ?
                        document.getElementById('fs2Adm').value : null;
            if(admNo && typeof gdQueueSave === 'function'){
              // Plain key (no class prefix) — for F5/F7/Statement
              var plainKey = erpKey('erp_fs2_') + admNo;
              var pv = localStorage.getItem(plainKey);
              if(pv){ try{ gdQueueSave(plainKey, JSON.parse(pv)); }catch(e){ gdQueueSave(plainKey, pv); } }
              // Class-prefixed key — the primary storage key
              var cls = document.getElementById('fs2Class') ? document.getElementById('fs2Class').value : '';
              if(cls){
                var classKey = erpKey('erp_fs2_') + cls.replace(/\s+/g,'') + '_' + admNo;
                if(classKey !== plainKey){
                  var cv = localStorage.getItem(classKey);
                  if(cv){ try{ gdQueueSave(classKey, JSON.parse(cv)); }catch(e){ gdQueueSave(classKey, cv); } }
                }
              }
            }
          }catch(e){}
          scheduleFeeCloudFlush('F2-Receipt');
        };
      }

      var _origSaveFs2 = (typeof saveFs2==="function") ? saveFs2 : null;
      if(typeof _origSaveFs2 === 'function'){
        window.saveFs2 = function(){
          _origSaveFs2.apply(this, arguments);
          scheduleFeeCloudFlush('F2-SaveBtn');
        };
      }
    }, {once: true});

    // ── 3. Also trigger on showFsTab (tab switch) — queue all fee data ──
    var _origShowFsTab = null; // captured once — never re-assigned after patch
    var _showFsTabPatched = false;
    function patchShowFsTab(){
      if(_showFsTabPatched) return; // already patched — don't re-capture, prevents infinite loop
      if(typeof window.showFsTab === 'function'){
        _origShowFsTab = window.showFsTab;
        window.showFsTab = _patchedShowFsTab;
        _showFsTabPatched = true;
      }
    }
    function _patchedShowFsTab(id, btn){
      // ── FIX: Save + flush current F2 student data BEFORE switching tab ──
      try{
        var curAdmNo = (document.getElementById('fs2Adm') && document.getElementById('fs2Adm').value)
                     || (document.getElementById('fs2Student') && document.getElementById('fs2Student').value)
                     || '';
        if(curAdmNo && typeof saveFs2Silent === 'function') saveFs2Silent();
        // NOTE: Pehle yahan localStorage ke SAARE erp_fs2_* keys (har student ka
        // cached fee data) blindly gdQueueSave + flush ho jaate the on every tab
        // switch. Agar kisi student ka local cache stale/empty hota (e.g. cloud se
        // abhi tak fetch nahi hua), toh yeh empty data cloud ke better data ko
        // overwrite kar deta — cross-device sync break ho jaata.
        // Fix: sirf ABHI active student ka data queue karo (saveFs2Silent already
        // karta hai upar). gdFlushQueue ka FEE DOWNGRADE GUARD bhi extra safety hai.
        // Queue static fee keys
        var staticKeys = [erpKey('erp_feeConfig'),erpKey('erp_feeMonths'),erpKey('erp_customFees'),erpKey('erp_fees'),erpKey('erp_persist'),erpKey('erp_lastReceiptNo')];
        staticKeys.forEach(function(k){
          var v = localStorage.getItem(k);
          if(v && typeof gdQueueSave === 'function'){
            try{ gdQueueSave(k, JSON.parse(v)); }catch(e){ gdQueueSave(k, v); }
          }
        });
        // ── Debounced flush — rapid tab switching pe ek hi flush ho (500ms) ──
        clearTimeout(window._feeAutoFlushTimer);
        clearTimeout(window._feeTabFlushDebounce);
        window._feeTabFlushDebounce = setTimeout(function(){
          if(navigator.onLine && typeof gdFlushQueue === 'function' && Object.keys(window._gdPendingQueue||{}).length){
            gdFlushQueue();
            console.log('[FeeSync] Debounced flush on FsTab switch to:', id);
          }
        }, 500);
      }catch(e){}
      if(typeof _origShowFsTab === 'function') _origShowFsTab.call(this, id, btn);
    }
    // Try patching immediately and after page ready
    setTimeout(patchShowFsTab, 500);
    setTimeout(patchShowFsTab, 2000);
    document.addEventListener('rsk-ready', patchShowFsTab);

    // ── 4. On feestructure tab switch: queue ALL erp_fs2_* and erp_fs5_* keys ──
    var _origSwitchTab2 = null; // captured once — never re-assigned after patch
    var _switchTabPatched = false;
    function patchSwitchTab(){
      if(_switchTabPatched) return; // already patched — don't re-capture
      if(typeof window.switchTab === 'function'){
        _origSwitchTab2 = window.switchTab;
        window.switchTab = _patchedSwitchTab;
        _switchTabPatched = true;
      }
    }
    function _patchedSwitchTab(tabId){
      // ── FIX: When leaving ANY tab, flush pending fee data immediately ──
      try{
        if(typeof saveFs2Silent === 'function'){
          var curAdmNo = (document.getElementById('fs2Adm') && document.getElementById('fs2Adm').value) || '';
          if(curAdmNo) saveFs2Silent();
        }
        // NOTE: blind 'queue ALL erp_fs2_* keys' removed — see _patchedShowFsTab
        // comment above for why this was unsafe for cross-device fee sync.
        clearTimeout(window._feeAutoFlushTimer);
        clearTimeout(window._feeTabFlushDebounce);
        window._feeTabFlushDebounce = setTimeout(function(){
          if(navigator.onLine && typeof gdFlushQueue === 'function' && Object.keys(window._gdPendingQueue||{}).length){
            gdFlushQueue();
            console.log('[FeeSync] Debounced flush on switchTab to:', tabId);
          }
        }, 500);
      }catch(e){}
      if(typeof _origSwitchTab2 === 'function') _origSwitchTab2.call(this, tabId);
    }
    setTimeout(patchSwitchTab, 500);
    setTimeout(patchSwitchTab, 2000);
    document.addEventListener('rsk-ready', patchSwitchTab);

    // ── 5. On gdInitLoadAll (cloud restore): also restore erp_fs2_* and erp_fs5_* ──
    var _origGdInitLoadAll = window.gdInitLoadAll;
    function patchGdInitLoadAll(){
      if(typeof window.gdInitLoadAll === 'function' && window.gdInitLoadAll !== _patchedGdInit){
        _origGdInitLoadAll = window.gdInitLoadAll;
        window.gdInitLoadAll = _patchedGdInit;
      }
    }
    async function _patchedGdInit(){
      if(typeof _origGdInitLoadAll === 'function') await _origGdInitLoadAll.apply(this, arguments);
      // Also pull dynamic fee keys from cloud
      try{
        var CF_URL = window.CF_WORKER_URL;
        if(!CF_URL || !navigator.onLine) return;
        var resp = await fetch(CF_URL+'/general/keys', {
          headers: (typeof cfGetHeaders==='function') ? cfGetHeaders(false) : {}
        });
        if(!resp.ok) return;
        var allCloudKeys = await resp.json();
        if(!Array.isArray(allCloudKeys)) return;
        var feeKeys = allCloudKeys.filter(function(k){ return k.indexOf(erpKey('erp_fs2_'))===0 ; });
        for(var i=0; i<feeKeys.length; i++){
          var key = feeKeys[i];
          // FIX Bug1: Stale local key skip mat karo — cloud data always wins on init
          // (user ne dusre device pe data bhara tha, yahan empty/stale copy ho sakti hai)
          try{
            var kr = await fetch(CF_URL+'/general?key='+encodeURIComponent(key), {
              headers: (typeof cfGetHeaders==='function') ? cfGetHeaders(false) : {}
            });
            var kd = await kr.json();
            if(kd && kd.value){
              var decompressed = (typeof rskDecompress==='function') ? rskDecompress(kd.value) : kd.value;
              // FIX Bug2: Mirror plain key bhi set karo (class-prefix ke bina)
              // Taaki F5/F7/Statement modules bhi read kar sakein
              localStorage.setItem(key, decompressed);
              try{
                var parsedForMirror = JSON.parse(decompressed);
                var mirrorAdmNo = parsedForMirror && parsedForMirror.admNo;
                if(mirrorAdmNo){
                  var plainMirrorKey = erpKey('erp_fs2_') + mirrorAdmNo;
                  if(plainMirrorKey !== key){
                    localStorage.setItem(plainMirrorKey, decompressed);
                  }
                }
              }catch(e2){}
              console.log('[FeeSync] Restored from cloud:', key);
            }
          }catch(e){ /* silent per-key error */ }
        }
      }catch(e){ console.warn('[FeeSync] Dynamic key restore failed:', e.message); }
    }
    setTimeout(patchGdInitLoadAll, 600);
    setTimeout(patchGdInitLoadAll, 2500);
    document.addEventListener('rsk-ready', patchGdInitLoadAll);

    // ── 6. Page unload: flush any pending fee data ──
    window.addEventListener('beforeunload', function(){
      // Sync queue all dynamic fee keys before leaving
      try{
        Object.keys(localStorage).forEach(function(k){
          if(k.indexOf(erpKey('erp_fs2_'))===0  ||
             k.indexOf('erp_fee')===0 || k === erpKey('erp_persist')){
            var v = localStorage.getItem(k);
            if(v && window._gdPendingQueue && !window._gdPendingQueue[k]){
              try{ window._gdPendingQueue[k] = JSON.parse(v); }catch(e){ window._gdPendingQueue[k]=v; }
            }
          }
        });
      }catch(e){}
    });

    // ── 7. Visual indicator: show fee sync status on fee tabs ──
    function addFeeSyncBadge(){
      var feeBtn = document.getElementById('tab-fee-btn');
      if(!feeBtn || document.getElementById('fee-sync-badge')) return;
      var badge = document.createElement('span');
      badge.id = 'fee-sync-badge';
      badge.title = 'Fee data auto-saves to LocalStorage instantly.\nCloud sync happens every 20 sec after changes\nor when you press ☁️ Save button.';
      badge.style.cssText = 'display:inline-block;margin-left:4px;font-size:8px;background:rgba(16,185,129,.3);color:#6ee7b7;border:1px solid rgba(16,185,129,.4);border-radius:4px;padding:1px 4px;cursor:help;vertical-align:middle;';
      badge.textContent = '💾 AUTO';
      feeBtn.appendChild(badge);
    }
    setTimeout(addFeeSyncBadge, 1000);
    document.addEventListener('rsk-ready', function(){ setTimeout(addFeeSyncBadge, 500); });

    console.log('[FeeSync] Fee F1-F7 auto-save patch loaded ✅');
  })();
  

